const T06 = {"name":"族氏方国","key":"06_族氏方国","count":657,"data":[{"id":1,"author":"张淑一; 苏建忠","title":"霸姬簋铭文史事新探——兼谈出土文献研究方法的问题","abstract":"霸姬簋铭文反映的是霸姬在霸氏家族立后之争中借助王室卿大夫的干预取得胜利的史事。霸氏应为卿大夫家族,而非诸侯国,霸姬与霸仲应为母子关系。霸仲墓所出记录霸姬与气诉讼的盘、盉,器主应为霸姬而非气。出土文献研究要注意与传世文献及其他出土材料形成多重印证,所作的推论应遵循古代社会伦理常识。将一些带有特殊性、地方性的事物上升到普遍性制度运行机制的高度,甚至视为制度性变化的依据,容易陷于揠苗助长。","categories":["06_族氏方国","09_其它"],"year":2026,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2026.01.016","pages":"164-172","volume":""},{"id":2,"author":"刘义峰","title":"先王与故国:商尊与商卣系周武王妃嫔作器考证","abstract":"商尊与商卣并非微史家族所作,而是庚姬为已故的周武王作器。铭文中的“文辟日丁”指周武王,“帝后”指周武王的王后王姜,“庚姬”是周武王的妃嫔。庚姬来自商王室,故以国名“商”自称。商尊与商卣揭示了武王灭商前后商周联姻这一客观史实,同时也是西周早期殷遗民之间密切交往与友好互信的见证。","categories":["06_族氏方国"],"year":2026,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2026.01.015","pages":"157-163, 192","volume":""},{"id":4,"author":"张昌平","title":"戴叔朕鼎、戴国及其所关联的汉淮与山东地区之间的文化交流","abstract":"传世的多件戴叔朕鼎，器形为盆形附耳，与两周之际前后中原地区流行的釜形底的附耳或立耳鼎不同，为汉淮地区所常见，具有区域文化特性。此类形制的鼎还散见于今山东地区及以南，从而勾连出汉淮地区与山东地区之间确切的文化关联。戴叔朕鼎及其附耳盆形的形制，既揭示出春秋早期戴国之亡，也再现了曾国在区域文化交流中的主导地位。","categories":["06_族氏方国"],"year":2026,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2026.01.005","pages":"4-13, 159","volume":""},{"id":25,"author":"黄明磊","title":"论西周金文中的三类族姓及其分类标准","abstract":"周人创造姬、姜、姞、姒、嬴、妫等带女字旁的“姓”，并将之赐予中原地区各族团上层家族。周王室只与拥有这类带女字旁的“姓”的家族通婚。但赐姓的对象不包括以商王室家族为代表的殷遗，故历代周王从未与商王室为代表的殷遗家族联姻。由此我们可以通过是否拥有带女字旁的“姓”将西周的族姓分为三大类：一是姬姓周人；二是被周人征服的殷遗民；三是被周人征服但又不属于殷遗民的族群，我们可将之称为“非商族姓”。“非商族姓”种类繁多，数量庞大。他们在商代臣服于商王室，并深受商文化熏陶，因而学会了使用日名，部分家族甚至拥有族徽，后又被周人征服，转而臣服于周，开始接受周文化影响。","categories":["06_族氏方国"],"year":2025,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2025.06.002","pages":"46345","volume":"45"},{"id":29,"author":"王帆","title":"由铜器铭文再论北白鹅墓地的族氏与族姓","abstract":"根据北白鹅墓地所出匽大子簋，可知北白鹅宗族为匽氏而非匽仲氏。匽仲盘和仲大父簋铭末均标识族徽“华”，北白鹅匽氏即西周晚期善夫华氏之分支。“太保匽仲”排行为“仲”，可能是匽氏首位宗子，盖因简在王廷，任职太保，得以获封匽地，其墓葬M5在墓地中规格最高。出自华氏窖藏的仲姞鬲所附“华”为仲姞夫氏，宗妇铸夫氏于铭后常见于西周，可举姬趛母鬲为证，故华氏/匽氏非姞姓；善夫梁其器铭与虢季甗铭可证华氏/匽氏亦非姬姓。北白鹅匽氏不可与传世文献的姞姓南燕或姬姓北燕比附，应是典籍佚记的另一支匽氏。","categories":["06_族氏方国"],"year":2025,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2025.04.006","pages":"69-74","volume":""},{"id":48,"author":"黄锦前","title":"陈国铜器铭文研究","abstract":"本文将传世和出土的陈国及有关铜器铭文加以整理，主要就铜器年代、铭文内涵及其所反映的两周时期陈国的历史文化等问题着重进行分析讨论。陈国有铭铜器贯穿两周时期，尤以春秋早中期为最多，在一定程度上反映了其政治、经济地位和文化水平。据铜器铭文可知，两周时期，陈系南土的一个重要诸侯国，在王朝和诸侯中地位非同寻常。大量的媵器以及反映婚姻关系的铜器铭文，表明两周时期陈国贵族与姬周王朝及郑、蔡、息等姬姓以及齐等姜姓诸侯广泛联姻，两周时期陈国地位之重要，由此可见一斑。春秋中期以后，陈国在内忧外患中风雨飘摇，屡屡为楚所侵迫，最终为楚所灭；春秋中晚期以后的陈国铜器暨铭文多受楚文化影响，至春秋晚期已几乎完全被楚文化所同化。","categories":["06_族氏方国"],"year":2025,"publication":"陕西历史博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJL4cFPlDy6Du0neGzwOMAEbEwIP8ygHUIcIXhjIzmge0HkQARVDQzqLmpIEZkD9zUVUIT-IDMceTbYdIWydQfeTdnl_3u8JyXJXtzwuR0sFrklGDOMuoieTzmvF4U0uCSS78FK11XlFA_7M74U6K_6NYQinTJVeluboO46t59NJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"178-194","volume":""},{"id":56,"author":"张志鹏; 尹俊敏","title":"南阳内乡郭岗出土彔子艅甗诸器及相关问题研究","abstract":"南阳内乡县郭岗出土的彔子艅甗应是西周昭王时期彔氏宗子“彔子艅”为其父所作祭器。清华简《系年》中的“彔子耿”是商纣之子武庚（耿）禄父，其与西周成王世器太保簋铭文中的“彔子”均应是早于“彔子艅”的彔氏宗子。源于彔子耿的子姓彔氏以位于后来周之北土范围内的彔为封邑，因以邑为氏。周初，彔子耿反叛周王室失败后，其子彔子继续对抗，至昭王世彔子之孙彔子艅臣服周王室，大概在昭王南征前后被南迁于周之南土，以阻止荆楚北上或抵御淮夷侵扰。随着楚国的壮大与扩张，彔氏被迫东迁，但终亡于楚，故地成为楚国彔邑。彔与六，源流与族姓均异，彔及楚国彔邑与六及楚国六县并无关系。彔伯所属的彔氏分支亦世代服事周王室，至少延续至彔伯星父时期。","categories":["06_族氏方国"],"year":2025,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLAOfNZFV1FaNnkJthbBqc5u5VjIlSds-cKwvGlTaWD-_waguz-0oF0PCjVjYBl5Tkl6aUorGD_rlLREEI0bkVEX-7PGMD2qjrZP017aFCaErTvaVMj90GQj3DzsXg1a326L5RxrBD-XQiym0t7Ifoe8Vk74RVDUXfu1JvBFI_COpk7syn8TKu6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-93, 180","volume":""},{"id":68,"author":"牟浩馨","title":"从新见格姬诸器看西周金文中的宗子遗孀","abstract":"山西翼城大河口M2002出土的格姬簋和霸姬盘、盉三器，记载了格姬在霸氏无君期间以宗子遗孀身份参与立嗣并提起诉讼诸事，是西周时期十分罕见的女性处理外事的铭文。从女性自作器中可知，宗子遗孀借助政治等级关系在家族成员中享有较高的地位，并扮演着女性家长的政治角色。部分宗子遗孀在特殊的政治情况下还可以参与宗族公共事务的处理，这种行为因产生了积极的治理效果而获得了普遍的认可。格姬簋等特例生动地展现出这一特殊群体在宗族内的生存境况，对研究家族内部政治形态、成员等级关系等问题有重要价值。","categories":["06_族氏方国"],"year":2025,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2025.03.015","pages":"51-59","volume":"46"},{"id":69,"author":"杨鹏飞","title":"山东济南地区出土青铜器的文化特征研究","abstract":"山东济南地区的青铜器在文字、纹饰等方面有其独到之处，体现了商晚期地域文化的多元性和融合性。文章从青铜器铭文的内容、装饰与艺术风格等方面，阐述了铭文在家族象征、社会结构和地域交往等方面所起的重要作用。通过对济南金文的研究，发现其文字与图案既有对中原文化传统的继承，又有独特的地域特征，是了解我国青铜文化与地域结构的重要材料。","categories":["06_族氏方国"],"year":2025,"publication":"文物鉴定与鉴赏","link":"https://link.cnki.net/doi/10.20005/j.cnki.issn.1674-8697.2025.17.035","pages":"142-145","volume":""},{"id":81,"author":"黄锦前; 朱子怡","title":"复议上曾太子般殷鼎的国别及相关问题","abstract":"本文从器形、纹饰、铭文内容、文例及字体等各方面详加论证,申述上曾太子般殷鼎应系湖北姬姓曾国之器,而非山东姒姓之曾。上曾太子般殷与曾子倝鼎的“曾子倝”应系同人,“倝”为其名,“般殷”系其字,其身份为姬姓曾国太子,后即位为曾侯,年代为春秋早期前段。鼎铭既称“上曾”,则当时必有“下曾”,这与两周时期曾国都城曾多次迁徙有关,上、下曾的确切地望,还有待进一步确认。","categories":["06_族氏方国"],"year":2025,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI69pQDVYVofLDCx3tE12Osv4D45TrtfUJWKm9RusAI-FROc2hJDELqylkLPqmVXREZE5Spx9s0S-bTMc6sBNDaMmt2VSTVLAWAFxOxZld_tYpr7DEsfNei0MncUOTMmtNiUt193Nhc0EdqZ41gjaesDvZ3iztMJiDhcLO8TUz3LA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-81","volume":""},{"id":112,"author":"王一凡","title":"效尊效卣铭文的新发现","abstract":"效尊、效卣是西周早中期的重要铜器。通过分析铭文中“王”“公东宫”“效”的关系；“不敢不万年夙夜奔走扬公休”的特殊情感；器形纹饰的分期断代；器主“效”的重要身份后，可将二器定为昭王末年，身为王孙的“效”所作之器。“效”与“扈”，前者为名，后者为字。而效尊、效卣的出土地点，将为寻找恭王之陵，乃至西周王陵区提供线索。","categories":["06_族氏方国","07_分期断代"],"year":2025,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2025.02.012","pages":"24-27, 35, 81","volume":""},{"id":119,"author":"王建峰; 井中伟","title":"周代芮国迁徙的考古学探索","abstract":"从铜器铭文、墓葬分布、葬俗特征等方面观察，梁带村墓地和刘家洼墓地应是包含国君墓在内的芮国墓地。根据对两处墓地中铜器墓年代的判断，梁带村、刘家洼遗址应是春秋时期芮国前后相继的两处都城所在。芮国都城在春秋早期晚段的变迁，可能与“芮伯万出居”事件有关。结合对虞国地望的认识，商末周初的芮国应在关中地区西北部。商末的争讼之芮与西周的公卿之芮似乎有别，西周初年芮国可能被重新分封。芮国在两周之际迁徙到关中地区东部，或与戎狄的侵扰有关。","categories":["06_族氏方国"],"year":2025,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIks1ugoL1g0cDoUkB4zpa8c3vS6oyWoKngqcKYMa-8O_8_0hjxH8UKb5GAIzNQ9DqYTHboyZ7Q9Oh0PhKqUjO3TnXhJCQvs61CvRY1l2Zv-hHJshQsHYgIQ1TT8qwVR3LhICga-2Y7CzqualNPR21i-HmwvJqOZtU-o5PJ89tJQrMZafYJnqYa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-77","volume":""},{"id":135,"author":"王宁","title":"雌盘人物及其相关史事考释","abstract":"申县贵族墓地M6所出的雌盘，形制上带有明显的楚系铜盘特征。器主雌的父亲子趒应是史籍中所见蔡景侯时奔楚的蔡公子履，“趒”与“履”一字一名，皆取有所往之意；雌应是其后裔在楚者。蔡臧君、子趒、子雌为世系连贯的祖孙三代。蔡景侯以后，蔡、楚两国公族间频繁通婚，这种甥舅之国的关系使得蔡国日益紧密地依附于楚国而存在。","categories":["06_族氏方国"],"year":2025,"publication":"文物鉴定与鉴赏","link":"https://link.cnki.net/doi/10.20005/j.cnki.issn.1674-8697.2025.10.033","pages":"138-141","volume":""},{"id":142,"author":"米童","title":"徐国早期文化、政治与社会生活分析——以费县出土徐子鼎为例","abstract":"徐子鼎于1966年出土于山东省临沂市费县南张庄乡台子沟村，鼎身通高21.5厘米，口径24.3厘米，重量3200克，其独特的造型、精美的纹饰以及蕴含丰富信息的铭文，为研究徐国早期的历史文化提供了珍贵的实物资料。通过对徐子鼎的深入分析，我们能够从微观层面切入，以小见大，探究徐国早期在文化、政治及社会生活等方面的独特形态。","categories":["06_族氏方国"],"year":2025,"publication":"收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLnpiKZKsZg-cKytRjlsgxxUOasqm0w1DrFe3Vo5qewhZ2JVRsloRPzV4jilF55QmWq_6j62SKOXU3STok-GjMiLvlowsCo-sN9PQH9q84AGcr2ZWkERwrsrUzhiyJr4w_rMMy3ef9_esdfgDwCPvlDQoL5ZCUOFtxm1bLMXMPNEHrlPObmL-Uv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-134","volume":""},{"id":147,"author":"李泽皓; 陶兴华","title":"商周时期六盘山地区古族古国研究","abstract":"商周时期六盘山地区的族群交融与文明演进,是理解中华文明多元一体格局形成的关键窗口。六盘山地区作为连接中原与西北的咽喉要道,凭借六盘山脉的天然屏障与泾渭水系的交通网络,成为周秦王朝经略西北的战略支点。活跃于此的密国、获国、猃狁、义渠等族群,通过军事博弈、联姻结盟与技术交流,形成了独特的文明互动模式。周人利用密、获等地方势力镇守关陇通道,以姬姜联姻构建血缘联盟网络,同时将殷商遗民以及他们的青铜铸造技术引入六盘山地区,形成“军事防御+文化渗透”的双重治理体系。秦人崛起后“霸西戎”,以城邑建设推动游牧族群向农耕定居转型,为后世政权的治理奠定了基础。六盘山地区诸多墓葬中出土的周式青铜器与草原风格器物,生动展现了中原文化与草原文化的互动融合。该区域的族群互动呈现出“冲突中融合”的动态特征:殷商遗民通过接受周王朝分封融入分封体系,活跃在此的各部族文化互相融合,诸如灵台白草坡、彭阳姚河塬等多个遗址出土不同","categories":["06_族氏方国"],"year":2025,"publication":"808","link":"","pages":"","volume":""},{"id":153,"author":"王占奎; 种建荣","title":"高祖伯括、皇祖南公与曾侯、曾侯谏及犺（夭）试探","abstract":"通过分析曾国三钟铭文与叶家山出土铜器及铜器铭文可知，高祖即伯括、犺可能是见于清华简《良臣》的南宫夭，而皇祖是南公，均为曾国远祖。曾是从皇祖南公这一支分化出来的，其称曾侯不当早于其皇祖南公受命于康宫即不早于康王之死亦即不早于昭王。叶家山三座大墓的早晚顺序当是M111、M28、M65，其中前两座是曾侯墓。叶家山有两代曾侯，延续时间大概在昭王前十五年。相比已有观点，年代推断略有推迟，但矛盾并不大，只不过是期内段位的稍早与稍晚的不同而已，在类型学年代判断合理的浮动范围之内。叶家山提供了背景清楚的一批昭王铜器。这一推断很符合康宫原则。康宫原则并不因曾公■编钟而崩溃而是显示出极强的生命力。","categories":["06_族氏方国"],"year":2025,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7cDR0msNvbSxEaxOyWxS5hQhGkx1MR757CRWC8CvfM_uTbL4f6bgzz6g-N__-55L1aAkvfBhmXH4G4dg9QwVKMdg7_UdatSoaP4Ph9AyJc0cERDDugr4lh7VMf31BfiQiIsULB2SRlvi0eaE-R17-e4xt7IddGyFH6TXQR_UxwlQBVzKbiSb-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115-126","volume":""},{"id":159,"author":"申红宝","title":"琉璃河遗址出土西周效尊、卣组器小考","abstract":"2002年8～9月，北京市考古研究院在房山区琉璃河遗址墓葬区I区发掘了12座西周墓葬。其中M2规模最大，等级较高，随葬的铜器较为丰富，有容器、兵器、车马器等。通过IM2出土的铜礼器中效尊、卣组器的铭文来看，墓主人应为效卣的器主“效”，族属为殷遗民。效尊、卣组器属于一尊一卣的配列组合，年代上应为西周昭王时期。该组器为研究西周昭王、穆王时期殷遗民在酒器器用上的简化方向提供了重要的实物资料。","categories":["06_族氏方国","07_分期断代"],"year":2025,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6IWtuUibyNmlpZjWItWGLiG_cCYDUkVnhqfaCBai1Orb2SO4PNNbfcLRW16rD4fZG6q1ouCFdHy94sdZuA9kI5YuWI0mFKx2fVCCLNSeDqKlNRqG5nFWSP0ozgHOi-5s8bCnfnq-qnPfjvaaGCB7Qbga-U6nuOz6X2V4BQmKUKr1VHbRU_rwi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-48","volume":""},{"id":187,"author":"鄢国盛","title":"莒侯少子簋与莒国灭亡问题新探","abstract":"关于莒国的灭亡，蒙文通曾考证其在战国中期为齐所灭，学者多不采信，仍坚持《史记》战国早期楚简王灭莒之说。莒侯少子簋是现存少有的几件莒国铜器，无论器形还是铭文字体、内容皆与陈侯午簋相似，时代当属战国中期。“莒侯”之称是东夷莒君僭用中原诸侯的称号。战国早期莒是小国，依附于晋、越两国，长期与齐对抗以求自存，随着晋、越对齐作战取得关键性胜利，三晋向周天子邀功列为诸侯（前403年），莒才效仿三晋僭号称侯。此后不久，三晋失和，越国南徙，齐威王复兴，莒失去依靠，为齐所灭，时间在齐威王九年至十四年间（前348—前343年），故蒙氏之说更为可信。","categories":["06_族氏方国"],"year":2025,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJv4rxsPor992iJofh5KdN3KK7BKZoaux9RvNgjIyXMbtJFtCLTUrTl-yFAxersdELLWcd9_Hp8helTehyo-GIeVqN2ZjLS15yYU5bYvY2RBcR4-EmblM2ZQli-5ftfoZM8OfL4CyzoQVhQM5WHEE4eYN4xA0tCyx6a3g72ijHDfaq_96VBXXf4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-96","volume":""},{"id":189,"author":"趙慶淼","title":"新見格公方鼎銘文試釋——兼論金文“格”與“霸”的關係","abstract":"北趙晉侯墓地M113出土的格公方鼎，乃是“格公”爲其媿姓夫人所作之器，用於夫家宗廟“隰宫”的祭祀活動。根據周代社會“同姓不婚”的原則，可知“格公”當非媿姓，而霸伯家族則在文化屬性上接近晉國的“懷姓九宗”，這便爲“格”與“霸”的區分提供關鍵依據。另一方面，金文“霸”“格”二字在寫法上或有交叉，僅是替换聲符加强表音所致，也不足以證實“格”“霸”爲一。結合人群族屬、地域範圍、國族稱謂及其通假用例判斷，金文霸氏與赤狄潞氏最相契合，二者很可能是一脉相承的。","categories":["06_族氏方国"],"year":2025,"publication":"文史","link":"https://link.cnki.net/doi/10.19325/j.cnki.11-1678/k.2025.01.009","pages":"220-234","volume":""},{"id":190,"author":"黄明磊","title":"论西周金文中的“多姓同氏”现象及其成因","abstract":"周人通过灭商和东征,控制了中原地区,同时攻灭了大批国族。为了稳固对新征服区域的统治,周王一方面在各地分封诸侯国,另一方面推行强制性的族群迁徙政策,将大批被征服族群迁至王畿地区安置。由此,宗周王畿内的丰、郑、京等都邑聚居了众多的异姓贵族。他们以新居地的地名为家族的新氏名,造成了西周金文中不同族姓的家族共用同一个氏名的“多姓同氏”现象的出现。","categories":["06_族氏方国"],"year":2025,"publication":"北方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLF4d1i7lQUzKWX1cY1d-UkahdT1aZXB57XK2FSycp3zSRmlwuzlhMfjw-ozoo9U4feCyvLdz8nApkJmKmauz-T3gqgVY1qGrPHvYgEEMoZgZWtnhP04sLRznsxmgkzNuTOQuG4EMXeu9QqqLEgPZNtRDAygEa0A6h6j9Ovx-JR-Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"174-183","volume":""},{"id":195,"author":"韓巍","title":"由格姬簋銘文再論霸氏家族内争","abstract":"格姬簋出土於山西翼城大河口墓地M2002,出土編號M2002:24,其器形早在幾年前已經公布。[1]其後此器入藏山西青銅器博物館,在提取完銅簋内土樣後,發現器内底有長篇銘文。2023年9月,嚴志斌、謝堯亭兩位學者發表《格姬簋銘研究》（以下簡稱《研究》）一文,[2]公布了格姬簋銘文,並做了很好的闡釋。爲了推動學界對這一重要新材料的深入討論,我在同年10月底舉辦的“考古新發現與周代國家形態研究”青年學者工作坊中,[3]專門設置了一場“新出格姬簋銘文專題研討”。會上由嚴志斌首先對格姬簋銘文做了導讀,","categories":["06_族氏方国"],"year":2024,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-Sxg3xxD-ZMkDnavO-0-DZ77Rs53B9K3g4nQpXRbWbgCHBmuz4iMavMqq4Thu_sPh4t1LZwbsDLAw5EInxZAtyWiWSAaKVl6lTJMJLgSlf71jhuMM8KwwnGOQLNJs5fxfcBSV3fCnlrP04dtADJ_ZcpZId3GnDiDfa6ooHmk7iw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-76","volume":""},{"id":216,"author":"孙慎鹏","title":"西周时期鲁国的婚姻——以亚薛史父己鼎为线索","abstract":"西周时期鲁国的婚姻以东土土著雄族为主要联姻对象，具有极强的政治性。晚商东土主要有姜姓族、任姓族、嬴姓族等土著，周公东征之后，嬴姓雄族被流放，任姓诸族成为东土最重要的势力。其中薛国实力雄厚，历史悠久，鲁国选择与之联姻，既可援为己助，又可怀柔诸任，有助于稳定对东土的统治。出土于陕西岐山北郭的亚薛史父己鼎盖为周初鲁薛联姻的产物，是薛国陪嫁给周公夫人的媵器，可作为周初鲁、薛联姻的证据，说明《左传·哀公二十四年》衅夏所言“周公及武公娶于薛”当属史实。","categories":["06_族氏方国"],"year":2024,"publication":"南开史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLuKHpxEXvjIAQQt428vbI-VSqR9r5cFwrm6iD5tEZ0ByKidQvfJ5213kBfO_FANMwP2CSiEtBoxfQx1_TFnfJcE4FBo-xRqOP_mQZWoGH5LSHYvJjas0Pyvek8oNE7vHG5-A8Jo2dipmmCTeHV_8ab3Pcz9bQViLrxJnmwNOl8kw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3-17, 286","volume":""},{"id":233,"author":"罗笛轩","title":"“用燮就楚”与“肈佐天子”:金文所见春秋中晚期曾楚、蔡楚关系对比研究","abstract":"曾国与蔡国均为西周王朝分封于南土的姬姓诸侯国。春秋时期，楚国崛起于汉水西岸，逐渐吞并了汉东及淮水上游地区。在这一过程中，曾国与蔡国相继沦为楚国附庸。在春秋中晚期的曾国金文中，曾国统治者一方面宣扬先祖辅弼文武二王、建立曾国的史迹，强调自身的姬周血统，一方面又将自身帮助楚国对抗吴国的事迹视作功绩加以记载。这反映出曾国统治者作为姬姓诸侯与楚国附庸的双重身份及其对附楚现状的接受。蔡侯申墓葬出土的青铜器铭文，呈现出春秋晚期蔡国统治者对周王室、楚人及吴人复杂的态度。两国金文勾画出附庸国在春秋晚期南土历史变迁中的心态，为我们认识这一时期南土小国的生存状态提供了鲜活的实例。","categories":["06_族氏方国"],"year":2024,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2024.04.016","pages":"95-100, 114","volume":"45"},{"id":242,"author":"辛怡华","title":"吴国与周王室之关系——从宜侯夨簋发现说起","abstract":"一、关于宜侯夨簋的讨论(一)宜侯夨簋为西周早期吴国器1954年江苏丹徒县烟墩山发现了8件青铜器,其中1件是宜侯夨簋。铜器由当地村民发现。江苏省文化事业管理局和江苏省文物管理委员会收到这批铜器后,遂邀请南京博物院、华东文物工作队共同组织调查小组,于10月17日到实地勘查,确认铜器出土于南北宽3米、东西长3.6米的墓葬。在此坑西北发现两座小墓,很有可能是第一个大墓的陪葬墓。[1]当时文物行政部门对这起文物出土事件处置是及时、慎重和负责任的,他们的结论应该是可信的。","categories":["06_族氏方国"],"year":2024,"publication":"秦始皇帝陵博物院论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkcuhJgwd1XHb7Ztq5Hv1O9KZIiKhwjn6DtsRox18g5rmLRMCaSLMBC45p4yKnfk6ZhdZuUs8eG8YftxyMfrpoBwuW492S37acgeA40KoOYRo13dv94HV78QPAuuqGTw4W1SzeTqH7oAJM2r93zkQdYT1TusLFwz7gp-YR-XOQxQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-46","volume":""},{"id":243,"author":"高西省","title":"芮伯作倗姬簋、王姊诸器及相关问题","abstract":"近几十年来,西周考古新发现取得的多项成果,如芮国、曾国、霸氏、倗氏等墓地纷纷呈现,2017年又在黄河西岸澄城县刘家洼发现了芮国春秋早中期的都邑遗址,发现包括2座“中”字形大墓在内的多个墓葬区,出土七鼎六簋、五鼎四簋组合及“芮公”“芮太子白”等铭文青铜器[1]。这些接连不断的突破性新发现表明,西周晚期到春秋中晚期芮国居址就在黄河西岸关中东部的韩城、澄城一带,而西周早中期芮国居址在何处一直困惑着学界。","categories":["06_族氏方国"],"year":2024,"publication":"秦始皇帝陵博物院论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWFLYrYu7bTzQR7KCrvxhrCxXUCoVYwB3gh7KTPKskA34lHBtUdmLxZrpq2IvzuwtHT9QiRqiAwXYNzFRIpNsDsGUb95wL52ZBHzFCs7cQ9z1OUsxRdlcvgNyVJf1H8ES4_3sm3uTYw9pfyS-hlDULjoT_xHb99cMsQx9cFl-BHA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-65","volume":""},{"id":244,"author":"黄锦前; 关秦豫","title":"邓国铜器铭文综论","abstract":"邓国是周代南土地区重要的诸侯国之一,《国语·郑语》载史伯云:“当成周者,南有荆蛮、申、吕、应、邓、陈、蔡、随、唐。”历来传世和出土的邓国青铜器数量已渐夥,近年又续有邓国与邓人铜器出土和刊布,本文即以近刊几件有铭邓国与邓人铜器为契机,对邓国有铭青铜器加以综考,以考见邓国历史文化之大概。","categories":["06_族氏方国"],"year":2024,"publication":"秦始皇帝陵博物院论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxElyVpAo0l6oRJaBSAQE9qDsPRhvScMDLfg78g8TsSghuQ9mxeBPcTU_l0fiGnp00oFxq-2mkTdb6kz8wvfGUKrvWljExP-HPy6KiVD7viiIWFJSGtVOADUDeRsrLV_TWespw1s_1JtdVcE5HI3SoaK0t42M9RqSzBVO1fQpzmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-145","volume":""},{"id":260,"author":"李春艳","title":"西周金文中的晋国大事记","abstract":"在西周历史上，晋国作为重要的诸侯国之一，在维护王权的正常运转中发挥着重要的作用。“国之大事，在祀与戎”，通过对相关青铜器铭文的爬梳，可以看到在整个西周王朝的发展过程中，晋国积极参与到中央的军政大事中，如西周初年的封建大典、祭祀大典、殷见大典、军事征伐等。","categories":["06_族氏方国"],"year":2024,"publication":"晋学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJogc_JJSNaT1X2c2Ycs8tfio7UUz9er42R8RgoulhYLP6qjc8eBMNZPSuv7aTkIEa1Ld2Cw9X2ro8XwNfacf4buhka2JvwxyX306KCo59V9Jw7eMUrrRIKw5VEmsYSMEBL1THoA-LKUdj3VaaGnxKCSFFBLEgnUKWruzm_Q__F5g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-73","volume":""},{"id":269,"author":"黄端胜; 雒有仓","title":"论西周金文族徽的种类、数量及其变化","abstract":"西周金文族徽既有不同于商代晚期的族氏名号，也有对商代晚期族氏名号的大量沿袭。这是殷遗民族群在西周社会存在与发展的反映。目前学术界对西周金文族徽尚缺乏全面的整理与研究。通过对西周金文族徽种类、数量的整理与统计可知，西周中后期的族徽种类和数量都呈现明显下降趋势。其原因除了这一时期周文化的强势影响外，主要与西周社会结构、社会关系的变化以及殷遗民对周文化的认同有关。正确认识西周金文族徽种类、数量的上述变化，对于深入认识西周社会组织结构、家族形态、族氏迁移流动以及民族融合等问题，都具有十分重要的意义。","categories":["06_族氏方国"],"year":2024,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2024.05.003","pages":"23-30","volume":"44"},{"id":274,"author":"黄錦前","title":"甲骨、金文所見商末周初獻國及其地望","abstract":"據殷墟甲骨文、商周銅器銘文及青銅器等實物資料可知,“天黽”族氏的起源,至遲可以追溯到商代晚期,係商王室即子姓貴族的分支;天黽族係商王朝的重要政治勢力,曾任軍事統帥類高級武職;商代的鬳(獻)國係商王武丁之子鬳(甲骨卜辭稱“鬳”“子鬳”)的封國,其地望在今河南省澠池縣一帶;西周早期的獻國,與商代鬳(獻)國一脈相承,其地望亦在今澠池縣一帶,丁侯、獻侯係周初前後相及的兩位諸侯,其活動年代分别約與周武王、周成王相當。天黽族銅器出自殷墟及其周邊一帶,即係獻國與商王朝關係的體現,部分銅器出自陝西岐山一帶,可能與商文化的傳播和族群的遷徙有關。","categories":["06_族氏方国"],"year":2024,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5k-JMUcAfpqwBXEVUm-JfxmJ3PuqEx0SLOXA7X-FBuqDBvpoifuB-57OslzexDAVscKKGAaU67ecCVWe_84LuPgklbLnVZUX9JnAN-htzlZ-Qs4kFsX41l6bQias3k8Ax4FRNJDIqI7Eqy0Zpr_PKNKUoQXZOLO2hd-8GpOGUKg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"580-591","volume":""},{"id":294,"author":"陈英杰","title":"班簋之“班”和“毛公”关系新考","abstract":"班簋铭（《集成》4341）197字（含重文2），所记人物及历史事件有重要的史料价值，是西周重器。清宫旧藏，著录于《西清古鉴》13.12，称周毛伯彝（1）。班簋时代主要有成王、昭王、穆王三说，多主穆王说（2）。其铭曰：隹（唯）八月初吉，才（在）宗周（3），甲戌，王令毛白（伯）更（赓）虢■（城）公服（4），■（屏）王立（位）（5），作亖（四）方亟（极）（6），秉緐、蜀、巢（7）令，易（赐）铃、■。咸，王令毛公以邦冢君、土（徒）驭、■人伐东或（国）?（8）戎。咸，王令吴白（伯）曰：“以乃■（师）左比毛父。”王令吕白（伯）曰：“以乃■（师）右比毛父。”■（9）令曰：“以乃族从父征，■（造）■（10）（城）卫（11）父身。”三年静东或（国），亡不成，敃（旻）天畏（威），否畀屯（纯）陟（12）。公告氒（厥）事于上：“隹（唯）民亡■才（哉），彝■（昧）天令（命），故亡。允才（哉）显，隹（唯）敬德，亡■（","categories":["06_族氏方国"],"year":2024,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLULDaNvVjUKXwUG5nZJvOGtPoYo8lTS4WadV3jkmpGfUUnWiMNAgYHGUryum9ttMBe6wk7bnM4Ei6dtwbyaqs-Dq40wgdP0oWxKTKbkuo7Y9qrhwFitM7JFvX203UaQ9gz1lDSltFNqw_PzRGC8TOt8eAD8ha4yYVrkXMnb_jGg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"208-212","volume":""},{"id":340,"author":"徐熠","title":"甲骨金文所见周族考论——兼说一种特殊的商周族氏类型","abstract":"殷墟卜辞所见国族“周”并非姬周，而是长期生活于周原一带的土著周族，西周金文所见妘姓琱（周）氏与晚商甲骨金文中的周族一脉相承。这一观点此前已有学者研究指出（详下），但对于周族的族属性质以及该族在商周时期的生活状态却尚未有讨论。本文拟从文献、考古两个角度对该观点进行补充，并进一步探索周族的族属性质以及该族在商周时期的演变轨迹等问题。","categories":["06_族氏方国"],"year":2024,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZhh35OXkwtbyGE4ExSwgy0L7Gy1Pe8-TCKvLE54Fsu34Wxev22O-y__7yTAp3aKCV-h6KDW8jkYNgKqOiXV-j2xo6DrsGYtnr-GrWj7L1pLpXi4klcnQesYb4REwQ9BDkIoXMQxHfNx0S7RG1jHkX-xNLL8WmeimV9mkhBM9g1w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-66","volume":"18"},{"id":343,"author":"陈絜; 孙慎鹏","title":"两周莒国重要铜器辑遗与相关史地疏证","abstract":"非考古发掘所得的传世铜器，其分域分国研究是金文资料史料化与商周古史重建的重要基础，须以精准的史地考证为前提。通过铭文史地信息的梳理可知，西周吕仲仆爵、繁卣、方尊、簋及东周莒大史申鼎等，悉属鲁东嬴姓莒国礼器，可补两周莒国历史复原的史料之阙，亦有助于姜姓吕国传世铜器的有效甄别。","categories":["06_族氏方国"],"year":2024,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2024.07.003","pages":"4-13, 139","volume":""},{"id":349,"author":"袁俊杰; 侯雅兰","title":"横水墓地M2158异族铜器与赗赙制度","abstract":"西周时期，直接记载赗赙制度的遣策和赗方目前还未发现，但西周墓地出土有非墓主所做的异铭、异国、异族铜器，为研究赗赙制度提供重要的实物资料。根据此类铜器并结合文献记载，探讨横水墓地M2158出土的异族有铭铜器，故知鲁侯鼎、太保鬲、亚高父甲提梁壶是鲁侯、太保、亚高赗赠给墓主倗伯的助葬之器。这不仅是为了表达对死者的追思，更是包含维持国家间敦睦邦交的深层社会关系，它将周王朝与诸侯邦族联系起来，具有定国安邦的重要政治意义。","categories":["06_族氏方国","09_其它"],"year":2024,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2024.04.008","pages":"57-68","volume":""},{"id":399,"author":"韩曈曈","title":"甲骨金文所见亚疑族考论","abstract":"亚疑族是见于商周金文中的一个非常重要的族群，在殷商时期就是显赫的贵族，在周代依然延绵不绝。本文通过考辨亚疑族的源流、迁徙和分化等问题来考察殷周之际部族的发展、周王室对待殷遗民的政策与态度等情况，这对于研究、论证殷周之际部族的来源、迁徙、分化等问题提供了一个很好范例。","categories":["06_族氏方国"],"year":2024,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2024.02.003","pages":"18-23","volume":"45"},{"id":423,"author":"邓浩然; 路国权","title":"胶东地区周代莱夷文化研究","abstract":"龙口归城是莱夷族群的核心分布区,作为胶东地区所见同时期规模最大、内涵最丰富的周代城址,一直备受关注。本文初步收录胶东晚清至近年出土、传世及相关莱夷青铜礼容器,结合铜器铭文、族徽、年代、出土散点分布,观察其中心聚落变动,分析对比其文化因素,旨在阐明胶东半岛青铜时代夷人国家的社会变迁,以期在社会历史范围内探讨其地望推定、国属关系以及文化面貌等问题。在绪 论部分本文首先梳理了胶东地区晚清至近年出土、传世及相关莱夷青铜礼容器材料的发现历史和研究现状。第二部分主要运用类型学的方法对胶东半岛周代莱夷铜器群进行分区与分期研究,把握铜器材料的演变特征,并对相关有争议的墓葬及铜器群进行年代判断上的相互佐证。对胶东半岛的莱夷文化进行分区研究,按照不同时段将其分为三个流域:胶东半岛西部、北部黄水河——大沽河流域;胶东半岛中部夹河——五龙河流域;胶东半岛东部沿海地区的乳山河——老母猪河流域及长岛诸岛。在一个相对固","categories":["06_族氏方国"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27272/d.cnki.gshdu.2024.003506","pages":"","volume":""},{"id":464,"author":"郝晓飞","title":"铜双叉形器新考","abstract":"铜双叉形器是商周墓中发现的一种数量较少的特殊器物，以往对其的称谓描述较为混乱，功能用途也多有舛讹。文章于此统一称谓，并在反驳以往功用观点的基础上推断这种“铜双叉形器”在商周时期应称为“铜干首”，是旌旗的顶部构件。河南淇县大李庄的族群，则很可能是“殷民七族”中的施氏族群。","categories":["06_族氏方国"],"year":2024,"publication":"文物鉴定与鉴赏","link":"https://link.cnki.net/doi/10.20005/j.cnki.issn.1674-8697.2024.06.023","pages":"93-97","volume":""},{"id":469,"author":"曹莉莉; 李鵬輝","title":"鄂國銅器銘文整理與研究","abstract":"鄂國傳世和出土有銘器較少,但這些銘文記錄了相關的歷史細節,反映的內容豐富,是瞭解鄂國史實的一手材料,具有重要學術價值。學界通過對鄂國銅器銘文的研究,已經在鄂國歷史地理問題上取得一定的成果。不過隨着安居羊子山墓及南陽夏餉鋪墓等新材料的出現,以及有關學者在原有觀點上提出的新見解,有些問題需要重新討論。同時,這些成果多散見於不同著作或文章中,不便尋檢,因此,有必要對鄂國銅器銘文進行一次全面、系統的整理與研究。本文 主要以《殷周金文集成(修訂增補本)》和吳鎮烽的《商周青銅器暨銘文圖像集成》《商周青銅器暨銘文圖像集成續編》《商周青銅器暨銘文圖像集成三編》等著作中所收錄的61件鄂國銅器銘文爲研究對象,對銘文中涉及到的字形、詞語、歷史等問題進行匯釋整理。文中 對鄂國銅器銘文的整理與研究共分兩個部分。第一部分是對鄂國銅器銘文的整理與集釋。按族姓不同將這部分分爲姞姓鄂國青銅器銘文集釋和姬姓鄂國青銅器銘文集釋","categories":["06_族氏方国"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.26917/d.cnki.ganhu.2024.002333","pages":"","volume":""},{"id":472,"author":"曹莉莉","title":"鄂国相关青铜器综述","abstract":"目前所见鄂国相关有铭青铜器62件，其中包含11件传世青铜器、随州安居一带出土的三批器物和南阳夏饷铺墓葬出土的四代鄂侯及其夫人作器。这些器物中蕴含了丰富的鄂国相关史实，弥补了传世典籍对鄂国相关史实记载的不足，是了解鄂国发展的重要史料。","categories":["06_族氏方国"],"year":2024,"publication":"今古文创","link":"https://link.cnki.net/doi/10.20024/j.cnki.CN42-1911/I.2024.11.017","pages":"53-55","volume":""},{"id":476,"author":"张垚; 左勇","title":"论西周金文中的墉氏家族","abstract":"西周金文中的■氏家族以往有墉氏、虢氏二说，本文分析“■”字读音，并结合■氏的族姓，认为西周时期的■氏不宜理解为虢氏。目前可见的■氏家族铜器有师■鼎、师■钟等，这些铜器反映了■氏是一个担任师类职官的非姬姓家族；本文也尝试利用这些铜器还原西周时期■氏家族的世系。","categories":["06_族氏方国"],"year":2024,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIp-DTN64ZqtPykPjbzO7a57CXYDxdhcPa9noN1D7S74aNRaluoMDXyzgnc-Co9L4jq8qHGbQOFYEygH9Tn2Bb5QBNvJ35CLP34X03p9A2dgALW4yaH_es43s7RxC-nHlln83dV1z3AZJlNLCoMjHQmPoM3DIBYp3urRHV7XA4rQsZXUTC3-9tO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"11-22, 169","volume":""},{"id":481,"author":"李振源","title":"麦尊铭文首句与邢侯受封问题再议","abstract":"麦尊铭文记载了有关邢侯和西周王室礼的重要史事，其首句“王令辟邢侯出■侯于邢”句读，应属■于侯，理解该句之关键即在于“出■侯于邢”，意指周王命令邢侯将■侯及其宗族带离■地，来到邢地以服事邢侯、拓疆御戎。麦尊首句“出■侯于邢”无关于分封或徙封邢侯事，而是西周早期周人克殷伐戎后将其强制迁族、授予诸侯的缩影。","categories":["06_族氏方国"],"year":2024,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2024.01.001","pages":"24-34","volume":"45"},{"id":486,"author":"李金; 樊森","title":"中山国华夏化进程研究","abstract":"中山国,其族属原属鲜虞部落,鲜虞部落原属白狄,白狄原居圁水(如今秃尾河流域),活跃于邠地(如今甘肃庆阳县至山西汾水一带)。自鲁襄公十八年(公元前555年)迁移至河北太行山东麓,后依托地理区位优势,建立中山国。春秋战国时期,不仅是中华文明形成的重要阶段,也是民族大融合大发展时期,中山国作为少数民族建立的国家,在此时大力推进华夏化,成为了同时期民族文化融合的典范。中山 国华夏化进程划分为三阶段:第一 阶段,中山文公、中山武公时期(公元前457年至公元前408年)。本阶段中山文公收拢四散国民,以少数民族集合立国,中山武公定都于顾,为魏所灭。该阶段的墓葬多出土带有游牧文化特征的典型器物;其时的文字构形特点及思想上不尊王室、山崇拜、“鲜犒”祭祀等现象,亦表现出明显的游牧文化特征。本阶段为中山国华夏化进程的初期。第二 阶段,为中山桓公、中山成公、中山王时期(公元前407年至公元前313年)。本阶段中山","categories":["06_族氏方国"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27672/d.cnki.gcsfc.2024.000283","pages":"","volume":""},{"id":493,"author":"程浩","title":"伯有父剑与楚国封君","abstract":"从形制与铭文的用字习惯来看，伯有父剑应该是一柄战国时期的楚国铜剑。器主伯有父自称“东王之孙”，所谓东王应即楚简王。其父浮君是战国时期的楚国封君，所封之地则有褒信与復地两种可能。","categories":["06_族氏方国"],"year":2024,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJNaBYyihNs8xe2fcrTud_o6mlX5KZhE4g883WM1J0CzZZeRGriQTIq3u960Yu_eAn7Xdxg6Q3WBjddt2u6liniNdRt4arRERnynweT27m5sGKxxavIDsIz7LN149hcr5lspDX467hnNM7Nafy3dD87ywQcEOqUWQXRjYeMva2xT7yILKwRRsaP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-95","volume":""},{"id":519,"author":"谢尧亭; 陈晓宇","title":"横水与大河口墓地人群性质再论","abstract":"自山西绛县横水墓地和翼城大河口墓地发现以来，学者们对其人群性质问题看法不一。本文从二墓地的年代、墓葬规模、古曲沃的问题和青铜器铭文等方面分析，认为横水墓地和大河口墓地人群的性质是西周王室的封国，而非晋国的“怀姓九宗”，既不是所谓的晋国采邑，也不是晋国的附庸。","categories":["06_族氏方国"],"year":2024,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLBZ9oRSrOkZK9iG34pLZCrXuLpwPZH3RIGy2-ipSP3F7_CeqjQfuqPPNRebN30Xlhz0l8GJd8hl8jQhsOOfkrq76GMouuaGfLUEcq70P7Cwvs0woy5ExCxGGX0Gset8KDZq_gJiXkOwejoHkMJtYDwyvF4kvih37sLHYOPsb4N4BcKARuqIbXI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"5-25, 2-4, 209-211","volume":""},{"id":521,"author":"李娜; 陈双新","title":"山西横水倗伯墓所出倗族铜器铭文的特点","abstract":"本文以墓葬为单位，对倗伯墓中所见倗族金文的书体进行了描述，发现到西周中期偏晚阶段达到了倗族铭文书写的顶峰。而在书体风格、铭文内容等方面，倗伯和倗族其他贵族又呈现出不同的特点。","categories":["06_族氏方国"],"year":2024,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPpdE93kRH2w_sDJLZ3Ke9-K_zcXDCXnVo2nvyT1WHRMIBe-k-JINfSR1V1VS-Lo7CAiC4qu-NxllMom2JGmXxJREnBQ4kJl7zP2NO_AHoTpQZodjsixbp3d-yqf7_aBaAS_DpvC5E0jqYFEKnOuDwMTT-0TpaZZ06eEqCst_wv93MTLmnPteP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-53","volume":""},{"id":526,"author":"燕生东; 赵璐璐; 王琦","title":"考古所见枣滕地区周代邦国及相关问题","abstract":"考古发掘资料、铜器铭文和文献记录表明，枣滕地区在周代存在着10多个邦国：有来自西部周文王子错叔绣所建的姬姓滕国，有商末就迁来此地的望族史氏、因与周王室通婚姻亲而受封的妊姓薛国，有因与周王室的姻亲和先圣王后裔妊姓邳国、姒姓鄫(缯)国，有祝融集团曹姓东夷小邾(郳)国、滥国及妘姓偪阳国，还有嬴姓粊(鄪)国、■姓虎佁、灵父及媿姓昆等当地东夷邦国。这里是东方地区发现周代邦国数量最多、姓氏及族属最为复杂的区域，也是商系文化、姬周文化、东夷文化等交融地区。","categories":["06_族氏方国"],"year":2024,"publication":"枣庄学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKA5mN8x8r08I2r-ogFYzapT2XZGGxddh4iIEyWSnz38yHZ3F8YEsPv92c9beCyJUgHmmwlGibz5vr5X_-ND9f8BoM0UKA_BnqRe_-2IvR2AO3PJ9sNxrWhuMqDBRU9IvRoMjqvoiEZvIjLE-wzVSpFEfIEuzhjzk8b1GlcMjmMO3r5xN8Wd7tv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-76","volume":"41"},{"id":527,"author":"王琦; 赵璐璐","title":"考古所见枣滕地区周代四个本地邦国","abstract":"枣滕地区考古发现了周代灵父、虖台、昆、小邾(郳)诸邦国的墓葬、城址及出土遗物，出土的铜器铭文中其国君自称“君”,与华夏诸邦国君称“公、侯、伯”等爵称不一致，其姓也比较特殊。结合文献记录，枣滕地区四邦国应属于东方地区的土著国家。这为我们研究枣滕地区周代邦国族属、来源、种类、文化等提供了一个全新的视角。","categories":["06_族氏方国"],"year":2024,"publication":"枣庄学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKA5mN8x8r08I2r-ogFYzapT2XZGGxddh4iIEyWSnz38yHZ3F8YEsPv2CpliG2-g81SgX60uuH4I0mrO2daqufZmffTdqynYSyhsWUJM72_KaJuBnuyBI7yYV8keWhzZFGz3WAxZZ3U2FC0O9ToYxsdPaUAzuawO_EJZLhGMgo3MC44Oz2w_8cq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-88","volume":"41"},{"id":368,"author":"羅笛軒","title":"兩周金文所見“曾伯”身份考——兼論“曾伯”稱謂消失的原因","abstract":"從相關出土銅器銘文來看，西周、春秋時期的曾國君主多稱爲“曾侯”。除“曾侯”這一主流的君主稱謂外，“曾伯”在西周晚期至春秋早期的曾國金文中也比較常見。金文所見“曾伯”的身份地位關涉到曾國宗族的特點、春秋戰國諸侯國君主稱謂的變化等重大問題，有較大研究價值。","categories":["06_族氏方国"],"year":2023,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEoHlKJhmI_kNW1synZJ2eRBkq8624_oRLph9orx2oHdP7RlADuPMI2qLlyH-y0vXM-vKvIpYlZ3Zs38XFGZPZ5zodv5Gqea9B3juIP4hJDbmdUmkubioBU6mnf1ugwWl2VYaWpi5Q1rkC1Hrl5-sy5G4jAprWKduDX0WvuB4lCg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46317","volume":""},{"id":501,"author":"李晓健","title":"义尊、义方彝及相关问题研究","abstract":"文章以新出土义尊、义方彝为线索,探讨了商末周初“■”族的变迁,认为“■”族因有功于克商之业,在周初得以享有不错的待遇。同时,对中原地区主要地方族氏进行了分析,认为晚商时期这些族氏分为殷墟迁出与地方土著两大类,殷周剧变时有的顽固支持殷商、有的叛商投周。面对历史变革,族氏的不同抉择导致了不同的命运。","categories":["06_族氏方国"],"year":2023,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZD5z76x5nrJPAz_43PVGkIh4bNEAMu4e8x26PPtywcZzukQ-j6botBveM1Y0e0AM3FzFtMb_5T8oqyNZSwQ4H7hXgGGwhZYVWWzCvtVSTdAbQNXSi8Ue2Gu-uEPYPjBpQ_Vo4z_Pod0MZ8S8oRQg49zeezbNNF-GojUmOeFefYA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-119","volume":""},{"id":555,"author":"黄锦前","title":"曲沃北赵晋侯墓地出土格公鼎与晋、倗、霸佚史","abstract":"北赵晋侯墓地M114出土叔夨方鼎的“叔夨”即叔虞，成王时始封于唐，其子燮父于康王末年徙封于晋，改称“晋”。M113出土格公鼎与大河口M1霸公墓随葬的兽面纹方鼎（M1:74）系同人所作，“格（霸）公”应即大河口M1的墓主成康时期的首任霸伯荆，“湿宫”系霸国宗庙所在，格公作此鼎以祭祀宗庙。M114、M113系晋侯燮父及其夫人之墓，晋侯昭王时卒，其夫人卒于穆王初年，霸伯荆之孙霸伯尚（大河口M1017墓主）以其祖之祭器赙赠，以表明对晋霸关系的重视。倗伯釐盘的倗公系成康时期的首任倗伯（横水M3250墓主），系南公与召公奭婿，格公系文王婿，成王姑父，倗、霸因其与姬周王朝及其宗亲特殊的姻亲联盟关系，故其始封君皆称“公”。","categories":["06_族氏方国"],"year":2023,"publication":"文物季刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKAkSpwjxzwGU9IBhqsOZiXmSQh3lOBYLwKAZOUh2ZOrOd7FgQNFPmMboUmXclrcK41YTheUCZ0QgMqDTDgf4Zc7vGcoV-R-mV2TvaVZaRWJ5NWZkUBK9APU9pusjGVbkzEqlojgKlpBHfm9JvoQ9PWF2PzZsvUU-gfKOQ2zVmTU7A--4QNFeOA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-95","volume":""},{"id":574,"author":"黄锦前","title":"新出曾伯■壶铭文所见春秋早期曾国历史与思想","abstract":"将京山苏家垄春秋早期曾国墓地新出曾伯■壶与传世曾伯■簠铭文进行分析对照,指出二者的异同,并分析其原因。进而就壶铭“余为民父母”句反映的春秋早期曾国有关历史与思想进行分析,指出当时曾国遵从和推行后来儒家的“仁”“礼”等思想理念,是西周时期德治与民本思想的继承,是传统姬周文化在南土地区传播的表征,也是后来以孔子为代表的儒家思想的来源之一。据曾伯陭钺铭,当时曾国注重和推行法制。“刑”“法”是威,“仁”“礼”是恩,恩威并施,并行不悖,二者对立统一,也符合儒家一贯的思想。簠和壶铭讲曾伯■“慎圣元/孔武”,“慎”和“圣”应同西周金文及后世儒家的相关概念和思想理念皆有一定的联系,也是后来儒家思想的来源之一。这些思想理念的发展,为后来儒学思想在南方地区的传播奠定了基础,开辟了道路。","categories":["06_族氏方国"],"year":2023,"publication":"人文论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJk-CnDqZdoAQoWrup3gX-oGZqsfuy_8-92LPo8l65-vD6sQOnYW50dnB8OToiU1w4ll2q5zzCLg6wYyZzrJLOOMtz4ddAVuWAACGGGT6yAFXmxzDWCIAwoSyjnA5pH8-2GvpRv7KpwMQz-Y_CjlFAeckkY4G5jHQia4JJXvG-jHw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-46","volume":"40"},{"id":580,"author":"雒有仓","title":"商代金文族徽传播与夏商族群的融合认同","abstract":"通常认为，金文族徽是商人族群的创制和商文化的标识。但在已发现的商代早中期王室铜器上却不见铭刻族徽，说明盘庚迁殷之前的商王族可能不使用族徽。从早期铜器形制及范铸铭文工艺看，金文族徽很可能为夏人所创制，后来才向商人族群自下而上传播，至殷墟一期始被商王族采用。金文族徽传播是夏遗民与商人族群文化融合认同的体现，在商代晚期已成为殷商文化的重要标志。传播方式分为三种，在族氏分封、奠置过程中出现了三方面的明显变化。由于地域化、政治化发展，商代晚期的金文族徽具有表示血缘关系和地缘政治的双重含义，在性质上也有类似变化。","categories":["06_族氏方国"],"year":2023,"publication":"河南师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16366/j.cnki.1000-2359.2023.06.13","pages":"86-93","volume":"50"},{"id":582,"author":"汤雷","title":"青铜龙虎纹鼓座：龙盘虎踞，鼓探钟离","abstract":"在安徽省博物院古代文明史陈列文物中，1980年舒城县九里墩春秋墓出土的龙虎纹鼓座陈列在展厅显眼的位置。它体形巨大、造型奇特，饰纹精美、气势恢宏，尤为珍贵的是鼓座外壁铸有上下两圈共150个字的铭文，是安徽博物院镇馆之宝之一。40多年来，吸引了众多参观者的目光和专家学者的研究讨论。鼓座上铭文的释读和研究，为我们揭开了江淮地区春秋晚期钟离等各方国之间纵横交错的关系，成为研究这一时期历史的珍贵实物资料。","categories":["06_族氏方国"],"year":2023,"publication":"江淮文史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJz6sudTUhvI2r0yQuzDYSzc0AnSlsS7wEANTvh-6DguhB5q2lULaWDU9fDhOSOfG2FzJtnIV-Xe0zOG_mbftDhRXxR4y7BctFj7DyuxQD0Biq1ushDpg17Gu2Kvx753MsViCXtEIhDAPQMXHf2oFdUYqevph46HF3BQ3hDDnsy8GwijV_p6HXV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-100","volume":""},{"id":584,"author":"徐熠","title":"商周胄族考论","abstract":"在中国历史进程中,“族”长期都是社会的基本构成,只是在组成结构、规模等方面有不同之处,从而产生氏族、贵族、豪族、宗族等类型[1]。“族”既为社会的基本构成,从“族”的视角观察历史社会的运行与演变无疑是很合适的。（?）族是商周时期的赫赫大族,相关铜器有近百件之多,出土地点遍及河南、陕西、辽宁、湖北、安徽等多省,时代跨度也较大,相关材料可谓十分丰富。但目前罕见甚至不见（?）族的研究文章,该族氏具有很大的探索空间。与中古史的家族史研究不同,","categories":["06_族氏方国"],"year":2023,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2fZYSDfV_BEFMhdDEQnOkR30g6K3IhODvcqI0zZ-yuBqn3XRR_IHFS9xrwR8OvjXaYYHnk6F20DQeX5HmZrzFVzmqksGNyGS-iwOE4eNjTHgTiqDOo7sfyMaWQOgEbMMpeyfHE5PCFxdnqEHsX1BlxueTmh_5LWEsZ2AYTq0RQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"283-318","volume":""},{"id":585,"author":"黄一哲","title":"烟墩山一号墓与吴国早期历史","abstract":"一、宜侯夨簋铭文引起的问题1954年,有村民在丹徒烟墩山翻土时无意发现了一批铜器,其中最为人所知的便是宜侯夨簋,该簋四耳高圈足,腹部饰有一周涡纹,为西周早期风格铜器,学界多断为康王时期。簋腹内的长篇铭文记录了周王将虞侯夨改封宜侯的历史事件[1]。当地文物工作者旋即清理出三个紧邻的器物坑,并认为是一座大墓和两座小陪葬墓,不过后续的整理认为三个坑中的器物更应看作是一座墓内的器物组合,因此学界一般将这三个器物坑视作一墓,即烟墩山一号墓[2]。由于“吴”“虞”“夨”三字可作互通[3],","categories":["06_族氏方国"],"year":2023,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsm-LNznTad7DJL346YtS1XW7XDdplOqvtoXzZ9lZoAltqKAUSxHL6X90DaY7FanOP1e_s9PBDM6CH1gjP0BaVvDLGR6ibo5eOaezuDmpy75Uu9WJhhLQPWU9tMolhdoDv1YmZFSFf-jQlBBUGqCxl489_aUsEHKDoPx0lfO4hiA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"207-220","volume":""},{"id":589,"author":"孔华","title":"从兑盆铭文论淮夷称名及伯侯兼称等问题","abstract":"山西翼城大河口墓地所出兑盆，铭文中的“淮南夷”与“南夷”“南淮夷”“淮夷”等其他称谓皆是周人对淮水流域夷族的称谓，因单用“淮夷”不能准确地表述其区域范围，故而出现了多种称名。西周早期只见东夷，未有淮夷，原因也许不是淮夷是东夷的组成部分，而是当时淮夷的势力相对弱小所致。盆铭中的应伯当为邦君应候。因侯为政治身份，伯为血缘排行，即使建宗有国，封侯保疆后，侯、伯仍可兼称。应伯非M95的主人应侯敔，而是其后辈。十月敔簋所记为周厉王时事，那么盆铭“唯王二祀”所言或指宣王二年。","categories":["06_族氏方国"],"year":2023,"publication":"阜阳师范大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.14096/j.cnki.cn34-1333/c.2023.05.03","pages":"17-22","volume":""},{"id":601,"author":"白嘉慧","title":"商周时期丙族的族属及相关问题探研","abstract":"殷商丙族铜器集中出土于河南安阳和山西灵石旌介两地。通过分析得知，丙族为殷商王族，最初居住在安阳附近，与商王室关系十分密切。晋南灵石旌介一带丙族的存在是统治者将该族群派遣至商王朝西土镇守边疆的反映。商周战争之际，丙族始终与商军一起奋力抗周，其并未提前归顺于周。西周建立后，周王将丙族遗民分迁于各地。不过作为军事实力较强的殷商王族，大量丙族成员被安置于宗周地区。该族虽曾在克商战争中与周为敌，但仍受到西周统治者重用，社会政治地位较高。","categories":["06_族氏方国"],"year":2023,"publication":"古代文明（中英文）","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2023.04.005","pages":"45-56, 154","volume":"17"},{"id":602,"author":"姚草鲜","title":"宜侯夨簋中“宜”非江南吴国新考","abstract":"宜国是传世文献佚记的西周诸侯国之一。若非宜侯夨簋、霸伯盘等青铜器的出土，人们无由发现它的历史踪迹。然而在宜侯夨簋被发现后，学者多将其视为江南吴国的铜器，用以考索吴国早期的历史。实际上，宜侯夨在徙封宜地之前为虞国之君，而虞国是武王时期分封吴国虞仲在晋南地区新建的国族。后来康王将虞侯夨徙封至宜，其地在今河南宜阳，而非江苏丹徒或其它地方。近出霸伯盘铭文中的“宜姬”不仅显示了宜为姬姓国族的事实，也提供了宜国与霸国相近而交往密切的证据。康王徙封虞侯夨于宜，使其与应国相互配合，共同组成抵御淮夷、南向拓疆的重要防线，以便实现周初经略南土的战略目标。","categories":["06_族氏方国"],"year":2023,"publication":"古代文明（中英文）","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2023.04.006","pages":"57-65, 154-155","volume":"17"},{"id":618,"author":"郁永彬; 田蕊","title":"蒋国铜器及其历史地理新探","abstract":"蒋国，是西周初期封于豫南的姬姓诸侯国。《左传·僖公二十四年》载：“昔周公吊二叔之不咸，故封建亲戚以蕃屏周。管蔡霍，鲁卫毛聃，郜雍曹滕，毕原酆郇，文之昭也。邗晋应韩，武之穆也。凡蒋邢茅胙祭，周公之胤也。”结合文献资料、考古资料及后世研究可知，西周成王时，周公旦第三子伯龄封于蒋国，至公元前622年前后为楚所灭，历400余年。","categories":["06_族氏方国"],"year":2023,"publication":"寻根","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyJcK_xcslP83UZiq0NpIGLDhy5lRycdnYsPXMxnMqve0B-iDiYos67Id-ATtxcpvSUX4DqoZp7QwwDEnt-5zNCE-Jq6iMJyNW8rZsN-xnLYQseLnxfvbUYD2mCRXAHhpSYyUXtYUxfO5BGaYH-YjvKH6sANnSrotun-y0RlEpZalmrRd_dW9Y&amp;uniplatform=NZKPT&amp;language=CHS","pages":"112-120","volume":""},{"id":629,"author":"宁镇疆; 高晓军","title":"叔虞方鼎与西周初期的唐晋因革","abstract":"叔虞方鼎是出土于山西曲沃北赵M114晋侯墓的著名青铜器，李伯谦最早指出铭文中的“叔夨”就是周成王之弟、晋始封之君唐叔虞，①由于牵涉晋国早期历史，遂引起广泛关注。经过多年研究，学者对铭文断读、“夨”与“虞”文字学上的关联等已取得相当共识。②对于方鼎主人身分这一问题，","categories":["06_族氏方国"],"year":2023,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI11yUVIPwZWJYxu6WGR8r4BtTXIQD4JGgvw5R_cKWuqguyFXCPUxfPn1AzfpW3O2WvSu_6BN9ltXL0XymN6h4nD5uEFuz_aYcKuHcnwbnjiez4OUPL8CgzJgwJJZEfGGqVUtOyuRsZfhH72HDuy4XMAvxD0R3G_lmZeVHbp_nJsbBydP0bXTEt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-218","volume":""},{"id":659,"author":"沈博","title":"金文“驭方”考","abstract":"西周金文中的“驭”字有三种用法，分别用作官称、兵种以及善驭马的戎狄，这三种用法皆与马匹相关。西周晚期青铜器铭文中出现一词，称为“驭方”，专指为周人蕃息马匹的部族。由于大规模的祭祀、丧葬和频繁的战争，周王朝对马匹的需求巨大。周穆王北征，安定周之北和西北地区，并将犬戎一族迁之于大原地区，使其能够在大原地区游居畜牧，为周王朝提供“戎马”这一重要的战略资源。其中一些臣服于周的部族，通过贡纳向王室献马。不独犬戎一族中有驭方，赤戎中也有驭方，厉王时南方淮夷的共主鄂侯亦称为驭方，此皆周人对为周蕃息马匹之邦的称呼，因其为戎狄蛮夷部族，故不称邦，而称方。","categories":["06_族氏方国"],"year":2023,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9eHpcHQFp14ULzNXhc9QH8JHcWijUaqsa2HbnmM3l8cTZ3_bfZYsrYJFO5cvuQzsNQOUyW-E-VQ_jHB3kOao6H1DwZXZiaLDPxtOHNPh8jDKS6TUC37WLda_JoDVO-ksW3zEspT5_GgDivMka7C2LcO5b7a8YEXb-VJPlz3Mk449GN-RNGQK5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-46, 188","volume":""},{"id":666,"author":"赵燕姣","title":"二祀■其卣与海岱古族逢","abstract":"故宫博物院馆藏的其三卣据传出土于二十世纪40年代的安阳地区，卣铭记述了帝辛时期的赏赐、祭祀等内容，它们是商代铭文中少有的长篇铭文。有关三卣的真伪曾有学者提出质疑，（1）朱凤瀚先生从周祭祀谱及所述地点间的相互里程等多角度分析，认为二祀、四祀卣的铭文不大可能是作伪者能伪造出来的，铭文内容是可信的。（2）后相关专家对其进行了X射线的无损检测，结果显示“铭文部分与器物底部也无焊接的痕迹，由此排除了在器物底部后贴伪铭的可能”（3）。","categories":["06_族氏方国"],"year":2023,"publication":"中国区域文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdqTKrA2v9gFe54MogoLUw7AQGNl3b-3gxtw6jS16i1QhCGAeAElBz8VhbLczrFOsdJkRTk0Ky3z_tkEP9758tjiRZu38_SzWEUEk_SA42eWjitzYTyRkz6vElT88Xu3ejx_iE9YSY-Q2AsPvfaRfskoaZRrJhq8cQZa9uxE_GKg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-23","volume":""},{"id":703,"author":"张天恩","title":"南方追孝鼎铭文考论","abstract":"南方鼎为西周中期偏早的铜器，其铭文的姓氏特点及祭祀对象“公仲”等内容表明，南方其人属西周名门南宫家族的南仲氏一支之小宗，所做铜器可揭示了西周世族的分宗特点，并结合相关金文和历史资料分析，不同分支在西周社会的生存发展不仅依赖其在家族的地位，更需自身的自强和努力。","categories":["06_族氏方国"],"year":2023,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLKBi2nMo3zBhzIFF6AD9e8wOMp7yDzUsKvrIuyYFKsuJOYZvJtueejPGqwTuW2ASZPo5eFMU5NqfELv_uxIyAO7yPsKOoqRGFRf37m4QEmayVnQXtbWtW2eHeFDCOQU_N2bXrA1yQaBYSK8UNBcQP1nMTn76W7uLrBhRb_e77x7ohbTO5yxPvO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-79","volume":""},{"id":705,"author":"韩雪","title":"浅议金文族徽“敦弓”","abstract":"商周金文中有族徽“■”,可隶写为“弓敦”。文章结合史籍与考古实物等证实，“弓敦”即文献中的“敦弓”,是天子之弓的专称，意谓五彩所绘之弓，故而负责彩绘的弓人因职事而名其氏。“敦弓”族徽的解读，为进一步探讨商周族氏铭文内涵提供了新的线索。","categories":["06_族氏方国"],"year":2023,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2023.02.018","pages":"49-52","volume":"44"},{"id":713,"author":"李春艳","title":"试论霸国对西周盐业的贡献","abstract":"霸国位于山西省临汾市翼城县大河口村，是西周分封的诸侯国之一。通过对大河口墓地有铭青铜器的爬梳，我们知道霸国在西周盐业生产和管理上贡献巨大，不仅参与周王室祈求卤盐丰产的祭祀活动，而且保障周王室盐源供应，同时操兵守卫河东盐池之安全。","categories":["06_族氏方国"],"year":2023,"publication":"盐业史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLHTJR68Dl5Q8HBZyyvScRgt6qkWE3ep7ws_YXSHnrCPlLai8iPvewvt_HT3aZaI8qqfdtrn_2FI2bAxC9DhRH-7CCt8tKzJxPidI3vzEhfONl8xHRP-NsjCvKDuXqZi-xFinwuKXyj9kLCRCabp57VcpUCqzcKTCB6NUrazw-MmcDdwzDNOm0x&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46375","volume":""},{"id":721,"author":"赵风; 张志鹏","title":"养国铜器整理与研究","abstract":"位于淮河流域的养国是一个文献记载严重缺失的方国,但好在有不少养国铜器出土。本文以全面收集、整理养国铜器为基础,采用考古类型学的方法,依据形制、纹饰、铭文、文化因素组成等特点对其分期断代,通过文化因素分析法分析养国青铜文化的阶段性特征及发生转变的原因,再结合相关出土材料与传世文献资料,在已有的研究基础上,探讨养国的兴灭演变,以加深对两周时期的养国和淮河流域文化交流的认识,并促进对周代南土地区政治格局及楚国附庸体系等领域的研究。主要观点如下:一、 通过整理养国铜器发现,养国铜器的年代跨度为西周时期至春秋晚期,分布地域以河南桐柏为中心,数量上以西周时期最少,春秋早期最多,器类以食器、酒器、水器、兵器为主。二、 将养国铜器中数量较多、变化较明显的鼎、簋、鬲、罍((?))、壶、匜、盘进行分型定式,根据其特征划分为三个时期,第一期为西周时期;第二期为春秋早期,以桐柏月河墓地M4、M22为代表;第三期为","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27118/d.cnki.ghesu.2023.000639","pages":"","volume":""},{"id":726,"author":"任晋芳; 陈小三","title":"芮国铜器及其相关问题研究","abstract":"芮国在商周时期长期扮演着非常重要的角色,陕西梁带村和刘家洼两处周代墓地的发现,为芮国的研究提供了丰富的实物资料。本文在前人研究的基础上,通过梳理相关文献资料和主要收获,对传世芮国铜器、墓地出土铜器和芮国相关铜器进行断代,认识墓地年代,在此基础上对芮国地望和世系进行系统探究。本文主要由以下四部分构成:第一章,绪论部分对梁带村和刘家洼墓地的地理环境,发掘过程进行介绍,对芮国目前的研究现状进行归纳总结,指出其中的不足和进一步研究的可能性,说明研究思路和方法。第二章,通过系统梳理西周时期传世芮国铜器,墓地出土芮国铜器和芮国相关铜器,结合文献资料,得出早期芮国国君有6代。受资料限制,芮国早期世系仍存在缺环。芮国在商末周初位于汧河流域,至迟在西周康王时迁往陕西大荔和山西芮城。第三章,对春秋时期的芮国传世铜器和墓地出土铜器进行断代,对芮国墓地进行编年,结合文献资料梳理出春秋时期芮国有6代国君世系。芮国在","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27284/d.cnki.gsxiu.2023.001858","pages":"","volume":""},{"id":736,"author":"薛田莉; 袁俊杰; 周伟","title":"莒国墓葬制度研究","abstract":"西周初期,周武王封少昊之后兹舆期于计斤(今山东胶州市西南),建立莒国,西周晚期莒国将都城由计斤迁往莒县,以此为中心,直至战国早期为楚国所灭,历时600余年,传30世,是周代最具代表性的东夷诸侯国。考古发现的莒国墓葬主要分布在沂沭河以及胶河、潍河流域,具体涉及莒县、莒南、沂水、日照、安丘等多个地区,这些墓葬类型齐全,随葬品丰富,年代跨度较大,为本课题的研究提供了丰富的考古资料。本文依据莒国墓葬资料,并结合历史文献,运用考古类型学、文化因素分析、比较研究等方法,对莒国墓葬制度及其相关问题做了综合研究,主要内容与观点如下:首先,对莒国墓葬做了类型与等级划分、分期以及年代判定。莒国墓葬的面积大小、随葬品的种类与数量以及车马、人殉等要素差距明显,根据墓葬各要素的情况,可把莒国墓葬分为等级不同的四个类型,这四个类型的墓葬依次对应的墓主身份分别为国君或国君夫人、卿大夫、士和平民。在分期与年代方面,对墓葬","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27114/d.cnki.ghnau.2023.000470","pages":"","volume":""},{"id":740,"author":"吕聪聪; 张振谦","title":"邾系金文整理与研究","abstract":"本文所説的“邾系”指的是西周春秋之時,在山东省滕州市東部以及山亭、鄒城、嶧城、木石鎮一代分佈的邾國、小邾國、濫國和狐駘國。這些國家的關係密不可分,其相關銅器、兵器數量繁多,器類豐富,年代多集中在春秋早期。邾系金文是研究邾系歷史文獻的第一手資料,不僅保留了各自的文字特點,有的還記錄了歷史事件,具有重大價值。隨著近些年相關遺址被陸續發掘,學界對於邾系金文的研究已取得了豐碩成果。但這些成果一方面比較分散,不便尋檢,另一方面往往局限於一國,或者局限於一器,並沒有形成系統,而且近些年新觀點不斷出現,也有必要對這些成果進行系統地整理與研究。本文以吳鎮烽的《銘圖》《銘圖續編》《銘圖三編》為基礎,結合相關論文著錄,共收集到邾系有銘銅器、兵器92件,其中邾國22件;小邾國57件;濫國3件;狐駘國10件(除證據充分屬於小邾國、濫國、狐駘國的,其餘一律先列入邾國範疇)。文中對邾系金文的整理與研究主要分為五個部分","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2023.000481","pages":"","volume":""},{"id":741,"author":"李玮璟; 衣长春; 梁松涛","title":"两周邓国青铜器研究","abstract":"邓国是两周时期重要的诸侯国,是周王朝在南方地区的重要屏障。至春秋早期,邓国被楚国所占有,并作为北疆经营了近四个世纪。对两周时期邓国的青铜器进行整体性综合研究,来探讨该时期的相关历史,具有非常重要的学术意义。故本文以考古发掘出土和传世的两周邓国青铜器为主要研究对象,主要从四个方面对其展开研究。一是运用与其相关的出土文字材料研究两周时期邓国的历史与地望。二是运用类型学方法对邓国青铜器进行型式分析,并据此与其他地区的青铜器进行类比从而进行分期断代,通过对器物的纹饰、时代特征的整理,对青铜器的变化规律进行分析。三是以邓国墓葬中随葬青铜容器组合较完整的墓葬为研究对象,分析两周各阶段邓国的青铜容器组合,并通过与中原地区墓葬中随葬青铜容器组合比较发现其特征,通过分析墓葬中随葬鼎簋情况,探讨其鼎簋制度至列鼎制度。四是对邓国青铜器铭文分析,首先对铭文内容进行分类;其次对铭文的内容进行释读;最后对铭文书写风格","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2023.002585","pages":"","volume":""},{"id":762,"author":"黄益飞","title":"曾公钟铭所见曾国建国史实考","abstract":"曾公■钟铭对研究周代天命观、分封制及建国史实具有很高的学术价值。曾公■钟铭追述的西周初年曾国高祖伯适受命及皇祖南公建于南土、受命作邦的天命观，与屡见于周代文献记载的周文王受命、武王克商建立周王朝的天命观相同，为周代天命观研究提供了重要史料。曾公■钟铭所记曾国封邦建国、藩屏周室的分封制度，尤其是受封为诸侯之时分殷亳社之土在国中立亳社之制(“析应亳社”)皆可与文献记载对读；并且钟铭所载皇祖南公受命为州牧、“涉政淮夷”等事，对于认识西周时期的州牧制度及周王朝对淮夷的统治提供了崭新的史料。对观曾公■钟铭记载的曾侯佐助昭王南征之事与湖北随州叶家山墓地的考古发现，可知佐助昭王者为叶家山M111的墓主人曾侯■。","categories":["06_族氏方国"],"year":2023,"publication":"北京师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJSUwoUr-n0a84zPOxvoXe7AQAWuRxhGuVrrjpIy1tWZb7GjQUYUwun6nfSwnQXCAXgTh2k2NekZxTDYytDMSkEIN_ieYsgr-HsCelelBEZO1LfZL9kZr1Zsy4C59TpeRXJdOMG3YWKNC8TzZn7Zuck0dasGipj8PcOT-c5HYuhozViWNosz6zx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"130-138","volume":""},{"id":770,"author":"侯乃峰; 蔡蒙","title":"新见郳公戈与小邾国世系补议","abstract":"山东省滕州市官桥镇大韩村墓地盗掘出土有一件郳公戈，可以证明大韩墓地当是春秋晚期到战国时期的小邾(郳)国贵族墓地，而且此墓地很可能包含有小邾(郳)国国君的墓葬。根据传世文献记载与考古出土的青铜器铭文材料，学者们尝试复原小邾(郳)国的世系，但由于材料不足征，复原的世系仍然留有不少缺憾。由于出土信息相对明确，这件新出郳公戈铭文中所见的人名“郳公克父”,对于复原小邾(郳)国世系具有一定的补充价值。","categories":["06_族氏方国"],"year":2023,"publication":"齐鲁学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIoW50g0WBxP1gab2hfLXmuXVQxhB5GJDR9Qu1348IJe6-VUss754gnR1P4e9-9oKZ_Io4WEks983Lx6vNMvd0vdVw1hQhfqq5ESaP4zjHIe-jY0pjZFBTpjCtFlHErUI0RMcr1bjbJUlIdfztVmMb9hDR_0R5trj9J-HofunZ2mE2P6T1ELsPy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-31","volume":""},{"id":778,"author":"史文欣; 董蓮池","title":"商周金文中“亞”徽記器的整理與研究","abstract":"“亞”字問題乃橫亙古今的討論焦點,“亞”徽記器的器類豐富、數量可觀、地域分佈廣泛,這一材料在“亞”字研究與商周的歷史研究等方面有較高的學術價值。本文以商周時期的“亞”徽記器為主要研究對象,全面收集可見材料以及相關研究成果,完成對“亞”徽記器的分類整理與內涵分析。論文 共分為四章,分別是緒論、出土“亞”徽記器的分域整理、氏族名集釋和相關問題研究。緒論 凡四節。第一節為研究目標與材料來源;第二節為研究價值與研究意義;第三節為相關研究現狀概述,概述分為“宋至清”和“20世紀以來”兩個時間段,後者從“‘亞’徽記器的分域研究”和“‘亞’的內涵研究”兩個角度展開綜述;第四節則是論文結構與研究方法。第二 章全面地收集了 2023年5月底之前的“亞”徽記器,以出土地明確與否為依據整理器物,其中明確的出土地有河南、山東、陝西、北京、山西、河北、湖北、遼寧、甘肅、江蘇、江西、安徽、內蒙古。同時錄入器物的器名、","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27149/d.cnki.ghdsu.2023.002824","pages":"","volume":""},{"id":789,"author":"杨昱浩; 井中伟","title":"晋南地区西周戎狄族群华夏化的考古学研究","abstract":"随着近年横水、大河口及雎村等具有独特面貌的西周墓葬材料逐渐公布,系统讨论西周晋南地区戎狄族群的面貌及其与周王朝之关系的条件已经成熟。本文的讨论分为以下五章:第一章为绪论。首先阐述了“戎狄”“华夏”的相关概念及本文判定族属的标准,随后介绍了本文研究的时空范围及这一范围内影响族群关系的气候、资源等自然要素。最后梳理了与之相关的考古发现及相关研究成果。第二章为墓葬材料的年代核定。对于已经发表简报的铜器墓,我们根据墓葬完整信息详细核定其年代,将之划分为三期六段;对于图录等材料中报道的暂无完整墓葬信息的铜器墓,选组合完整者归入分期体系内;对于曲村等地发现的陶器墓,根据前人研究成果划为三期,与铜器墓三期分别对应。第三章为墓葬特征分析。在第二章分期断代的基础上,从历时性变化的角度分析戎狄族群墓葬等级、墓地布局、墓向、腰坑、葬式、殉葬、墓上建筑、随葬车马等葬俗的发展与演变,并进一步分析了其葬俗及器物上表现","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2023.001444","pages":"","volume":""},{"id":793,"author":"白慧敏; 谢乃和","title":"西周畿内井氏宗族研究","abstract":"西周之时,世族盛行。世族政治构成了西周政治的重要一环。其中姬姓世族作为数量最多、王朝影响力最大的世族群体,在西周王朝政治体系中占有重要位置。畿内井氏作为畿外邢国小宗这一重要姬姓世族,不容忽略。井氏是西周中期以来的三大世族之一,经过近百年的经营,井氏逐渐占据了西周王朝的权力核心,地位显赫。本文对西周畿内井氏宗族做了较为系统的研究,共分为三个部分:第一部分是对井氏之族源与世系进行探讨。本文认为,井氏属姬姓,为周公之后代。畿内井氏宗族分为井伯、井叔、井季等多个支族。本文分别对这些井氏分支的世系进行梳理,得到井氏宗族较为完整的世系延续情况。第二部分对井氏之职官、婚姻与井氏之居邑进行研究。穆恭时期井氏长期垄断司马一职,位高权重。本文认为井氏作为司马,除了承担军政事务之外,还承担着处理民事诉讼与为周王室选贤任能之职责。井氏之通婚范围较广,包括外族、外服诸侯与西周世族,其宗族联姻除了自身的主观意愿外,或","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27011/d.cnki.gdbsu.2023.000777","pages":"","volume":""},{"id":794,"author":"张震; 田河","title":"东周中山国墓葬中的北方文化因素研究","abstract":"中山国是春秋战国时期冀中平原西部一个北方民族建立的国家,传世文献对其政治、经济和文化记载语焉不详,上世纪60年代开始陆续发现的中山国考古学遗存为解决这些问题提供了资料支撑。由于其系北方民族在中原文化区内建立的国家,东周中山国墓葬中表现出浓厚的北方文化因素风格,又明显受到中原文化影响,“魏灭中山”与“赵灭中山”是其国家历史上的重大事件,对其文化面貌产生了重大影响。本文从春秋中期至战国晚期的中山国墓葬资料出发,详细探讨中山国墓葬中北方文化因素,并结合历史文献历时性考察其北方文化因素嬗变情况。全文共五部分。第一部分,梳理了北方地区代表性的文化因素,分为葬俗和随葬品。葬俗方面,北方文化带中表现出来的墓葬用石现象、东向墓和殉牲现象;随葬品方面,北方系青铜短剑、铜鍑和铜泡饰、金盘丝耳环或手镯以及玉石串饰等;除此之外,还有北方常见的动物题材或纹饰,例如虎、鹿、绹索纹等装饰风格,为后文讨论中山国墓葬中北方","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27410/d.cnki.gxbfu.2023.000468","pages":"","volume":""},{"id":799,"author":"孙文强; 李娜","title":"孤竹国相关遗存及地域变迁研究","abstract":"据传世文献记载,孤竹国是从商代初年延续至春秋早期的古国,存续时间近千年。本文以孤竹国史料、相关青铜器铭文以及文献记载孤竹国地域范围内的考古文化遗存为研究对象。本文做了以下方面的研究:首先对孤竹相关有铭青铜器的铭文隶定及涉及到的族属问题进行讨论;其次对拟研究区域内商周时期考古学文化所体现出的相关性作出合理联系,并试图从这种客观存在的相关性中寻找孤竹国地域变迁的方向;最后利用文献结合考古资料对孤竹国地域变迁作出合理推测。本文搜集冀东地区围坊三期文化与辽西地区魏营子文化相关实物遗存,通过类型学的方法分析已知年代器物发展和演变的规律,论证孤竹国由南向北的迁移动向。总体来说,孤竹国是商周时期位于我国北方的诸侯国,迁移方向可能是由滦河下游迁安唐山一带迁至辽宁喀左,自南向北。以考古视角整理孤竹国相关遗存及研究成果,不仅能在文献中探寻孤竹国之所在,还可以在了解这两地域考古学文化整体面貌的前提下,利用两种考","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2023.001250","pages":"","volume":""},{"id":817,"author":"白嘉慧","title":"1961年张家坡西周铜器窖藏的族属及相关问题研究","abstract":"1961年10月，陕西省长安县沣西公社张家坡村发现一西周铜器窖藏。明确该窖藏所出伯庸父鬲、筍侯盘、伯梁父簋、伯喜簋、伯百父盘的作器情况，对探究窖藏主人族属问题及其所属国（族）对外交往情况大有助益。张家坡西周铜器窖藏主人为某姞姓国（族）之长。该国（族）在当时政治地位较高，与姬姓筍国存在联姻关系，同时与丰丼叔氏交往甚密。窖藏反映出的联姻交往状况一方面为西周时期“姬姞耦”提供新的材料证明，另一方面证实西周时期地缘性因素在畿内各诸侯国（族）的联姻交往中具有重要影响。","categories":["06_族氏方国"],"year":2023,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLObIryyyCLBqzEcXEi778UomEXVpOgU7fEco9ULWq0B_VVv3RlEvytQ7NWFYqgRAJ8W6Ta2Fljsrx2ytu7ffxVWeEgd_HxwxtVf43-48r6gGfmEkNtwaP-lMFg-eiu_J4MMkdf59DpGvDiZ1D1fnLCXP8qoXS4I74OWt_Yq5koLd2DNl0cA_nJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-83, 48","volume":""},{"id":825,"author":"王子悦; 杨琳","title":"鄂国青铜器及其历史地理综合研究","abstract":"本文以青铜器为切入点,结合文献资料,对商周时期鄂国的地望变迁、文化因素变化、族源和对外关系等问题进行了探讨。全文共分为六章,包括绪论、正文与结语三部分。第一章绪论。首先对本文研究的时空范围和研究对象进行了界定,对以往研究取得的成就和存在的不足进行回顾和总结,同时对本文的研究思路与方法进行简要阐述。第二章青铜器材料分析。对随州羊子山和南阳夏饷铺鄂国墓地等遗址出土的青铜器进行整理与分析,同时对与鄂国相关的征集器、传世器进行收集和辨伪,在此基础上建立对鄂国青铜器的整体性认识。第三章类型学研究及分期断代。将文中涉及的所有鄂国青铜容器进行类型学分析,在此基础上进行分期断代研究,将鄂国青铜器划分为三期六段,分别为商周之际至西周早期中段、西周中期后段至西周晚期前段、西周晚期后段至春秋早期。第四章文化因素分析。对鄂国青铜器的器形、纹饰、铸造等方面进行细致分析,根据其所含文化因素差异将其分为商文化、周文化、","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27123/d.cnki.ghlju.2023.001751","pages":"","volume":""},{"id":841,"author":"黄锦前","title":"垣曲北白鹅墓地族属及有关问题","abstract":"北白鹅墓地出土铜器铭文的匽与文献记载的南北二燕皆无涉。匽系位于今垣曲一带的国族，姞姓，在畿内有采邑，北白鹅墓地系匽国贵族墓地。夺簋的夺厉王时在王朝任要职，其后人中义父及匽仲皆于王朝世袭卿士。太保匽仲与周原出土的中义父诸器的中义父同系华族之人，中氏，春秋早期在王朝任太保，死后归葬故国。东周兵器铭文中的“匽氏”或即其后裔，系以地为氏。匽国在晋西南一带至迟自西周中期延续到春秋时期，两周之世，匽之实力不容小觑。传世与近出匽伯鼎、匽太子鬲、匽子盨、燕伯圣匜、匽公匜等皆系匽而非北燕之器。匽与虢邻近，互有婚姻往来。北白鹅墓地所出虢季（子白）诸器的虢季（子白）与虢季子白盘的虢季子白系同人，盘之年代亦应系春秋初年。《诗·大雅·韩奕》“溥彼韩城，燕师所完”的“燕”应即“匽”，所谓“燕师所完”，即匽国民众为韩侯营建都邑，与文献及金文所载召伯为申伯营谢邑等事相若。","categories":["06_族氏方国"],"year":2023,"publication":"文物季刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZObmUF3liIm52QmzlcxcGzH-inOs2y8DjbsKSdF_pMCm8hi47DJV1Y9Onb_yr1cmdkxwGb3iIIlAKMo3wanWmop5n4FUqQgojlETRI4gfvyljZCL0DpisRJHNQKJTCRaFDKYmpZESjqW90XqoYCW5U1-42P6yHDCQF0ppWQ6zOWgBA5oOfeg2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-81, 110","volume":""},{"id":857,"author":"潘墨晶; 冯时","title":"商周噩国历史之再考察","abstract":"噩国是商周重要诸侯国之一。文献仅记载商末噩侯因进谏为纣王所杀一事,此后噩国不见于史料。湖北随州羊子山墓地与河南南阳夏饷铺墓地发现后,大量噩国青铜器问世,结合几件传世青铜器,噩国的历史已经可以基本还原,但仍存在一些需要探讨的问题。本文将对之前学者的研究成果进行系统整理,以相关青铜器为中心,对噩国的历史再考察,通过对“丧”、“噩”二字的正确释读,明确卜辞中的“丧”与文献中的噩国之关系;通过对噩国相关青铜器的整理,解读有铭青铜器并结合传世文献、考古材料等,梳理清楚噩国的历史,探讨从青铜器及铭文中反映出的噩国国力变化、族姓变化等问题作进一步探讨,进而全面整理商周噩国的历史发展。","categories":["06_族氏方国"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27642/d.cnki.gskyy.2023.000045","pages":"","volume":""},{"id":870,"author":"晁福林","title":"作册般甗补释——兼论殷代夷夏关系","abstract":"以子姓为核心的商族是后来所称的“华夏”的一个重要组成部分。商族与东夷族的战争与交融是殷代夷夏关系的重要问题。殷代后期器作册般甗的铭文反映了当时夷夏关系的一个侧面，即商王朝一方面讨伐诸夷族，另一方面还与一些夷族分支保持良好关系，夷夏间相互交往、交融，为中华民族的形成做出了贡献。","categories":["06_族氏方国"],"year":2023,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJllDDcY1zO9QqqR1HFiI_LpYDZ2SWAQ8DmE7VEmQfLlbjC45dkJfG3rPDd5Kk_hloPvlH5SU-25dJ_gZMCCxFQzZzef1qTEdiZiKfCYgHkJSnLY9QLIRw3at1LQOG-aHQwiPDItwKrSgGyQ8R-U9bPcrvfr4-ELq7N1Cb-yTUjXL7UrybKCKgE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46164","volume":""},{"id":871,"author":"齐韶花","title":"因安吉周家湾铜器再考秦先人与商奄之关系","abstract":"安吉周家湾铜器自出土日起即备受争议，重新解读此组铜器，非常必要。首先，从青铜器工艺的角度观察分析，这组铜器是：1.同文化同工艺下的青铜铸件；2.是原属商中心文化的一支武装力量到达越地后的本地铸造；3.从纹饰中出现的勾连C纹、蛇纹来看，此铜器组的制作不早于殷墟三期；4.铜器铭文出现了简单句式“强祸”，故此组铜器的制作，已然接近殷墟末期。其次，结合殷墟卜辞对“强”的记录，来解释周家湾铜觚内壁出现的铭文“强祸”，则意在卜问武丁之子“强”是否遇到了灾祸，或是在卜问秦先人弜（费）氏一支中的后族首领“强”或后族“强”是否遇到了灾祸。第三，钩沉史料可知，战国秦汉的文献中出现了两种截然不同的关于秦先人与商奄族群的记载：1.秦先人与有商一代的商奄族群全无瓜葛；2.秦先人要么来自商奄族，要么至少与商奄族群在商王政务中相随以共，在周公伐奄事件中，秦先人飞廉还被驱赶至“海隅”而“被戮”。综合以上三个方面的分析，本","categories":["06_族氏方国"],"year":2023,"publication":"东方博物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-KxvvcLnmCUnHsppCu16Ppc5Rhol6np0_auGnUcjPC3DVpeNsPn4mPOn4oENjPxz4OnqGqCgx_V3oW77m8pG6weSNSksQxb9VDwp3w1Rj1pCtQBTKfi28JhAas2ja8q---y4mqQES7tnUsXRs7Tb__yb5xAfao2LKk91UW2dlWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-21","volume":""},{"id":879,"author":"王瑞钢","title":"“卫父己”铭文青铜器族属研究与“卫”溯源","abstract":"新乡市博物馆所藏青铜器数量丰富,中原地域风格突出,其中馆藏铸铭青铜器五十余件。“卫父己”铜觚和“卫父己”铜觯尤其引人注目。文章通过对“卫父己”的释读,对其进行族属研究。通过对比研究和对器物铭文的阐释,挖掘其历史文化内涵。从汉字字源、商代政治背景出发,对早期卫氏与卫国进行探讨,为早期“卫”文化溯源打开新的视角。","categories":["06_族氏方国"],"year":2023,"publication":"文物天地","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImG-G6hTaw3cfhjUDSf5I_qEQp7OACIVa-5rOqv4cXvrnl8O5IY4oWsJjLSMK325a80ZaOSFCcQu2ai9yRu4vbCSumRnbAeGxVK-6dPFGjH53mS3YKw4EXMEDeO8s6wB2TnPes4lUhs0WzayXaPLEhefS7xK1ChDfEFF-QWQ6-oiTL2Lbvw0At&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-22","volume":""},{"id":887,"author":"伊格慧","title":"近出金文与西周鄂侯历史探研","abstract":"鄂国是商王朝的诸侯国，商亡后成为西周在南土分封的重要诸侯国。西周早期，鄂侯被临时安置到了盩城。西周晚期，王室实力衰弱，鄂侯率领东夷、南夷发动大规模叛乱。禹鼎中记载周厉王为了平叛，下达“勿遗寿幼”的命令，但从南阳夏饷铺考古发现的两周之际的鄂国墓地来看，鄂国没有真正灭亡。根据鄂侯簋可知鄂国为姞姓且与王室有婚姻关系，在南阳夏饷铺的鄂国应该依旧是姞姓鄂国。在南阳夏饷铺鄂国墓地M19和M16中的两对孟姬壶都不属于墓主，它们可能是赗赙之物，孟姬和墓主有姐妹或者姑侄关系。","categories":["06_族氏方国"],"year":2023,"publication":"南阳理工学院学报","link":"https://link.cnki.net/doi/10.16827/j.cnki.41-1404/z.2023.01.019","pages":"96-100","volume":"15"},{"id":901,"author":"辛召; 谢尧亭","title":"山西绛县横水墓地发现的倗国铭文","abstract":"","categories":["06_族氏方国"],"year":2023,"publication":"中国书法报","link":"https://link.cnki.net/doi/10.28129/n.cnki.ncsfb.2023.000007","pages":"1","volume":""},{"id":921,"author":"宣柳","title":"金文所見春秋楚地滅國遗民及相關問題","abstract":"春秋時期戰争頻繁,大國除争霸戰争外,還兼并周邊小國,完成領土擴張。探討春秋各國滅國史事,對於了解東周社會轉型很有裨益。然而,關於此議題,前(5學者多致力於概述宏觀進程,或是考證具體滅國時間,[1]對於滅國遺民的活動關注很少。基於此,本文對金文所見春秋滅國遺民進行研究。因資料所限,相關論題集中於楚地。第一部分按照被滅國家,","categories":["06_族氏方国"],"year":2022,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxWOwKlFEJHnuA1EivGsmIKf_z0sws6bfGyLi7aQBAZQLOikqaR2otrzD6FVtzxTkXaHXayLL-zE84E8INbNe9G8o8z4CsvVoMy-G1PLLimPhKsPv1g-61pgL-aRKM6HksIRe8ln8XT1qZv3xCc2oGWuzouBuRXY2xkdH3iqGjrA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-109","volume":""},{"id":943,"author":"韩雪","title":"试论王俎姜与西周的房国","abstract":"西周彝铭中有王■姜，学者一般认为是周穆王的王后，然而该字的隶定一直未有定论，内涵也鲜有揭露。■当隶定为俎，俎姜即房姜，王俎姜来自姜姓的房国，大致位于今湖北省保康县至当阳市的沮河沿线地带。王俎姜身份及房国的探讨，对西周的历史地理研究具有重要意义。","categories":["06_族氏方国"],"year":2022,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKe5HH4HKuc7V6G4BUXTzuaDKCKNfkimVGLBdYmqcb_dO5wJC0Z-yBXVJVrevEMct9gGg4RjzsIb6_MKmQWMmb0z9Z_Z01EaSCmHMWT1a78ZY9gf8zfVX_sH3FxDfyQBF1dmntUs2SWcv4SAeswr9Ts25M8XAbvBJkN_bBNp8mFQlY6lCUJmoOJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-97, 110","volume":""},{"id":944,"author":"王鑫","title":"新见晋荆氏妃鼎初识","abstract":"晋荆氏妃鼎为2019年山西公安机关追缴，现收藏于山西青铜博物馆的国家一级文物。晋荆氏妃鼎的作器时代当在春秋早期早段，作器者应隶定为“晋荆氏妃”。铭文主要描述晋国的荆妃作铜鼎，传之子孙永宝。晋荆氏妃鼎中的“荆氏”或与五祀卫鼎中的“荆人”及散氏盘中“荆丂”同族。荆氏应该与楚有比较密切的联系，可能即是因某种机缘来到宗周及晋国，以所居故地为氏的楚人。","categories":["06_族氏方国"],"year":2022,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPEvoEhVa6r5BJHaMsUANTbhDLlk-q13_IRZ-hcn8M6zF7HxBW9p1G5uLYPi35ybqs5miVsO71CLUuZknX86hXJLwvWvfZSmivf11wLRZGkGsSUDq9MtWsWlH8KTYmsymphzd03WoaM-5bfBcqqW7Ce9v4rmB9HdRct4gf4SnEVp0IvTBN8uRN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-110","volume":""},{"id":948,"author":"黄锦前","title":"芮公叔盘与西周芮国的重要史实","abstract":"芮公叔盘系西周早期昭王时器。芮公簋、芮伯簋(卣)、芮公叔簋(盘)等的“芮公”“芮伯”“芮公叔”、“芮姒”“芮少姒”、“祈宫”“祈公”皆分别为同人，前者为昭王时第二代芮伯，芮少姒系其妻，后者系其父，即霸簋与文献的王室大臣“芮公(伯)”,系成康时首封芮君。伯六■鼎与伯鼎的“祈”“祈仲”皆指“祈宫(公)”,“仲”为排行，伯即伯六■系第二代芮伯芮公叔，“伯六■”系称字，“叔”为其名。祈伯簋、旂伯簋的“旂(祈)伯”即芮伯，叔友簋与旂姬鬲“旂姜几母”“旂姬”的“旂”皆系族氏名，系以地为氏。旂(祈)系芮都宫室宗庙所在地，故以旂(祈)代称芮，二者实一。芮国于周初始封于殷商祈族故地，在今陕西扶风一带。","categories":["06_族氏方国"],"year":2022,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2022.06.001","pages":"5-10, 25","volume":"42"},{"id":958,"author":"黄锦前","title":"潦伯（司徒）疑铜器与潦之族属及地望","abstract":"沬伯（司徒）及有关铜器铭文中旧释“沬”之字实应系“潦”，所谓“沬伯（司徒）”应系“潦（寮）伯（司徒）”，应据改。作为国族名，“寮”“潦”应系一字之异构，皆从“尞”得声。沬伯（司徒）疑诸器的“疑”系其名，“沬”系其国族（族氏）名兼地名，“沬伯”系沬国族的首领（?系其徽记符号），“伯”或兼作排行。疑的身份系沬伯，兼任沬司徒职，成王时随卫康叔一起就封至卫。传世潦伯甗的“潦伯”与沬伯诸器的“沬伯”或即一人。沬系姒姓，其地望在沬即古“妹”地，今河南淇县一带，与淇卫邻近。沬族系殷遗民，或即《左传》定公四年“分康叔以……殷民七族”的“殷民七族”之属。","categories":["06_族氏方国"],"year":2022,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2022.06.012","pages":"122-127","volume":"10"},{"id":976,"author":"贾洪波; 刘亚楠","title":"周代蔡国和“蔡女”铜器铭文综理及相关问题探讨","abstract":"梳理目前所见周代蔡国铜器墓葬和铜器铭文，可以辨析蔡国铜器中的女性称谓和身份，结合史籍记载，从联姻视角探讨周代蔡国与其他诸侯国的关系，蔡国在不同时期的联姻意向受政治局势变化的影响，西周至春秋中期多与畿内贵族和中原邻国联姻，春秋晚期则多与南方的楚、吴两国通婚，并有北向通婚冀北山戎族的迹象。","categories":["06_族氏方国"],"year":2022,"publication":"南开学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrN4JWQ8QqU_8KVVX7oY4uulFxGthyu9GujAfZWP4MEiKEYyiYO0Rw5jm7G3ZQfYSVeSImPLVIlMN4I2Ro2JrTIaP8l4ev6drWGiiZUQzFIopwUA_P6uyhlUSTr8BVM8Ci_FZy_wnkS-TSkgW6wYyB77M6HbClTEeQbQ0OoAnccLCRYoafLPgY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"123-132","volume":""},{"id":990,"author":"孫亞冰","title":"商周時期的獻侯","abstract":"商周時期的獻侯，見於殷墟甲骨文和西周早期金文，學界有根據卜辭中獻侯與人方等的關係，推測獻侯的地望在東方，本文利用近年山西省公安機關追繳的一批帶“天黽”“獻”銘的商代銅器，將其地望定在今山西省聞喜、曲沃一帶。","categories":["06_族氏方国"],"year":2022,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ30Xeb6nosps_pxd5Nzmfbrk9vV0YRxIqy3uwQPIaEAWE1K2_wsQV7HZiAShgsKj1cMceVSz9GFBWuQiU4XbIqnJ-YhnE3Qkdnjs0CHCLQHVCME6K9V5vhTyfRQSXSXHYi-bikN-AXHlAqfYLzieJBct0IfcyjpiJVLS409tBxpg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"329-338","volume":""},{"id":992,"author":"王冠涛; 赵倩","title":"楚公■诸器考","abstract":"楚君名号在《左传》《史记》中有较详细的记载,其异文散见于《国语》《战国策》《世本》《汉书》等史籍。此外,还有一些与楚君名号相关的文字资料,特别是近年来与楚君相关的有铭铜器材料逐渐增多,楚君名号问题越来越受到学界的关注。由于史料有限,关于西周时期楚国历史、楚君名号所知甚少。","categories":["06_族氏方国"],"year":2022,"publication":"秦始皇帝陵博物院论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTgu2zIz3YbZeOWbyo9outUwo3RABZnbe-T4TyelyRwfmmDjJExS9BLIMOMlXvWf6xBrEutQxv1lJPK_vE6_c6Q0N10T5rx4JtiODy0bMMsPL8JVyqzKdGrb5SXTn2IdlwKvJD72sYSDELZsMkqyAtnJIfHetHqqHdJAd0Dtct8g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"183-195","volume":""},{"id":994,"author":"黄锦前","title":"楚沈尹氏铜器两种考释","abstract":"据者梁戈的形制、纹饰及铭文内容，考证“者梁”应即见于《左传》及楚简的楚大夫沈诸梁，即“叶公子高”。楚平王五年（前524），沈诸梁被封于叶邑（今河南叶县南旧城），为首任叶公。河南南阳八一路楚墓出土的叶公臧鼎铭中的“叶公臧”即见诸《左传》“定公五年”的楚叶邑邑公沈诸梁之弟“后臧”，在叶公子高之后继任邑公，故称“叶公臧”，此铭可补传世文献记载之缺失。","categories":["06_族氏方国"],"year":2022,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2022.05.008","pages":"21-24, 29","volume":""},{"id":1007,"author":"朱凤瀚","title":"酒务头墓地与“天黽獻”器群","abstract":"闻喜酒务头墓地2015年被盗，5座甲字形大墓中仅M1未被盗。确知出于此墓地的青铜器中多有“天黽”氏名，而2015年以后较集中地被各种书刊报道的“天黽”氏铜器应与酒务头墓地有关。在这些铜器中，皆铭有“天黽獻”或“天黽獻亞■”氏名。本文分析了M1器组与近出的“天黽獻”器群中各器类的形制、同铭器的组合，认为酒务头墓地可能是“天黽獻”氏（或其分支■）上层贵族的墓地，年代在殷墟文化三、四期，M1下限则可能晚至周初。由此可知商后期商金文中常见的商人大族“天黽”氏亦曾驻守于运城盆地，与临汾、晋中盆地其他商人族属共同构成商王国西部边域的屏藩。西周早期金文中属于“天黽”氏的獻侯，应与酒务头的“天黽獻”氏有密切关系。","categories":["06_族氏方国"],"year":2022,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhnPw1N1vmH_06gqdG7OlI7SqMX8BcEV3xQDV67QLjZof9FuW0mKjPp-K6RD5c2RIGHQy8VmuEd3gip6nsoybds56pO11WXRUDu5uVUGhDW0Qs4DJDWCh_ZFyRDmO_zIULqQgWPbqshTpCDQ4cPbgUoEDQSvUVGSLPO0oWK6M9ReZDeD0E_jyG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-93","volume":""},{"id":1008,"author":"张全礼","title":"西周燕国青铜器研究现状及相关问题","abstract":"本文以西周燕国青铜器进行定义，并给出判断标准，根据西周燕国青铜器的概念、时空范围和判定标准，梳理了近年来北京及周边6个省份的考古发现和传世的西周燕国青铜器，对西周燕国青铜器的研究现状进行评述，总结研究成果，发现当前研究在资料阐释和相关问题的认识上所存在的困境，提出对策。","categories":["06_族氏方国"],"year":2022,"publication":"首都博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1KTVOxI_RDTAQH9hfuqBo5XXL9CCNPfhdaD3CrKUbk9fenqHH5JOVpuUq_5t-elOuDZ92ESBi6SNCOsD3oODGvh3JYg8hdSZ9iXWoSRJKmXCJERMK330ksbzmo-zqt1nsskErppMH7952GAdXixp-oQ3aArg8EWzQEvlM0RxeEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46039","volume":""},{"id":1049,"author":"岳洪彬; 岳占伟; 王祁","title":"河南安阳市殷墟刘家庄北地M793","abstract":"1994年发掘的M793为竖穴土坑墓，葬具一棺一椁，墓室底部有一腰坑。出土遗物有陶器、铜器、玉器、石器、骨器、蚌器等。墓葬年代大体为殷墟二期晚段。根据铜器铭文和墓室规模，推测墓主为卜辞中“弜众”的一员，而非亚弜或弜族的族长。M793的发掘，为推断刘家庄北地是亚弜或弜族的一处集中居住地提供了重要线索。","categories":["06_族氏方国"],"year":2022,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvLa7wKZtpjFk3_hQfimfypwJk3DmfjdHwBQQVGkWYj_WIbkKLXvK_IGcXjUyWfdBBTau8GO7H_gZ-PrYkX2b9Q-0-vFLqWpYAa7tP3YlabsT5sN62HevIaeyCRcE9DNS0qtDLpBLSrTjI5zreIat1NeBTWaFeIPGJ7QkHLbdxhv7T6SNHbqrt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-45, 2","volume":""},{"id":1050,"author":"田伟","title":"由新见材料再论绛县横水、翼城大河口墓地的性质","abstract":"山西绛县横水、翼城大河口墓地是21世纪周代考古的重要发现，学术界对其性质的认识尚不统一,主要有诸侯国、晋之附庸两种说法。作者以两处墓地新见材料入手，从控制范围、葬俗和铜器铭文三个方面探讨了墓地的性质，认为横水、翼城大河口墓地的葬者生前分属怀姓九宗中的两宗，墓主生前为晋国之附庸。","categories":["06_族氏方国"],"year":2022,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2022.08.003","pages":"62-71, 140","volume":""},{"id":1052,"author":"赵庆淼","title":"仲爯父簋铭文所见人物关系与宗法史实——兼论“南申”“西申”的名号问题","abstract":"南阳出土的西周晚期仲爯父簋，其器、盖铭之间存在异文，一作“南申伯大宰仲爯父厥辞”,其余三件则作“仲爯父大宰南申厥辞”。通过语法结构的分析和对比可知，两种句式的主干成分是基本一致的，均为主谓结构的“南申厥辞”,意即“南重申了仲爯父的命辞”。据铭文所云，“南”的身份为“仲爯父”家宰，受后者之命作器祭祀二人的祖考。结合周代贵族家族的作器制度和祭祀通例来看，“仲爯父”与“南”当为同一宗族内部的亲属成员。其中，“仲爯父”身为宗子，对整个宗族的作器与祭祀活动拥有支配权，而“南”的宗法地位低于前者，所以要服事并听命于“仲爯父”。仲爯父簋铭文的重新释读与相关史实的钩沉，有助于考察“南申”名号之缘起及其与“西申”的关系问题。","categories":["06_族氏方国"],"year":2022,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYooyTrSLhfS_o8AxpE8LaHDtbSiKNbW-gTMgcJGXDedmgog83EhxONsAqz9_g0ATDLzMeKX7r22SDwoCGnkA5GyJGNquCtfR1ljEW-kb96MbUGamuEZW9WrRvC4DbjgaW8vKDahPjvs1ozf8f550Qt1s6AsFRatsRSuf9vL_WbCZC6Rub7sdT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-68","volume":""},{"id":1112,"author":"曾芬甜","title":"再议夏饷铺鄂国族姓、时代问题","abstract":"夏饷铺鄂国过去被认为是西周晚期叛乱的姞姓鄂国后裔。本文首先从“媵器返回作器者墓地”这一独特现象出发，论证夏饷铺鄂国是重新分封的姬姓诸侯。其次，通过回顾三门峡虢国墓地的断代争议这一学术史问题，并细致检讨夏饷铺鄂国墓地M5、M6及相关墓葬出土材料，论证夏饷铺鄂国分封于春秋早期而非西周晚期。总之，夏饷铺鄂国是一个分封在春秋早期的姬姓鄂国，从始封到亡国前后延续了不到一个世纪。","categories":["06_族氏方国"],"year":2022,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmGclJHxF1JPRyckVxU-rGggwk88acMWZSNMGjXhdAnQco9QIskg6NS2UAOZXmE98roctQGz_KpitmZLCotiOgsB4EUvcpO02mOcJqh4MLZT7MuuRFsOTRnMXczNOsHikhPQCi78_PPZIw6IVfNGoVziD2XOQlWP9VY-JvBqJjCy4Onegqr7DM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-72, 155","volume":""},{"id":1122,"author":"黄端胜","title":"西周金文族徽研究现状","abstract":"西周金文族徽的研究，对西周家族形态、社会组织结构、族氏迁移流动、民族融合与文化认同等方面具有重大意义。目前，西周金文族徽的研究取得了较丰富的成果，主要有两类：一类是研究较为零散的论著；一类是研究较为集中的论著。前一类往往是在研究族徽的性质与功能、商周文化异同与融合、金文隶定与考释、商周族氏的历史与行迹、商周家族结构、金文族徽特点与字形书体等问题时，涉及到西周金文族徽。后一类往往是对前一类相关问题的综合性研究。但是，在众多研究成果中，几乎很少将西周金文族徽作为一个单独的研究对象进行考察，亦很少见到全面整理西周金文族徽的论著，使得西周金文族徽的相关研究不甚深入。","categories":["06_族氏方国"],"year":2022,"publication":"佳木斯大学社会科学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8MJjB6qLt78nGNFYXogFHj5jj9JEBNBX94quto46TQ67ehKCmPnGQDiZVMFi307AF8C_nV32jnPhTy-xOigp-ZcGQ_fuPybTXplK77xFyBIuJojmUA6eB5KCwJpXESBdobWeeidzCEeF3KDTbogH31yPV9rjDODUgqZ-YHSfGYtCTsTUJ3Whf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-153","volume":"40"},{"id":1137,"author":"张彭程; 熊贤品","title":"虢季子白盘及相关青铜器研究","abstract":"虢国是周代重要的封国,起着拱卫王室安全的重要作用,为周王朝的稳定和兴盛立下了汗马功劳,限于材料有限,我们至今还未能了解虢国历史的全貌。《虢季子白盘》是一件虢国的青铜器,自清代出土以来,对其关注从未停止,铭文的释读和年代的断定一直争议不断。近年来,《虢季子白鼎》的出现和北白鹅墓地的发掘,为我们的研究《虢季子白盘》提供了新的材料。《虢季子白盘》铭文的释读和年代的断定,将为虢国相关青铜器的研究提供参考,也为我们解开两周之际虢国历史的谜团提供了帮助。本文 主要围绕《虢季子白盘》的铭文和年代展开叙述,在此基础上对相关青铜器进行了考释,并尝试着探讨了两周之际的相关史事。主要分为三章:第一 章对《虢季子白盘》进行了汇考。笔者在前人研究的基础上,对铭文内容进行了重新的分析和释读,又从铭文的内容、字体、文体,《虢季子白盘》的纹饰形制,出土地点等方面出发,结合新出材料推断出《虢季子白盘》的年代为周携王时期这一","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27137/d.cnki.ghusu.2022.002181","pages":"","volume":""},{"id":1163,"author":"陈兆潘; 张怀通","title":"曾公求编钟铭文集释及相关西周春秋史实研究","abstract":"曾公求编钟出土于湖北随州枣树林曾国墓地M190墓中,因作器者为曾公求,因而被命名为曾公求编钟。该编钟铭文内容涉及到西周早期与春秋早中期的曾国史实,部分内容可以与曾侯与钟铭、芈加钟铭相互印证,是十分重要的文献资料。自其铭文被刊布以来,就有学者对铭文进行了考释,留下了丰厚的成果。但学者之间说法不一,因此还需对铭文释文进行整理。笔者将在学者研究的基础上,对曾公求编钟铭文进行集释,并以此为研究对象,结合相关考古资料,对铭文中的相关问题进行研究。曾公求编钟铭文记载了迄今为止所见到的、最早的曾国国君自述的周初封建史事。其铭文中提及的“南公”就为曾国的始封之君,本文以曾公求编钟铭文中的“南公”为切入点,结合南公有司鼎等器物铭文,对铭文中的“南公”进行研究,确定“南公”的身份。然后再将曾公求编钟铭文与考古资料叶家山墓地相结合,对叶家山墓地中的三座曾国国君墓进行研究,确定三座大墓的墓主身份,进一步梳理曾侯家","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27110/d.cnki.ghsfu.2022.000168","pages":"","volume":""},{"id":1171,"author":"张天宇","title":"由“曾侯”铭文铜器分组论叶家山侯级大墓的排序","abstract":"本文对叶家山墓地出土的“曾侯”铜器按照铭文内容、字体进行了分组研究，指出大部分仅署名“曾侯”而未具私名的铜器，实际上为曾侯犺所作，墓地所出的“曾侯”铭文铜器中根本无法找到所谓的“未具私名的曾侯”，因此墓地仅有曾侯犺、曾侯谏两位曾侯，三座侯级大墓的早晚关系为M111（曾侯犺墓）→M28（曾侯谏墓）→M65（非曾侯墓）。","categories":["06_族氏方国"],"year":2022,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2022.05.010","pages":"72-86, 136-137","volume":""},{"id":1172,"author":"刘义峰","title":"微史家族世系新议","abstract":"1976年发现的陕西扶风庄白一号窖藏出土青铜器造型精美，纹饰华丽，铭文内容丰富，对西周青铜器断代及西周历史的研究具有重大价值。根据铭文，作器者有商、（1）（祈）、陵、丰、墙、、孟、伯先父等人。其中祈、丰、拥有共同的族徽“”,墙与又拥有共同的先祖“微史烈祖”,他们四人同属于一个绵亘商周的古老史官家族——微史家族。","categories":["06_族氏方国"],"year":2022,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJteJXUTIAbdo8yRRL20aHRnqNXKAZuRt-Oh4cL4gGOwV3oy5UWL49IGGfziPhLn0stLWq5K_5nMdH1Y43yXJnPpL7JFg4BviCC_DTUq78jFRJMgzRvE22x8JEfsqj34X9knz0OiHAFIoso7Zc4IL0-J3t_MsHhWDTwE463Ci8D_Qfg4liFTY8w&amp;uniplatform=NZKPT&amp;language=CHS","pages":"194-199","volume":""},{"id":1173,"author":"雍际春","title":"嬴秦非戎族新考","abstract":"学术界在秦人族属问题上长期存在“东来说”和“西来说”之争。但超越二元对立，深入挖掘史料，将文献记载与考古材料、人类学方法相结合，秦人非戎族之线索清晰可辨。文献和金文资料所谓嬴秦为戎狄的说法，皆为政治需要和习俗之论，而非族属称谓。考诸史乘，无论周人、六国、西戎还是秦人自己，均不视秦人为戎族。秦人兴起于西戎环伺的天水地区，长期与戎狄交错杂处，难免习染戎俗，但无论戎化有多深，并不能因此而改变其来源和族属。毛家坪等四个西周至春秋战国时期的秦人典型遗址的考古学研究，以及墓葬人骨资料的人类学观察，也证实秦人源自东方，与西方戎族差异明显。","categories":["06_族氏方国"],"year":2022,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFIVEiReLjNFvoibzqxeCrQYISCwvAHs2U4u8O012p26K-4LT26YfzZDLVqxWije4jiRP4fjexEShDrMLC6uL_9MTA_L3g3b3eDZAEF7HBuucGP8cL9_8jTMAxht0yZFECjTXM-IRrHHkRzdqGwYWK6IGtUtyu9Be8fvm-lKc4skRvGGdnn1NP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46161","volume":""},{"id":1177,"author":"曹莹; 谢耀亭","title":"晚商西周时期山西境内戎狄研究","abstract":"“戎狄”是先秦时期华夏族对“非我族类”少数部族的一种称谓,在商、周王朝的交替之际,与中原王朝的交流也更加频繁,戎狄称谓逐渐细化。由于特殊的区位和自然地理环境,山西成为华夏族和少数部族交融的前沿阵地之一。本文试图更为系统、全面的对晚商、西周时期戎狄的族源、分布、迁徙状况进行探讨。甲骨文所见晚商时期山西境内的戎狄多以方国的形式存在,多分布于山西西南部,山西境内发现的晚商时期考古,也一步步印证着山西戎狄分布情况。至西周时期戎狄的称谓更为细化。西周时期山西境内除分布有周王室所封诸侯国以外,还有犬戎、燕京戎、条戎、奔戎、姜戎、猃狁、北戎、余无戎以及始呼之戎和翳徒之戎等多个少数部族活动。犬戎、猃狁皆为西戎,犬戎位于晋北,猃狁位于洪洞一带;北戎、燕京戎位于晋中太原一带;姜戎为羌族,分布于介休附近;条戎和奔戎位于中条山一带;始呼之戎和翳徒之戎分布于太行山附近。由此可以看出多分布于吕梁山、太行山、中条山等附","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27287/d.cnki.gsxsu.2022.000944","pages":"","volume":""},{"id":1178,"author":"齐志慧; 谢耀亭","title":"战国时期三晋地区胡狄等族研究","abstract":"本文以战国时期为时间范围,以三晋地区为空间范围,通过文献资料和考古资料的充分运用对战国时期三晋地区的胡、狄、戎等少数族群进行研究。其中第一、二、三章为戎、狄、胡族源、分布的研究,第四、五章以宏观视角去探求整个战国时期族群的迁徙以及社会生活状况,透过胡狄的社会生活等方面去探讨战国时期戎狄的“华夏化”过程以及北方长城地带“边缘化族群”的融合。战国时期三晋地区的狄族主要是由春秋中晚期东迁而来的河西白狄构成,在晋国“和戎”政策影响下,白狄鲜虞、无终等部落先后迁至晋北、冀中北地区,建立了代、中山、仇由等国。而战国时期的戎远没有狄活跃,仅从文献资料以及考古资料中发现零星几处战国戎人痕迹,且都处于中原国家的统治之下。三晋地区的胡主要有林胡、楼烦,从现存零散的文献中几乎无法看出二者的族源,但可通过出土器物、人种等方面的分析,揭示林胡、楼烦复杂的文化构成,以及“胡文化”逐渐占据上风的过程。三晋地区在战国时期","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27287/d.cnki.gsxsu.2022.001018","pages":"","volume":""},{"id":1179,"author":"叶先闯","title":"翼城大河口M1034所出叔骨父簋铭浅议","abstract":"新近公布的山西翼城大河口M1034所出一件叔骨父簋，据墓葬年代及铜簋形制、纹饰判断，时代当在西周中期前段。铭记叔骨父曾得到过“侯”的作庙赏赐，后举行祭祖的■祭礼。可能为特意表达对侯的感激或恩赏之意，并延请侯莅临，然后又得到了侯的额外赏赐。铭文所言之“侯”或当指晋侯。簋铭的史料价值，主要在于为进一步研讨西周时期晋、霸之间的关系提供了新证据。","categories":["06_族氏方国"],"year":2022,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2022.03.002","pages":"79-84","volume":""},{"id":1203,"author":"闫亚琼; 张振谦; 徐世权","title":"霸国金文及相关问题研究","abstract":"霸國是根據2007-2011年發掘被盜的山西省臨汾市翼城縣大河口西周墓地時出土的青銅器銘文而確定的一個諸侯國,在此之前,史書中沒有留下關於它的隻言片語,所以研究其銘文對認識霸國、了解霸國具有非常重要的意義。本文主要以《商周青銅器銘文暨圖像集成》《商周青銅器銘文暨圖像集成續編》《商周青銅器銘文暨圖像集成三編》以及《霸金集萃》爲參考資料,同時結合其他期刊論文,全面搜集整理出霸國相關的銅器共81件,並以此爲研究對象,在充分吸收各家觀點的基礎上,對銘文進行全面的整理研究。本文分爲緒論、霸國金文整理與研究、相關問題整理、結語、附錄五個部分。第一章是緒論,對文章的研究對象、目的和意義,學界關於霸國金文及相關問題的研究現狀進行簡單介紹。第二章爲霸國金文的整理與研究,將霸國金文按照西周早期、中期、晚期三個時段進行分類,著重對各時段所涉及銘文的隸定、疑難字詞的考釋、語句的釋讀等問題進行論述,並在前人研究的基","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2022.002419","pages":"","volume":""},{"id":1239,"author":"李宏飞","title":"试论殷遗系铜器群","abstract":"一问题的提出自北宋以来，“商器”的概念基本等同于商代铜器。《殷文存》序言即谓：“殷人文字，自宋以来，世惟于彝器中见之。……若夫彝器，则出土之地往往无考，昔人著录号为商器者，亦非尽有根据，惟商人以日为名，通乎上下，此编集录即以是为■的。而象形文字之古者，亦皆入之，虽象形之字或上及夏氏，日名之制亦下施于周初，要之不离殷器者近是。”[1]容庚也指出：“吾人所据以定为商器者，一为图形文字，一为以日为名。然二者皆下及周代，故颇难■定。”[2]彼时学者侧重于商周铜器断代研究，尚未从商周两系的研究视角对商系铜器展开深入考察。","categories":["06_族氏方国"],"year":2022,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKMmR5XufLRHrwffPopq9QlpLE_CE-SJAE1SbWOJLUz-1_Ss-FjeXDM43MCvt_Zy8rBE0y2NQq-Dv2mO7kXJgQEs7SzjUkRW2ytOwn6kFqTgbaGae4BtDcAPzVS1EUIu7K0fJmQEb22md6LlOXf2oXvxAXHP7_rcIJ9mfBnVxCcqvsfkjhZCb_w&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-170, 285-288","volume":""},{"id":1245,"author":"陈丽新; 张昌平","title":"“鄂”名迷踪","abstract":"说到『鄂』，大家自然会想起今天的湖北省。湖北简称『鄂』，同时，鄂也是我国商周时期一个重要的诸侯国。古之鄂国与今之湖北省的简称『鄂』，的确有着千丝万缕的联系。鄂出现得很早，在甲骨文、金文中写作『噩』，传世文献中一般多作『鄂』。作为诸侯国的鄂，在史籍中的面貌并不清晰，它从哪里来？又往何处去？今之灵秀湖北，古为荆楚大地，","categories":["06_族氏方国"],"year":2022,"publication":"书法","link":"https://link.cnki.net/doi/10.16769/j.cnki.31-1067/j.2022.04.042","pages":"105-120","volume":""},{"id":1249,"author":"周秦汉","title":"陶唐氏后裔四系新考","abstract":"陶唐氏是晋南的远古部族，亡于夏代，其后裔分化为异地独立并存的古唐国、刘累、唐尧和丹朱四系。直系后裔古唐国应是商周古文字姚姓“昜伯”之国，而非“■子”之国。支裔“刘累—范氏”一系出居在外，夏孔甲时始封为御龙氏，商武丁时被封为豕韦氏，周宣王以前为唐杜氏，即祁姓杜氏，不应分为唐氏与杜氏。尧出于陶唐氏，早年活动于丹水。丹朱后裔在东周为狸姓傅氏。房国非丹朱之后。“尧为唐氏”说不晚于春秋晚期，“尧居晋地”说流传自战国三晋。“尧为祁姓伊氏”说是汉晋后起附会之说，不可信。汉室虽能追溯至刘累一系，出自陶唐氏，但并不能追溯至尧一系。汉人杂糅诸系，遂完成“汉承尧运”“汉为尧后”的政治神话。","categories":["06_族氏方国"],"year":2022,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2022.02.006","pages":"65-76, 158","volume":"16"},{"id":1253,"author":"陈淑娟; 曹媛媛","title":"甲骨金文所见“鱼族”略考","abstract":"在商代甲骨金文中，一些族氏名与人物称名以及地邑之名往往是相互对应的，如甲骨卜辞中见有“获鱼”“呼鱼”“省鱼”“鱼亡冎”之语，这些“鱼”或表示鱼族之人物（首领）称名，或表示鱼地，或表示鱼族，本文中将有关鱼族，鱼族人物称名，鱼地的甲骨文、金文资料统归为鱼族史料。目前，共统计出鱼族甲骨史料9条，鱼族金文史料97条，通过对这些甲骨金文及相关资料进行梳理，从而整理出殷周之际鱼族的相关史迹。","categories":["06_族氏方国"],"year":2022,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI03ctsI8YjKAOkL5wCUL8GzMZHkCG2cZqdvZW3Mgj3geW0mgDVs32hXoGQngg-fAHcPThFw3s6BC5AkT-JvKKkjQQOjBhDoZ93S69wlxf9oLDhGwTe5LSPZR_3ugt1S2dg15yDL5b6I1JbsT0Z3BUdItClC0QAeCIhMnhrVPXkFKZoYEO2rS5s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35, 59","volume":""},{"id":1258,"author":"蒙家原; 彭邦本","title":"先秦秦汉时期巴地华夏化进程研究","abstract":"本文研究的主要内容为先秦秦汉时期巴地的华夏化进程。首先 ,本文对“巴”这一地理概念在上古时期地理范围的变化过程进行了梳理。作为一个地域名称,“巴”早在夏代就已经出现,主要指今丹淅流域,而到了商代晚期,“巴”又变成了一个方国的名称,其地理内涵则主要指的是这一“巴方”所活动的晋南一带。至西周及春秋时期,“巴”则改为主要指宗姬巴国统治下的汉水上中游地区。而当进入战国时期之后,“巴”的地理内涵又变为主要指今嘉陵江上游、涪江和沱江下游一线以东的四川盆地东部地区。战国时期以降,“巴”的地理内涵便基本已经凝结,不再发生大的变化,直至今日,“巴地”仍主要指的是这片区域,而这也是本文研究的主要对象。其次 ,本文对秦灭巴、蜀以前巴地和华夏的互动情况展开了考察。需要指出的是,居于巴地、被称为“巴人”的人群及其所构成的政治体才是真正意义上巴地历史活动的主体,而通过本文对巴人历史的重新探讨,可以看到“巴人”主要指战","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27342/d.cnki.gscdu.2022.007442","pages":"","volume":""},{"id":1260,"author":"雒有仓","title":"金文族徽兴起发展与夏商族群融合认同","abstract":"现有资料表明，金文族徽可能兴起于夏代晚期，它是当时社会组织形式由姓族转向氏族的重要标志。商代早期至中期，族氏的政治化发展日益明显，金文族徽数量也随之增多，地域分布有所扩大。商代晚期，金文族徽数量显著增加，以人名、地名、官名为族徽的现象增多，复合族徽所占比重增大。这是商代族群融合认同逐渐脱离血缘而转向地缘政治并不断加强的表现。然而，由于当时的族群融合认同仍以血缘色彩浓厚、独立性较强的族氏为本位，尚未深入到社会个体和家庭层面，因而并未形成一个基于地缘关系的民族共同体。","categories":["06_族氏方国"],"year":2022,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2022.02.003","pages":"23-31","volume":"10"},{"id":1261,"author":"李喆; 刘伟","title":"谭国史若干问题再研究","abstract":"谭国是位于济南地区的先秦古国,南倚泰山,北傍黄河,处于兵家战略要地。谭国既有先秦小国史料缺失、依附强国而生存、屡次迁徙以避强敌等共性,亦不乏其自身特点。对谭国的起源与地望、春秋时期谭国的灭亡与复国以及谭大夫所作的《诗经·大东》等问题进行重新审视,进一步揭示谭国历史文化面貌,有助于我们了解先秦谭国的历史特点,加深对谭国史、先秦史以及济南区域史的理解。谭国的国名经历了“覃---譚-谭”的演变,今在全国各地发现的覃氏家族青铜器或为春秋时期谭人先祖所作,为研究谭人源流的重要材料。谭人本为伯益嬴姓后裔,称皇覃氏,定居于城子崖一带。禹死后,伯益并未即位,城子崖一带已成为大禹姒姓后人的居住地,嬴姓谭人被迫西迁至濮阳,建立了自己的方国,称方。武丁灭亡方后,令嬴姓人迁回城子崖故地,又将城子崖一带重新封给子姓贵族,并继续沿用谭国名号。自此,谭国族姓完成了由嬴姓到子姓的转变。谭国人民几经迁徙,至周而终定,后终谭","categories":["06_族氏方国"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27267/d.cnki.gqfsu.2022.000013","pages":"","volume":""},{"id":1262,"author":"黄国伟; 胡宁","title":"垣曲北白鹅墓地与周代的“西燕”","abstract":"山西省考古所在垣曲北白鹅村发掘了一批春秋早期墓地，墓地出土大量匽氏铜器。有铭铜器主要出自M3、M5、M6三座墓。铭文显示匽氏曾任周之太保，匽氏曾与虢季子白之女通婚。北白鹅匽氏出自嬴姓京氏小宗的膳夫克家族，使用华字族徽，葬俗上多腰坑殉狗。膳夫克家族在两周之际东迁至北白鹅一带，因地命氏称匽氏。南燕国与北白鹅墓地所属族群之间并无实际联系，二者同时存在于春秋初年，为示区别，可将北白鹅之匽称为“西燕”。","categories":["06_族氏方国"],"year":2022,"publication":"湖州师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQgHk9knsPOxWC-OfikYGgAu9qiuOjTXwi8zVQ4Wx970wLLjZ0IxazxCmbAurfHF0qra25aYdVw0Vh1S3K9nf4Rzh-aeLW5mmV2Lv83EztwwiDcZS4GoW75ibSj3orARVbIvlo5VMZoLVhYwpLyLncY1w-ubQ21Q7ONpB3-4BsgN4_gWx3K4ca&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-101","volume":"44"},{"id":1264,"author":"吴镇烽","title":"衍簋、槐簋研究","abstract":"衍簋和槐簋是西周中期后段之物，该文对其铭文进行了考释，认为衍、槐以及传世的康鼎的作器者康，同是郑邢氏家族的祖孙三代，都曾“死司王家”，主管王家的内外事务。文章并对“咸邢”作了辩证，认为咸邢、郑邢、丰邢是邢氏的三个分支。邢氏最早的封邑在周都丰京附近，后来子孙繁衍，一支被封在西郑，称郑邢；一支被封在咸地，称为咸邢，留在原地的便改称丰邢。","categories":["06_族氏方国"],"year":2022,"publication":"文物季刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQHIhyc1-RTUsK1AbR6_FyQgGnNY-PqvJpf-EGNzmo4n7UvrjG_j5lsozr7CO8SnbadH7RfjOVkdjUdHZlNij86QirDYnOoTRMB54l93ZBBJDqpbd_53Aua1vRrmA2VGDpY0B_MDo1q5iOzszcrTJkf2V1Zv2PK3AQUtkatnWuYry2FrCxXwAS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-113","volume":""},{"id":1265,"author":"黄锦前","title":"夷伯盘考释","abstract":"本文对山西绛县横水墓地出土的夷伯盘铭文进行考释，指出其年代应为西周中期后段，与传世的桋伯鼎年代相若，铭文字体风格近似，“桋（夷）伯”或即一人。盘铭与甚孪君簋、乖伯簋等铭文文例及记事皆近似，夷伯与甚孪君及乖伯身份类似，系东夷国族君长，夷（桋）的地望在今山东青岛即墨西。盘铭用字和措辞风格独特，与同时期周人及中原铜器铭文风格迥异，而与淮伯鼎等颇似，东夷本土风格特征明显，但与周人及中原文化多有关联，从侧面印证和折射了盘铭所反映的当时东夷与周王朝及中原的关系。","categories":["06_族氏方国"],"year":2022,"publication":"文物季刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLluXRasSkEMjWKwveBDrfhfoK4YI4xVvC7VaWEyIO5-5Np9l8ANBdN-T1lj_IKdWu3RHrOFjHz2Vug7HsMMxQ8fRU8R_jYLIFyD-lD_miin9HvHIv2r4sGmr7fz4h15AD0egWYYyKiaOCv7KTZ-mdtfXjMazWSmX7UqO9iebmTh_zlSBeIz_BQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-120","volume":""},{"id":1269,"author":"何艳杰","title":"赤狄新考","abstract":"赤狄研究始自清季，近现代民族史、晋国史等论著中多有涉及。然而相关研究集中于部族构成和分布地域、外交关系、战争及来源等有限方面，且多从中原华夏民族的视角审视赤狄之事迹。限于文献记载简略不详，赤狄的文化、经济、社会、习俗等基本面貌目前尚有待深入研究。本文搜罗赤狄相关的出土文献、金文和考古资料，以《伯硕父鼎》铭为中心，兼及相关考古资料，论证西周晚期赤狄可能居于泾河上中游一带；据两件“皋落”戈铭分析赤狄可能使用晋系文字；据《清华简·系年》揭示狄联盟曾以“群戎之师”的称号存在，奉晋国为霸主，参与城濮之战助晋伐楚；狄联盟首领号称“赤狄王”,狄联盟内部形成了王(部落联盟首领)——子(各部落首领)——贵族——平民的分层社会。","categories":["06_族氏方国"],"year":2022,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2022.01.019","pages":"65-72","volume":"43"},{"id":1273,"author":"蒋伟男","title":"嬭加编钟器主身份补说","abstract":"湖北随州枣树林M169所出嬭加编钟的作器者为嬭加,而非曾侯宝。全篇铭文以她的口吻来表述。铭文第一段嬭加简单概括了曾国的始封历史,她自述以楚文王之子孙、穆王之女的身份嫁到曾国。第二段铭文中,嬭加回顾在丈夫&quot;龏公&quot;去世后,她勤勉为政、保有疆土的历史。嬭加编钟提供了春秋中期曾国历史的新资料,也进一步丰富了学界对这一时期曾楚关系的认识。","categories":["06_族氏方国"],"year":2022,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI9UbSUlLFIwOxoPZXWB8lhLlFsubnzPTP5T1fipz950UX2INtEL73gBLcdlY3NXEmbzgC6rkHUEerIaPsx7nFmKt_s_3dWFXyUMs1GVzt0GFsxpq3tjno7bn13eWNZxJePzO77xBYO6-r_kQ3w8uPATla6qfyw5HrB7xUfU3e_hpNMgS2KsGU4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-49, 155","volume":""},{"id":1275,"author":"程浩","title":"出土文献与郑国史新探","abstract":"郑国虽是西周诸侯国中出封最晚的一个,但却在西周以降的历史进程中扮演了极其重要的角色。纵观郑国四百余年的政治发展历程,称得上是整个春秋时代社会历史变革的一个缩影。本书立足于清华简以及青铜器金文中新见的郑国史料,结合《左传》《史记》等传世史书的记载,力求还原郑国发展的几个重要阶段、若干重大事件,并尝试将郑国历史的发展纳入春秋战国社会变迁的全局进行思考。","categories":["06_族氏方国"],"year":2022,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDtAQjX_txv4dwWWFZNfV3LipOlkrxOpulvnEMhqPl9ml7qdy1VHM61MgR5LirMm66k--bjKmeoEadWNKjUoHbW34n7w294xDsaOgqqMvjz6ZN4VxbVN0Ou1CueOI7QUjpVhOo1Qwnl5WlI99lcRFj75jxPnacaJGatL6h_0CR5uTiIU0V_Iz8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"162","volume":""},{"id":1285,"author":"马超","title":"叶公臧鼎与叶公子高史事考论","abstract":"综合考察器物年代、出土地点、语音通假、人物事迹等内容，可以确认叶公臧鼎铭文中的“叶公臧”应即史籍中的“叶公子高(叶公诸梁、沈诸梁)”,典籍所载叶公私名“诸梁”之“诸”,当为语助，“臧”“梁”则为通假关系。据此还知叶公也并非如王引之所说因“都梁山”而得名，旧或认为《上博简(四)·柬大王泊旱》篇中的“圣人良”乃叶公子高，当非。鼎铭“均邦”一词意为“安定楚国”,实指叶公平定“白公之乱”这一历史功绩，“均邦”之语是叶公对此事的亲口述评，史料价值尤为突出。","categories":["06_族氏方国"],"year":2022,"publication":"西南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13718/j.cnki.xdsk.2022.02.023","pages":"246-252","volume":"48"},{"id":1288,"author":"王晖","title":"加嬭编钟铭文研究——兼论曾国从周之方伯到楚之附庸的转变","abstract":"从加嬭编钟铭文可知，加嬭是楚文王曾孙女，楚穆王长女，曾恭公之妻。加嬭编钟应是楚庄王时代之器。加嬭在丈夫曾恭公去世后，借助娘家楚国势力，临朝执政，辅佐少主，其亲政的时代在春秋中期楚庄王时期。加嬭统治之时，她借助母方的背景和势力，收复了疆土，称雄周边诸夏小国；她同时也敬畏朝中的卿士大夫，小心地处理朝政，为曾国兴盛做出了努力。加嬭是中国历史上已有文献所见首位以女主身份临朝执政的女性，加嬭编钟铭文所述曾国外交内政事务是值得关注的。从这一时期起，曾国也开始了从周之方伯到楚之附庸的转变。","categories":["06_族氏方国"],"year":2022,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCP2ymD6OSp2rp5GfpJ1ZkOpNCJJzXbWlFheUarFgc6BsNuYPJUmFNmmXWcy9RjK9OF2sSWCAN7GbMqkomRfhuaheDALQ3qiXgKsku2JWl7hX7-25vQdmKtRvHVcASJPqKcPcdXMz3Pa5wADV0tpXPqdxW2qD01f8nlAsgPOCQgaVy2ClOWiso&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46162","volume":""},{"id":1306,"author":"陈絜; 聂靖芳","title":"甲骨金文中的朿族与商周东土族群流动","abstract":"商周族群流动研究关乎国家形态、社会形态与民族融合等重要课题。近年来,随着商周地理研究的系统化,细致梳理商周时期东土族群的分衍、流动及其成因,已成为可能。甲骨与金文中习见的朿族具有典型意义,可作为相关研究的切入点。通过分析可知,商周朿族最早的族居地在今山东泰安、泗水一带的朿地。晚商时期,形成朿正、朿舟、朿保与朿厚等分族,均盘踞于母族的周边。另有部分族众因特殊的政治需要而徙居殷都安阳。西周早期,在王朝武力胁迫之下,朿族宗子徙居成周,在洛阳北窑留下了墓葬遗址。昭王时期有部分子嗣因战功出任王官,并进一步西迁宗周,形成新的分族&quot;朿■&quot;氏。但依然有族人留居东土,即汶水下游地带的朿厚氏与朿蛇氏,其中朿蛇氏一直延续至两周之际。商周朿族的分衍变迁,是东土族群流动总貌的折射。其社会与政治层面的动因,对分析东土其余族群的分衍变迁有重要借鉴作用。族群流动并非是整个族氏组织全体搬迁的现象揭示,相","categories":["06_族氏方国"],"year":2022,"publication":"史学月刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImKzNEoMYQ2pgyeisfHFEX349TMLyaSFjFscSgs2qZeZ_fEtZWn2pOspxZeCvmott2sPxrCfu3qNX_NFGvdj76B6n7yGJSUDIG5vRP204L19uCYDulyv-9EKXo6ws6cvxbOfkc_mqsDXgidYXL2FPvMgHh6nBTC7rw6uz_eNaq42knKcDeOzbY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46160","volume":""},{"id":1311,"author":"张丹","title":"南阳地区出土铭文所见两周时期重要贵族人物考述","abstract":"南阳地区出土许多两周时期的铭文铜器,涉及两周时期的一些贵族人物,对这些信息进行梳理可以发现,南阳地区出土铭文所见两周时期贵族人物在不同的历史时期反映出了不同的邦际关系秩序:从有限的铭文材料看,西周中晚期时,南阳地区作为西周王朝的南土,它的邦际关系秩序始终是围绕着周王朝展开的;春秋时期,南阳地区的邦际关系秩序则完全是围绕着楚国展开的,周王朝在这一带的影响力已经基本上可以忽略不计了;进入群雄混战的战国,邦际关系秩序的建立则已经开始更多地依据武力,而不再过多地凭借联姻、行政建制等手段展开。","categories":["06_族氏方国"],"year":2022,"publication":"南都学坛","link":"https://link.cnki.net/doi/10.16700/j.cnki.cn41-1157/c.2022.01.016","pages":"109-119","volume":"42"},{"id":1313,"author":"雒有仓","title":"西周金文族徽的地域分布与商周族群的政治认同","abstract":"金文族徽由河南地区向陕西大量传播始于商末周初，这是当时政治中心由东向西转移的一种反映。西周早期，金文族徽分布主要以成周、宗周、岐周为中心。见于西土之地多分布在今陕西宝鸡、凤翔、陇县。东土之地多分布在今山东滕州、济阳、黄县。北土之地多分布在今北京房山琉璃河、顺义牛栏山，辽宁喀左。南土之地多分布在今湖北随州、蕲春、江陵等地。相比较而言，西周早期金文族徽的数量有所增加，地域分布有所扩大，西周中晚期则呈急剧减少的趋势。前者与分封时大量分散迁移殷遗民、以宗盟制构建王权政治和地缘政治有关，后者与商周文化融合、族群结构改变、政治认同加强有关。","categories":["06_族氏方国"],"year":2022,"publication":"中国历史地理论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfcAnzgvy023bEB_Df8HSj65ialJ_L-zVEfEWqIFdxSHskvc6TjT-aNZA-9maJ5Nw_hqz9PlEyrI2YtekOU1ns20sQ6IvXVYVnC5lcWYXsl0Z25_LY5835WzXPoJYafm92077PZcQs1XADq0DiUsny36Lf5F_h7I-dDKl9t_7XDpDArdV48InL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-91","volume":"37"},{"id":1314,"author":"赵燕姣","title":"从班簋、孟簋铭文看典籍中的徐偃王——兼论两周时期徐之迁徙","abstract":"徐偃王在后世典籍中多被誉为“仁义之君”，然由于历史久远且文献阙佚，有关其史实多幽渺难考，结合班簋、孟簋铭可知：徐偃王确有其人，活动年限约西周中期周穆王世，地处周王朝之东，因自小身染骨病以至神形怪异、面目可憎，在班簋铭中被讥为“东国戎”。徐偃王作为部族首领，同时也身兼巫师的身份，在孟簋铭中被称为“无需”，这一发现也与古时的巫师多为残疾之人这一习俗相吻合。","categories":["06_族氏方国"],"year":2022,"publication":"中国历史地理论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfcAnzgvy023bEB_Df8HSj65ialJ_L-zVEfEWqIFdxSHskvc6TjT-aMGUkDBMQoRq49X7yd1otKC715-XF6iIwuiWWxpnTKA1J7zHk_lCmzA7pN5WUnRvCa8ZJHY2Z8zPKbSe54znze-l3YpOWhepZS2-3jtkYKcVgSDeL-OAXMLviRwfmXJtF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-149","volume":"37"},{"id":1316,"author":"张新俊","title":"从甲骨、金文看逢氏青铜器与失落的古逢国","abstract":"1976年湖北省随县周家岗一座春秋墓葬中出土了一批青铜器,其中有两件所谓的&quot;季鼎&quot;和一件&quot;季盘&quot;。由于文字的误释,这几件青铜器的族属一直没有得到合理解释。从文字考释入手,联系殷墟甲骨文、商代金文以及传世文献,可以确定这几件逢氏青铜器与失落的商周古逢国是有密切关系的。商周时期的逢国位于今山东济阳一带,至迟到春秋早期,有一支逢季家族迁移到了南方,并长期活跃在政治舞台上。","categories":["06_族氏方国"],"year":2022,"publication":"河南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKh5RecIz0bHKAt4V2V8G9bcBT7e7Qx5MCG3r7W-3JrZl8yY3eI1q48a50wzzh5OiGhWaVgyzAW-w_QRHL3iDPjFFsApHx6WXmgnAA2vXorxOqyiAZeDXhuxwFFhKPugcMdHT--nytYsouDK698pQqtTGUNGP7Mn82HsW4jQL4mAZ4pH3g0lUUd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-30","volume":"30"},{"id":1299,"author":"吕国华; 葛海洋","title":"试述“史”器及“史”族相关问题","abstract":"本文结合前掌大墓地出土大量带有“史”铭的器物，分析“史”器区域分布情况及出现在不同地区的原因，可以考虑或为战争战利品、联姻的媵器，又或与殷商遗民的迁徙有关。并由此解析从前掌大墓地中体现出的“史”族文化因素，认为商文化在这里占据着主导地位，但也形成独特突出的自我特色，显示了不同寻常的地位。","categories":["06_族氏方国"],"year":2021,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtKr511OBCp9YnwPxU3dV4HTkB1xAJP93FaJyIBgR9qlzkWwdSZF-UCZXPHuQsZRAQ9p0MlZdzFaf5IJmvhuAONXEFdnbUMweYMGSFfqkWWwWaFSxiFYMgyFBeWZLdRQXtPJ25mElU6qIbn_fMilQxD4OdfhEYDb6k_NUe-jcgsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"193-199, 4-6","volume":""},{"id":1321,"author":"王长丰","title":"殷周金文族徽综合研究","abstract":"本文针对殷周时期金文族徽现代汉字表述、族徽研究概述、族徽的类型、族徽的内涵、盟姻族徽的内涵、族徽模型和族徽研究例证等几个方面,进行综合研究,得出殷周金文族徽有基本族徽和盟姻族徽两种类型。基本族徽包含姓、氏等家族称谓,这些称谓是以这些姓或氏为国(邑)名或族名称谓的国族姓氏;盟姻族徽本质上就是国族姓氏之间以&quot;同轨&quot;&quot;同盟&quot;&quot;同位&quot;&quot;外姻&quot;等途径形成的&quot;结盟&quot;或&quot;外姻&quot;等关系的血亲组织,不同形式的&quot;盟姻族徽&quot;代表着不同的&quot;盟姻组织&quot;。并且,本文从方法论的角度对殷周时期部分族徽进行的示范性例证研究。","categories":["06_族氏方国"],"year":2021,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhBnPq3R1R40UpyUlELgZq_YppBbA0xaiZPS4kK5aiEq3InPilEbEB_tVPeB0NVrZyB_Q9ZS6J988bV-imGVqYpEQhVLeBAQNAKce4uvXffLroM6M2-4lRTXJXTrE9Dy7F-1DxRl5LG5sofUkhyTClU49sVnDfg1x_5lXf46ty1A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"146-193","volume":""},{"id":1327,"author":"陈民镇","title":"新出铜器与伯括、南公及曾国始封试探","abstract":"新出曾公(田求)编钟铭文提供了有关曾国先祖以及曾国始封的新史料。铭文所记“高祖”即伯括，他辅佐文武克商建周，相当于传世文献中的南宫括。“皇祖”与“高祖”均可作为受命之君或始封之君的尊称，“皇祖南公”亦指伯括。南公（伯括）受到册命，其子曾侯谏就封，在南土肇建曾国。叶家山M111的墓主曾侯亦为南公之子，他或是昭王时期接受赐钺的曾侯。在春秋时期，曾国公室业已形成较统一的先世叙事。","categories":["06_族氏方国"],"year":2021,"publication":"西部史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdy_dt8TH8cAOL7DkhdIhvLKIooMSz7_PRIm4YDXSfsDVNUW59_IaDt9ww7wOpbZdBQlmi1rvseSLuLPrvSXqhTHL4lOreLm8eG0QfDiNCLuWOHQPH4yjiwqAshEOkHehIdOpH0e0A0VhERYFk9_xUHQ8flwkUtxv14AsXmDGXgg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-33","volume":""},{"id":1331,"author":"黄锦前","title":"探寻湮没已久的周代姚国","abstract":"本文通过对器物形态和有关金文文例的分析,指出姚季鼎、壶的“姚”应即文献记载的周代子姓姚国,其地望在今山东菏泽一带。金文中常见的作为姓氏的“姚”当系文献记载的虞舜的后裔,与姚国之姚无涉。姚季鼎、壶系姚国铜器的首次发现,揭开了湮没已久的周代姚国的神秘面纱,为重新认识文献的有关记载提供了可靠的依据。","categories":["06_族氏方国"],"year":2021,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIs12Kbm4TQ25mtTVOQYgTx4W4xSlu7iU8KmUERtTPk0bkAdtP6cfOk5yWNhydxrVd5LAbd8aCZmUUM56bEyJINaI_craLRHR6WB0MZ2Q8jpKMejfpp57FGa3lhy7ZQjo6R7To5n7czhe0afb0aR2w55dN0dGmOmD0EftKmmROW2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-67","volume":""},{"id":1334,"author":"陳民鎮","title":"從春秋述祖銘文的體例看南公的身份","abstract":"“南公”之稱,不見於傳世文獻。從兩周金文看,南公是周初的重要歷史人物:1.■乍（作）剌（烈）考南公寶■（尊）彝。（南公方座簋,《銘續》30371,西周早期）[1]2.令（命）女（汝）盂井（型）乃嗣且（祖）南公……易（賜）乃且（祖）南公旂……盂用對王休,用乍（作）且（祖）南公寶鼎,隹（唯）王廿又三祀。（大盂鼎,《集成》2837,西周早期）3.先且（祖）南公、亞且（祖）公仲、必父之家……用乍（作）朕皇且（祖）南公、亞且（祖）公仲……（南宫乎鐘,《集成》181,西周晚期）","categories":["06_族氏方国"],"year":2021,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJK0Ou9Y8HC4AlIkm7u0rtY2gkJ851aYXUvMp3igwfNXAma_p8LfYPIPHZxWb3CEdtW-Ls3V11uAcHQPIdUXNaTzTWTt6P_vxgGQUb93SSYUN9b9zo-mExA1WpdAZ_UQvhxwR869F8jQYn4Qc_FxpQ_-_IGYWkJ-R9lM07hW0aJsQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-83","volume":""},{"id":1337,"author":"李秀亮","title":"山東高青陳莊遺址所出金文與齊史新證","abstract":"2008—2010年間發現於山東淄博高青縣的陳莊遺址,被公認爲近年來齊文化考古的最重要發現之一,填補了多項歷史記載的空白。遺址出土的西周城址、貴族墓葬、夯土祭壇以及青銅銘文、刻辭卜甲等遺迹遺物,都爲西周時期齊國歷史文化的研究提供了重要的最新資料依據,備受學者矚目。時至今日,有關陳莊城址的性質、夯土祭壇的功能、青銅銘文的釋讀等問題,學界已取得較多共識。[1]但利用這批寶貴資料來系統研究齊國的早期史事,仍有很多工作要做。筆者不揣淺陋,願在前輩學者研究的基礎上,對此問題試做討論。","categories":["06_族氏方国"],"year":2021,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhOCucfhJVZ01YN9Bdz3F12Y65KDO456pEvRCO6y_zuqdgi9f8wLP2bKZVZs8J4uG7Dcp_eNxFnbaBB2itksXu1nIYcEskMVwKynpxFe6wMPCRrHxIopqAMIOCr601_Nqtenrkhd7cmOaMWzFRfrbS2r_76RdtiyggkQl-14T7Ag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-74","volume":""},{"id":1340,"author":"韓巍","title":"垣曲北白鵝墓地族姓解謎——兼論春秋初年關中世族的東遷","abstract":"山西省垣曲縣英言鄉北白鵝春秋早期墓地是近年周代考古的重要發現。墓地雖遭盜掘,但出土文物仍相當精彩,尤其是衆多帶有銘文的青銅器,藴含有豐富的歷史信息。據山西省考古研究院楊及耘、曹俊介紹,“多座墓葬出土有‘太保燕仲’銘文、族徽‘華’等内容,初步推斷該地爲春秋早期至春秋中期太保召公奭次子後裔沿襲了太保官職,","categories":["06_族氏方国"],"year":2021,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbkzNeFTVT7iPkDQjB8AZiXTdhVhFJ1-5qU8KXdHGwAKs09Y0VIO-lsJIPfxqYpk-OCQD1f89gdcuMBkOecQaixm1spCCqpqkH2KGSHfOSeyY4kbyr48aEgsRe_lFtKI6NcTdNETmEX8Rq0ycRIj-p4Dy4MCqdr6M2zcdmrX_LmA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-47","volume":""},{"id":1352,"author":"田成方","title":"鄝器与姬姓鄝国、楚鄝县","abstract":"姬姓东蓼与己姓西蓼在铜器铭文中的国名用字存在区别。西蓼之蓼的基本构成是从翏从茻,东蓼及后来的楚鄝县在铜器铭文中一般作&quot;鄝&quot;。目前见到的东蓼铜器有春秋中期晚段的鄝子戈和春秋晚期的鄝叔义行戈,他们的出土背景都可能与东蓼灭亡相关。鄝公鼎、缶、鄝公铸公子戈之&quot;鄝公&quot;,分别是春秋中晚期之际和战国早期楚鄝县的县公。作为楚国县级政区,鄝县当设置于东蓼灭国后不久,约春秋中期晚段,延存至战国晚期。","categories":["06_族氏方国"],"year":2021,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOPJ8s52o0Sw-RBSn6eE-KNc1MUEXvVuwr9De7qyhoIjbCHueQ7MkObl42mFWfeerGvjGVyIV0lJRwk-f9h6TQee-L6F75MlXndANpqwqB6J1euiNa5V4Rja8SxAEf0Toj2coUHiwLH-Ka5X5roP_0jdtUiErhMSCCyN0Q5JrN6_k8PXxXpivg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-94","volume":""},{"id":1363,"author":"方勤","title":"曾国世系及相关问题研究","abstract":"历经近一个世纪的曾国考古,揭示了考古出土的青铜铭文&quot;曾&quot;就是《左传》等文献记载的&quot;随&quot;。曾国考古发掘了16位曾侯和10位夫人墓葬,出土文物尤其是大量金文揭示了尘封的曾国历史,书写了一部名不见经传的曾国历史,这是考古史上的传奇,也是诸侯国别史研究的奇迹。","categories":["06_族氏方国"],"year":2021,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL46iPW_93j1pMJ7CivH5rh4Pe-OluCADEXhFsHpQ6mAycixRFMkouChPfkHQo_NkpKvBVPW0R7QCQIm-SzovPHqsvrQMOa-IAogrp_3lmVd7bPV_Ln2GZ4_02XyugUcRSdKu0v_2kHpJSAn8CDfIVPSJYD2qUAdPrR5WI-5knabG1Ywlpc1MC5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"192-196","volume":""},{"id":1378,"author":"孔德铭; 孔维鹏","title":"殷墟出土的“戈”铭青铜器研究","abstract":"戈族是一个古老的氏族,源于夏代,至少在洹北商城时期就已经迁到安阳一带生产生活,在商代晚期该族得到了较大的发展。殷墟考古出土了大量的带有&quot;戈&quot;铭的青铜器,特别是2016年以来在安阳辛店商代晚期铸铜遗址内的贵族墓葬中出土了30余件带有&quot;戈&quot;名的青铜器,这是目前已知考古出土带&quot;戈&quot;铭铜器最多的区域。这一发现为戈族的地望、职业、地位、文化、发展、迁徙及&quot;戈&quot;铭铜器研究等提供了丰富的资料,具有重要的研究价值。","categories":["06_族氏方国"],"year":2021,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLosG_QEeMqZAfruF5itQ6XYNmVW2SW3y6l7LAE0sH6E1rwMbpLUOm1vsheGqsOa2dA-dL5qIEHy7qS1yqktehjT7NmVLaEAKLSdgMXEwHBcCR-mXbaDF5h-dAFlkfVDlOAoRXJFYtowADOMUSYLb6aePVckEOHx-dar-N8ilxSRM2IMnmNCA7v&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-97","volume":""},{"id":1381,"author":"雒有仓; 黄端胜","title":"西周金文族徽的沿袭变化与商周族群的文化认同","abstract":"通常认为,西周金文族徽是商代晚期族氏名号的沿袭,事实上,西周金文族徽还存在许多变化:一是族徽地域分布中心转移,二是族徽铜器数量由增转减,三是族徽种类减少,四是人名、地名、官名性族徽增加,五是族徽功能与性质有所变化。正确认识西周金文族徽的这些变化,对于深入认识当时周人铜器上出现殷商文化标记的族徽与日名,大量殷遗族氏分散迁移各地与周人族群融合,以及西周中晚期殷遗族徽、日名显著减少与周文化的认同等问题,都具有重要意义。","categories":["06_族氏方国"],"year":2021,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2021.05.003","pages":"22-30","volume":""},{"id":1390,"author":"吴毅强; 张卉","title":"王子申盏盂的器主身份及时代","abstract":"通过近年新出铜器&quot;嬭加编钟&quot;,可确定嬭加为楚穆王之女。进一步梳理相关金文与传世文献,可论定王子申的身份为楚穆王之子、庄王之弟,和嬭加为兄妹关系,籍此,王子申盏的年代当为春秋中期中段偏晚,定在楚穆王时期较妥。该器可说明春秋时期女子出嫁,除常见的父辈为女儿做媵器外,兄弟亦可为姊妹制作媵器,补充了礼书之缺。","categories":["06_族氏方国"],"year":2021,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyJFWYB2QTY7OXFaAd8v2NMSlHgzvz8ONfM7DAoD3Vu7dAWjK8v3-TtXpvKppCiYMQ213m8Luj-Lemrk57zB-uwopzpncsKXDf-AMMEr-efXeINZ6SsQrmrhJ0lXgi_4y7eYci8awxSYLVjB_rhK_HOIlJQzqfXdgkZD2jB-fgqQddmN1GKaZN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"113-117","volume":""},{"id":1416,"author":"蒋鲁敬","title":"纪南城周边近年出土的古文字资料与楚文化考古研究","abstract":"楚纪南故城周边墓葬出土的卜筮祭祷简所记墓主的名字与职官,提供了楚国高等级贵族墓葬制度的重要资料,是辨析墓主族属的依据。有关楚王族的卜筮祭祷简和楚铜器铭文资料,揭示出战国时期楚王族墓葬的墓向为东向。一件秦铜铍刻铭的纪年,为区分楚国核心区域战国晚期晚段的楚墓提供了重要依据。","categories":["06_族氏方国"],"year":2021,"publication":"长江大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4nqCTI_uXZWWzmhtt5ptlDbgGoxK7qW9OIVqc3yKBs9Zab01ALfk2FOcU3S1V912HgIfbdJROchJzKAxGZnZ2Dp56to9zTH8UTdlIYnd99i6bH8wGRzUmln6H5D0eaUH9hW5A3niXPmmCaOkWOsxsHhpNkoTJYYN3XfA47b4hXzJZIL1QLA8p&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-53","volume":"44"},{"id":1420,"author":"孙明","title":"罗山天湖“息”器铭文与息族相关问题探讨","abstract":"罗山天湖墓地位于河南省信阳市罗山县莽张镇天湖村,&quot;息&quot;铭铜器自1979年发现以来[1],一直是学术界关注的重要课题之一。学者们虽然从多个角度进行探讨并产生了一系列重要成果[2],但是铭文书体、息族世系、息族去向等问题尚未涉及,息族与殷商之间的关系、天湖息族被姬姓息国替代的时间等问题也有深入探讨的必要。以前人研究基础,本文拟对上述几个方面进行探讨。","categories":["06_族氏方国"],"year":2021,"publication":"文物天地","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaOGS5G_NAPGo209D0I8uefaEVsWYn3e-v0CpT8ue8tf6kepGWEb5QG3a0LomEpAfFufQz_wYwvLg00VURHX22adD3-ATv-UBgMvsDNdr27xtFEmqere9ukOlNYz4RtjO-ocV0gcyja3oZot64uUoSEIYBlrA1P2kh4HFyKQMM64A7-h33eBem&amp;uniplatform=NZKPT&amp;language=CHS","pages":"112-118","volume":""},{"id":1432,"author":"刘余力","title":"苏公鼎及相关问题考略","abstract":"本文介绍洛阳发现的一件战国时期的&quot;苏公鼎&quot;,鼎口沿上刻有&quot;安居稣公鼎二斗二升&quot;9字。&quot;安居&quot;为地名,不见于文献记载,地望待考。&quot;苏公&quot;可能为原居住于陕西关中一带的苏氏,后迁居洛阳。","categories":["06_族氏方国"],"year":2021,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJUdLjculjLi7EgbuKFyoeBHgmy2c1aHS5OMC72PoetdvRPZdn94ollbP7l5Ic2npoUQwBahp6ZZxZoLbIjgn-9ka9w7l3h2pKe5xj8Tngd8TzqY5h4VHncO8N0iXBgz0VUeBKCxTCdN70QKqhkwQnP_Hk46u0usOX1LDio02LbRN0eH62Ghf3f&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93-96","volume":""},{"id":1445,"author":"贾海生; 袁茵","title":"倗国君臣作器祭祀祖考而使夫人摄祭的原因","abstract":"倗国是根据考古资料发现的一个方国,其族属于赤狄,其姓则为媿姓,西周至于春秋立国于今山西绛县横水一带,始终处于大国强族的包围之中。倗国君臣制作用于祭祀祖考的礼器,在铭文中明言使夫人摄祭,与华夏民族夫妻共承宗庙祭祀的周礼截然不同。究其原因,或是面临随时被兼并、灭亡的命运而将顾命之语铸为铭文,或是赤狄族群固有不同于华夏民族的风俗。","categories":["06_族氏方国"],"year":2021,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2021.04.011","pages":"87-91","volume":"9"},{"id":1448,"author":"韩雪","title":"“安州六器”器主考辨","abstract":"&quot;安州六器&quot;器主为&quot;中&quot;或&quot;师中&quot;,他曾奉王命省察南国并受到周王赏赐,是昭王伐楚事件中的一位重要人物,其身份鲜见探讨。梳理与&quot;中&quot;相关的铜器,并结合史籍及相关器铭对其身份试做考证。研究认为,&quot;中&quot;或&quot;师中&quot;主要活动于昭、穆二世。昭王时期,&quot;中&quot;曾参与伐楚战争,又称&quot;师中&quot;、&quot;遣&quot;;穆王时,&quot;中&quot;继任为毛公,称毛公或毛伯遣,其为毛叔郑之子。","categories":["06_族氏方国"],"year":2021,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2021.04.009","pages":"77-83","volume":""},{"id":1462,"author":"薛铭博","title":"芮国铜器与芮国世系探微","abstract":"芮国考古方兴未艾,近十几年来不断有芮国相关的遗址被发现,其中最大的收获便是芮国国君墓地的发现与芮国带铭铜器的出土。通过将这些出土铜器与传世铜器、文献相对比、结合,可以对芮国历史有更加深入的认识。芮国自西周初年到灭亡为止,可能经历了13代国君,历时近400年,芮国地位经历了较大的起伏。其中,芮国晚期曾迁徙到韩城梁带村、澄城刘家洼地区,在春秋早期经历了由畿内贵族到独立封国的转变,最终为秦国所灭。","categories":["06_族氏方国"],"year":2021,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLPOAQMFwvH6pU1H2nMNulAzNaFYRG8hlsTcMflxDtCuebzW2Kd4pLeZhLmkJr84SlsJd8NosBJE4v93mKuSffSC6w0m7p16PyVS4AK5Pc9n6OZoxP1uTNCJSrQQP9rvDLz9EkLfMXsgPtu4BoqmRRROvUMRBMXbm6nElYCjTc5K6LCmIFkv5L&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-103","volume":""},{"id":1463,"author":"梁云; 张志丹","title":"甘谷毛家坪出土秦“子车”戈探讨","abstract":"甘谷毛家坪遗址秦墓M2059出土的&quot;子车&quot;戈,其年代属春秋中期前段,铭文中的&quot;秦公&quot;即秦穆公。墓葬的年代为春秋中晚期之际,墓主为秦国子车氏家族成员,子车氏应属嬴姓公族。毛家坪遗址可能为秦国冀县县治,M2059为该遗址级别最高的墓葬,墓主人应是秦君派驻到当地的军政长官。","categories":["06_族氏方国"],"year":2021,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCYKO487tdtyYaL95UGzpI-jk0afdH8Bbyg7Q6Wr3eaWPyRtonO8iZwPOYCX3QCaRik7vS-1baBtjYTqaGbURDbSoW41szoKaZzbSWKlRW75Ufbp4CsdYt7McTAO8aV23hME9EQ7BaIcSzUcktoaDRUxCKZ4cudKy4R94ebQzIhI3NHf1SstTq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-107","volume":""},{"id":1465,"author":"程浩","title":"加嬭编钟与楚庄王服曾","abstract":"新出春秋铜器加嬭编钟是曾侯夫人加嬭的自作用器,但铭文中自称&quot;文王之孙子,穆之元子&quot;之人并非曾侯,而是楚庄王熊侣。器主加嬭即随仲嬭加鼎中楚王所嫁之女随仲嬭加,她依靠楚国的支持在丈夫曾侯宝去世后代执国政。编钟铭文所记是楚庄王巡省已归附楚国的曾国,加嬭代表曾国燕享楚王之事。从加嬭在楚庄王面前自称&quot;孺小子&quot;来看,其人应即庄王之女。如此一来,加嬭媵器随仲嬭加鼎的作器者也宜定为楚庄王。","categories":["06_族氏方国"],"year":2021,"publication":"北方论丛","link":"https://link.cnki.net/doi/10.13761/j.cnki.bflc.2021.04.002","pages":"14-17","volume":""},{"id":1471,"author":"黄锦前","title":"岐山孔头沟出土尚爵与虢氏家族的有关人物及史事","abstract":"岐山孔头沟出土的尚爵与师■钟及姬寏母豆的&quot;■公&quot;即&quot;虢公&quot;,即班簋的虢城公,系太公之子,师■钟及姬寏母豆皆系虢氏家族器。■伯堕簋及■伯鼎亦系虢国器;鼎、簋的虢伯堕系穆王前期的虢伯,与&quot;尚&quot;系兄弟,为虢城公之子,继任王朝卿士;虢伯甗、虢伯鬲的虢伯,系西周中、晚期的虢伯。厉王时的虢仲(虢公长父),宣王时的虢文公子■、虢宣公子白,皆系在王朝任虢公者。虢仲虢叔虢季同出一源,别为支系,或为王官,或为诸侯。文献所谓虢仲、虢叔之别,其实一也,所谓多个虢国的纠葛,应重新认识。岐山孔头沟遗址或与虢国有关。","categories":["06_族氏方国"],"year":2021,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2021.03.001","pages":"46157","volume":"41"},{"id":1474,"author":"邓悦","title":"邓国媵器铭文小考","abstract":"邓国是两周时期与楚国有着密切关系的诸侯国,目前可见15件周代邓国青铜媵器出土材料,整理分析其内容及出土地点,并根据铭文拓本深入探讨铭文内容与字体风格,梳理周代邓国的政治经济文化水平以及对外姻亲关系等问题。从出土文献材料出发,结合传世文献,重新反思历史和考古,以提高全方位解读材料的辩证思维能力为目的,以邓国媵器为个例进行研究,对青铜器加以释读。","categories":["06_族氏方国"],"year":2021,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6gLPrJSlvZN9Uustv5Bzf_UgcGhzIVTZfmKeR4YHcNRs9HuprFOpkiqhovTkRMDjBnkxpTIIXDV3nnI-5xqHg87T0Btc3zCOYRpZnPk9LEFxOqBXXZvR8u80UUiiC9Me2L2HV1MaMhgqlPr8NV1ZtHcvVwZkHBQzy5GSJtPCx84EoHVywO7fM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-67","volume":""},{"id":1475,"author":"胡嘉麟","title":"上海博物馆藏京姞盘札记","abstract":"上海博物馆早年征集到一件京姞盘,其年代应在西周厉王时期。这件器物对于西周厉、宣时期青铜盘断代标准的建立具有重要意义。京氏本为山东地区的嬴姓东夷族,这件器物的铭文反映了京氏与姞姓贵族通婚的状况,对于研究京氏族群的相关历史问题具有重要的研究价值。周初东征后,京氏族群实际上分成两支。一支为京叔氏在山东地区,主要与东方国族通婚;一支为京仲氏,又称京氏在关中地区,主要与姬姓、姞姓和姜姓的族氏通婚。西周末年犬戎之乱,关中地区的畿内采邑纷纷东迁。京国迁徙至晋西南地区,在春秋早期被芮国所灭。","categories":["06_族氏方国"],"year":2021,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIesPboSYIgxMEsBTm85hIv79nsGzLhKnAxJBkIlxUrqBtF9ksvR83tdrA8pzJcLiPRSbjTqJK_R5thct7mG4V6ltZA3bR--d55QYNx53yT9pAwFFCCV3cxVfeqkpSUA9Im6ls0Czi_CxPWqaQTBZn8BVjDv2Sn-bMvWDS4qsvQN9mTIXWK9JkW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-110","volume":""},{"id":1490,"author":"王红星; 卢川; 孙建辉","title":"曾侯世系辨正","abstract":"根据最新考古发现资料,对曾侯墓葬的规模、礼乐器组合、曾侯自铭等现有曾侯实物史料进行全面梳理,确认迄今为止已发现15位曾侯、4个曾侯墓地,并发现其间有一定规律。曾国历史时间框架,早自西周早期,延续至战国中期。曾国主要时段的政治中心,均在今随州市境内。","categories":["06_族氏方国"],"year":2021,"publication":"长江大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzin9K-gGy80-bV9r_9tbq-7QGklQ0uTWwgiN4BXG6FW6wuA9TL4EaRCsb7cpj1YTQg-GewhThB5mVYxjTK5x4Gxivo-rnrTyoBJne3vkzTxZz6O4tcHRkmeLnAyMMOcplM-JpjsP8OpMkWcQ93eS8A9t70uzaKH5Y6QWKpqNZXXY5op0JBrV1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-51","volume":"44"},{"id":1505,"author":"叶先闯","title":"周代二密史事探论","abstract":"周有二密国,一为西土密须,一为畿内密。二者族姓、地望、政治进路迥异,一度并世共存。泾上灵台姞姓密须曾遭文王攻灭,而于其故地另封姬密则系乌有之事。共世密康公即为姞密后裔。畿内密与周王同姓,政治进路以出任王官为常,密伯供职于成周,协助周王巡守并控御外服诸侯,于河南密县领有封国,密叔则于宗周王廷出任高级军官且任册命傧右。透过畿内密大小宗于王室任职经历,似能看出周制世卿世禄外,仍有一定建官用贤功能。","categories":["06_族氏方国"],"year":2021,"publication":"中国典籍与文化","link":"https://link.cnki.net/doi/10.16093/j.cnki.ccc.2021.02.007","pages":"59-68","volume":""},{"id":1523,"author":"胡子尧; 井中伟","title":"周代申国考辨及其相关问题","abstract":"一、问题提出两周之际的申国因曾参与灭周及拥立平王等重大政治事件而备受史学界关注。但历代文献中关于申国地望所在有着不同记载,这便给学界探讨与申国相关的历史问题造成了极大困扰。少数学者认为周代仅有一个申国,或认为申在南阳[1],或认为申在信阳[2]。","categories":["06_族氏方国"],"year":2021,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIkvNwQUMT0BJeXI6q8nrRi-AY52zlZzQNnqpSLDalMDgSJInFE6Rm6XBleDtmT1BpvE-I5CHGfRGuNB1o7A2ZQAbkekwfWlea_HFM0jHaDXGmkC1MqdclJXz2cTmLNfamsp-hiS7d8YEhZUbVdSXJfdgryMWIe0YtCQOC5BC6aI6BIvZnp7a3m&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-96","volume":""},{"id":1546,"author":"王祁","title":"邢侯簋“州人、重人、庸人”新释","abstract":"西周成康时期邢侯簋(《集成》（1）4241)有铭:&quot;王令荣内史曰:‘井（邢）侯服,赐臣三品:州人、重人、庸人。’&quot;这是研究者经常引用的一段话,十分重要。关于&quot;州人、重人、庸人&quot;,学术界或认为州、重、庸是三种氏族,（2）或认为州、重、庸是三个地名。（3）《左传》隐公八年:&quot;天子建德,因生以赐姓,胙之土而名之氏。&quot;（4）地名与氏名往往联系密切,&quot;州&quot;&quot;重&quot;&quot;庸&quot;为氏名或地名,并无本质差异。","categories":["06_族氏方国"],"year":2021,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJY7-6akB8_9yu31_rP-q0Wn95zpQrzTmX5iG2Oxkfh84Xu3i-OlxLvZIogLSfT6x49cIvn1fSWLyluv5Q56MY3bLFj_anvu0yFwCkfTkP9zk9VIKY30KjPHE75nPWRGLSJVssdxNQGJp-qtQ5Ot1OAe1HbqxUGaj4f0lWLVUwsSUt0Cx_-PK-D&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-56","volume":""},{"id":1550,"author":"柯圻霖","title":"论王孙遗者钟的国别","abstract":"王孙遗者钟的国别问题一直以来都有许多争论,学术界有楚器说和徐器说两种观点。文章针对其国别问题从形制、纹饰、铭文字体和内容等方面展开讨论,同时把王孙遗者钟与楚器和徐器在这几方面都做了比较,发现王孙遗者钟不管是在形制纹饰还是铭文字体和内容都与徐器十分相似,因此,王孙遗者钟应定为徐器。","categories":["06_族氏方国"],"year":2021,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgfyZiCkkRstnRKNhM5v1q_oRz-HLmOV8LxjR2P9HLpR3SZtp2oOHoIQDqO4D1cRBT0Nz1Q4FKjcjpzjDnjxmk9IGi4_8S4AQPxBXmpCwHPoRTlWJAeebkK6HKTgZsnJpPCJafiPreb2yDg7C6oGaWsjYqT3sQ4qGx020fcKpgDmzEs5egG3ir&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-33","volume":""},{"id":1557,"author":"金方廷","title":"从西周同姓诸侯国看周王室的宗族分化","abstract":"周王朝在西周时期分封了大量驻守地方的诸侯国,这些诸侯国的家族中有不少与周王室同为姬姓,且据称这些姬姓诸侯国宗族均为周王室的分支。结合出土文献和传世文献中对这些诸侯国宗族谱系的记载,可以看到西周时期的同姓诸侯国往往并非直接从周王室分化而来,它们往往源于已经从王室分立出来的分支宗族,如周、召、毕等生活在王畿地区的世族。同姓诸侯国在政治和礼仪等级上通常逊于王畿地区的世家大族的现象,或许正和这些诸侯国在姬姓王室宗族中的地位有关。","categories":["06_族氏方国"],"year":2021,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.issn1002-3828.2021.01.11","pages":"85-94","volume":""},{"id":1562,"author":"曹斌","title":"胶东铜器与西周纪莱","abstract":"光绪二十二年(1896年)即在胶东半岛的龙口鲁家沟出土有西周铜器,由于文献早有龙口归城为周代莱国都城说,近代以前学者多据文献支持此说。随着胶东半岛东西两侧铜器的不断发现,特别是一些涉及国别的铭文铜器的出土,学界对于胶东西周封国的认识出现分歧,","categories":["06_族氏方国"],"year":2021,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPy8jiA-_NDNvdrCYkoDhXR2leW_TICFSmYqbUVtE7ORzcFks-pvZ-551pt3VX2Wxwh0CSttoglSJTjThdpGzHIL5PX9JCKPtr-Qr569V_8hzUDDi1l9fXfHNe0xF5W9GsIhlZ7mBaOMqZB19QAh3YTJJiqYYPhmUsC65ccEuaNxUR558j_LpD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-89, 127-128, 90-99","volume":""},{"id":1565,"author":"王晖; 姜春萌","title":"周原出土昔鸡铜器与昔氏分封诸问题考证","abstract":"周原出土的昔鸡爵铭,昔鸡作为周王后宫负责传达王姒之命的宰官,在联姻活动中既起到了传命并护送艿姞前往韩地的作用,也是代表周王室以及媒人王姒介绍的重要角色,并且获得韩侯的厚赐。《风俗通义》中记载西周有周大夫封国而昔氏的氏姓出现,可与昔鸡簋等铜器铭文中所记载的内容相印证。可证周大夫受封采邑而有氏的事实确实存在,而且可知是在西周早中期之际的昭穆时代,到春秋时宗妇鼎中的国已经称为昔国,是西周早中期之际周大夫初有受封有土获氏的重要证据,填补了这一学术问题的空白。","categories":["06_族氏方国"],"year":2021,"publication":"宁夏社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLMS96hmzjiRWhXsnT7RrTqx2YQFc1WalpOSRCceILuv-HQ_24dgHJmiO9T_uiXi5MlGuHyns3g_uGe2uC0nPW4p21Atbc-wgbIWYDx-XRURL-Q6NQSnS02F47ZNiDJENm1gRRb7np9bin13ThYlC87B-kuAUbQn3kR59DHrYYOraoKuVTSxEh_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"189-196","volume":""},{"id":2584,"author":"张鑫; 袁俊杰","title":"山东沂水纪王崮春秋墓研究","abstract":"山东沂水纪王崮春秋墓的墓葬规格高,随葬品丰富,为研究海岱地区春秋时期诸侯国历史及其文化面貌等学术问题提供了珍贵的实物资料。本文基于对相关的考古发掘资料和金文资料的整理,并结合相关文献记载,通过对山东沂水纪王崮春秋墓的出土器物、丧葬制度、墓葬国属等的系统分析,得出以下几点认识:一、山东沂水纪王崮春秋墓的器物,一部分在造型风格和形制特征上较为复古,同时又有部分器物则反映出明显的春秋晚期的特征;铜器纹饰图样丰富、种类多变,以龙纹居多,在不同器物及器物的不同位置所使用的主体纹饰也有所区别;主体器物组合与春秋晚期以来的器物组合变化趋势相一致,由形制特征、纹饰特征以及器物组合,综合判断墓葬年代应在春秋晚期偏早阶段较为合适。二、山东沂水纪王崮春秋墓在丧葬制度上与中原地区基本一致,但在部分习俗上显现出明显的本地特征。棺椁制度、器用制度的随葬品组合、车马制度,与中原地区有着较高的相似性;但与此同时,器用制度","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27114/d.cnki.ghnau.2021.001543","pages":"","volume":""},{"id":2602,"author":"何林萍; 熊贤品","title":"曾公(田求)编钟铭文及其相关问题研究","abstract":"2019年随州枣树林贵族墓地M190出土的曾公(田求)编钟,丰富了曾国的考古材料,铭文中的内容涉及曾国的始封、世系与铜器断代里的康宫原则等问题,为研究曾国历史文化提供了重要的信息,该编钟铭文内容揭示了 M190的确切年代,大致可以将春秋中期曾公(田求)、曾侯宝、曾侯得三位曾侯的年代序列排列清楚,填补了春秋中期曾国世系的空白,推动了曾国历史文化的研究。目前已经有众多学者就曾随之谜、族属、曾国世系等历史文化问题进行过深入的探讨,对于曾随之谜、族属问题已经基本达成共识,现在曾公(田求)编钟铭文揭露了曾国始封、世系等历史信息,并且可与同墓地的嬭加编钟、曾侯舆编钟铭文内容相互印证,可以进一步推动曾国历史文化的研究。本文采用文献法、二重证据法,结合传世文献、考古材料以及曾公(田求)编钟铭文内容进行研究。文章共分为五部分,主要内容如下:第一章是绪论,说明本文的研究意义、研究内容、研究方法及研究现状。第二","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27137/d.cnki.ghusu.2021.002912","pages":"","volume":""},{"id":2606,"author":"熊帅; 鄢国盛","title":"西周倗国研究","abstract":"倗国是西周时期的一个封国,该封国在传世文献史料中没有任何记载。2004年在山西省绛县横水镇发现了倗国墓地。倗国墓地中出土了大量可以提供倗国信息的文物,主要有青铜器、陶器等,其中倗国国君夫人墓中出土的荒帷是最为重大的发现。倗国墓地发掘前后都出土了大量与倗国有关的器物,这些器物上的文字、图案从各方面反映了倗国的原始面貌和西周时期的政治社会情况。倗国是赤狄的一支,媿姓倗氏。倗国早期居住在黄河周围,之后迁徙到晋南,原为商代封国,周文王东征之后为西周建国立功并被重新分封在晋南。倗国文化受到商周两族的影响,并结合了自身文化特点。倗国与大量周的同姓联姻以此来维系自身地位,与周边的封国,特别是晋国存在合作或交战。倗国因晋国曲沃小宗扩张而在春秋时期的曲沃灭翼前夕被吞并。","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27212/d.cnki.glnsu.2021.001258","pages":"","volume":""},{"id":2612,"author":"吕海路; 王青; 路国权","title":"三邾青铜器及相关问题研究","abstract":"本文所说的三邾指周时活跃在鲁南地区的大邾、小邾(或称郳)和滥三个东夷古国。周武王封侠于邾,邾国始封。至西周晚期,先后封友(肥)于郳,封叔术于滥,至此邾分为三。三邾在漫长的历史中创造了较为辉煌的青铜文明。目前共收集到三邾青铜器570件,数量多,器类丰富,年代多集中在西周晚期至战国早期之间。这种材料的相对集中也造成了各器类之间缺环较多,三邾铜器的谱系目前仍很不健全。从文化构成上看,三邾铜器不管在形制、纹饰还是组合上都受到中原地区的强烈影响,表现出浓厚的中原特色。春秋中晚期以后受南方楚、越文化北上的影响,部分铜器在形制和纹饰上也表现出楚式、越式铜器的特点。除此之外,山东本地特色和风格的铜器也是三邾铜器的重要组成部分。其中B型鬲和B型罍目前在三邾地区发现较多且年代最早,可能为邾族群首先使用的器物。最后本文还对三邾铜器涉及到的邾君世系、墓葬形制和疆域问题进行了讨论。","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27272/d.cnki.gshdu.2021.005575","pages":"","volume":""},{"id":2624,"author":"高长浩; 谢乃和","title":"甲骨金文所见?族及?国考论","abstract":"?国见于甲骨金文,是绵延商周两代的古国,时间跨度较长,相关?器亦有多处出土地,因此学界对?国相关问题的研究一直聚讼不断,近些年来仍有不少学者提出新见。笔者在前贤研究之基础上,考证相关出土材料,结合传世文献,从?国族源、?国史实、?国地望、?国是否为佚记古国等四个方面,对?国相关问题加以探讨。第一部分主要考察?国之族源。通过对“其”“”“?”相关卜辞及“亚其”“亚”“亚?”类诸铜器重新分析,得出如下结论:?族应源于商代的“其方”,“其方”首领被商王任命为“亚”,称“亚其”。在祖庚、祖甲之时名为“”的“其侯”成为商王之贞人,同时担任“亚”职,称“亚”。或因“亚”之功劳颇大,“亚”之后人发展为氏族,在铭文中署“亚”以标识其出身。“氏”中的一支沿袭“亚其”之名,称“其亚”或“亚其”,继承“其侯”职位的一支“氏”则称“其侯亚”。“氏”中还有一支或被商王新封于“?地”,从而分化出“?亚”“亚?”,称“","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27011/d.cnki.gdbsu.2021.000493","pages":"","volume":""},{"id":2625,"author":"刘晋; 张利军","title":"新出金文所见周与霸关系考","abstract":"霸,不见于文献记载,是先秦时期晋南地区重要的狄人国家。自2007年山西省翼城县大河口村西周墓地被盗掘后,山西省考古研究所对此进行了抢救性发掘。霸国墓地出土的有铭器物多且长铭较多,霸伯盂铭文详细地反映了西周时期的王聘诸侯礼,霸伯簋铭记录了西周王室对河东盐业的管理,兑盆、霸伯盘、格仲簋等青铜器铭文表明霸对周尽有搏戎、抵御淮夷、捍卫国家安全的职责。过去学者对于霸国问题的研究主要集中于以下几个方面:借助霸伯盂铭文探讨周代聘礼;对霸国性质的研究;霸对外关系的研讨。学者取得诸多丰硕的成果,对于周代王聘诸侯礼、狄人礼、独立个体霸国的对外交往有了较为全面的认知,但学者们对霸的性质仍有“怀姓九宗说”和“媿姓狄人国家说”之争,故而霸国问题仍有探讨的空间。本文主要从以下几个方面展开研究:首先,探讨霸国的源流、沿革以及霸伯的政治地位问题。翼城县大河口墓地存续时间,上溯西周早期下至春秋初年,故而霸国可能是周初统治者","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27011/d.cnki.gdbsu.2021.000482","pages":"","volume":""},{"id":2626,"author":"徐策; 谢乃和","title":"文献彝铭所见周代的尹氏家族","abstract":"周代是“家族社会”发展的重要时期,从某种意义上来讲,世族的兴衰变化已经成为周代政治体制变迁的缩影。从世族发展的角度看,两周时期社会政治格局变迁的总趋势是王室政权由盛转衰,王朝卿族由于自身实力的提高,经历了由依附王权到秉持国政的转变。尹氏在商周鼎革之际投靠周王朝,入周之初便依附王权,凭借专业文化素养成为王近侍之臣。其地位经历了由小到大、由殷商旧臣向周之卿士的转变,在幽王时期甚至权倾朝野。降至东周,在周王室实力衰败的大趋势下,尹氏也不可避免地走向衰落,后因参与王子朝叛乱最终覆亡。尹氏家族的兴衰这一个案实蕴含丰富的政治蕴意,秦汉以降如《汉书·楚元王传》等文献皆引用尹氏盛衰事迹,以作时人鉴戒。本文通过梳理传世典籍和出土铭文中有关尹氏家族的相关记载,对尹氏家族做一个较为系统的论述。全文除了引言和结语外,分为三个部分。第一部分通过对尹氏起源和世系问题的探讨,试图还原尹氏家族的世系传承。第二部分,按照尹","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27011/d.cnki.gdbsu.2021.001049","pages":"","volume":""},{"id":2631,"author":"黄端胜; 雒有仓","title":"西周金文族徽初步整理与研究","abstract":"西周金文族徽是研究西周家族形态、社会组织结构、族氏迁移流动、文化习俗以及民族融合等问题的重要参考资料。但由于材料的零碎分散、考释的繁琐复杂和铜器断代的不易等原因,尚无对西周金文族徽进行全面整理与研究的论著出现。鉴于此,本文对2019年12月前(部分资料的时间下延至2020年)所见的西周金文族徽进行了较全面的整理与研究,以期能对西周有关族氏的迁移流动、地域分布、相互关系以及兴衰变化等历史问题研究提供帮助。全文主要由以下几部分组成。在绪论中,我们对西周金文族徽的概念进行了较明确的界定,以避免产生歧义;对西周金文族徽的研究概况进行了回顾与总结,指出了西周金文族徽的研究成果与存在的问题。在此基础上,我们探讨了本论文的研究方法,指出了本论文的研究意义、创新点与不足。第一章是西周金文族徽的分期整理。该章主要按照西周早期(分为“西周早期或商代晚期”与“西周早期”)、西周中期、西周晚期三个时段对西周金文族","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27699/d.cnki.ghbmt.2021.000091","pages":"","volume":""},{"id":2638,"author":"陈鑫远; 田成方","title":"黄国历史文化的考古学观察","abstract":"黄国是先秦时期淮水流域重要的古国。前辈学者关于黄国的专题研究成果丰硕,但尚有不足。近年来考古工作者在信阳地区做了大量工作,发掘了一批关于黄国的考古资料,为综合研究黄国历史文化提供了契机。本文通过全面梳理黄国的考古材料,结合文献记载,考察黄国从在淮水立国到为楚所灭的过程中,黄国的考古学文化、国族兴衰、历史地理等情况。正文共分为三章。第一章主要就黄国的疆域、城邑、聚落等方面展开探讨。考古资料表明,黄国疆域北以淮河为界,南抵大别山北麓,西至罗山高店,东及老李店磨盘山,主要包括今河南信阳的光山、罗山、潢川等地。黄国城邑方面,黄国故城和高店古城是黄国最重要的两座城邑,其中黄国故城是都邑。黄国故城平面呈长方形,大型建筑基址集中在城址南部及西南部。两周之际开始修建,延续至战国晚期还在使用。高店古城则是黄国傒氏家族的封邑。黄国聚落多沿浉河、小潢河、白露河、潢河、寨河、竹竿河分布,主要选择在淮河支流两岸的平","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27466/d.cnki.gzzdu.2021.004946","pages":"","volume":""},{"id":2642,"author":"简敏; 田成方","title":"鄀国青铜器及历史地理研究","abstract":"鄀国是商周时期的古老国族。传世文献中关于鄀国的记载较少,殷商时期的若族资料更是匮乏。学界主要依据鄀国青铜器以及简文材料对鄀国的历史地理文化进行专题研究,但缺乏系统的资料收集和综合性的探研。本文收集整理了鄀国青铜器材料,结合鄀国文献材料及近年来学界的研究成果,进一步探讨鄀国铜器的文化特征,族属及历史地理等问题。全文共分为三章。第一章首先就鄀国青铜器进行类型学研究及分期。鄀国铜器共分为三期,第一期的年代为商代晚期至西周早期晚段。第一期典型器类有鼎、簋、方彝、爵等,主要以食器和酒器为主。一期铜器形制、纹饰和铭文风格不仅带有殷墟四期铜器特色,还具有典型的姬周文化特色。第二期的年代为西周中期晚段至春秋早期晚段。这一期形制和器类虽与第一期相比变化不大,但铭文字体上产生变化,如这一期铜器的铭文字体开始变长。第三期的年代为春秋早期晚段至春秋晚期晚段。这一期的鄀国铜器较前两期来看,已发生根本性的改变。例如器","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27466/d.cnki.gzzdu.2021.001037","pages":"","volume":""},{"id":2655,"author":"万冰冰; 严志斌","title":"出土族氏铭文所见殷墟族群研究","abstract":"本文通过对殷墟遗址范围内出土的族氏铭文进行统计和梳理,分析殷墟族群的构成和性质,进而对商代晚期殷都的社会结构、聚落形态、家族结构、族群分布以及族群关系等内容进行研究。绪论中,对本文涉及的特定的词汇和概念进行说明,对族氏铭文和殷墟族群的研究史进行了回顾,并提出本文的研究目的和内容。第一章对出土于殷墟的族氏铭文做了系统的梳理,结合甲骨卜辞等文献,对殷墟所见族群做出了整理和分类,区分出居于殷墟的族群90组(106种)、非殷墟族群5组,以及私名12种,并对族群的性质、延续时间合地域分布进行了逐一分析。第二章着重讨论殷墟族群之间的关系。同墓共出的殷墟族群15组,族群之间的关系主要有婚姻关系和赠与关系;复合族氏铭文中所体现的族群关系9组。复合族氏铭文所体现的关系主要分为四类:族群联合、母族与支族的关系、婚姻关系和共同作器关系。第三章,对18组活动于殷都内和外服方国族群之间的关系展开分析,认为其主要关系","categories":["06_族氏方国"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27642/d.cnki.gskyy.2021.000003","pages":"","volume":""},{"id":2919,"author":"陳光宇","title":"夷方無敄與古越人名","abstract":"晚商作册般甗銘“王宜夷方無敄咸王赏作册般貝用乍父己尊來册。”學界對其銘“宜”字含義以及銘文如何斷句的問題有不同見解，以致影響對該甗銘文反映史實真相的認知。考量“宜”及“無”二字在卜辭、金文的用例，“無敄”以及族徽“舉”見於無敄鼎的事實，筆者比較諸家論述，認爲所有相關資料均指向“無敄”是夷方首領的結論。作册般甗的形制大小與殷墟出土兩個盛有人頭骨的銅甗極爲相似。作册般甗記述時王以夷方無敄進行宜祭，該甗可能與處置作爲人牲的無敄有關。金文以“無”作人名詞頭的例子多達15位，其中如無需、無土等人物與東夷有關。《吴越春秋》記載越國君王有無餘、無壬、無顓、無强等諸人。基於古越語與侗台語、古泰語的聯繫，語言學家對古代吴越人名、地名的取名原意多有新見。夷方無敄取名所用的“無”字或與古越語作爲尊稱“無”的漢字記音有關。","categories":["06_族氏方国"],"year":2021,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXze-_aT63stZScFBYxoHNvj0CBQmZ1CkVsG1iRz9fRupdrWjFS5C58IhuuPQAbmh5d4I2YyF_YO9q5lkZ8LPu9eGnWIJZSS2AGCFUcQUTx7VasBMew52g4kQ34i_TukzGmhLBpa4i0ufajcay8wGGBrAnBuXkYeo9Hddt5ZqemA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"325-334","volume":""},{"id":2920,"author":"高晋南","title":"我方鼎銘文與青銅器亞類族氏銘文的文化内涵","abstract":"“官爵説”和“宗法關係、小宗説和次一級氏族説”是學界理解金文“亞”字影響較大的兩類觀點。參考卜辭，對讀我方鼎銘文和亞[若]族氏器銘，可以確定“亞”字内可以銘入多位接受祭祀的男、女祖先稱謂，這一現象不能用上述兩類觀點合理解釋，但却暗示了“亞”字與祖先和祭祀的聯繫。在字形上“亞”字與商人祖先廟、陵墓平面圖相似，於卜辭和文獻中也有“廟”義。因此，商末周初盛行的“亞[某]”族氏是商人在祖先崇拜和交感巫術觀念影響下將原有族氏、祖先私名或各類稱謂銘入“亞”字形成的。而殷墟二、三期“亞某”、周代早期的“亞某”在時代、結構、内涵上都與“亞[某]”不同，應該區分理解。","categories":["06_族氏方国"],"year":2021,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ681cfB2-jrOasly0Wbjti6C16V0u0FXdePLv7WHh8A0OaJJ0mvX1S12V7p29U2vB4mqLIbNjtq2a9on0Kz50gt3AT0cimW6IMu4dOCCEKj88TUSpFnAT-CABnJ67Lt3U6emCrlTHn9wio5-mm3zUyEGExCAezvXW4qK1PZIRHNw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"335-348","volume":""},{"id":2921,"author":"陈光鑫","title":"新出(彡兄)盆铭文补释","abstract":"山西翼城大河口墓地M6096出土一件青铜盆。本文考证,铭文中的&quot;应伯&quot;是一代应国国君,而且可能是河南平顶山应国墓地M95墓主人应侯敔的孙辈或重孙辈。","categories":["06_族氏方国"],"year":2021,"publication":"北京史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJfrXjDGIt7QwjdD-2aWLRYk-axb7PORVzWG_1SZWdUGXevfCgr-eF24e_Hzj54qRHBiPGfmRlQ-XvCkEUzKDJ5lw4sRZl2NeMedq6dmhtZKs3s5xptHedFS8Xq4sJKCnvBbuXNKZQGDe5qgYQ8uyzUgUsd5MRisAfPoR39vRqeMQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-77","volume":""},{"id":2926,"author":"陈光鑫","title":"周初燕国殷遗民考","abstract":"西周初年,燕国殷遗民多是商王朝贵族后代,与商王朝权力中心关系密切,应该是随周人迁入燕地的。燕国是在周人和殷移民的共同努力下建成的。在北京早期历史上,殷商文化功不可没,不仅限于社会下层,燕国统治者也深受殷商文化影响,以至于召公家族同样深受商文化影响。这有助于理解召公家族墓地与青铜器铭文带有明显商文化特征,更为解开召公的身世之谜提供有力证据。","categories":["06_族氏方国"],"year":2021,"publication":"北京史学2023年秋季刊（总第18辑）","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2021.082610","pages":"278-291","volume":""},{"id":2947,"author":"雒有仓; 阴玲玲","title":"夏人后裔国族铜器族徽与所见族群融合认同","abstract":"青铜器铭文记载的夏人后裔国族主要有杞、虎、费、鄩、繁、戈、辛、山、■、鲍、薛、史、苏、番等15个,所见姒姓族徽有辛、虎、■、山、戈、■、史、■八种。夏人后裔与商族的融合主要表现在族徽、日名以及丧葬习俗上的文化认同,而与周族的融合更多地表现为通过族外通婚实现彼此血缘上的融合与认同。夏商周三族融为一体约在春秋时期,最明显的标志就是代表血缘关系的族徽最终消亡,这是华夏族自我认同最终形成的一个重要标志。","categories":["06_族氏方国"],"year":2021,"publication":"中国区域文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJimUJuHkSHJB1V-fw2fLTs5JYJNwrTUltIpFasQQdFivuVJslWJN-_GYuvttXtt2HCiEb2A92tq4bDGCPYTpt2BvWL3_qpw5uF8lV8VV6OMR5WApg7hdARCBsgVg6wTsbzhDohQuub2AV3QIhhMwiLr2GMg4Ik1z5lh723LaRmAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-75","volume":""},{"id":2948,"author":"黄锦前","title":"新刊唐侯作随夫人诸器及有关问题","abstract":"唐侯作随夫人鼎、壶、随仲嬭加鼎、加嬭鼎、簋及传世的王子申盏盂盖等,皆系楚共王时或稍后器,&quot;随仲嬭加&quot;&quot;嘉嬭&quot;&quot;加嬭&quot;系一人,为楚共王之女,王子申之姊妹;随仲嬭加鼎、加嬭鼎及王子申盏盂等系楚共王和王子申为其所作媵器;加嬭簋系其生前自作器或葬器;唐侯作随夫人鼎、壶系唐惠侯为随夫人之丧所作赗器;该组器所自出的墓葬,其墓主为随夫人,即随仲嬭加,系曾侯宝夫人。阳飤生诸器及阳小叔父鼎的&quot;阳&quot;皆应读作&quot;唐&quot;,系姬姓唐国器。传世的叔姬鼎(金父鼎)与阳小叔父鼎铭可互勘,系同人之器,前者文字多误摹,阳小叔系唐国公室;参照传世叔姬鼎可知,&quot;阳小叔父&quot;应系其即位之前作为公室时的称谓,即位后称&quot;阳伯&quot;。郧县萧家河、乔家院等地出土的唐子诸器器主应系唐国公室,其出自楚墓,系楚灭唐时","categories":["06_族氏方国"],"year":2021,"publication":"西部史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKU0st6De0vx3eInqH6vPG3PwozZTQ6gPLP_tt5o2y9g7rLflh7j2jMg7nmLQ2LbPzlWU9EGl9Uek6sgEj6qsH2smwp7CUDCFpDm3itr5wudA-p1SOrdAkFoTk8BtMBTjBwiFdju9hdf1Q3bvNJg7Z39Zt2GQpeG3aAdwYLDxdy7w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46095","volume":""},{"id":2960,"author":"张天恩; 刘锐","title":"春秋早期关中周余民及文化遗存浅识","abstract":"《史记·秦本纪》所载:“十六年,文公以兵伐戎,戎败走。于是文公遂收周余民有之,地至岐。”讲的是公元前750年,作为周平王分封诸侯秦襄公的继承者秦文公,伐戎获胜后占据了关中的岐山以西地区,也接收了周平王东迁洛邑时滞留于关中故地的普通民众和贵族,被称“周余民”。这一段话涉及秦人在关中立足、发展的重要问题,故研究早期秦史的论著中常被引述,①但对“周余民”及其考古学文化的说明却基本不见。究其原因,是过去关中地区两周之际的考古资料发现过少,","categories":["06_族氏方国"],"year":2021,"publication":"陕西历史博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyC6Sl9iwokv1nCFavQrFD8BeK7Xeu5KFmna8cheK7lee5uFadPbYpTIxEzmliE_t3STfIxHPKVyLTwtQ8hM9iUHLPf3tA-CfQo8fLDfqRfVa-Vtt1Oz_RWKIHDKr-MUHEq5EW7OefzYOQroG2Mm4ATppxM_gAWaInwfusUpqHOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-56","volume":""},{"id":3693,"author":"","title":"神秘消失的噩国，在上博揭开历史迷雾","abstract":"你知道有一个已被遗忘的噩国吗?这个长久以来不为人知的古国,却在青铜器铭文中不经意留下鸿毛鳞爪,等待后人发现。在古老的史书里,记载了这样一个发生在商代的故事。文王、九侯(鬼侯)、噩侯在商纣王时位列三公,地位显赫。九侯之女被献于纣王后惹怒了纣王,九侯也因此遭受醢(hǎi)刑(剁成肉酱)。噩侯于是向纣王进谏,被纣王&quot;脯&quot;(做成肉干)。","categories":["06_族氏方国"],"year":2021,"publication":"艺术品鉴","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIoL_YmnZjaugNNe-GBfPpkBjCEgljX0zmrpgxMMM5ZfsmVYILXY3gr8BkiF0l5Hsj1UNAC2dlG7RwvAxylh2v4n-LRt-YTN4Z-q3qtJiD0eMg6SrqWOXfSIJgFvSR7iA2D1AZtckf4Odz825UVHrs3EY5HPwgQQrM_4t-R3bxZb3d1NoRphR_S&amp;uniplatform=NZKPT&amp;language=CHS","pages":"171","volume":""},{"id":1588,"author":"耿超","title":"戈亳册父丁簋与复合氏名","abstract":"河北大学博物馆收藏的戈亳册父丁簋,应是著录于《商周金文录遗》中的第131器。戈亳册为复合氏名,戈为族氏名号,亳为地名,册为官职名称,此复合氏名是族名+地名+官名的形式。戈亳册父丁簋的发现对商代晚期青铜器与族氏铭文的研究有重要意义。","categories":["06_族氏方国"],"year":2020,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsp70xpJ_hB_yJjRiaogv8fqEDpuux8IgXwJmu9om4OW1wdXRooU0dtMjTiy4BPQZaVwlR92reMr10rIFUCmQjj4tq6d8vvEzBazmKppFrrdEZspL65ahAVTCKoeCaGliZuH0-mU6iEFX3T4vBRyfhBjmkaVNGkwRgxv8qgGwm25cL30p-2v1a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-92, 114","volume":""},{"id":1622,"author":"徐世权","title":"辽阳博物馆藏战国铜鼎的国别及其刻铭“枳成”新考","abstract":"本文从铭文刻写风格、鼎的形制以及铭文释读等三方面对辽阳博物馆藏战国铜鼎铭文的国别加以考订,提出其应该为战国中晚期魏国所铸刻。铭文中以往读为&quot;相成&quot;或&quot;宛城&quot;者当释作&quot;枳成&quot;,即魏国重要的交通要塞&quot;轵&quot;县。","categories":["06_族氏方国"],"year":2020,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJwnxbye2jvjpO-Lojgl4hD-W9-AnQOBhxLNLn75YR1ZxmzdFuNChpb_R5wUAXOlHgGs8coBrff2xFkJXfIPADCwOoECY-oYp5BuZw_pVENXNanJkEgPxF6atFmTE2jcLpVrkqEm_iP34hE-eFIXmyZaiUWrFcwStEEpITOxrcHbsv8TvL0LmJb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-63, 156","volume":""},{"id":1627,"author":"高长浩","title":"甲骨金文所见■族考论","abstract":"商周时期的■器有多处出土地,这使学界关于■族、■国地望的讨论趋于复杂。笔者从■器出土地、■器铭文特点来分析,认为■族是殷代强宗,周初一支迁至燕地,一支迁至宗周附近。其中,西周晚期迁至宗周的■族再迁至今山东烟台,成为姜姓■国,至少在战国早期依然存在,&quot;■侯&quot;&quot;■伯&quot;之称在礼仪上应该存在某种程度的差异。","categories":["06_族氏方国"],"year":2020,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2020.02.004","pages":"21-29","volume":"41"},{"id":1630,"author":"韩炳华","title":"新见三件“叔休”器及相关问题","abstract":"本文通过研究追缴回来的三件&quot;叔休器&quot;和见于著录的五件&quot;叔休器&quot;,判断目前所见所有&quot;叔休器&quot;均属同一器主。叔休可能为春秋早期管理当地盐业贸易的职官,身份地位均较重要。同时结合铭文内容等认为&quot;叔休器&quot;可能来源于淮河流域信阳一带的周代诸侯小国&quot;冠&quot;。冠、番、樊等可能是被淮河以外诸国称&quot;繁&quot;的不同小国,它们位于淮河流域信阳一带,在商周时期盐铜贸易环节发挥了重要作用,逐渐形成盐铜交易枢纽&quot;繁阳&quot;。","categories":["06_族氏方国"],"year":2020,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqembJyhrqIj6aPtyZV5W_FDbQyB0bzCM40euWvfvK-fRRqQG5yMbUVeoOPtwSd6rPl5cB0N_3wOYNwFWPE0qEmRFZvyKRlNVN8RgBUhn-eSK9PR68H7WkioI7puq_huppK9wBLm_OP0l_0TYV96IcbsdK3xRKsQhToTfKSfH_j-c5DBvneFYp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-82","volume":""},{"id":1639,"author":"徐玉凤","title":"虢国有铭铜器所见人物考述","abstract":"虢国是西周初年分封的姬姓诸侯国。有关虢国的史料记载多有抵牾,学术界也难辨真伪。传世和近年考古发现了多批虢国有铭铜器,为研究两周时期虢国历史与文化提供了切实可靠的实物资料。文章将传世与近年来出土的有关虢国有铭铜器汇集在一起,根据铭文中涉及的有关人物进行分类、分组、断代,并对史事进行考述,以期对两周时期虢国历史发展和文化风貌的认识更接近其原貌。","categories":["06_族氏方国"],"year":2020,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0Z4NDOzqATLpHMQJxsRjPbVPcXxQMqIQsvY2ndj0kMkmjnyrZLjTtItMiDxfYbrw48OLwR9AH5U2mHwHUZZC8Yj0I1eyFDE2qO9L9My5eFSl4uN-QKXJQ0nsEtESw9NIuwGvrr-fy36boTq7pVAI6GmulD92KGjk1bCCwDoGjS61R00PNubqA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-17","volume":""},{"id":1651,"author":"陳絜","title":"郳國墓地所出畢仲簠與殷墟卜辭中的畢族","abstract":"山東省棗莊市東江古墓群M2所出畢仲■簠,或爲畢仲■所贈的用以助喪的賵賻之器,其他如慶艅、魯宰虤、魯酉子安母與子皇母等姻娅及族内親族成员,亦共同襄助,從而湊成4件1組的青銅簠,以供隨葬。這種助喪形式,與晚商安陽小屯M18相似。此於研究商周賵賻制度,當有參考價值。對商周時期同一墓穴中出土多族銅器現象的理解,亦有啓迪之功。畢仲■所屬之畢氏,其源頭可追溯至武丁時期,也即賓組等卜辭中習見的畢族,屬東土諸妊,它與關中畢公高之後的姬姓畢氏無關。這種異族同名現象,在商周時期比較普遍,研究者於梳理先秦族群、族系之時,須持謹慎態度,不可率爾牽合。","categories":["06_族氏方国"],"year":2020,"publication":"文史","link":"https://link.cnki.net/doi/10.19325/j.cnki.11-1678/k.2020.02.001","pages":"46160","volume":""},{"id":1655,"author":"雒有仓","title":"商周金文族徽内涵刍议","abstract":"金文族徽研究中新提出的&quot;祭礼标志说&quot;&quot;职衔称谓说&quot;,虽然对于部分族徽能言之成理,但不能用以解释所有族徽内涵。金文族徽作为族氏名号,代表着家族集体与祖先形象,承载着当时社会浓厚的祖先崇拜观念和家族情感。由于来源与构成复杂,金文族徽除表示族氏名号外,还有体现血缘关系、家族集体、身份地位以及表示族氏关系、民族认同等多种内涵。正确认识这些内涵,对于深入了解商周社会家族形态、社会结构、民族融合具有较为重要的意义。","categories":["06_族氏方国"],"year":2020,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2020.02.004","pages":"32-40","volume":""},{"id":1662,"author":"黄锦前","title":"论贾国青铜器","abstract":"本文对《商周青铜器铭文暨图像集成》及其《续编》收录的一组贾国有铭文青铜器进行了系联和讨论,认为该组青铜器当系同时所作,系贾伯、贾叔及贾子伯父为贾伯女孟姬所作媵器,年代为春秋早期前段,孟姬所适乃晋国氏,纠正了过去有关器物断代和铭文释读方面的一些错误。同时对过去著录的贾子己父匜的断代和文字释读等方面的问题也加以纠正。凡此可与文献有关记载互为补充、印证,对重新认识春秋时期贾国的历史具有重要价值。","categories":["06_族氏方国"],"year":2020,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8wAwRhC2Indu3eh92F39KBngpWjTpBVap0_Qb4dquxAw5SD6dEqhuGuTrcn5wctAfCY4ePSUo1V9UnSTj-1Dhm6sJyWUDFvoctvWiLVYje1M12WPi27RYT0PMQpDaK_kAyUToLzE3MNYpI2l0EKnfmYUJnxBI4t136TlOsH40PWgR7SgyFH5h&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-78","volume":""},{"id":1665,"author":"马超","title":"妀善鼎年代与国别质疑——兼谈箕国灭亡时间","abstract":"妀善鼎的年代或以为是战国早期,或以为是春秋早期,从该鼎的纹饰、器形、铭文字体来看,其年代最有可能是春秋晚期,或提前至春秋中期后段。该鼎的国别旧被认为是山东纪国,但是春秋早期之时这个位于山东的姜姓纪国已经被齐国所灭,金文中以&quot;&quot;为国名者尚有一个箕国,此国春秋晚期尚存,且地望与燕国临近,两国关系密切。器主自称&quot;妟生&quot;,金文中&quot;妟&quot;声之字常读为&quot;燕&quot;,&quot;妟生&quot;意即燕国之甥。从鼎的年代以及器主自称两方面考虑,妀善鼎应属于箕国,该鼎的出现也证明了箕国的灭亡应在春秋中期以后,合于《路史》&quot;春秋犹有箕、崇之国&quot;的记载。","categories":["06_族氏方国"],"year":2020,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNrbGQbvlbhPhHsIgj337exBYVZOu1Mc45Mimz4cVtKqweEv0qdhn95Zs2htQwYDNpMtKlt3zRPBhDspFHRuSTBZvS9c3fk9DX1BDfdwK3Nl8RvKDqTlT4idXgJOEkIFSzzFIu9g3LMqI-HYHVMLPScZw89waF6HsQYfC4roNd2VOTNTPtCSME&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-42","volume":""},{"id":1667,"author":"谢尧亭; 陈晓宇","title":"疏公簋续说","abstract":"2007年,在香港发现一件西周早期的青铜器&quot;疏公簋&quot;,铭文反映出很多信息。结合文献认为晋国之前的叔虞之唐存在的时间为37年,此后迁封至晋,都城由唐之鄂迁到了晋之翼,即今天马-曲村遗址一带。在疏公簋铭文的末尾有一个族氏铭文&quot;五&quot;,表明疏公属于&quot;五&quot;族,疏是其中的一个国族。结合晚商和西周早期发现的30余件&quot;五&quot;族器及铭文信息,讨论了&quot;五&quot;族的发展变迁和&quot;五&quot;族的族姓等相关问题。西周早期以后,&quot;五&quot;族铭文青铜器基本不见,说明此&quot;氏族&quot;已被周文化的&quot;姓族&quot;所取代或同化,而不再使用其族氏铭文了。","categories":["06_族氏方国"],"year":2020,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.20200407.008","pages":"78-84","volume":""},{"id":1670,"author":"唐英杰; 邹芙都","title":"甲骨金文所见庚族考论","abstract":"商代方国林立、族群众多,考证具体方国、族群的地望及史事,对研究商代族群关系及历史地理等尤为重要。庚()族是商末较为活跃的族群之一,见于甲骨金文记载。庚族与诸多族群存在婚盟、军事关系,这些族群基本分布在今山东地区,结合《左传》&quot;庚宗&quot;的记载,可将庚族地望确定在今山东省泗水县东部。庚族臣服于商,并在王朝供职,接受商王及王族的差遣;曾多次参与王朝征伐,拥有一定的武装力量。庚族在&quot;成王践奄&quot;后走向没落,姬姓周人占领了庚地,但仍沿用了旧时地名为族群称谓。","categories":["06_族氏方国"],"year":2020,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2020.02.007","pages":"66-73, 127","volume":"14"},{"id":1673,"author":"雒有仓","title":"从青铜器族徽看夏人后裔与商周族群的融合认同","abstract":"在夏商之际的族群迁徙与融合过程中,商人不仅沿袭了夏人创造的青铜合范铸造技术,而且继承和发展了青铜礼制以及铸刻族徽的文化习俗。青铜器铭文记载的夏人后裔主要有杞、虎、费、■、繁、戈、辛、山、■苏等国族,其中可以确定的姒姓族徽有■、戈、辛、虎、山、■等六种。夏人后裔与商族的融合主要表现在族徽、日名以及丧葬习俗上的文化认同,而与周族则更多的表现为通过联姻实现了彼此血缘上的融合认同。夏商周三族融为一体的标志是体现单一家族组织的族徽最终消亡,其时代应在春秋早期。","categories":["06_族氏方国"],"year":2020,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2020.02.003","pages":"24-33","volume":"8"},{"id":1683,"author":"黄巧萍","title":"黄国青铜器综考","abstract":"周代的黄国是淮河南岸的一个小诸侯国,其青铜文化以周文化为主,兼有楚文化、群舒文化、东夷文化和淮夷文化等因素,但也有自己的特色,如新形制的铜豆以及铭文中特有的嘏词&quot;霝终霝后&quot;。此外,铜器铭文反映出黄国既和邻近的汉淮地区诸侯国联姻,也和较远的山东地区有交往。","categories":["06_族氏方国"],"year":2020,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2020.01.009","pages":"52-62","volume":"41"},{"id":1684,"author":"徐熠","title":"甲骨金文所见“四单”考论","abstract":"甲骨金文中常见&quot;西单&quot;&quot;南单&quot;&quot;北单&quot;。甲骨文中的&quot;单&quot;应当解释为&quot;墠&quot;,意指商都四外郊野。&quot;四单&quot;原为地名,商周金文中的&quot;西单&quot;&quot;南单&quot;&quot;北单&quot;单独出现时一般用作复式族氏铭文,当与其他族氏铭文组合时,&quot;某单&quot;作为地名前缀,是一种公共族氏名。结合&quot;北单戈&quot;族氏铭文来看,近年发现的殷墟以北10公里的辛店遗址或即属于&quot;北单&quot;范围,以殷墟为原点、半径为十公里的殷墟文化遗址圈可能与&quot;四单&quot;有关。","categories":["06_族氏方国"],"year":2020,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2020.01.003","pages":"46379","volume":"41"},{"id":1686,"author":"韩炳华","title":"息父乙册簋及相关问题","abstract":"临汾庞杜墓地出土的息父乙册簋,器型与纹饰都很特殊,与宝鸡地区同时期器物相似,属于同一文化系统。结合商代息国研究成果进一步推定息国在武王灭商前已经归周,并迁至宝鸡一带,息国贵族在周王朝任&quot;作册&quot;职官。由于颇受当地文化的影响,息族人铸造出了这件别具一格的方簋。周初,周人为了政治需要分迁息族于汾河下游,以助晋国藩屏周室。","categories":["06_族氏方国"],"year":2020,"publication":"山西大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13451/j.cnki.shanxi.univ(phil.soc.).2020.02.009","pages":"68-73","volume":"43"},{"id":1690,"author":"陈絜","title":"商周东土夏遗与夏史探索","abstract":"传世文献中存在《史记》系统与《左传》系统两种夏史体系,二者对于夏早期历史的记载,在叙事空间上一西一东,互不相协,而《史记》系统更受世人青睐,成为后世探索夏史的主要线索。梳理和考证商周时期夏遗的地理分布可知,诸姒之族主要在今山东省境内,姻亲中分布于鲁豫间者,占相当比例;与夏史相关的地与族,亦基本分布于山东及豫东、豫东北一带。《左传》夏史系统不仅与甲骨、金文中的地理线索合辙,也与其他传世文献相关记载互洽,值得重视。对夏文化源头及夏王朝早期史的探索,海岱地区及鲁豫交界地带也需充分关注。","categories":["06_族氏方国"],"year":2020,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIiq_As8iLloKz8yudRbTjYHPu7IC0eZlbCZLaBaCsojt9N0vM9d2yJrQr-kzSVBgZqz9zoXx42ORalyws_JbTzx2w8yGlNMTgotn3lDJmginHzu_NiQzmulDI5DVlEI-MFHPWBwUMQfihdMse99JKVL1O1lF6-P7tX12ZyPPrAiXf4vaj4IywH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-67, 219-220","volume":""},{"id":1691,"author":"贾一凡","title":"命父瓶与霝父国相关问题考证","abstract":"2002年山东省枣庄市发现了春秋早期小邾国墓地,一号墓出土的命父瓶铭文有&quot;霝父&quot;二字,系金文初见。对命父瓶铭文的释读可知,&quot;霝父&quot;为国族之名,&quot;命父&quot;是当时霝父国国君的字。&quot;霝父&quot;是太昊部族中崇拜雷电、雷雨的部族首领,他居住在一高处,后人称为&quot;霝父丘&quot;。此后,&quot;霝父&quot;成为地名、国族名。霝父国君的自作青铜瓶出现在小邾国墓地,体现了以霝父与小邾为代表的东周小国为谋求生存而进行联盟的外交策略,但霝父国与当时的霸主齐国相邻,却未依附于齐,因此最终被齐桓公所灭。","categories":["06_族氏方国"],"year":2020,"publication":"河南科技大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15926/j.cnki.hkdsk.2020.01.014","pages":"84-89","volume":"38"},{"id":1695,"author":"黄锦前","title":"雌盘考释","abstract":"本文对河南南阳出土的雌盘进行了考释,认为其年代为春秋晚期前段。盘铭的&quot;蔡臧君&quot;即蔡庄侯甲午。器主雌的生活年代,应与蔡景侯大致相当,约在公元前560年前后。雌盘和蔡侯班戈等蔡器在南阳的发现,印证、丰富和补充了传世文献关于楚灭蔡的有关记载,使我们对当时的蔡楚关系等相关问题有了更清晰的认识,具有非常重要的史料价值。","categories":["06_族氏方国"],"year":2020,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL3DgnIT1vuKtrWfrd5f_s5k_8-iUYiXu4g6BtdxY-eu3hn4XrD9-It00LQ1zG0lkZRRIE9SXp3q8CnBeMYyBUE4aT8rMdbEOhngWHMEsr5DeYGJeZPU-9RLVDTb2dRfwc5qGWe3mkWBkOSNqNOltD-G9Q65EFUcnMGfPx2c240UaZCdFbSNhD9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-114","volume":""},{"id":1761,"author":"朱凤瀚","title":"枣树林曾侯编钟与叶家山曾侯墓","abstract":"随州枣树林墓地春秋中期偏早墓M190出土的曾侯编钟、镈铭文,言及其&quot;皇祖&quot;在昭王继位后,先曾受命&quot;建于南土&quot;,拱卫于应、蔡之南,并作汉东之屏障,征伐淮夷,至于繁汤(阳),知南宫氏初受王命戍守南土之地,当在今南阳盆地以东、淮水上游以北区域;铭文言昭王南征荆楚前命南宫氏于曾,以征伐&quot;南方&quot;,是此时南宫氏方乃封于曾,经营之区域遂南移至汉东。由铭文所言联系叶家山曾国墓地,亦可知M111墓主人曾侯,即是在此种形势下始受封于曾的。","categories":["06_族氏方国"],"year":2020,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_B9syoNbIlrZ5n8oZ8hFYpv7iOOh5gQXzZy_xvPOE7ZgZoXo7eGk1e_XE1k2bAWM_BeWDFv4pjpKVtwPPMIUFHt-vONYk-tej-GcqI6jCBN38KkjksjgWUqNl0uGmjQ_kividpBbRm8g4VCRxzhbPER9sSdZIkWIm0vIjfvvXMVjPfPm4H5kE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46223","volume":""},{"id":1766,"author":"马超; 邹芙都","title":"旨扬镈与韩国世系校正","abstract":"从器形考证,旨扬镈应为春秋晚期至战国早期器。镈铭所见人名有&quot;韩告公&quot;及其子&quot;旨扬&quot;,&quot;韩告公&quot;之&quot;韩&quot;应指东周以后的晋国韩氏。铭文中的&quot;旨扬&quot;应读为&quot;启章&quot;,是韩武子私名,据此则知&quot;韩告公&quot;当即韩武子之父&quot;韩康子&quot;。&quot;告&quot;与&quot;康&quot;二字在战国及秦文字中写法相似,史书&quot;韩康子&quot;之&quot;康&quot;很可能是&quot;告&quot;字形似之误。","categories":["06_族氏方国"],"year":2020,"publication":"中州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJiK9o4TgjFMCyW-AnqsAvaGnW_BwBhWiXAN4hkczQxEKyvP25tcyzEC955IUEnutcKljHhS3G7DpQJJrXy8jBftDWx1qFO2HRf1X4YsRRKUwwU_n5lb0vB3J87-YWI7Ajgg5-JJ1TJEhdukmzRX4GhLgnN144lK3zDMpqO2R1ZipqRakHYNKL4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"144-148","volume":""},{"id":1780,"author":"金方廷","title":"从周代宗族分化的称谓惯例看曾国铜器铭文中的“伯括”","abstract":"根据对曾国世系的研究,西周时期分封在南国的曾国源出南宫氏,而在反映曾国世系的一系列铜器铭文中,西周早期南宫氏重要的家族成员南宫括常被曾国国君称之为&quot;伯括&quot;。这个称呼或许反映了曾国家族与南宫氏之间的亲族关系。参考西周时期其他姬姓宗族分化的称谓案例,曾国作为南宫氏的小宗很可能与南宫适分属于南宫氏的不同分支。通过对铭文的详尽分析,比对、归纳周代宗族分化过程中的称名惯例,便能更加清楚地了解西周早期南宫氏的宗族分化状况,进而可以从宗法的角度探讨畿内世族与畿外诸侯国的关系。","categories":["06_族氏方国"],"year":2020,"publication":"国学学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIMLjb0lftV5f42v7TT7tij_VWbokMt8Mlqy6YQMRkWlQt5PBwUbU5GO07uut8fdgQBqt76MGdcB9FpCYj_JozOWD1USx8H8GEmJLRpeMnA5NCXHSJUluKA6nj4ys4LhljDn_o5NPrxQc3y0LrUEdGGe7-XKWltLqfykB90aMWK5Csq5r500A0y&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-94, 144","volume":""},{"id":1782,"author":"李伯谦","title":"两千年来殷周金文族徽研究的大成之作","abstract":"七年了,从上次为王长丰博士《殷周金文族徽研究》(上下册)写序,到今天看到王长丰博士《殷周金文族徽集成》付梓,并邀我再写序,其间不知经历了多少不眠和艰辛。《殷周金文族徽集成》这部书共40册,分38册著录,另外2册分作目录和索引。连续几天学习后,在我的大脑里呈现出一套王长丰博士关于族徽产生、发展及其演变的模型,这个模型是基于在族徽发展、衍生过程中应运而生的,是基于对全部殷周金文族徽系统深入研究基础之上搭建起来的。对于这个模型、这厚重的40册集成,我有许多话想说。","categories":["06_族氏方国"],"year":2020,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmJx5xmuG04XzVoMZWx1Prxiyq4KsahUkWC4YywCvE54gIN50WQF1yhrfw-mU_S7ejBTgq94V_LaaLxMrbcWA0DhAJPS62ON6Q8j_lziBAXTjfgd0eboKLtcA7ZmReo-7uDfDDEI2gtu5zg-_gN34aA8D-Gg-takSqj_V2PzhY1RBkDN5McYwV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46027","volume":""},{"id":1784,"author":"李爱民","title":"从曾侯與钟铭“申固楚成，改复曾疆”谈曾楚关系","abstract":"随州文峰塔M1出土的曾侯與编钟铭文内容与公元前506年&quot;吴师入郢,楚王避难于随&quot;的历史事件有关。这对研究曾国的历史、曾随关系以及曾楚关系具有重要的意义,可补史载之阙。同时,结合传世文献中&quot;国&quot;可训为&quot;国都&quot;义来进一步证明学者关于曾随一国二名的论断,&quot;曾&quot;为国名,&quot;随&quot;为国都名,而国都名可以指称国家在出土及传世文献中皆是常见的现象。最后,结合曾国铜器的出土地探讨了历史上曾国疆域的变迁,同时对曾侯與钟铭&quot;申固楚成,改复曾疆&quot;的内涵意义进行了探讨。","categories":["06_族氏方国"],"year":2020,"publication":"怀化学院学报","link":"https://link.cnki.net/doi/10.16074/j.cnki.cn43-1394/z.2020.04.016","pages":"77-81","volume":"39"},{"id":1788,"author":"王建军","title":"殷周时期“虢族”“虢国”及相关问题研究","abstract":"本文在整理甲骨文和金文所见&quot;虢族&quot;&quot;虢国&quot;资料的基础上,对&quot;虢&quot;字溯源并就早期的涵义进行了解读,同时还考察了殷商甲骨文中的&quot;虢族(方)&quot;及其地望;重点对西周金文所记载的&quot;虢国(君)&quot;史料进行了分析与探讨。","categories":["06_族氏方国"],"year":2020,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjAUZB4H7Nu5EdEE9cv1UaS2_rSWp62HNYDyEJl7eppDoTna_Gi1JNX5sKSMq3MvSqjumx30aYcBto9-yl6aVHQQUShkL4Pr1HQm2ivIWE7UxE5PTfHcEcSf1nkEaflQNNRefoRyYSKpWlj3xREleuTKPd0tfe4ZxNaPZyRztSYSbWVPvyR3wK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"136-144","volume":""},{"id":1796,"author":"田成方","title":"曾公■钟铭初读","abstract":"新近公布的曾公■钟铭是一篇曾国宗庙祭祀文书,由三部分构成:一是赞颂高祖伯括的生前事功及福赐子孙;二是颂扬皇祖南公受昭王命&quot;建于南土&quot;,以至受赐铜钺,&quot;用政南方&quot;。曾之&quot;皇祖&quot;在周昭王时期的二次受命,过去未见记载;三是器主程式化的自述和祈福。结合曾侯与钟、加嬭编钟铭文,可证伯括因勤劳文武,故在周成王时受封立国。曾公■钟铭受昭王诰命的&quot;皇祖&quot;,疑即随州叶家山M111墓主曾侯犺。曾国二次受命以后,被周王朝授予主政南土的职责,由此奠定了日后&quot;汉东之国随(曾)为大&quot;的基础。","categories":["06_族氏方国"],"year":2020,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLo846sOwG0RMUvnprnlER_S006weUie7HDyLere_QmCO6tq7MlQs4h3W4BBnKK5nynmIx2Njy-3mFyswPDiyuM7zxnWlHxY9MoxShj9NYtiWXBd_sCfb_y1pisfpO3tD30OPZdHQBAAx9jypRBW_VLgztbxL_0zV0WBpdBu5TXv_-QmF-9CMUR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-120","volume":""},{"id":1798,"author":"黄锦前; 贺传凯","title":"淮滨王岗楚墓出土公子戈及相关问题","abstract":"公子■鄝公戈应系春秋晚期楚器,器主公子■系楚昭王或楚惠王子,曾任鄝县县公。淮滨王岗M1的墓主或即公子■,亦即鄝公,墓葬年代为战国早期。蔡公子吴戈应系公子■即鄝公在灭蔡战争中所获的战利品,死后以其随葬。台北故宫博物院藏鄝公鼎和缶的&quot;鄝公&quot;,亦应指楚鄝县县公,而非鄝国国君。王岗楚墓所出有关材料与包山简等所载楚鄝县的有关情况可互相印证,互为补充。","categories":["06_族氏方国"],"year":2020,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjX9db6kXbs6VwgsBi9_kMOgpKB2u04lixQDJVzHwUMRqERO6CfbDWIekzbw6bEk81vWCyC1yEphaRuEDJsZWTqTTy8kuIFmFeiqBD978TJ_XoRzIJc1gPasr5tuROECEesPdRbtFe_95veg3u54sKznO91uUiejRRsa5ZtuQwcFdbyoSNoncr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-56","volume":""},{"id":1801,"author":"何连海","title":"故宫藏“兽面纹印”图形符号解析","abstract":"文章围绕北京故宫博物院藏&quot;兽面纹印&quot;,将印面上的兽面纹与器物纹饰相对照,将图形&quot;■&quot;与殷商金文和甲骨文所见近似者加以比勘,初步推定该印出自商晚期,而&quot;■&quot;是一族氏铭文,为统治阶层标志性的图形印记,而该印亦是族氏铭文与兽面纹组合出现的一个例证。","categories":["06_族氏方国"],"year":2020,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLctq-Aw-DyvpzW4CCmuEAbinE7V6gLKJsSU9f8Fv-keZjkPD6iJYTOoj_3MIWBUozqk4eXIH1ZdSZoOT-rOpG_mP1xt1BauzqCAmVG2hA078mGt4yeZ0kVSDWjBSs1oXYVxmhiSrjAM4lwOrRx7acCtS5GeXvqATH419-nf1CIhdvIIPK9PIul&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-200","volume":""},{"id":2193,"author":"张伦敦; 彭邦本","title":"《庄子·至乐》篇所见帝王世系考","abstract":"本文的研究始于《庄子·至乐》篇“种有几”这段文字,古人的注疏通常将其解释为“鸟兽草虫”之变,因其寓意天道往复、万物相禅的思想,且涉及诸多名物训诂,所以传统注疏并不能很好地通其辞、达其义。经梳理,着重与《楚辞》、《山海经》等文献对读,并和纬书、道书相参证,我们发现“种有几”这段文字可能存在另一种解释,即讲述的是一类失传已久的上古帝王世系,本文基于此认识展开深入探讨。“种 有几”以“乌足(踆乌)”为界,踆乌之前的文字大义是说“圭田出日”,踆乌之后的文字才是讲世系。这个世系始于“踆乌(帝俊)”,遂由“帝俊”分出两支世系,一支名曰“齐糟”(泛齐),一支名曰“枯枼”(鱼妇),经比对,这两支世系很可能就是正史里记载的“青阳”和“高阳”,也即“少昊”和“太昊”。由“ 枯枼”到“鴝掇”的变化,其实是讲鲧、禹之变,即《楚辞·天问》所言“伯禹愎(煏)鲧,夫何以变化?”这是“种有几”里最难理解的部分。由鲧至禹的","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27342/d.cnki.gscdu.2020.000202","pages":"","volume":""},{"id":2198,"author":"孫海燕; 胡長春","title":"黃淮間中原十國金文整理與研究","abstract":"兩周時期,在黃河淮水之間,存在著許多周王室所分封的諸侯國。本文對西周至春秋時期,在中原地區比較活躍的十個國家的銅器銘文進行整理和研究。這十個國家分別是:衛、許、陳、應、胡、鄭、蔡、宋、凡、虢,後文簡稱為中原十國。黃淮間中原十國的金文是中原文化圈銅器銘文的典型代表,是兩周銅器銘文的一個重要組成部分。中原十國的銅器銘文的風格特征從西周早期到春秋晚期有著顯著的變化,這和兩周時期的歷史演變有著明顯的關係。對位於黃淮間的中原十國銅器銘文的整理和研究,對了解和探討這一地區的歷史變革狀況,研究西周至春秋時期周王朝的興衰變化,都有著十分重要的意義。金文分域研究是當前金文研究的一種重要方法。而中原地區是華夏文明的一個重要源頭。目前學界對中原地區金文的研究也越來越重視。因此,本文以中原十國的具銘銅器為研究對象,對其進行系統的搜集整理和探索研究。本論文的主要內容包括以下幾個方面:一、對中原十國的具銘銅器進行全面","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27684/d.cnki.gxndx.2020.000201","pages":"","volume":""},{"id":2666,"author":"刘安鲁; 方辉","title":"山东出土东周异域诸国青铜器及其历史背景探析","abstract":"自夏商以来,一直到东周时期,山东地区呈现出中原文化与东夷文化相融合的过程,这也就造就了山东地区独特的文化特征。东周时期山东地区古国众多,与周边诸国产生着千丝万缕的联系,各个古国间通过多种方式进行人员的交流、器物的流通、文化的传播及国家的融合。作为史料的两大重要来源,历史文献和出土文献为我们构建出先秦古国的基本脉络,在东周时期,最重要的出土文献当属青铜器铭文。本文通过对山东地区出土的有明确国属铭文的东周青铜器进行梳理和探究,试图从古文字学、器物学、历史文献学三个角度剖析这些异域诸国青铜器来到山东的原因。本文的整体构建建立在山东地区出土东周青铜器的基础之上,着力挖掘符合条件青铜器的第一手考古资料,提取相关墓葬信息,共梳理出陈、黄、江、樊、楚、吴、徐、宋、北燕9个东周古国的16件出土于山东的具铭青铜器,着重阐释分析了每一件器物的铭文隶定和铭文释义。文章通过历史文献的分析和研究,还原出器物原属国的","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27272/d.cnki.gshdu.2020.005425","pages":"","volume":""},{"id":2678,"author":"艾卉番; 张志鹏","title":"黄国铜器综合研究","abstract":"两周时期诸侯封建,黄国位于淮河流域上游,其踪迹于历史文献记载中较少提及,幸得近几十年来考古发现出土多批黄国青铜器,加上多有传世黄国铜器,尤其具有铭文者,是研究黄国历史文化的重要资料,对这些资料系统、科学的整理显得愈加重要。本文立足于前人的研究成果,广泛而深入地考察黄国铜器在形制、纹饰及铭文等方面的地域特征,并结合文献资料,对黄国历史进行探讨。正文内容分五章:第一章综合各种来源渠道的黄国铜器,采用科学方法进行整体的归纳,分为时地明确、时地不明以及相关器等三类。在研究过程中,以时地完整的黄器为主,其余材料为辅,为后续研究打下基础。第二章在系统整理之后进行类型学方面的分析,综合考察黄国铜器器物类型差异,将黄国铜器主要器型按器类划分型式,为年代研究做好支撑。选取典型器类参照标准铜器年代分期要素,将黄国铜器分为四个时期。第三章参照周边主要文化区域铜器特征,对黄国铜器的形制、纹饰以及铭文文化特征作整体","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27118/d.cnki.ghesu.2020.000498","pages":"","volume":""},{"id":2684,"author":"李宇田; 鄢国盛","title":"商周举族研究","abstract":"举族是活跃于商周时期的大族,拥有独立的氏族武装,强大的军事力量,经常为商王对外扩张提供武力支持。举族经历了两次迁徙,武丁时期将领举大致活跃于汶水以北,山东平阴一带。经过一段时间的发展,家族日渐庞大,分支日益增多,商末举族主要活动于汶水下游及曲阜一带即泰山以南的鲁中地区。周灭商后,举族成为殷遗,一部分服侍燕侯,在北京房山琉璃河的燕国任职,一部分在陕西的周王畿附近担任师、犬官等官职。商代举族的分支大体分布于举族母族周边,分别为:长清的(?)族、汶水下游沿岸的商族、淄水流域的齐族及棘族、泰山东南一带的次族、鲁东莒西的向族、山东费县的皻族、泗水县东的庚族以及河南安阳的(?)族。举族的分支以其母族为中心向东侧发展,这也就代表着举族族群势力范围以汶水流域为中心向东侧扩大。举族作为征伐人方的重要氏族,在镇抚东土上起到了重要作用。(?)族、史氏家族、(?)族、周王室与举族有过联姻关系,其中(?)族、史氏家","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27212/d.cnki.glnsu.2020.001207","pages":"","volume":""},{"id":2692,"author":"刘芳; 张振谦","title":"西周邢国和井氏铜器铭文整理与研究","abstract":"西周邢國、井氏銅器銘文是研究西周世家大族發展歷史的重要文字資料。西周邢國出土和傳世有銘銅器較少,相比之下,井氏有銘銅器較多。學界長期以來致力於研究與邢國和井氏有關的歷史、族源等問題,並取得了許多成果。同時,在銘文字詞考釋方面也取得了較大成果,但大多較爲分散。且隨著新材料的出現、新觀點的提出,有必要在充分吸收學界已有成果的基礎上,對西周邢國、井氏銅器銘文進行全面系統的整理研究,並對相關問題作進一步探討。本文主要以吳鎮烽《商周青銅器銘文暨圖像集成》和《商周青銅器銘文暨圖像集成續編》爲參考資料,同時結合其他期刊論文等,搜集整理出西周邢國、井氏自作器及他人作器共82件。其中,邢國銅器11件,井氏銅器71件,並以此爲研究對象,在充分吸收各家觀點的基礎上,對銘文進行全面的整理研究。同時結合銘文字詞的考釋,進一步研究與西周邢國和井氏有關的歷史、族源問題。本文分爲緒論、銘文集釋、相關問題研究、結語四部分。","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2020.000275","pages":"","volume":""},{"id":2709,"author":"孙毅利; 王晖","title":"商周鄙的起源与发展","abstract":"都鄙是商周时期两种对立存在的地域性组织。“都”就是都城,相关研究在考古学和历史学领域开展地己经相当深入。而与都对立存在的“鄙”,无论是研究成果和关注度都相对较少。从目前发现最早的成熟文字甲骨文来看,地域组织意义的鄙字在甲骨一期刻辞中就已出现,由此可见鄙作为一项社会制度至少在殷王武丁时期就已经形成。古文字是我们研究古代社会的一把关键“钥匙”,特别是商代的甲骨文字,由于是据义绘形,其形义统一的特点使得甲骨文中一个字的字形结构其实就是这一事物在当时社会生活中的直接反映。我们从甲骨文中鄙的原始形体来看,鄙的初文“啚”由“口”和“(?)”两个部件组合而成。部件“口”是城堡之形,所谓“城为保民而为之”,说明鄙的产生应该与军事防御密切相关。古代城堡“定之方中”,称作“都城”,同时“四境盈垒”还建于国境,称作“列城”。都、鄙在古代因为是一对相对概念,鄙的原型其实就是“列城”。因此,啚从口从(?)的字形结构","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2020.002022","pages":"","volume":""},{"id":2723,"author":"张金桥; 燕生东","title":"春秋时期东夷族群华夏化研究","abstract":"春秋时期,海岱地区邦国林立,族属构成也较为复杂。依据族群认同理论,从他称和自称两个方面,大体上可以将这些邦国的族属划分为“东夷族群”和“华夏族群”两大族属系统。“东夷族群”是一个具有族属意义的他称,其内涵并不直接与文献中常见的、具有多重内涵的“东夷”一词等同。尽管在不同历史时期,“东夷族群”的构成和分布范围是明显不同的;但从“族群边界”的角度来看,文献中被称为东夷的群体,均是在“中原”或“华夏”中心视角下,位于“边缘地带”的“他者”。因此,春秋时期的东夷族群即是“诸夏”以外的那部分群体。春秋时期社会变革的加剧,使得这一时期东夷族群、华夏族群间的交流互动更为频繁和多样。在频繁互动中,东夷、华夏族群间在政治、军事、经济、文化等方面的联系逐渐密切,两者之间的“族群边界”也逐渐模糊。东夷与华夏族群之间族群边界进行调整的过程,即东夷族群的华夏化过程。从文献记载来看,春秋时期东夷族群与华夏族群间的交流","categories":["06_族氏方国"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27280/d.cnki.gsdsu.2020.001160","pages":"","volume":""},{"id":2940,"author":"赵谚丽","title":"从青铜器铭文看西周早期燕国","abstract":"西周燕国在北京史中占据重要地位,然而传世文献却少有记载。1986年北京房山琉璃河M1193出土的克罍、克盉提供了西周初年燕国初建的重要史料,基本确证了琉璃河遗址即是燕国早期的都城,把北京建都的历史向前推进到了距今三千多年的西周初期。青铜器铭文尤其是出土铜器铭文,作为第一手史料,较传世典籍更有可据性。本文试图利用&quot;二重证据法&quot;,将青铜器铭文结合传世文献,对西周早期燕国概况,包括召公封燕、家族世系、社会组成以及初期疆域等进行梳理分析,从青铜器铭文概览西周早期燕国。","categories":["06_族氏方国"],"year":2020,"publication":"北京史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIx1FZctBXNNCgXBuamBb002UpXNquBdmBxWAsJ6VGWsSNj-cGhD97TMNYIrHg-YY6RcNcExPKiRtdUZlqtSaJF9sN1dVQLYrIMhQdXA4aT-nSJDoA8i4y-TZalxbGbM_dGhyf92YuwLsTyugy6T1DjGHezlJAkMywC72YAu-7cFQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"332-347","volume":""},{"id":2964,"author":"刘攀峰","title":"论西周初期召氏家族的世系","abstract":"文章对目前所见西周初期有关召氏家族的铜器进行了梳理和研究，对召公、燕侯克、燕候旨、父辛、召伯父辛等相关人物及其关系进行了辨析，讨论了西周初期召氏家族封于燕国和留于畿内的两支世系。","categories":["06_族氏方国"],"year":2020,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI11KkpXvRM127EiPx31xLy7dVbTdUgOnDM6TT74OgfyWyu1TP5H2wzxjFi9BPucg2alus0aOPNz8CtLmlGzUynAeAEHzcApgCtDEXLRVHOR2GLK6Mmz-GLCHfVFeAUBMkTBAV7AlQyAcnjs_tjOU3eeQ5yGMYpodGrRq26fB09vw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-66","volume":""},{"id":2967,"author":"曹锦炎","title":"阜平君钟■铭文小考","abstract":"提要战国时期赵国的刻铭青铜钟虡，存虎形底座和框套。自名为“虎■”，铸于十五年三月，重百镒。铭文所记器主“阜平君”为赵国封君，大约生活在武灵王时期，典籍失载。二次所刻“阳文君”即赵豹，曾任赵国相邦。铭文对研究赵国历史具有参考价值。","categories":["06_族氏方国"],"year":2020,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZF0dJn0jqniQgt5_kIlZC77BmbJ0hF8uUmgfemtnCzbVnqXJ10EEP9BDL4NeWWspn1FDp_8GXW34IMzd1PKRnauS_BIPnAOw8Y9VZK2FuZvGcINUU32Cx1wHVB_kfiGLuiXqWEbUUR6StMdQsM0oW9xycNGpPplP_6jTxxv65Eg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-98","volume":""},{"id":2968,"author":"赵敏","title":"“成阳左戈”戈考","abstract":"本文对出土文献中有关“成国”的材料及传世文献中关于“成国”的记载作了梳理，认为成国初封于陕西，平王迁都后封于今山东省宁阳县的堽城，后迁至今山东郓城境内，再迁至“成之阳”-今山东鄄城东南，称“成阳”。山东新泰出土的“成阳左戈”戈铭中的“成阳”与其他出土文献中的“城阳”字形、铭文辞例及器物的材质、器形均不同。此戈当为成国迁至“成之阳”改称“成阳”后，其左库所铸兵器。","categories":["06_族氏方国"],"year":2020,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGlLpkDctrZla93ZWyvag0eDJ2IOoE9lXdD-NRyTZyB6-LD6hbQ8yLxr7yfr6uP6r7IWPzX_GWvSdWBsT2rOnb3i-EZfGCAnvTjSCP4diyu__msvyzbeZrMkDdqjucwGJbfTVX0jgu9WIQ2RXHReFaLUgK9Md6pIErAAoILaKcHQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-113","volume":""},{"id":2984,"author":"黄锦前","title":"敬事天王钟与侯古堆M1所出编钟、编镈为曾器说","abstract":"据相关文例,从铭文内容、措辞及有关用语如&quot;敬事天王&quot;&quot;江汉之阴阳&quot;等所体现的作器者身份及地理等信息来看,河南淅川下寺春秋楚墓出土的敬事天王钟当非楚器,而应系曾器,作器者为春秋晚期前段的某一位曾侯,约与楚康王年代相当,此套编钟或即&quot;楚康王时&quot;以战争途径掳掠自曾人。据器物形制、纹饰、铭文字体及内容如&quot;保此钟鼓与楚&quot;&quot;百岁外,遂以之遣&quot;等来看,固始侯古堆一号春秋墓所出鄱子成周编钟和编镈亦应系曾器,与敬事天王钟为同人所作,其来源亦同。","categories":["06_族氏方国"],"year":2020,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6prPMmJ-JzIgB8LXZ2PUby7vBVkx-xMF41eSSwPZgOdWxGFAP9UdY_tfOGxdpxX--5S6Vc4bovjZgDdimbAU6aoX4cyh27xQpR_iPR_josS1NMxZMlBnOW0ev10Wlw0WVSI2YG1RpZgzGTunCevrqXyYOkOGoVLwFN6xbbVuEBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"152-156","volume":""},{"id":3004,"author":"黄锦前","title":"枣庄小邾国墓地出土与传世昆君妇媿霝诸器铭文中的“昆”","abstract":"据铜器出土情况和铭文内容、文字、文例及地理等各方面信息,春秋早期的&quot;圆&quot;即&quot;昆&quot;应系今鲁西南地区与小邾国即今山东枣庄一带邻近的国族,系昆吾之后。昆君妇媿需壶出自枣庄小邾国贵族墓地,表明昆与小邾国之间有较为密切的往来;也为传世的昆君鼎和昆君妇媿霝蓥等器找到了归宿。","categories":["06_族氏方国"],"year":2020,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgyDGbOe9TTO7QyJxuLiwg7m5d2tLdwEN0N5PlC06YLdl-Dg3F84rwsh8WJt345LEXWEQESOVQfS5a_7CNnrgCeHsppDsSav_0VrjhOcIWN1lYC_f0nnsoLr8O8lQGzPOtW93_YRXsVhT5_PlC_LFJcES9DO-mHq_51Fnb7PY0wQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-130","volume":""},{"id":3046,"author":"肖圣中","title":"《周易·比卦》的“不宁方”与金文中的“不廷方”","abstract":"《周易·比卦》卦辞曰:&quot;比:吉。原筮,元永贞,无咎。不宁方来,后夫凶。&quot;这一段,尤其是&quot;不宁方来,后夫凶&quot;一句,向来是比较令人费解的,历代解说也较为纷歧。如,王注:&quot;上下应之,既亲且安。安则不安者所托焉,故不宁方所以来,上下应故也。夫无者求有,有者不求所与,危者求安,安者不求所保。火有其炎,寒者附之。故已苟安焉,则不宁方来矣。将合和亲,","categories":["06_族氏方国"],"year":2020,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITMmHKD2VSELswGpSB3PuZuS4BxNzp5C1guZchrQ1TyXRT3IZ5XuhNAaWQ6xs77gzwnNhGeCIK_RiFkSfKHfZAOpAx8suuo0ndIEwnq76n793BfvQKRTB3uDRB7_2HGSxnG0JAxMak-MVVnORoS6zVTQsbzqctL4qdOCin1itsPA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"232-235","volume":""},{"id":3275,"author":"张振谦","title":"新见燕王讙兵器考证两则","abstract":"自燕易王以降,史料中战国时期的燕王世系是清晰完整的,但是,传世文献之不足致使有些燕王名字缺失,有谥无名。相反,在出土的燕王兵器铭文中,燕王皆有名无谥,这就需要对这些出土的燕王名作进一步的考证。通过对燕王戈铭文中的“称谓”“动词”及其“数量占比”等进行统计研究,得出“郾王戎人”即燕惠王,“郾王”即燕武成王。通过对两件新出土燕王兵器铭文的研究,得出“郾王”应读为“燕王讙”。","categories":["06_族氏方国"],"year":2020,"publication":"燕赵文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoZ1zwP2mWryBMvr7LYtWxAFerIpIb6b4p_fuXt9GuDayXM-qDFqGlnw9eRm_KT_tX8fndHr_2DjAXx1AklWU8LYKq8yHdtXoyrHXvTcDErQjP_2S1hhSxmZktQUe0wI1CTU3CGOEbMqb4UabhxRgHEfNrCfQiZy_dctp7su8iwA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46029","volume":""},{"id":1668,"author":"邹芙都; 唐英杰","title":"商周灷族地望考论","abstract":"据金文&quot;复合氏名&quot;与甲骨卜辞可知,灷族为商末较活跃的族群之一。该族与在今山东中南部的举、弓、庚、戌、鸟、规、龙、甫等族多有交集;与在今滕州市东南的、启两族地望相邻;以在今鱼台县附近的方、昜二邑为其西鄙。金文及简文里国名或地名&quot;滕&quot;异体多见,但均以&quot;灷&quot;为声符,结合相关地理位置及文字构形综合考虑,商代族地名&quot;灷&quot;理当读为&quot;滕&quot;;商末灷地应即周代滕国,在今山东省滕州市姜屯镇附近。","categories":["06_族氏方国"],"year":2019,"publication":"兰州大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13885/j.issn.1000-2804.2019.06.004","pages":"13-19","volume":"47"},{"id":1728,"author":"张丹","title":"应国媵器及联姻关系研究","abstract":"史籍当中关于姬姓应国的记载本就极少,至于其联姻关系,更是罕见。根据平顶山应国墓地出土及其他来源铭文材料可知:西周早期到春秋早期,应国的联姻关系始终比较简单,固定,一是与王畿之内的异姓国联姻;二是与同处南土境内的姜姓国联姻;同时也保持了与王畿之内和南土境内同姓国之间的良好外交关系。唐姒簋及应侯簋反映了应唐交好与应单交好的史实,也是西周时期同姓不婚及媵婚制的见证。应国的这种联姻面貌既与当时的政治地理结构有关,也与周王朝经略南土的举措有关。","categories":["06_族氏方国"],"year":2019,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKw9ckxdKHw5EPc2eogJr85OyGGAqX1hP6OhgFjd8gf_UdRmCuouwonKA7S-IDfLz8A64sBUwNj5r1wUbnjvbQm4JRTGk6Bo-yHxkoB8rqX0ZL5dr_BBLH8y2QY3bi6E-RYq9y1K5lBPiFh36eyrQzq1o3AvKoQ0YSVHBGqe-Xe8pP-CDN9zD60&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-84","volume":""},{"id":1745,"author":"邹芙都; 马超","title":"西周金文所见佚记古国及相关问题讨论","abstract":"西周金文中存有多个文献佚记古国,学界虽有讨论,但在相关史实解读方面,仍有较多争议和误解。综合考辨人物称谓、墓葬资料、铭文内容等各类线索,可基本探知鄳、緐、霸、、相、散、■、的族姓、地望等信息。、、、僰、量、欲、买、鼬、乖、軧等相关资料较少,目前难以探明准确信息。佚记古国的考辨与讨论,为进一步推进&quot;古诸侯称王&quot;、&quot;汉阳诸姬&quot;等问题的研究提供线索。","categories":["06_族氏方国"],"year":2019,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtUkBXb41HwJGS2T5W5e67Pbid6QUOkYHcWahXRIfMSND9-rfJpLBROvGzfxey8_toJAQ7_hzhMiQZEEdLqDjsvpFYxOy_hXjIbPQ-wLQnZ7Ky0YJyfWvBMnq3ezjhMunGlkM1_n2C0EQVu00LsC3me3jM7hFJeUuOLJX_kkk1lBjCNAZnst_U&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-145, 192","volume":""},{"id":1826,"author":"朱继平","title":"商周东土吾族地望新证","abstract":"晚商东土有■族,■及与之关联的上■作为商王征夷方时的重要驻跸地,战略位置突出,是深入解析晚商东土地缘政治格局的关键节点。■与上■地望,学界多主张对应《春秋》文公七年鲁国郚邑。鲁郚说虽与■字构形、音义相符,却与卜辞所见同版地名间的地缘关系不合。综合各类文献可知,■、上■与向、莒、■三地皆近,唯有以■、上■对应《春秋》庄公元年齐国郚邑,方能同时满足这三组地缘关系。且汉晋古书所见与齐郚邑系联的浯水、浯山,亦可进一步佐证齐郚说可信。因此,卜辞■族即西周史密簋、《春秋》经传等所见吾夷、郚邑之前身,故地当在今潍水上游安丘西南李家西郚村郚乡故城遗址。","categories":["06_族氏方国"],"year":2019,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2019.11.007","pages":"68-76","volume":"40"},{"id":1833,"author":"唐英杰; 李发","title":"三门峡虢国墓M2009墓主虢仲考","abstract":"三门峡上村岭虢国墓是一处重要的周代国君贵族墓葬遗址,M2009虢仲墓是一座经科学考古发掘的高等级国君墓葬,确定墓葬年代及墓主身份对研究当时的经济政治制度、历史文化风貌等至关重要。本文在前人研究基础上,运用类型学、考古学、文献学的方法,通过对比器物的形制、纹饰,系联铜器铭文,结合相关文献记载,对虢仲的身份进行了考证。传世虢仲鬲器主虢仲即M2009墓主虢仲,为国子硕父鬲器主硕之父,器物年代较虢季氏(虢文公)子鬲稍晚,较虢季(虢公忌父)鬲稍早,在两周之交;虢仲墓出土的两类虢仲鼎均具有明显的西周晚期宣、幽时的特点,其时代亦在两周之交;虢仲生前曾&quot;受天子禄&quot;,其身份地位与两周之交时扶植周携王的虢公翰相符,M2009墓主虢仲应即虢公翰。","categories":["06_族氏方国"],"year":2019,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIb3ca6bCb_p2IcqacNa9ePsK5GYd6LIc0GsBU3LhH1I0PSn-fat_8p0Y8-hJ_MTg2lFmGWa3yB5JQWsjqGqTAXDJYUX7-GvDd9Qlqfau0uZcjHsDBn7jytIRWI7lGlvUNLecZenf-UxRX0LMgp1I57r08BAln-Pe4Eib9ZiDBm-CzbJow5OfMb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-80","volume":""},{"id":1838,"author":"雒有仓","title":"金文族徽的功能及其时代变化","abstract":"金文族徽见于商周时期青铜器,前后历时一千余年。在这样一个漫长的历史进程中,其功能随着时代发展而产生变化。作为依附于青铜器的铭文形式,金文族徽具有标识铭记、美化装饰、体现身份地位的功能;而作为族氏名号,金文族徽代表着家族组织,具有表示血亲关系、体现家族集体身份的功能。在长期发展过程中,身为商人族群共同体的文化符号,金文族徽还有体现职业分工、表示族氏关系、承载民族认同的功能。正确认识金文族徽的这些功能,不仅有助于了解金文族徽自身的发展变化,而且对深入认识金文族徽的内涵及其性质,也具有重要意义。","categories":["06_族氏方国"],"year":2019,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2019.05.016","pages":"102-108","volume":"7"},{"id":1842,"author":"徐少华","title":"河南南阳李八庙一号墓的年代与番子鼎之属性","abstract":"2004年5月,南阳市考古研究所在南阳市郊李八庙砖瓦场清理了1座墓葬。该墓形制为长方形土坑竖穴,墓向为119度,墓底长3.1、宽0.98、深3.12米。墓中出土青铜器7件,包括鼎2件、盆1件、甗1件、浴缶1件、盘1件、匜1件。其中1件鼎内有&quot;番子&quot;作器的铭文[1],对研究周代番国的历史及汉淮地区列国的文化演变具有重要价值。发掘者已就器物特征和墓葬年代做了初步分析,得出了一些基本认识,但有些问题仍有进一步讨论的必要。本文结合相关出土资料,讨论","categories":["06_族氏方国"],"year":2019,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvDM20okVpA13FsVQ_fzZTJqPp0PrEXqRI6A0_bFuIYtLIT2j0TeI7yvh_mg8YrMEg78EoO__JdG4it115NfsLWO_Z1TLFWwthBgZPyaB8Qf4yobgixQygA48Bxn-tx3m5toRS7NprxEcir5CvyQxXi4UKkW7FNj-Wut4gxid4SF34UZBdrVoS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-92","volume":""},{"id":1844,"author":"董珊","title":"秦子车戈考释与秦伯丧戈矛再释","abstract":"本文考释了2015年甘肃甘谷县毛家坪春秋墓出土的子车戈,又重新讨论了旧著录的多件秦政伯丧戈、矛,认为&quot;伯丧&quot;与&quot;子车&quot;即秦穆公时的大臣公孙支和子舆。这对研究春秋秦史具有一定的参考价值。","categories":["06_族氏方国"],"year":2019,"publication":"国学学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYj3S-pQuM7kC2Isza-D-oj4jarF6By_4QgW4FPUcdqBPwnsoDpbdukykLXAgxgdQph-kgs-HZ9s94lqr4Bb4NR-0t_tmKTmxBpc1KYC_k-KgfoxNMoNm5_ZyUSBNkkK-qrbNEjZ6NNL0SJHV0rgzO9DGkx3MvdnX9fDnJSKdgSTQB3pjK09Rl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-47, 141-142","volume":""},{"id":1845,"author":"陈絜","title":"过甘敦鼎铭与商周东土过族","abstract":"东土过族最早见载于武丁卜辞,结合传世文献可知,晚商过氏当为东方诸妊之一,是有商政治与军事势力的有机组成部分,其族居地或在鲁西南或鲁中南一带。周公东征以后,过族顺服有周。昭王时期,则参与南征并立有战功。妊姓过族在东土的活动至少延续至两周之际,章丘所出过甘敦鼎,是其重要物证。过伯簋等传世器,也可能出自山东。商周过族的梳理,亦有助于夏文明尤其夏族起源问题之探索。","categories":["06_族氏方国"],"year":2019,"publication":"邯郸学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-HMe6tRZWDqt0c7M2BIAXwUwtMJ3LcunTyeQ7bxCH20H_tO0gfOSTNnKWr8n5rYB43VM5C581l47jSRTahKaOKp6AZYdSUNB5CVNdCp2WEvi92hV7iPalzBexiHy1ATFTxkuDOFyPNVMuB0VNhdi80wJzpfQkr_fzQJ3fP6t3ykNd-NWg-eCK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-55","volume":"29"},{"id":1874,"author":"马立志","title":"论周代的寻氏铜器及其相关问题","abstract":"山东临朐出土的寻仲盘、匜和上海博物馆收藏的寻伯匜,时代不晚于春秋早期。&quot;寻&quot;和&quot;谭&quot;在上古音中韵部同属侵部,根据出土文献和传世文献中的例证,&quot;寻&quot;&quot;谭&quot;可以通假。铭文中的&quot;寻&quot;指的是文献中记载的周代谭国,谭国春秋早期偏晚时被齐桓公伐灭,据齐器鲍子镈铭文记载,(谭)地曾赐给鲍叔作为采邑。寻(谭)公遂戈、簟(谭)公戈分别是春秋中、晚期器,寻公、簟公是谭邑大夫之称谓。谭的地望大致在今章丘县龙山镇一带。寻伯之女称&quot;邾子□□&quot;,根据周代女子的称名规则,推测齐国伐灭之前的寻氏可能是子姓。","categories":["06_族氏方国"],"year":2019,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZkcxYHaFMmI2pjIepaks-bfIfG7cF4vVtSTLbkgaMv_i5UCm3twJwqh8g3Wz8ZBaw1CVMV-vOyJnftX7k50HxW5zP8JqrVD4gF61SmDRXseuIRxj5rMUrhJEnJF90GRV4166cvKbAMrXfxWIY7EmeLZlZ4bi1fClw3rkcxtkm5LS6By_eW5c_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-40","volume":""},{"id":1888,"author":"鄢国盛","title":"师卫器丰公、郐师小考","abstract":"传世文献记载周代有姬姓之丰,此丰氏在以往发现的相关金文材料中不易辨别,吴镇烽先生的《商周青铜器铭文暨图像集成》所收师卫诸器铭文中的丰公,应当就是文王之后姬姓丰氏,他驻军的会师在今河南新密,而员卣中被周人征伐的会则是东夷国族,其地望或在鲁东南的临沂,西周中期以后南迁至淮河流域。","categories":["06_族氏方国"],"year":2019,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLc3e1xZYZyal9yQhuOmlSPOKC1oruATvRVIG2cw020K3V3x-TuxnlNSc3Qnq3SGhYwf5uE11hXuM3CpRM7K1suYzwcPl9p-CllSvp59iRAk44e5IboxQwrxihXWQg0mrJ9tq3tyYkqd1BR45imweWXhHSEjxnq38pS5ceriJsNV08EdSI4Y8-T&amp;uniplatform=NZKPT&amp;language=CHS","pages":"161-166","volume":""},{"id":1894,"author":"曹辉; 陶亮","title":"上蔡郭庄一号楚墓“競之朝”鼎铭文及相关问题试析","abstract":"上蔡郭庄一号楚墓出土的青铜圆盖大鼎,按照其自名来看,当为鼎,也就是饗食宾客、烹饪用鼎的意思。这件鼎涉及到器主人名,通过对名字的隶定,结合其为楚平王后裔身份以及器物时代特征等,认定器主人是楚平王之孙公孙朝。同时本文试着解析了同墓出土的競孙鬲上&quot;競孙旟&quot;应该是楚平王之孙公孙宁,即公孙朝之兄。通过对上述器主人名的分析,初步推断上蔡郭庄一号楚墓的墓主人是楚平王庶长子公子申,也就是公孙宁和公孙朝的父亲子西。","categories":["06_族氏方国"],"year":2019,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJ3fhACBg_cieuxCQBLghowyE0VZxCtq4bIAFfuW3EkQy-03Zv75N667OjRYKTp3gLMmoDJoaeqtVx58XiIOLVZ7M2i2ANm999AiCfX4AIPVgxxAA4GvjTMYSwc1bEGv_43GQxXyOZrP9XJlzYpqE0_bjwujaDVjO5cklbd6UODA_IXJW_A65e&amp;uniplatform=NZKPT&amp;language=CHS","pages":"116-119, 128","volume":""},{"id":1898,"author":"郭军涛; 向野","title":"浅析西周金文中的国族区分","abstract":"本文将西周早期到春秋早期铭文为&quot;某伯&quot;的有铭铜器进行了梳理,再结合与之相关的仲叔季铜器,发现可分为两种情况:一是&quot;某伯&quot;根据金文和文献资料可确定其阶位并非为伯的,则&quot;某伯&quot;当为行辈称谓,此类铜器可称之为&quot;某国&quot;青铜器;一是&quot;某伯&quot;阶位不可考,此类&quot;某伯&quot;不能笼统地界定为阶位,其中当有不少为行辈称谓。笔者建议,将此类铜器命名为&quot;某氏&quot;青铜器,而不宜称之为&quot;某国&quot;青铜器。","categories":["06_族氏方国"],"year":2019,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJP9zgvutMTdo-3k2gwddZdV7dIVx_-Ssf3UG-p-4fzORogJjLcZlX0RqrJVDQRSx77YzYJOC5qVwWbhNtQCgM1CXXl1zQVhcNDMv1cwZ1ccMnf2Lcz8FS8GfgqrrGFaMEeea9mIvYWYwHlB3ZihudWk-Pj-MBlpEM8hVYMxFZOLdf9Q_qv7Szi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-108","volume":""},{"id":1908,"author":"申红宝","title":"略论北京昌平区白浮墓的族属问题","abstract":"北京昌平区白浮西周墓出土了带有&quot;其祀&quot;的铭文以及&quot;■&quot;和&quot;■&quot;的族徽,表明该墓地是商周时期&quot;其&quot;国首领或贵族墓葬。其族属既不是商人也不是周人,而是当地土著部落方国&quot;其&quot;族人。结合其他甲骨文和金文来分析,&quot;其&quot;国作为一个部落方国,在商周时期与中原王朝是一种由敌对、臣服到最终融合的政治关系。","categories":["06_族氏方国"],"year":2019,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2019.02.004","pages":"26-29, 91","volume":""},{"id":1919,"author":"黄锦前; 何金斌","title":"新刊许国金文三种读释","abstract":"本文对新近公布的许子鼎、许成季鼎及许公作叔姜簠三篇许国金文的时代、有关文字及铭文内容进行了讨论,认为许子鼎与许成季鼎出于谷城,可能与春秋早期郑国联合齐、鲁两国伐许,攻破许都的史事有关。邱家楼墓葬的墓主,即鼎铭的&quot;许子&quot;亦即&quot;许成季&quot;,系卿大夫一级贵族,主要生活在公元前730年前后的许庄公、楚武王之世。许公作叔姜簠的作器者&quot;许公&quot;,应系许灵公宁。此二簠系&quot;许公&quot;为其女&quot;叔姜&quot;出嫁所作媵器。","categories":["06_族氏方国"],"year":2019,"publication":"博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJVWG_R-q9hTCVVGZwX8gItJWPR7NXz3yOoWNcF4-VxsR2iNUYVtiEFp2Ady2Kr-M_lmS0egh_HOfxgoq7kzP6t4SGtNjyMqblnYvIs0fccB-4VNcvtzhjNJbgETdx3nZ4VG4IXSYinilPWExJjKCGnIzlssmRmUF7U5TpbsFv4mgBUX3hfxPL_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-70","volume":""},{"id":1921,"author":"杨文山","title":"西周邢国两次封命与两个封地考辩——兼回庞小霞对邢国二次迁封的批驳","abstract":"根据有关文献和青铜器铭文记载,文章认为西周邢国有两次受封受命:第一次受封为始封,封地为河南邢丘;第二次受命为迁封或称改封、再封,封地为河北邢台。批驳西周邢国有两次封命和有两个封地,力主只有一次封命和只有一个封地的种种辨析都不能成立。","categories":["06_族氏方国"],"year":2019,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2019.02.003","pages":"20-25","volume":""},{"id":1956,"author":"杨承友; 陈晓芳","title":"“鬼方”新考","abstract":"历史上关于&quot;鬼方&quot;的研究分为北方说和南方说。作者仔细研读史料,发现北方说代表性人物王国维的&quot;鬼方&quot;就是&quot;畏方&quot;的判断、北方说的&quot;鬼方易&quot;的解读都存在破绽,并且从地理方位来判断&quot;鬼方&quot;在北方的不可能性,也剖析了梁伯戈&quot;鬼方蛮&quot;的&quot;蛮&quot;字的普遍涵义,从而肯定了南方说的科学性。","categories":["06_族氏方国"],"year":2019,"publication":"遵义师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoURjUlzdMesp89Ja9H77dxJEdJ282H2tS6ET7wP0hFnDU307rlFMI6PYTX_U4Vwm0-_3vySui8m974ja-X2niEX_IgKFnCmDhQzCk3cVFH5p6NqHqcExZ3dro-KotVMPQJbB5rD8yLeeYocKp-07wMUNEACCXlZwe8JtnnuhhWEq60E19mJUt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-34","volume":"21"},{"id":1969,"author":"黄锦前","title":"师臾钟及相关铜器系联研究","abstract":"本文对陕西扶风强家村铜器窖藏出土的师臾钟年代与铭文所载虢季氏世系重加分析和讨论,指出师臾钟应系西周晚期厉王时器,同出的恒簋的&quot;恒&quot;应即师臾的先祖&quot;虢季&quot;。铜器窖藏的形成当与西周末年厉王时期国人暴动所导致的社会动乱有关。同时对太师小子豢簋等一批过去年代判定错误的器物重新断代、系联,将西周时期在王朝历任师职的虢季氏家族的有关铜器串联起来,反映了虢季氏一支自西周早期昭王世至西周末的发展脉络,对更清楚地认识虢季氏家族的历史和西周历史发展的有关细节皆有裨益。","categories":["06_族氏方国"],"year":2019,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJNHEc-tEqf1zCnFkEKamTvQjsp2KVyW1Yee3jj9-l0-2ykpWHeL9nkeuEtUT1zFOHb3w3wCmvkt8N6qz-DHm6cDzjaZaKizF0A8JQpV9dkt-VEwUMXr_LaQkaKx984vUD00VjdbpEUsZmnOLHQmFP7Kq6yDu-AQIgehFDtW6PRVRPx4CqqISpL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-63","volume":""},{"id":1979,"author":"郭德海","title":"卫康叔墓蠡测——卫侯墓研究回顾与名称隶定","abstract":"辛村墓葬1931年发掘后,大型墓墓主人问题甚少有人论及。文章回顾卫侯墓研究工作并隶定墓葬遗址名称;卫师甲泡、成周戈等出土兵器可证明该墓葬为卫国公侯墓葬群;出土青铜器陆尊和传世青铜器沬司徒疑簋等青铜器上的铭文是蠡测21号墓墓主人为卫康叔的有力证据;根据西周墓葬习俗和墓葬位置关系,推定21号墓墓主人为年代最早的卫公,蠡测21号墓为卫康叔墓。","categories":["06_族氏方国"],"year":2019,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLt_jhf0QKuqeqaPE2fBRpPHR28aZwibMInIuPHF4QHltwBDoH5ibGoOk1luo8oC47MxIg-DvwGOpuN58st89Zt8q9PuFlyy3tTrn1ECU0UyPSXCCEIIaPboimMC2CBhOAXg6LnZfO6Ufhu9VklUBYzAlLElDYJfZhJBzDPW6iPUdm0vHgzX7sE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-65","volume":""},{"id":1988,"author":"田率","title":"宜侯夨簋铭文相关史地国族问题补论","abstract":"本文借助高清的宜侯夨簋铭文照片,纠正了以往释为&quot;入&quot;的字应为&quot;内&quot;字,并对&quot;立于宜&quot;、&quot;&quot;等词句进行了新的解释,梳理了西周时期夨、吴、虞、宜等国族源流脉络。","categories":["06_族氏方国"],"year":2019,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2019.01.004","pages":"39-44, 126","volume":"13"},{"id":2207,"author":"李雪婷; 张昌平","title":"西周诸侯国地位研究","abstract":"目前发现的西周诸侯国遗址分布各地,与文献中记载的西周时期诸侯国林立的情况较为相似。考古发现的西周诸侯国遗址往往是通过墓葬材料中的国属铭文加以确认。这些国属铭文一般出现在国君墓葬中,并且国属铭文之后,通常会有称谓铭文来确定国君的身份。然而在不同的诸侯国遗址中发现的国君称谓会有所区别,常见的包括“侯”“伯”“公”“子”等;这样的现象与文献中记载的五等爵制又具有相似性,而五等爵制与诸侯国等级地位有明确的关联。因此,本文意在通过考古学材料和考古学的方法来对诸侯国之间的地位关系作研究。西周青铜器年代序列研究基本成熟,因此本文将在已有研究的基础上对诸侯国遗存进行分期,采取公认的早、中、晚三期的分期方式,将诸侯国遗址纳入到统一的年代框架中。西周中期材料较少,并且与早期材料之间有较强的延续性,因而在问题分析中将西周早中期进行归纳,以两大时间段作为问题分析的基础。西周诸侯国遗址遍布各地,以丰镐-成周为中心,","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27379/d.cnki.gwhdu.2019.002419","pages":"","volume":""},{"id":2208,"author":"刘树满; 曹玮","title":"西周时期黄河中下游诸侯国青铜容器整理与研究","abstract":"本文主要从三个方面对西周时期黄河中下游诸侯国青铜器展开研究。一是对该地区政治地理环境的论述,试图通过考古、文献资料理清西周王畿地区与诸侯国在空间分布上的关系。二是对目前资料比较丰富的诸侯国青铜器进行系统分析,理清各诸侯国的发展演变脉络、组合关系及风格特点。三是对诸侯国青铜器进行文化因素的比较分析,探讨各诸侯国之间以及各区域间的文化差异,并揭示产生地域差异的原因。现将主要的发现和结论摘要如下:一、黄河中下游诸侯国的政治地理环境分析。西周时期的黄河中下游地处中原腹地,地理位置比较特殊。从自然环境看,该区域地貌类型多样,山脉和河流相间分布,自古以来是中国粟作农业文化的腹地,是当时人类生活的理想场所。从政治环境看,该地既是周王朝的权力中心,也是诸侯国的主要分布区,王畿以外尤其以黄河的支流汾河谷地和太行山两翼的山前平原最为重要,是西周诸侯国的重要分布区,以晋国、卫国、邢国等为代表的姬姓大国,成为周王","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2019.001462","pages":"","volume":""},{"id":2749,"author":"杨健; 张俊成","title":"小邾國金文及相關問題研究","abstract":"春秋戰國時期,列國林立,見於文獻記載者數以百計,然除個別大國典籍記載詳實外,其他小國多爲隻言片語,出土的考古資料亦不多,給先秦各小國的研究帶來極大的困難,小邾國的研究正是如此。2002年東江村小邾國貴族墓地的發現,爲小邾國的研究提供了新的契机。小邾國貴族墓地,爲3組夫妻異穴合葬墓。6座墓葬中M2、M3保存完好,M4、M1、M5、M6遭到不同程度盜掘。小邾國貴族墓地雖遭盜掘,但墓地仍出土了26件(M1出土5件,M2出土12件,M3出土9件)有銘青銅器。加之警方追回的11件和北京中貿聖佳國際拍賣有限公司從香港購回的13件小邾國墓地被盜有銘青銅器,目前已知的小邾國墓地有銘青銅器共50件。這些有銘青銅器中記載了邾友父、胙曹等大量人名,對於研究小邾國的分封、國名、族屬、世系等問題具有重要意義。如文獻中關於小邾國始封之君的稱呼有“肥”、“友”、“友父”三種,小邾國貴族墓地M1出土4件“邾友父鬲”,鬲銘","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhvxrtGypJzB-1U7NTFdjInzGBaZCgFLg0C6UU-52_4oKrVhY7DgFRBGyycqhyaflu9vGBwr35cFCKWU1pIIanN2zjs3RmB1OUr-GGrZG5GGz5jsMgBPtKTv-udJVp09QREV9pFeIoArgWavkMe51jjsfHRuwN3qNOTAmLGETUOH66FtDSnFMZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2751,"author":"李变变; 谢耀亭","title":"《史记·晋世家》新证","abstract":"《史记·晋世家》记载了晋国从兴起到被韩赵魏三家所灭的发展历程,是研究晋国历史的基本文献,历来受到人们的重视。随着山西省考古工作的深入开展,出土了大量与晋国有关的遗址、墓葬、青铜器、简帛等考古资料。学者们利用这些新出土的资料,形成众多研究成果。本文尝试整理这些出土资料与研究成果,结合传世文献,从世系、纪年、都城、疆域、事件等五个方面,对《史记·晋世家》进行新证,以期有助于晋国历史的研究。首先,结合传世文献与晋公、叔夨方鼎、觉公簋等铜器铭文,以及北赵晋侯墓地、曲沃羊舌墓地等,对《晋世家》所记晋君世系进行了考证,得出《晋世家》记载的早期晋君世系可信的结论,并对叔虞身份、叔虞受封原因、燮父改国号原因、羊舌墓地族属等问题进行了考证;理清了哀公、懿公、敬公实为同一人,孝公又称桓公,静公即悼公。其次,利用《左传》、《世本》、《竹书纪年》等传世文献与觉公簋、晋侯苏编钟、羌钟等铜器铭文及《清华简》等,对《晋","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27287/d.cnki.gsxsu.2019.000975","pages":"","volume":""},{"id":2767,"author":"张晓莉; 耿超","title":"西周早期燕国青铜器研究","abstract":"燕国是两周时期重要的诸侯国,西周时期它是周王朝在东北地区的重要屏障,地位非常重要。本文以考古发掘出土和传世的西周早期燕国青铜器为研究对象,主要从三个方面对其展开研究。一是运用类型学方法对西周早期燕国青铜器的型式分析,并据此对其进行分期断代,通过对器物时代特征的梳理,对青铜器的变化规律有进一步认识。二是以西周早期燕国墓葬中随葬青铜容器组合较完整的墓葬为研究对象,分析西周早期的青铜容器组合,并通过与中原地区墓葬中随葬青铜容器组合比较发现其特征,通过分析墓葬中随葬鼎簋情况,探讨其鼎簋制度。三是对西周早期燕国青铜器铭文分析,首先对铭文书写风格进行分析,发现其字形特点。然后对铭文内容分类,主要分析赏赐类铭文中提到的人物和铭文中体现的燕国与其他地区的交流互动。最后通过分析部分铭文来考察燕国早期世系及铭文中体现的居民来源。","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5a6_d3XFZOwMkhsimIWdiZU0AOidCfc_PrJkBBiSMwq6AXJlkjYCi9qD2MDyHz9pH76Ea09gJioBPUb3IrBcCDtRkpGUziNFYXi9Dqs3DYIYyJt6c1BU9zJTr6sDoQWVRq2YoaBmOGIT6HsSIC9m-bIekqLIKsfaW0Davgw7p69kpmYu-AK1E&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2775,"author":"高晋南; 胡新生","title":"商周青铜器族氏铭文历史来源分类研究","abstract":"有关商周族氏铭文的构成、内涵和意义等问题,是当前金文研究的难点也是热点之一。近来已有多部论著对商周族氏铭文资料作了系统的整理,并就上述问题提出了很多有价值的论断和推测。这些研究为准确把握商周族氏铭文的历史面貌奠定了坚实的基础,也为后来者继续探讨该领域尚未解决的难题提供了启发。在前人研究的基础上,本篇论文尝试对商周青铜器族氏铭文的历史来源、类别划分及其与周代贵族命氏制度的联系等问题作些新的探索。本文所说的“历史来源”并非商周族氏铭文与某些史前文化中的刻画符号之间的历史渊源,而是特指族氏铭文的构成成分的社会政治内涵和来源,对于前者的探讨是另一个需要专门研究的课题,本文暂不涉及。依据构成成分的含义和历史来源,本文将青铜器族氏铭文归纳为图腾类族氏、祖先名字类族氏、官爵类族氏和地名国名类族氏四大类。通过对商周族氏铭文来源的分类归纳,可以发现商周青铜器族氏铭文的四个主要来源与后世西周春秋间流行的“因生","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnH-EMeFS4-_NCkCQ2S4OA3aIrG5JIIzB_25vrBRPJrXojc-0axvwiWcKWmb7X9dYfcea8ZuhktUUzYwFxsnIpUIqx82xzuX5nbu3qSoFrdGlUyfd44tvkb2uX37FCtPyQXJaSVZe6pMJgNk4Y50PgjBRBhesgtVacNWuFjmhs1exW8oFypEj9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2797,"author":"姜春萌; 王晖","title":"周原出土西周青铜器及铭文族属问题研究","abstract":"周原在西周时期为周人的核心聚居区域之一,即使在周公营造洛邑之后,周原依旧是周人的重要活动区域。根据目前在周原发掘的考古资料可知,在西周中后期,周原这一地区有众多贵族家族聚居。直到西周灭亡,周王室都洛邑,周原地区在周王朝的重要性才迅速下降。自汉代以来,周原就陆续出土西周青铜器,但是由于其历史过于久远,保存不易,难以明确出土时间与地点,所以对其铭文的研究成为学术界的重难点之一。清末到民国时期,大部分出土器物的时间和具体地点已经开始有较为明确的记录。建国后至今,周原地区多次发现青铜器窖藏,周原考古队等考古工作团队对遗址墓葬区展开科学的考古工作,也发掘了大量的西周青铜器窖藏。出土铜器的铭文内容,涉及西周的社会制度等多方面问题,也有助于探讨纪年等问题。周原的青铜器窖藏,大多数埋藏极为精细,窖藏中的青铜器在埋藏之时,按照一定的规律摆放,基本上都为某一人或某一家族的器物,并且大多有铭文。除此之外,部分家","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2019.000401","pages":"","volume":""},{"id":2798,"author":"孔丽静; 张志鹏","title":"蔡国有铭铜器整理与研究","abstract":"数量丰富的蔡国有铭铜器,蕴含了大量的信息,对探究蔡国的考古、历史、地理等问题有十分重要的意义,也很好地反映出了蔡国青铜文化从西周到战国的发展变化情况。本文先对蔡国的有铭铜器进行全面地收集和整理,根据形制、纹饰以及铭文的因素进行分期断代,再结合传世文献和考古资料,探讨蔡国青铜文化的演变过程,以及铭文涉及到的史地问题,进而对蔡国的历史进行一个详细的分析。首先,笔者按发掘时间将蔡国有铭铜器的出土情况做一个简介,并对个别重要墓葬的随葬品情况进行简单说明。接着对出土地点明确的铜器、传世器、新见器物以及与蔡国有关的有铭铜器也汇集整理起来。在此基础上通过对器物的形制、纹饰和铭文等信息的分析,判断器物所属年代,必要的时候运用比较法,尽可能详细的推断作器时间,尽量详尽到某位蔡侯的年代甚至是某一年。然后,主要根据器形及铭文的变化,分析蔡国青铜文化受周文化、楚文化及吴越文化的影响,并结合当时的历史背景对变化缘由","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27118/d.cnki.ghesu.2019.000153","pages":"","volume":""},{"id":2800,"author":"王静; 田成方; 樊温泉","title":"霸国有铭铜器及相关问题研究","abstract":"霸国位于山西省临汾市翼城县大河口村,是根据大河口墓地出土的青铜器铭文而确定的一个西周诸侯国。随着大河口墓地材料的逐渐披露,霸国的族属及历史问题引起学术界的关注。本文以霸国墓地出土材料为重点,通过全面收集、梳理与霸国相关的有铭铜器,结合文献材料以及近年来对霸国铜器铭文研究的最新成果,探究霸国的历史、族属、文化面貌等问题。正文分三部分:第一部分分析霸国墓地的葬制、葬俗,将霸国墓地与姬姓晋国、芮国、北燕国墓地、媿姓倗国墓地进行对比,指出霸国墓地的早期墓葬异族特征明显,中期受周文化影响较深,但仍然在壁龛、斜洞、随葬原始青瓷与漆木器等葬俗上保留了自身的文化传统。总体来看,霸国墓地与姬姓国族墓葬在葬制、葬俗上的差异较大,与横水倗国墓地在葬俗上的共性更为突出,其文化渊源和族属可能相近。第二部分具体分析了与霸国相关的有铭铜器及铭文内容。霸姞鼎、霸姞簋之“霸姞”是嫁入霸国的姞姓女子,反映了霸国与姞姓国族通婚","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKaPrfmaxIo3TAitnV5rUdsn6Xq7oFtZObqjOayt1nCB4RHG168dI9WYqcz8SwX4BmN-sUOrl3jJ1l_u0fxTxNTIJw-67jUr3XfHDVWXfTySfBhRMH9hHg5XdZ9wTU-OFS7BRr44tH4ulT6tugQbxtTpqBfAGSYMv9p_AfWxOJm03L9TCG1Wcqb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2808,"author":"于桐; 蒋金玲","title":"辽金时期鲁谷吕氏家族研究","abstract":"辽朝是契丹人建立的多民族政权,契丹人与汉人作为辽朝诸多民族中最具有影响力的群体,探究非汉族王朝下统治者的民族政策与汉人世家兴衰的关联,有助于了解其相关统治政策以及汉人的心态、地位与作用、各民族发展及民族间的交融具有典型意义。本文主要利用已出土的墓志石刻,并结合相关文献史料,对辽金两朝时期鲁谷吕氏家族的世系、仕宦、婚姻、家学等方面内容进行全面、系统的论述,以期最大程度还原此汉人科举世家的面貌,考察其家族长盛不衰的原因,从而深化对辽金史的认识。本篇论文分为绪论、正文、结语三部分。绪论,主要包括本文的选题目的和意义、研究现状、研究方法与创新等,从而为正文写作奠定基础。正文分为四章。第一章,辽金时期鲁谷吕氏家族世系考。吕氏家族目前可考者共有十代人,分为吕德懋、德方两系,以吕德懋、吕士宗、吕嗣延等杰出人物为代表,子孙后代跨越辽金两朝。第二章,辽金时期鲁谷吕氏家族的仕宦。吕氏家族迁至燕地后,一直以耕稼","categories":["06_族氏方国"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL4w6OTU5oK9wtfbMaA47G0holqvXZIUmduLloU0MzkQqDd0pPAzfa_Cyq2XuJIpSMBukogAOOgUINetfg_DfxTKK13S0q3_9opHXHXTS8-QruyQGlSX949WSNWm-xGnETvNzVQ8GpWynUEDeQ5k7x6I1Ha_F_vQlg4FVTTavaRZwH9Mx3DjY09&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3089,"author":"刘攀峰","title":"《金文世族谱·帝系谱》校记","abstract":"吴其昌先生的《金文世族谱》一书是第一部利用金文材料对周代世族进行全面系统地整理和研究的著作，书中有诸多创获之处。但随着出土材料的不断丰富和研究水平的日益提高，书中的不妥和漏洞之处也逐渐凸显出来。本文对《金文世族谱》中第一篇——《帝系谱》的内容进行了校记，希望能够抛砖引玉，使《金文世族谱》一书在今天仍能发挥它最大的价值。","categories":["06_族氏方国"],"year":2019,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGAE-tQiEowdUcrR-t-NSaw5SkkTbfRYgRzHTpN4-bSvrGP8P23q0r4h3lvv7BHr9PHJc2PzKkNrTQALr8VnEGoTkt5ttf3vSOg0WXip3Iyv0N_GD00XIuVUWOFl_uaPOaQ3A33uf4RHUX2jSKTdp8z-CVoUUTYl79Q9YKMUFzCA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"164-168","volume":""},{"id":3288,"author":"马超; 邹芙都","title":"仲阪父盆自名与古圭国研究","abstract":"仲阪父盆自名为&quot;益&quot;,属金文首见,颇为费解。学界或将其读为彝,或认为从■得声而读为盆,恐均难成立。益声之字或被音韵学家归入质部,从出土文献所见资料亦可推知&quot;益&quot;与质部关系密切,金文&quot;益&quot;字形体也应分析为从八、从血双声,据此知铜盆自名&quot;益&quot;应径读为&quot;盆&quot;。盆铭&quot;■伯&quot;之&quot;■&quot;为玉戈专字,当释作圭,&quot;圭伯&quot;就是圭地封君。《左传》载郑穆公后妃有&quot;圭妫&quot;,同为圭国之人,仲阪父盆证明了西周晚期作为帝舜之后的妫姓圭国就已存在,这对先秦古国历史、姓氏源流等研究具有一定的史料价值。","categories":["06_族氏方国"],"year":2019,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgrwO90ihLYOx80eVfaYpk52J3_UKhydCDSSVxlzTtTp1TTqPnV4yAMte3AkSc6Tt_57jpMrO8LCEumX_-sN93EfbD8RBKGbihuQ1Bk_zZML82QOiSrSgeusMCFphIzMw5HOavImnzwvJBTgadNT0rIbmUDAicULKAbaSJZOKBYw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-25","volume":""},{"id":3320,"author":"谢明文","title":"“■”族铜器铭文的整理与研究","abstract":"&quot;■&quot;,旧主要有&quot;离&quot;&quot;罗&quot;&quot;禽&quot;三种释法,本文赞同&quot;禽&quot;这一释法。通过对族铭文资料比较全面的搜集整理,本文指出过去的相关释法中,有很多铭文中的&quot;示&quot;字都被漏释了,而亚干示爵、亚干示觚中所谓的&quot;干&quot;应看作&quot;■&quot;之省。相关铭文中的&quot;示&quot;既不是器主的私名,也与古代祭礼无关,它可能是族名&quot;■,示&quot;是&quot;■&quot;族与&quot;示&quot;族组成的复合族名。","categories":["06_族氏方国"],"year":2019,"publication":"西部史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiPHOY2F2ufigP-nbZJMmNkpeHw744isritDoMP-IQw93M8MLmzqmVYvkrTX9TrLOAHK_1LUVp5S3kWruWkIkd9Urd14v8hkRnJPfOS0obDapJN3HOApIuR_hULMNZTbbmTlagheJf7flQgWvHTFFDVxf1qhhWJU0LkoESpQLVpw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-63","volume":""},{"id":3347,"author":"張志鵬","title":"逢叔盤與匜及相關問題研究","abstract":"自山東濟陽劉臺子墓地資料公布後,[1]多位學者綜合傳世文獻、逢國金文與考古資料,對逢國地望及其變遷、逢與周的關係等問題進行了很好的研究,[2]但還有進一步探討的空間。本文擬在重新認識逢叔盤與匜的基礎上,參考前賢時彦的研究成","categories":["06_族氏方国"],"year":2019,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOJxbd0H-1VNpLvRs0CBEaLaBmzEAr7LISXmzYW_lLxqE2ZHTwIZwmZnpcoRhLtWnSXnwB-kCITJ_K2ubKZFCDvIAG1zk-N6Yq0Z0mZFnnbWCZQYxk20ZvUu8jRDXF-OtBEEtxCWvnht3O70Cv-LILUMWUeiKIwsacE1Dpme5aRg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-101","volume":""},{"id":3377,"author":"馬超; 鄒芙都","title":"新出霸國銅器與宜國地望研究","abstract":"一、宜國歷史的幾點争議宜作國名本不見於傳世典籍記載,直到二十世紀五十年代康王時器宜侯胡[1]簋的出土才爲世人所知。據介紹當時銅簋的出土情况是:一九五四年六月間,丹徒縣龍泉鄉下聶村農民聶長保的兒子在煙墩山南麓斜坡上翻山芋地&quot;壟溝&quot;時,無意間在地表下三分之一公尺的土裹掘出一隻鼎,他就小心地擴大挖的範圍,在三分之二公尺的深度,共掘得銅器十","categories":["06_族氏方国"],"year":2019,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLKl6DvWCtJj2ryUyGnCzNyJv-keS0xcEijFq5-OR058HDnvcMYqjSovoqNsiwaHrm2kpdzAJgHBFqZvvidmEmmDkKvqAW1RwqYYlGKjHrdNZywUI7_AN58yeMRoXaA7_yooicwLuS6Dl9bZLhHukegSslLZ6VxI6Cwvj3jlJym5Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-73","volume":""},{"id":3386,"author":"张程昊","title":"略论西周氏族的地名标志","abstract":"西周时期有不少氏族以地名为氏,同时西周金文中也有一部分人在其族氏名之前添加地名作为标志。通过梳理西周金文,我们共整理出郑、丰、丼、晋四个地名标志,并对这些地名标志的使用情况进行了分析。分析结果显示,西周氏族所用地名标志的产生是氏族分化和氏族迁徙共同作用的结果,使用地名标志主要是为了与同一氏族中的其他支系相互区别。同时,分析结果也表明,西周中晚期有多个氏族成员集中迁至郑地,这一现象当与周王经营郑地有关。此外,西周早期铜器丰卣铭文显示,■族人物&quot;丰&quot;曾迁徙至晋地,并且很可能与唐叔虞之子燮父徙封至晋地有关。","categories":["06_族氏方国"],"year":2019,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBNF07D7gq-ysbPxG27wGHcDV8fz8ur6nkGsIGd_COjiJ9GLbhkcvmWRB-dfD-ni3R96EzKgb9VS8bwUXGlBV9XiW1yL1KJqoVIpnj1QEmt6XUQ3oPJIfy8s50Sd_CMNT5x2dcl0gxTVK0qMqiUTLWT17TwRI0aoh2XVKJThn_Cw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-118","volume":""},{"id":3387,"author":"辛怡华","title":"岐山孔头沟遗址族属及相关问题","abstract":"以赵家台遗址发现空心砖为线索,周公庙考古队于2006年对其周围进行了大规模科学调查与发掘,取得了丰硕成果。本文在学者研究基础上,通过对双墓道墓葬M10出土的尚爵铭文的研究,结合遗址考古资料,认为尚爵铭文中&quot;墉公&quot;就是姜太公之次子,&quot;尚&quot;可能就是&quot;献公&quot;,而孔头沟聚落遗址所在地在商周时期是太公次子的封地,也就是太公家族的采邑。","categories":["06_族氏方国"],"year":2019,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIiLMgG6RD3mz0l7K5qDvZzZHbwzW02cfAuRxJWm6N_7kqwSEDXuyzqc68MAUZSgxRWJt1v1rpU8_aAOcppW50hNmF_l20vIfN8VBr2dEV7h3bc7VoVvGuLbbdb9wvsEDzq-zgVqjslfTRVrHZNLhouAXS6y7pdvmqekesiEMTCxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-98","volume":""},{"id":1993,"author":"薛璞喆; 贺淑红","title":"《商雒鼎铭》探究","abstract":"《商雒鼎铭》系北宋英宗治平元年(1064)欧阳修从刘敞处得见。因得之于商州上洛郡,故依此命名之;后郭沫若依铭文所现&quot;下鄀&quot;二字,又命名为《鄀公缄鼎》。通过对铭文内容的考释,该鼎制作于公元前699年或公元前639年的末月晦日,也有可能是祭祀时日;&quot;下鄀&quot;地处丹水下游之商密,与楚国比邻。西周末春秋初,二鄀是并行的。","categories":["06_族氏方国"],"year":2018,"publication":"商洛学院学报","link":"https://link.cnki.net/doi/10.13440/j.slxy.1674-0033.2018.06.013","pages":"67-70","volume":"32"},{"id":2002,"author":"王进锋","title":"西周时期小贵族家族的崛起——以董家村铜器所见裘卫家族为中心","abstract":"西周时期贵族家族的地位并非始终不变,而是在历史的发展过程中有起有落。某些最初地位比较低下的小贵族家族后来反而兴盛起来,裘卫家族就是其中的典型代表。我们可以通过考察它的发展轨迹,来窥见整个西周时期小贵族家族崛起的状况。裘卫家族主要见于董家村铜器。对董家村铜器的时代弄清楚之后,我们可以大致看出裘卫家族的人员、世系和发展轨迹。裘卫家族在西周中期的时候只是一个小贵族家族,后来通过不同代人持续的拼搏努力,再加上与更大的贵族家族的联姻,最终在西周后期实现了家族的崛起。","categories":["06_族氏方国"],"year":2018,"publication":"历史教学问题","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ63-kyhcWu0hwmprA-5XsYaZolZ-Lohy43zL-DT5Enne-S2BxVHOq50E4mJIy7U2aoEaUTuMiYkG3C1lf8CwE5kqZBXgQmrC6NwwQQ2YnRFR0I1V_Z_3ZsO0cLz41570bJgbKo3-2Tk_346qJvJfORxJqP6xA8BGhKLDksOshn5kpvNxrc16mO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-38, 135","volume":""},{"id":2008,"author":"侯乃峰","title":"山东沂水纪王崮春秋大墓墓主蠡测","abstract":"山东沂水纪王崮春秋大墓的墓主究竟属于春秋时期的哪个小国,为中国考古学界出了个难题,目前已有多位学者提出好几种说法。通过对墓中出土的青铜盂铭文&quot;邛&quot;字的分析,结合纪王崮春秋大墓的具体地理位置,笔者以为邛国最有可能是指《左传》中提到的项国,并对此说法进行了论证说明。","categories":["06_族氏方国"],"year":2018,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfPdg1jqPRil8VguE3pLw4UlJyth5Po7CBuDGZlK43OZuXTUzCI0QKSsA2YYSs3kwOwrk6om5bKp7rCNQvyOFLcNdBz_fAFfRXnwFWvWmfgxmp-HONjPSDydYW8UaoK_Ba4kXR6QjjOMd9SjsnaDzbZNCvI_uaQYaDPUnigkFVLNfLGffD6XoA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-77","volume":""},{"id":2012,"author":"黄锦前","title":"湖北枣阳曹门湾M43出土铜器铭文及相关问题","abstract":"从器物形态及铭文辞例等角度考证,可知湖北枣阳曹门湾M43出土铜器群的时代为春秋早期。从器物时代及称谓来看,湖北随县周家岗所出曾太保簋的曾太保当与曹门湾M43出土的曾太保发簠的曾太保发关系密切,二者或系前后任的关系。夨叔匜出于曾国墓,系曾虞联姻而致,孟姬系M43的墓主。","categories":["06_族氏方国"],"year":2018,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAI4sTYTqfR0hDnCh2Z6Jm19PwkOVLuYzsaoZRWZSqQzIUMxVUFJz-pOg5NOmoPVGnKpRSxnRbJTDnwSaPRPNh96NfTh1C4Q36_IcvQYN7FkCjl3lMGN_MKXfhkfshquBSbOXFnHMaFRBxUQgTI4TJACxvUocS19_Sytz963XzNNGZ8JjLvJFQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-40","volume":""},{"id":2021,"author":"王长丰","title":"殷周金文族徽内涵研究","abstract":"殷周金文族徽可分为两大类:一类可称为基本族徽,另一类则称为盟姻族徽。基本族徽是反映社会、宗教、血缘亲族组织最基本的族属单位,是封国、命姓、授氏等制度的具体体现。殷周金文盟姻族徽在形式上就是由基本族徽通过累加或缀联等形式形成的族徽类型。这些盟姻族徽本质上就是由国族姓氏之间的以&quot;同轨&quot;&quot;同盟&quot;&quot;同位&quot;&quot;外姻&quot;等途径形成的&quot;结盟&quot;或&quot;外姻&quot;等关系的血亲组织,不同形式的盟姻族徽代表着不同的盟姻组织。","categories":["06_族氏方国"],"year":2018,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLBpPJR16u0paBjCOoQjJW1kOIUmy69FBOaN3hdIdyWN6REN7s5IK7w45ahdmSTo6VFea2WPOEHYN5lvy2e9v_ZvlSTTM9HLQ_jnaQL2vwok8iquvpic89I0HU7RD4KtW9UXGzUVZvFcILeh-PxpSmt7_uzmFVWCCp3S5lfervtTPXj6HLou_en&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46155","volume":""},{"id":2032,"author":"李腾","title":"四年咎奴蓸令戈的国别及相关问题","abstract":"四年咎奴蓸令戈,以往关于其监造者的名字多有误读,国别的归属也有待商榷。我们将字形和文例联系起来,可得出监造者&quot;■■&quot;应释为&quot;狄■&quot;,而不是&quot;壮罂&quot;。考虑到皋落戈之&quot;皋落&quot;得名于东山皋落氏,无终三孔布之&quot;无终&quot;得名于无终,露方足布之&quot;露&quot;得名于赤狄潞氏等等,四年咎奴蓸令戈之&quot;咎奴&quot;应得名于廧咎如。我们通过对廧咎如地望的考察发现,其地望战国时属赵国领土范围,故我们可知得名于廧咎如之&quot;咎奴&quot;乃赵国城邑,四年咎奴蓸令戈为赵国兵器。而这些带有少数民族族称的器物也在某种程度上反映了赵国民族融合的历史及多民族国家的特色。","categories":["06_族氏方国"],"year":2018,"publication":"邯郸学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjoahQTo1gJEY0AsuGzq4taUs7I7edyiTqD9Jua5wGhuLr10HLyhmlvh6IuWUkdc5tVWVByzFBwCLJgHiZ-BGlKn8WbPCOBY_zzyuNu93adWS3LInRjme2aSN7NqphoTGTxOq2y_Ir3uH-6I61eX35EwlTV3UnO_O9nMu2zNoNIvmb_kIBktKo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-36","volume":"28"},{"id":2068,"author":"黄锦前","title":"龏?诸器及相关铜器系联研究","abstract":"传世两件龏?鼎与龏?觚应系同人所作同铭器,据此可以订正过去对鼎铭的有关误释和误解;从器物形制、纹饰及组合等角度来看,龏?诸器的时代应为商代晚期,而非西周早期。据以器物铭文、形制纹饰及出土地点等线索,可将龏?与河南辉县一带出土的子龏及子龙诸器加以联系,&quot;子龏&quot;与&quot;子龙&quot;实即一人,&quot;龙&quot;系&quot;龏&quot;之省;龏?方鼎及觚铭的&quot;龏?&quot;与女子觯(子龙觯)及龏母簋的&quot;龏母&quot;或即一人;&quot;子龏&quot;与&quot;龏女(母),子&quot;铭文同铸一器,二人或系夫妻关系;子龏应系子族,系商王室贵族,所任应系高级武职,其聚居地应在今河南辉县一带。据以文字和文例,&quot;司&quot;或&quot;?&quot;即&quot;姒&quot;,系商王之配偶;&quot;龏?&quo","categories":["06_族氏方国"],"year":2018,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2018.02.007","pages":"30-37","volume":"39"},{"id":2071,"author":"丁军伟","title":"甲骨金文所见“失族”问题再论","abstract":"甲骨金文中&quot;失&quot;字常见,通过对甲骨金文及相关资料的梳理,可以发现甲骨卜辞中&quot;失族&quot;主要活动于武丁时期,武丁早期及中期前段其与商王朝处于敌对状态,武丁中后期其被商王征服后长期臣服于商朝,并在王朝任职,卜辞中其地望当在晋中、晋南一带。洛阳马坡一带乃其后人迁徙之地,据金文来看,此族人亦曾在周王朝任职。","categories":["06_族氏方国"],"year":2018,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2018.02.005","pages":"19-25","volume":"39"},{"id":2073,"author":"杨亚长","title":"浅说金文新见之韩侯","abstract":"据典籍记载,西周时期曾有韩国,此古国已为新出金文得到证实。古韩国为姬姓侯国,其地望历来众说纷纭,本文经辨析后认为,当以山西省河津与万荣之间说最为可信。","categories":["06_族氏方国"],"year":2018,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpcWCs7Dq9893AuS6aKdabp96i7PRD1y9_NgXGYh9BygUCglFQMCMaTLsyj6adVZJB3z1fYbXO-SjtxySBGaJndG76D5-3tHnDToGBkCiG5Kg5noTlED7GrRLY7ZAMHqDH6Vm9sq6Fu0BfhaadPAo0PaFKofIOp5uL4OJPYWdI2RW3Q7TFtrku&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-66","volume":""},{"id":2076,"author":"孙敬明","title":"剑戈不容渎犯者必惩戒——从新见郳公戈谈起","abstract":"先秦时期海岱区域古国众多,尤其鲁南一带更是方国林立,直至战国时期尚有&quot;泗上十二诸侯&quot;之谓。今枣庄一带有:历史极为久远的夏代老牌曾和薛、商代见于甲骨文记载的邳、西周初年新封的滕;以及西周晚期从邾国分衍而出的郳与滥国。经过千百年的历史发展文化积淀,在此广袤的区域内留存丰厚的人类文化遗存。大地坤厚,黄土沉沉,掩埋着众多的城址、宫阙、碑碣、造像和无数的王公贵族与平民百姓的丧葬之圹。它们长眠地","categories":["06_族氏方国"],"year":2018,"publication":"走向世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_d6v51m7ZMyrkMxUQF-N2T8hpK-RDvQl-Klds4v9RknSH7n4iG-W03-bNQLnep8JHDE4qk1HWjp4LGV4Dn7AmSG--dvqnjoCZALyns8U37hk22Zz6TUA0UeDRnwXNhPI2hZbLPnlFgTtJBrUJhQZsBLUlOF0fM3wNU2JK6K9wsssHAgzCi2ua&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-81","volume":""},{"id":2079,"author":"孙敬明","title":"鲁国出土异地商周金文通释绎论","abstract":"勾稽鲁国出土奄、薛、周王太史、燕召公、陈、楚国睽士父、郙、莒、乘父士杉、杞、邾、铸、邿、史显、宋、鄫、徐、齐赒子叔子、蔡等十九国族带铭文青铜器五十余件;铭文篇章人事名物所涉之疆域东起海岱,西抵周原,南达江淮,北逾燕代。试对相关铭文内容酌为联缀诠绎,藉以揆度各历史时期鲁国对外文化交流趋向与融合之态势。","categories":["06_族氏方国"],"year":2018,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.issn1002-3828.2018.02.20","pages":"122-128","volume":""},{"id":2092,"author":"黄锦前","title":"仲■父诸器系联及有关问题","abstract":"据以铭文内容、字体,结合器形、纹饰等特征,可以发现:传世两件仲卣(仲作好旅彝卣)的作器者&quot;仲&quot;,系传世仲■父组铜器的&quot;仲■父&quot;之省称,两件仲卣与仲父组铜器实系同一人所作。又从器形、纹饰、铭文等角度,对该组铜器进行分析,确定其时代应为穆王前期。对照近年发掘的陕西岐山贺家村M11出土的青铜器,对这组器物的组合情况进行推定,可以认为,它们系一套食器和酒器的组合,原本可能应有尊等器,已佚,或难以确认。器主仲■父的身份应与贺家村M11的墓主昔鸡不相上下,系高级贵族。","categories":["06_族氏方国"],"year":2018,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2018.02.02","pages":"13-16","volume":"38"},{"id":2097,"author":"杜勇","title":"新出金文与鄂国史地问题考辨","abstract":"随州安居镇羊子山和南阳夏响铺两地鄂国墓葬的发掘,出土了一批与鄂侯相关的青铜器铭文,证明了西周早中期鄂国的都邑当在安居羊子山一带。由此上溯商代末年,鄂都亦应在此,而非通常所说的河南沁阳。西周夷王时,楚君熊渠所伐之鄂非安居羊子山鄂国都邑,亦非南阳西鄂,而是当时鄂国的别邑,即后世所称的东鄂(今湖北鄂州市)。周厉王早期,鄂侯驭方联合淮夷、东夷发动大规模反叛战争,几经曲折和反复,最后王师伐灭鄂国,少量鄂遗民被迁往河南南阳一带,新封鄂侯以续其祀,夏响铺鄂侯墓地即其遗存。此支鄂国遗民,清华简《系年》称为&quot;小鄂&quot;,后世亦称&quot;西鄂&quot;。鄂国作为西周中央王朝的藩属异姓诸侯,由臣服效忠到发动反叛而被诛灭,反映了当时统一贵族国家的结构形式已无法适应时代需要,将被未来历史发展所淘汰。","categories":["06_族氏方国"],"year":2018,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2018.02.01","pages":"46154","volume":"38"},{"id":2100,"author":"谢明文","title":"试论商周“或”族的分衍与联合","abstract":"族氏的分衍与联合是一个值得探讨的重要课题。本文赞成甲骨文、金文相关资料中的&quot;&quot;应释作&quot;或&quot;而不应释作&quot;戉&quot;,并且探讨了可能与&quot;或&quot;族具有分衍或联合关系的一些族氏。&quot;或&quot;族是&quot;望&quot;族的分支,而&quot;光&quot;族、&quot;或&quot;族是&quot;或&quot;族的分支,&quot;或&quot;族与&quot;&quot;族可能是联合关系而不是主分支关系。","categories":["06_族氏方国"],"year":2018,"publication":"杭州师范大学学报（社会科学版）","link":"https://link.cnki.net/urlid/33.1347.C.20180329.1420.036","pages":"127-131","volume":"40"},{"id":2110,"author":"赵庆淼","title":"“微盂”、“微斝”铭文补释与卫国早期历史","abstract":"旧称&quot;微盂&quot;、&quot;微斝&quot;的两件西周早期铜器,乃是卫康叔直系后裔所作的祭器,祭祀对象即卫国的始封君康叔封。以往学者多将器主名误释作&quot;微&quot;。实际上,该字应释读为&quot;髟&quot;,综合国族、时代及文字通假等因素来看,其人很可能就是第二代卫君、康叔之子康伯髦。清华简《系年》称周成王、周公迁殷遗民于洛邑,而封卫康叔于&quot;康丘&quot;,与沬土簋铭文记载的&quot;诞令康侯鄙于卫&quot;为同一史事。至于卫人自&quot;康丘&quot;徙居&quot;淇卫&quot;之举,则应该发生在康伯髦之世以后。","categories":["06_族氏方国"],"year":2018,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-WX-tTFmUC1PNI-Un_wZXTnI6gVq2eWQMp-kjimLYtiO3mztkG3Ziyyi2k_Ie7K4E4o7vMtBEYwckE8zjhw12Z6aQKnRs4qNOaWGnvaVA_mx2F4bAIxvCKSA61fNh-aQfj3lJfl4JwO4n9g5NtglS67qNKW0hxUM3IkvAphTRKfiFnaEKTZsw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-52","volume":""},{"id":2114,"author":"沈昕; 陈治军","title":"殷周金文族徽研究的集成之作——评《殷周金文族徽研究》","abstract":"古文字学研究员王长丰博士所著的《殷周金文族徽研究》[1]一书由上海古籍出版社出版,该书为北京大学震旦古代文明研究中心学术丛书之三十二,由夏商周断代工程首席科学家、北京大学考古文博学院李伯谦教授作序并题写书名。王长丰博士长期从事文献学、古文字学、历史学研究工作,功底扎实、视野开阔、成果丰硕。《殷周金文族徽研究》是其所著的第六部学术成果(1),也是其数十载潜心研究殷周金文族徽的集大成之作。全书分为上、下两","categories":["06_族氏方国"],"year":2018,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1KYXDfl5f3WPM6VY5QRwOsSlgPdmSLgWMznJk6OIn1HQ3o9aDc9P_2YWgmCHh7Cjc4XnliJsFJO3Gd8-mA5BoyUJ-6cQ6MlJjzsbjg1N5xSF18NMRCbF7dKiDFtAW-TxGnKcjgjv08PUZcSGFWb0d1QKFbkQGRnmJrLiTBnbChJdm7AMz8sxL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-113","volume":""},{"id":2128,"author":"马媛媛","title":"青铜器上的宋国史","abstract":"因宋国故地为黄泛区,目前存世的宋国青铜器数量极少,且无一件是在宋国故地经考古发掘出土。这些青铜器或为传世器物,或是由文物部门征集到的文物,还有不少是在其他地区考古发掘时发现的宋国陪嫁所送的媵器,这为宋国史研究起到了证史、补史的作用。除以上三类宋国青铜器外,还有一类虽为他国之器,所铸铭文内容却与宋国历史相关,这类器物也是研究宋国历史的重要出土资料。","categories":["06_族氏方国"],"year":2018,"publication":"商丘师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGaXotp1i30u1XLnkX9tifY8z8zkBt6Z9YN-ezC7oOb2-3Vh1vLouB6iW596TVzN4i2g0fh65iXHHFYKYTlAHjp8455U6U1P0Yzw-_JatU8P1n2y4ThrsphiyMRdWsgV_kj8bSKead0RTgV1gKmPK8kKw2aQ65YP2d48vo1e-PXGpbRUnE08iA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-73","volume":"34"},{"id":2134,"author":"高晋南","title":"商周族氏铭文中的鼗鼓形态与鼗族","abstract":"一般认为鼗鼓(即近人俗称的&quot;拨浪鼓&quot;)的图像始见于汉代画像石,其实商代青铜器族氏铭文中已经出现鼗鼓的形象。族氏铭文&quot;庚()&quot;字即是鼗鼓之象形,这是目前所见中国最早的拨浪鼓图像,比汉代画像石早一千年左右。商周时期的鼗鼓是大型礼仪活动中的重要乐器,故鼗鼓图形被执掌鼗鼓演奏及相关礼仪活动的乐师家族视为本族的象征。商代以鼗鼓图形为族氏的鼗族曾与商王室联姻,掌管军事、册命等事务,地位十分显赫。随着商朝的灭亡,拥有精美礼器和悠久文化传统的鼗族急剧衰落,不知所终。","categories":["06_族氏方国"],"year":2018,"publication":"民俗研究","link":"https://link.cnki.net/doi/10.13370/j.cnki.fs.2018.01.009","pages":"72-77","volume":""},{"id":2217,"author":"黄尚明","title":"曾侯世系考辨","abstract":"随着新的考古资料被发现,曾侯世系的再研究很有必要。曾国的始封者为南宫括,但南宫括并未赴任,文峰塔编钟铭文中的伯括和南公是同一个人,南公并不是南宫毛,曾国的始封时间为成王时期。&quot;曾伯陭&quot;仅是&quot;曾伯&quot;,不是曾侯。&quot;曾侯子&quot;也不是曾侯,把&quot;子&quot;当作曾侯的私名是站不住脚的,&quot;曾侯子&quot;意为&quot;曾子&quot;或&quot;曾公子&quot;,只是未写出&quot;曾侯子&quot;的私名。擂鼓墩二号墓墓主人不是曾侯,而可能是曾侯夫人。根据新的考古资料,在原知曾侯世系的基础上,又增加了曾侯谏、曾侯犺、曾侯宝、曾侯得、文峰塔M4墓主人(不知名字的曾侯)、曾侯丙。目前得知的曾侯世系比以前有所增加,但依然不够全面。","categories":["06_族氏方国"],"year":2018,"publication":"华中师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-rzBmRE992wQR0e5fwkBjSahkIcWis4Mv6Q1L1d4O7hHVIBIhaSpTb5fcBRle0tZ22TZFcGMU2pvLVUN64RvEMO_AfQsiJ7PvPuYTYNC90Wu8_Kg4JlNFxTDFoXLq2EUEpArJAgrM-gtMqirbeJM6NHq6qJ5BK4N_Maq0Gmfb8o_qAFjHjG25&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141-148","volume":"57"},{"id":2218,"author":"蔡靖泉","title":"曾国考古发现与曾随历史问题","abstract":"考古发现的周代汉东曾国,应是殷墟甲骨卜辞所记商代曾国的延续。曾国的得名,或与曾人先民擅长制作和偏爱使用炊具甑、甗有关。当因周武王以其宗姬封于曾,曾国在周初变为姬姓诸侯国,以致西周早期曾文化既以周文化为主导又杂有传统商文化、族群和地域文化因素。两周曾国的政治中心,应一直在今随州境内。曾侯在国内也据周代爵制封有伯、子,故曾国铜器有铭&quot;曾伯某&quot;&quot;曾子某&quot;。曾国与典籍记载的周代汉东随国,实为一国二名。曾入周后新建都城名随,周代史官想必为显周室封建的正统而一律书&quot;曾&quot;为&quot;随&quot;。西周晚期,曾随因强邻鄂国被周厉王遣师扑伐而扩为汉东最大诸侯国。春秋早中期,曾随成为楚国附庸。战国中期前段,曾随或因吴起变法而亡于楚。承继殷商、绵延两周的汉东曾随,历史长约千年。","categories":["06_族氏方国"],"year":2018,"publication":"湖北社会科学","link":"https://link.cnki.net/doi/10.13660/j.cnki.42-1112/c.014760","pages":"184-198","volume":""},{"id":2223,"author":"王博","title":"芮姞簋新研","abstract":"台北&quot;故宫博物院&quot;所藏的芮姞簋,还当释为东方姞姓女子嫁入姬姓芮族的自作器。铭文末尾的&quot;■&quot;应当释为姞姓作器女子与其夫氏芮族的居住地名,&quot;■&quot;族非殷遗,今陕甘交界的汧、陇一带并非存在一个姞姓芮国。","categories":["06_族氏方国"],"year":2018,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK27z2gzotYU99pHa0NJ_bOdMo69YqoXmhITUtqK9zKjaXuGZ0WgzoTPSq0TaLjHLhSxovy14T3mH9MkClmYTm7Mj5NYhRVpZyKScgEaYWxh0MTLVp649SBRl3Tm5e4JSYBgjvmdfAzZPjBlfH2I4r7tJAJemDHi9cwoPsJ_kptMweeoGtgEU-r&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-37","volume":""},{"id":2225,"author":"叶先闯","title":"由新见五器试论西周郑井氏世系","abstract":"吴镇烽新编《商周青铜器铭文暨图像集成续编》新收录与西周郑井氏相关五件器铭,在衍簋、槐簋、槐鼎等铭文参照印证下,西周郑井氏为井叔氏分支可进一步确定,但其分立时代却可往前推至懿孝世。在一百余年的家族分立史上,多达八位家族成员大致可将其世谱划分为四代,郑井季可定为第一代,衍、槐、康三人为生存及任职年限有先后的第二代,伯良父与叔爯父当紧随其后为第三代,郑井叔蒦父年代或最晚,可列为第四代。","categories":["06_族氏方国"],"year":2018,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2018.05.003","pages":"18-26, 49","volume":""},{"id":2226,"author":"黄锦前","title":"曾仲考论","abstract":"综合有关古文字和考古资料来看,曾仲之孙戈的&quot;曾仲&quot;,应即湖北京山苏家垄所出曾仲斿父诸器的曾仲斿父(曾侯仲子游父)、襄阳出土曾仲子敔鼎的&quot;曾仲子敔&quot;及传世曾仲盘的&quot;曾仲&quot;,系曾侯般殷之仲子,即次子,名&quot;敔&quot;,字&quot;斿父&quot;。","categories":["06_族氏方国"],"year":2018,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2018.05.005","pages":"33-35","volume":""},{"id":2232,"author":"李腾","title":"白狄与赤狄之名探源","abstract":"学界通常认为,&quot;狄&quot;和&quot;翟&quot;是由狄族名称音译而来,白狄和赤狄的名称与狄族自身信仰有关。考之殷商、西周和春秋早期史料可知:狄族多以&quot;狄&quot;名之,且不带有蔑称的含义;&quot;狄&quot;与&quot;翟&quot;并不互通,&quot;狄&quot;与&quot;翟&quot;假借实是战国及战国以后之事;白狄和赤狄之所以冠之以白、赤应是区别其族属,指示其所处地理方位而已,与自身民族信仰无关。","categories":["06_族氏方国"],"year":2018,"publication":"河北北方学院学报（社会科学版）","link":"https://link.cnki.net/urlid/13.1415.C.20180928.1047.010","pages":"19-24","volume":"34"},{"id":2827,"author":"崔妍妍; 谢耀亭","title":"《史记·韩世家》新证","abstract":"《史记·韩世家》系统地记载了春秋时期韩氏发展及战国时期韩国历史,与《左传》、《战国策》等传世文献相结合,便可大体窥得韩国历史发展之全貌。韩氏在晋国为卿时期的地位便举足轻重,以至于三家分晋而韩氏占有其一;降至战国,地处中原地区,扼天下之咽喉,战略位置十分重要。近些年来,随着考古工作的有序进展,出土大量有关韩国的简帛文献和青铜器(带有铭文),学术界对韩文化的研究也取得很大进展,据此可弥补司马迁因据战国年代久远难免造成的记载疏漏,本文尝试整理这些累积的出土材料与研究成果,结合传世文献,从世系、人物事件、城邑及疆域四个方面对《韩世家》进行新证。首先根据《左传》、《世本》等传世文献与羌钟、《清华简系年》及温县盟书等考古发现相结合理清韩氏家族世系脉络,并对历代王室人物有争议的纪年、谥号等问题加以论证,主要理清韩氏族属、武子后三代、有无简子庄子、有无列侯文侯及韩哀侯至韩懿侯世系等问题;其次对整个《韩世家","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCk3j_k1Uav--6Me0PIhvtm5LFz1LwgxGFOwMRcDj8nNiJBEooWym13eT5TNTXWKcuKqS0GRqUz1I49zGjDuBbxXv2mvgJoNTsfybMQjwiRrx-_bEYxXtZPY-XuJTMlsXQDcZZ8Rm0Ry94qj2PRxjssQyMmjPHrPMdkfalrWluiu1nI5Oo4na_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2839,"author":"楊欣; 白於蓝","title":"陳蔡兩國銅器銘文整理及相關問題研究","abstract":"陳蔡兩國雖均爲小國,但也一直是平衡諸方力量的重要諸侯國,史書中對二國之史事多有記載,學界以往多有討論。新中國建立以來,兩國銅器大量出土,推動了兩國相關研究的發展。上世紀90年代,已有學者對兩國銅器銘文資料進行過匯集整理。但是近年來,隨著考古工作的深入,又有大量新材料(如九里墩青銅鼓座、射壺、蔡公子戈、蔡公子劍和《上博簡》、《清華簡》等相關材料)陸續公佈,對於補充陳蔡兩國史料具有重要意義。因此,有必要在充分佔有原始材料和吸收學界已有研究成果的基礎上,對陳蔡兩國銅器銘文進行全面系統整理,並對相關歷史問題加以進一步探討。本文共分爲三章。第一章對陳國銅器及別國相關銅器進行了系統整理,並在諸家研究的基礎上,根據銅器的出土情況、形制紋飾以及銘文字體、辭例等,對銅器的年代進行了重新考訂。另外,對陳國銅器中的某些疑難字詞進行了重新考訂。第二章對蔡國銅器及與之相關的銅器進行了系統整理。並在諸家研究的基礎上,","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLy4NKqxAjGFqrW6-vrfF_oA8kuMmCfbqlk8sKNvkYZ2T_wqF2duh4hLoLz1Iu9cx4_oBo3ebkgB8Qxnj8wNgpkdd6QrLHfSKGUKZ5Cpcet7F4Vtj021cG10PZI6uFNekmhhCKf_e7FhBTouZWzxJy50VnU0rJUDqVWIWdnF2a_EoIeyWaubH9D&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2842,"author":"方勤; 傅才武","title":"曾国历史与文化研究","abstract":"曾国(本文讨论的是两周时期的湖北之曾)是一个历史文献上几无记载的诸侯国,对其历史的了解主要通过大量的考古发现所取得的丰富的材料,这在周代的诸侯国历史研究上,是绝无仅有的。本文依据考古发掘资料,以及出土文献材料,并结合极少量传世文献,对名不见经传的曾国历史进行了梳理。文章主要分以下几个部分:第一章绪论部分主要是对文章的选题背景、研究意义进行简单介绍,回顾曾国研究的学术史,并就文章的选材和研究方法进行说明,搭建文章的主体框架;第二章主要结合考古新发现介绍曾国丰富的考古材料,对全文的讨论建立一个材料基础;第三章根据考古材料所反应的文化内涵的区别,把曾国历史分为西周早期、西周晚期至春秋早期、春秋晚期(含中期)至战国中期三个大的时间段,分别论述每一阶段曾国的文化内涵,借助考古与文献材料,试图探讨每一阶段的曾国疆域和政治中心所在。第四章在考古材料所反映的文化内涵基础上,分析曾国与周王朝及曾国与楚国的关","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeqC1M7YvZLZYiSeTXVCNyctGcz8yTpfRbN2QWMczXhJXehOe2pOLpQEvihRm0B5aVuisXxhfzyxI_vErpz--kCIDtbu-V3W6rGpOhIp-DDePWsuFj1o6JwMs1fTd25Zn98nfru_YTk7nJeSU2LYkf2ZbPUUfqQRbEmy3CKntWg-RqXDINDjm2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2857,"author":"程佳楠; 杜勇","title":"三门峡虢国历史问题研究","abstract":"纵观中国历史,东周西周俨然是一个以氏族家族为基本单元组织建立起来的贵族国家。一个个的家族作为政治、经济、军事、文化为一体的血缘组织形式,其兴衰荣辱,发展历程都与周王朝有着密不可分的关系,牵动着周王朝的枝脉。本文意从三门峡虢国相关历史研究问题入手,既有助于解决三门峡虢国的历史研究中存在的问题,探析两周之际虢氏家族发展概况,同时,对我们了解两周时期国家的政治体制,墓葬制度,礼乐文明等情况亦大有助益。论文一共分为三章,这三章也是三个问题,本文就三门峡虢国存在的这些历史研究中的问题逐个分开讨论,各有侧重。第一章针对三门峡虢国的来源进行讨论,学术界对此问题看法甚多,也一直没有统一的意见,本章把众学者的观点分门别类,归纳出五种观点:周文王始封,周武王始封,东虢分支,南虢北虢一国,西虢东迁。根据学者观点逐条分析,同时结合文献及三门峡考古出土资料及考古墓葬的挖掘分析,对比同期赵晋侯墓地等形制,分析三门峡虢","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuACvixXgitqT-hef7vDlchvhyFxwbLieSTPdPqyq9Gird362lcocydxj7FQESDndI9LbrTC5Jh6MMFd9v8lho9Z07-xWwy6cVdrzOIVYjU36WJxYhP1x4fnXCnMPfxyp9kttWqUdJ434VfwoS8P8AUWU8peupA7jj1gtVMiMkwl-Nb2mM1AR-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2859,"author":"徐文婷; 张德良","title":"西周时期陇东周人墓葬研究","abstract":"本文试图构建西周时期陇东地区周人墓葬的年代框架、族属、国别和其与周王朝的关系,旨在解析西周时期陇东地区的文化面貌。本文主要运用了类型学、文化因素分析法和二重证据法。通过类型学的方法对陇东地区西周时期墓葬中的随葬器物进行分析,并对墓葬进行了分期。运用文化因素分析法和二重证据法,解析陇东地区周人墓葬中的多种文化因素,对其族属国别以及与西周王朝的关系进行探讨。根据随葬器物的分析,陇东地区的周人墓葬分为四期,即先周时期、西周早期、西周中期和西周晚期。通过对各期墓葬的文化因素分析,可知该地区在不同时期文化面貌均较为复杂。先周时期,陇东地区有先周文化和商文化;西周早期,该地除周文化和殷遗民文化外,还有寺洼文化,其中以周文化为主;西周中期,该地除周文化和殷遗民文化外,该地还出现了北方民族文化;西周晚期,周文化在该地仍有发现,但比重较小,北方民族文化比重增加。同时结合传世文献和新的出土资料,对陇东地区各方","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHfTKh9UwGu5Rhg5gHM_vU5ixA-_KJ13GlXUHcxnogW2NM3pb6_DvTpaAhLN0JRnOXl9nuiGhTZJ3qYph9UlbYvYi62jVo1robuFBIgY0fOztpqrVTEaMOwOnEr6iwve6LCXS_Phe1bsxMDZ9aLC12cjGM3VmrwsP8gkAPLzg6jyWzjoZI4qhj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2861,"author":"王梦迎; 杜勇","title":"商周时期“亞”族氏铭文研究","abstract":"族徽或族氏铭文,蕴含着商周社会丰富的历史信息,然一直以来,由于字词考释困难,铭文断代分歧不断,遂滋生诸多难题。而在众多族氏铭文材料中,“亚”字铭文材料无疑是其中较为引人注目者,这不仅因其缕缕镌刻于青铜礼器之上,而且于商王墓葬中亦见其身影。“亚”字铭文材料的丰富性,其性质、含义及反映商周思想的复杂性,“亞”形观念对后世的影响等,使得对“亞”字铭文材料的整理和综合研究,成为可能。本文尝试就这一问题展开探究。论文第一章讨论“亞”之族氏铭文性质。其性质问题可谓是探讨其他所有问题的根本前提,在前贤时彦关于其性质的各种猜想与分析的基础上,本文除了对甲金文字有所分析外,还从青铜器自身以及商周墓葬所反映的历史信息中观察“亞”字含义的衍变及多重性。得出的结论是:“亞”之含义并不单一,而其初始意即为宗庙。但是,宗庙画作“亞”形的原因何在?前文文章已经通过正面来源的角度加以分析,受启发自张懋镕先生的观点:周人代","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJanydyokZm8UG85lJrFb6_lUT81qbbGSI1SnTpMZfuLzcG4T2Rtcu6UobFmQFyy8BmVPRWU_0xmJXJ3BU_9ZA0sbJ-yEAJq9dw7Fsp1EiZLMN0dF63SEnqBZt7_1TBqEA_g6sBCTZJS_MRkaJ5Vwbl-UhKrfKn3OlffnxRYQJnsrflmfctzT5Z&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2864,"author":"白星飞; 侯乃峰","title":"出土文獻所見鄭國史材料整理與研究","abstract":"鄭國是春秋時期一個非常重要的諸侯國,從鄭桓公始封於鄭,到韓哀侯滅鄭,鄭之國祚綿延四百餘年。鄭國史的研究歷來受到學者們的足夠重視,鄭國史的相關研究成果頗豐。出土金文與簡帛文獻中也不乏與鄭國史相關的內容,對鄭國史的研究具有非常重要的參考意義。包山楚簡《集箸》、馬王堆帛書《春秋事語》、上博簡《鄭子家喪》、清華簡《繫年》《良臣》《鄭武夫人規孺子》《鄭文公問太伯》《子產》《晉文公入於晉》篇中都包含與鄭國史相關的內容,尤其是清華簡中包含豐富的鄭國史材料,其中亦有未見於傳世文獻的鄭國史事,具有相當高的史料價值。此外,經收集與整理,共收錄與鄭國相關的有銘青銅器七十七件,其中十四件存疑。有銘文短小,僅寥寥數字者,也有像鄭莊公之孫鼎、封子楚簠、與兵壺這樣的重器。涉及鄭國史的簡帛文獻和金文的內容是非常豐富的,大量出土的簡帛與金文爲鄭國史的研究提供了非常珍貴的參考材料。對於涉及鄭國史的簡帛文獻及青銅器銘文,前(5","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://link.cnki.net/doi/10.27267/d.cnki.gqfsu.2018.000004","pages":"","volume":""},{"id":2865,"author":"史國豪; 張俊成","title":"東周魯國金文整理與研究","abstract":"對於銅器銘文的研究是歷史學研究的重要環節,銘文中所反映出來的歷史信息能與傳世文獻當中的記載相對應,同時,也能夠佐證出土考古資料的本身時代。且銅器銘文因為載體和書寫困難程度的原因,很難被人為篡改,因此,是進行歷史學研究不可或缺的材料。山東地區在東周時期主要由齊、魯兩大國和其他的諸小國組成,而魯國作為姬姓封國的代表,其歷史地位不言而喻。針對這個特點,對東周時期魯國金文進行整理與研究,對整個山東古國史的發展有其積極意義。本文主要分為伍個部分,從研究綜述、金文匯釋、齊魯金文的比較、魯國金文所見制度和魯國金文所見禮俗等方面對魯國青銅器銘文進行分析研究,以探討魯國的政治、文化、官職、外交等方面的問題。第壹部分為緒論部分,回顧了相關學術史,主要為研究内容、研究目的、研究方法以及研究現狀和述評等方面,研究述評分為叁部分,梳理有關魯國金文記載和研究的相關文獻,按照年代分為宋代至清初、晚清至民國、建國之後,在","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjM4QRUYDHO1TS3rJUUTCOtdQGqhPkU5MaEWIp4wkV6UGu2z4lz-LKWkOgILA64a1lCuoO9YssqGMI57bV9f4fMdMVB2zQ1ZdZkdUTQJ3gw7xyFKxCs_1DVKGDIdXZSG25kC6pNylH82oKIQT__8t0-KBm-eKEW9No_2uWzurRVmoOanaU1pFk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3106,"author":"何景成","title":"商周时期的貊族研究","abstract":"貊是一个古老的民族,也写作&quot;貉&quot;。传世古籍&quot;四书&quot;除《大学》之外,都提到过貊。汉代以降的文献中仍用这一族称来称呼当时实际存在的民族集团。所以貊在中国民族史研究中具有不可忽视的重要地位。（1）在先秦文献中,常用&quot;蛮貊&quot;&quot;夷貊&quot;&quot;四貉&quot;指称一切异族,表明貊是在古人心目中颇有分量的异族。如《诗经·宫》云:&quot;至于海邦,淮夷蛮貊,及彼南夷,莫不率从。&quot;","categories":["06_族氏方国"],"year":2018,"publication":"纪念徐中舒先生诞辰120周年国际学术研讨会论文集（下）","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2018.036158","pages":"328-334","volume":""},{"id":3125,"author":"国光红; 周丙华","title":"齐国何以得名“齐”","abstract":"关于齐国得名之原因,《史记·封禅书》是这样说的:&quot;齐所以为齐,以天齐也。&quot;又说:&quot;天齐,渊水,居临淄南郊山下者。&quot;《索隐》转引顾氏案解道彪《齐记》,云:&quot;临淄城南有天齐泉,五泉并出,有异于常。言如天之腹齐也。&quot;（1）&quot;腹齐&quot;就是现在说的&quot;肚脐眼&quot;,&quot;天齐&quot;——&quot;天之腹齐&quot;就是上天的肚脐眼。","categories":["06_族氏方国"],"year":2018,"publication":"纪念徐中舒先生诞辰120周年国际学术研讨会论文集（上）","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2018.036087","pages":"233-241","volume":""},{"id":3140,"author":"陈晨; 宫希成","title":"钟离国的考古发现与研究","abstract":"钟离国为春秋时期淮河流域的赢姓小国,位于安徽省蚌埠、凤阳一带。古文献中关于钟离国的历史记载极少,且其中还存在较多模糊甚至相互矛盾的地方,这给研究钟离国的历史带来很大不便,因而长期以来钟离国的研究难以取得重大突破。1980年,舒城九里墩出土了一件带有铭文的青铜鼓座,经过有关专家学者的不断考证和讨论,认为这件鼓座应是钟离国的遗物;2006年以来,蚌埠双墩一号墓、凤阳卞庄一号墓先后进行了抢救性发掘,确认为钟离国墓葬无疑,这为钟离国的研究提供了重要的一手资料,也使关于钟离国的研究一时成为学术界的热点。2013年安徽省文物考古研究所对乔涧子二号墓进行了抢救性发掘,该墓葬判断为春秋晚期钟离国墓,也是目前钟离国发现的第一座贵族墓,为钟离国的研究又增加了新材料。本文主要利用上述几座墓葬的出土材料以及凤阳钟离古城的调查材料,并结合有关传世文献的记载和一些学者的研究成果,从以下几个章节进行论述。绪论:第一节,","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInhNa1dX498KZOiQKlUvpL44_WJXAIg1qCtxQzOBxylTmgxRyJC8kGaiKQTcmdkFVU5TYJIqxiL9fd0vW52K_QU5_P8bin0xPJykq8WJ9mOVcOmacHjyXEHH7V7zIv4HcyeHwlG19LuZ4pG3Mm3pJU3nE7MKDMgClOmiMeXfwm_h08RbOfmINa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3142,"author":"蒋娟; 吴国升","title":"汉语国族姓氏用字历时考察八则","abstract":"中华姓氏文化源远流长、博大精深,历来关于姓氏溯源及文化研究的成果十分丰富,本文则转换视角,并依据出土文字资料与传世文献,具体梳理了廖、趙、邾、徐、鄧、鄭、邿、番八个姓氏的历时用字情况。在前人关于姓氏起源、发展、演变研究基础上,进一步探讨八个国族姓氏的变化及其原因,并着重探讨与该姓氏有关的字形以及其间的关系。八个姓氏的主要用字情况如下:“廖”姓(严格来说当是“廖”氏),西周春秋时用“蓼”记录,春秋时用“鄝”记录,春秋晚期用“飂”记录,汉代开始用“廖”记录。其中,“蓼”、“飂”、“廖”字当是借字记录;“鄝”字当是从“翏”增添“邑”旁所分化出的专用字;后世文献用“廖”记录。国族氏名{趙},春秋时期始见。用“肖”记录当属假借;“”当为从“肖”增添“邑”旁的专用字;用“趙”记录当属假借;“赵”属“趙”的简体,为现代通用。国族氏名{邾},西周早期假借“”字记录,西周晚期用专用字“邾”字记录。春秋时期除","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIG_WjCfHLeA404a-gWbaABF0SuS3FWGyJAD5Ilw1NGHmR1g6HL3Uy4T_nMkhnglO-HndpJvjdpz5gVaU70GzOEIsXGdcisKv9T5YR03ArgfphIIVLSMVaDMjEpCZHC-uWPeYeFtb9rD55mJ0nTbhnEbwOzsKZxhtZj4DBuwxUGuzGdux5iqPLk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3145,"author":"张圣霞; 刘伟","title":"春秋齐国诸姜研究","abstract":"春秋时期,齐国诸姜活跃在各国政治舞台上,成为一道亮丽的风景。但近年来,对齐国诸姜的研究比较片面,多集中在文姜、穆姜等个别女性身上;侧重于对诸姜婚姻、政治活动的单方面研究,缺乏对齐国诸姜的婚姻、政治活动的系统研究。在史料运用上,侧重于传世文献,对出土文献关注较少。因此,结合传世文献与出土文献,对春秋时期齐国诸姜的婚姻、政治活动进行一个系统、全面的研究显得尤为重要。首先,本文将对诸姜的婚姻状况进行一个系统梳理。从传世文献和出土青铜器两方面来考证春秋时期齐国与王室及其他列国的联姻情况。婚姻为政治服务,此时的婚姻多是邦交婚。在这种婚姻中,齐国诸姜没有选择婚姻的自由,被母国嫁往列国之间。通过对青铜器铭文的分析,可以考察出传世文献中所没有的一些诸姜婚姻,这弥补了传世文献的不足。通过纸质材料与地下材料的结合,可以对春秋时期齐国诸姜的婚姻状况有一个较全面的了解。其次,本文将对嫁入列国的诸姜在夫国的政治活动","categories":["06_族氏方国"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJSJbPUMTLQH3K7DtV_5g-BHwH_BMOPnIYqtN6OkIkCzTSB-5IfWbFC29sFcYpoooI7aLzWd6VDWJiHOyqQE6hXpg0DLr0SPincfAPK7Atx6RelJdK7wJrG6UPO2ZIE5VEDyEPpRKgnkd40OD00zZt3Teal8r4TFEVJVjxBTJB5RXgmtDnPQQJY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3270,"author":"黄锦前","title":"颗器及相关铜器系联研究","abstract":"以考释古文字中的“颗”字为契机,将颗所作几件器物系联起来在此基础上,以铭文中的徽记符号为线索,将颗及其家族成员所作诸器进一步加以系联、分类、排比和分析,厘清相关人物之间的关系,探寻相关的历史、地理信息,指出“■邑司”“■邑豕”“■男”“嘼”等应为同一人,系周初武、成至康王时人,■邑司或嘼及其“父乙”“父丁”皆系级别很高的贵族;颗与■为同一人,系■邑司或嘼之子,“子■”系其族徽。“■”应读作“阳”,即在今山东青州一带的阳国,系子男之爵。羌鼎的“■叔”应为“■男”的小宗。应国墓地M257出土的考史簋“■姒”的“■”亦应读作“阳”,指在今青州一带的阳国。北京保利艺术博物馆藏阳仲卣、上海博物馆藏阳尹簋等,皆系山东地区的阳国器。据出土铜器可知,阳国在商末周初的实力应较强大。","categories":["06_族氏方国"],"year":2018,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvKVNVwK-2lg1nlsY6zbTPpA2ZoNiaPycBThCf0IGbT0o-FLF55QJllys_-p1aA7zFdHX15nEfofFt_Hbq0hVDSn67UZnFrCPdA7fsM-c4oRJXnbSIu3JiqHI5aMJZqI0NyMQIxyO1lRYT4ewt2zo0MN70xxu99MLzWfzVWBHSOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-55","volume":""},{"id":3334,"author":"辛怡华","title":"密叔、密国及相关问题","abstract":"一、铜器铭文中的密叔（一）■簋、虎簋盖密叔见于■簋及虎簋盖铭文。以下金文释文除个别关键字外,尽可能使用简化字。1.虎簋盖1996年出现于陕西省丹凤县,据说簋盖早年出土于县城西北2500米的西河乡山沟村,出土时已断裂为4块,盖内铸有铭文13行,共161字,重文一。铭文的主要内容是周王对一位叫虎的重臣的册命和赏赐（图一）。多数学者认为此器的年代为穆王时期[1]。铭文释文如下:","categories":["06_族氏方国"],"year":2018,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEVe-d_BE7ugpN1N4SQ-OuVWB9pTLVAz-ktZZ8RU3fFntK2DAySUvCLUNTi3F9NDsVkifei6wEQnVkuLH4erf8SI6PPC5tNgi9Go5zCdTHap83STEbd7WCpnhgfrCsyT0sEEFh3Czdj0EngTmsC8S_rq2ZD4acM5pefC0EtZvH9g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"272-280","volume":""},{"id":3337,"author":"雒有仓","title":"金文族徽的内涵、性质与商代的族墓地","abstract":"金文族徽是商周青铜器上较早出现的铭文,常见为一个或几个标识性、象形性较强的文字符号,数量约占现存金文16000余器之半[1]。由于铭刻简短,考释困难,内涵复杂,学者们对金文族徽解读历来见仁见智。曹大志先生在《&quot;族徽&quot;内涵与商代的国家结构》一文[2]中提出,&quot;很大一部分常见'族徽'可能是当时的亲属和职衔称谓&quot;,并以&quot;族徽是亲属职衔称谓&quot;作为新的解释体系来论证商代国家结构为官僚社会。这个看法不仅与&quot;族徽为族氏名称&quot;的传统认识不同,而且牵涉对商代社会结构、","categories":["06_族氏方国"],"year":2018,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeW-z8Bm3e1nmrIUEhN60SeXc163H1hkycpR4eC9mwu2mzhwtQgrteg1GYSwlF9n-1VNzk0N2_qoYotuCbuAjzrd1IvFxDzzg5Kr9RkoU2M7P6Leq_WPMkN4wv8Aa-Jmccne4lLxGK6-qOkSAoEpUvq0MUj5gycRcwqKezp6jQyA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"470-496","volume":""},{"id":3373,"author":"武刚","title":"周原出土昔鸡铜簋与西周韩国封建问题新证","abstract":"2014年周原考古队在宝鸡市周原遗址M11号墓葬中发掘出土昔鸡铜簋,簋铭中涉及艿姑、韩侯等称谓。昔鸡簋为西周早中期铜器,这表明至迟在西周中期,韩已经获封为&quot;侯&quot;;同时艿地的地理位置为西周前期韩的地望提供了佐证。过去学术界关于西周时期韩国的封建问题分歧较大,有河西、河东、河北三说;昔鸡的职责与艿地的位置均表明韩的受封应在河西一带,是河西说有力的佐证。根据《诗·大雅·韩奕》的记录,韩国与燕国地理位置接近,则与&quot;河北说&quot;的记述较为吻合。这表明《韩奕》实际上是描述韩侯受命改封的文献,结合出土材料,可以确知西周时期韩国先封于陕西韩城一带,后迁徙到河北地区,与燕为邻,这是出于西周晚期北国地区边域形势的需要。","categories":["06_族氏方国"],"year":2018,"publication":"历史地理","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_OsSg_fMEg0-CtdJIsZ7IiuH1USW6KmBlSRgNFBt1GGxGKnoVuDK0uC7ne7QtpUijAs_A-B-ZpmiWS3e8VIMeQQJhdmVHNJAF2P1ZKXTHA-RsaeVPh-JoEfb0GjH0OJ5Ov4v1O8zRBEMoJrgvtcPEHTq82V5ydfsL09gaA7gOQA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-47","volume":""},{"id":3385,"author":"黄锦前","title":"由新见阳小叔■父鼎看叔姬鼎等铜器及相关问题","abstract":"据上下文及有关金文文例,阳小叔■父鼎铭的&quot;阳&quot;应为国族名,系位于今江汉地区的姬姓唐国;&quot;阳小叔&quot;系唐国公室,&quot;龏叔姬&quot;系其妻,&quot;龏&quot;为其氏。传世叔姬鼎(金父鼎)铭的&quot;■&quot;字应系&quot;阳叔&quot;二字之误摹,&quot;金&quot;字系&quot;■&quot;字之摹误,作器者&quot;■金父&quot;实应系&quot;阳叔■父&quot;,与新见之阳小叔■父鼎的&quot;阳小叔■父&quot;及上博藏叔姬鼎的&quot;阳伯&quot;系同人;鼎铭的&quot;叔姬&quot;与阳小叔■父鼎的&quot;龏叔姬&quot;及上博藏叔姬鼎的&quot;叔姬&quot;亦系同人,为&quot;阳(小)叔■父&quot;即&quot;阳伯&quot;之妻;该鼎时代应为春秋早期。东","categories":["06_族氏方国"],"year":2018,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBNF07D7gq-ysbPxG27wGHcDV8fz8ur6kR6trQFHqHLaCh4X37KgCfTW-rJfKd-f13lkP_JFy6YnkNRrgOnRU4kC3pMpiCTR-qft3nRuNXNTT9iXiuYk0u_jV9vx9EBVFEOV-fDPnnvwYZbmo1hKpnGjO19H1zQSCvXU3g6SFbbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-61","volume":""},{"id":3407,"author":"朱鳳瀚","title":"宗人諸器考——兼及再論西周貴族家族作器制度","abstract":"吴鎮烽先生《銘圖續》收入三件西周中期偏晚至晚期初的青銅器,[1]作器者是&quot;宗人&quot;或器歸宗人使用,銘文均涉及西周貴族家族内的宗法關係,故頗值得注意。此外,其中兩件也涉及在貴族家族内製作青銅禮器的問題,而此前筆者曾有小文專門探討過西周貴族家族内的作器制度,[2]故本文對於後面個問題的討論,可以叫作&quot;再論&quot;。","categories":["06_族氏方国"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ7WKOyjxjGIb2spi6yb3GBHhiuzTMPinxAmalFNcqe3tDg_e_xrxoTtS4MbDAjzYE7NfMa0vPJ7LAf9o9PhiY20M8XAOsuI7KXAvWGgJy9TjdvUYh5OTKm3A7959-qYM3WXqOAK4e5ofirk4F8eauQUsTTyUpB2_qPnoyO3qUXBA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-28","volume":""},{"id":3410,"author":"李龍海","title":"賈孫叔子屖盤與賈國、賈季(狐射姑)關係再論","abstract":"賈孫叔子屖盤於1981年出土於山東諸城都吉臺,與盤同出的還有一鼎,但該鼎資料未見公布,二器現均館藏於山東諸城博物館。由於該盤銘文漫漶不清,學者有把該盤作器者隸定爲&quot;賈子叔子屖&quot;的,[1]也有把作器者隸定爲&quot;賙孫叔子屖&quot;的,[2]但中國文字博物館在介","categories":["06_族氏方国"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIA7he3jXrxfxB1iSY0JxWy2HlkuM3b4WAt56CZxJopUm7j1mes7Z73UOQHY2pawzt2Debn7djmntO8xnzztyKMXzKzhVxl3aDtgHf27t372QTLw41h_Sy2XvFabdOAeGjCQq5oA4Mu_bl795aymzoYUF9mqBrk21K3zBEqF6-EKw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-117","volume":""},{"id":3411,"author":"韋心瀅","title":"克之家族結構與相關問題研究","abstract":"光緒十五年（1889）以前[1]在陝西扶風法門鎮任家村窖藏集中出土一批有關&quot;克&quot;與&quot;仲義父&quot;的青銅器。1940年2月,任家村又再一次出土有關&quot;梁其&quot;與&quot;善夫吉父&quot;的青銅器。另距任家村窖藏四五公里的北橋村,1972年12月出土了三件&quot;伯吉父&quot;青銅器。[2]在如此小的範圍内分三處埋藏成組青銅器多套,在私家禮器不宜放置他人宅地的情况下,些埋藏點不僅應與器主具有地緣關係（或爲其居址宗廟所在地周邊）,[3]器主彼此之間亦應具某種親緣關係。","categories":["06_族氏方国"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIA7he3jXrxfxB1iSY0JxWy2HlkuM3b4WAt56CZxJopUm7j1mes7Z73B29VFeNNGnoJFMZzMmM7tY4iFhk96QUhJG0bsqqyyAfQp5RP8PCWpW5dHn07_B-4OOnZ7u0IqnShrdpYCB1G92Rz-SACk_56HFVFVd1Hkk0JkKqttrP8jw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-143","volume":""},{"id":3412,"author":"陳絜","title":"小臣缶鼎與晚商■族族居地","abstract":"商周甲骨、金文所見■族,乃當時最爲著名的族群組織之一,在商周尤其是在晚商的歷史舞臺上,異常活躍,對土方、■方與人方的戰争中均能看到該族的蹤迹,是商王朝對外戰争的重要依靠力量。該族所鑄青銅禮器數量頗豐,且多長銘,但銅禮器的出土地點却廣布各地,涉及甘肅靈臺,[1]陝西岐山、扶風、西安市、長安與麟遊,[2]河南安陽與鹿邑,[3]山東","categories":["06_族氏方国"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKl6rBYdLRkT7WJoYSH2yq7Qv6SsfhthnO_uVPwSlWSLFefg5qmlFk5YjlNK-ui8UE0SXlSf_Y__HRphEQnMlr8YrG5owVw-ROba21lj5dOiIbCiYFk0Nv1D_-JBmu_6xvjKJesei7EHRj7fjeT7OPQxwU-dZMoQpazSOLx-E-oDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-89","volume":""},{"id":3442,"author":"黄锦前","title":"伯氏始氏鼎的年代及史事","abstract":"将伯氏始氏鼎铭与相关铜器铭文及《春秋》经传等有关文字对读,可以确定,鼎铭的&quot;芈嫚?&quot;应即《左传》桓公十三年及庄公四年所云之楚武王夫人邓曼,系楚文王之母、邓祁侯之姊妹,该鼎系邓伯及夫人姒氏为其出嫁楚国所作媵器。鼎铭的&quot;伯氏&quot;与邓公簋盖铭的&quot;邓公&quot;系一人,即见于文献的邓祁侯之父邓侯吾离,其在位时间当在春秋早期中叶前后,卒于公元前705年以后,其在位和亡故时间皆较其婿楚武王在位(公元前740—前690年)和亡故时间(前690年)略早。","categories":["06_族氏方国"],"year":2018,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJfCokst9AIGH320OtjBfhRg6GdZ9UkFWu3uZAkmwwYJD0tU_1np7O3CJ3aropSKLlzBl326JruQ8EtRKF01LF_qk7NHHHl_33CYcClH3XtyWeSQbBzZMeLE_rfhSuBWfxhTycRVn1mmBEBtPieBSIducgsKnpxki6Lp2DldEFVpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-59","volume":""},{"id":3446,"author":"黄凤春","title":"曾侯世系编年的初步研究","abstract":"曾侯乙墓的发掘开启了对曾国系列相关问题的考古学研究,40年来,随着曾国遗存的不断增多,有关曾国的族姓、始封年代、受封者及曾国与随国的关系等诸多问题都获得了重大突破。随之而来的是曾侯的墓葬及曾侯的遗物也不断增多,使得曾侯的世系也越来越清楚,开展对曾侯世系的研究已刻不容缓。通过统计,已具有明确曾侯自名的遗物已达347件,所见不同曾侯达12位之多,时跨西周早期至战国中期早段,积年达近700年。有些学者在探讨这些曾侯所在位的年代时多有不同。通过对这些曾侯器重新梳理,并对这些遗物的进行年代学的考察,重新排定了各曾侯的具体年代。对曾侯世系编年的重新和准确判定,将有助于对曾国史更深入的研究。","categories":["06_族氏方国"],"year":2018,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6sCEz-D4_Jk9qzrdmst9qbdfejZHnLKYHA8RH3VE0y4uOPPwyKbmZHo8e2A6UV4qm9K70JXxTksnrae24jsvk9mbjeYixi6mbt2yJ2rLzJBvY2i6jN3uorciKMinYIE2FnyT4Ap-98bSHIBPM0gl5KTsp99b1nMHIwNkcJ7E77Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"314-320","volume":""},{"id":3450,"author":"張惟捷","title":"晚商人物“師般”史迹考述——并論文獻中“甘盤”的相關問題","abstract":"研究緣起與方法人物是構成社會歷史的最基本要素,因此對某一時代中重要人物的研究,可視爲傳統歷史學發展論述的主要基礎。19世紀末的安陽殷墟出土的甲骨文爲學術界帶來了極大的震撼,豐富的第一手資料不僅證明了《史記·殷本紀》在世系記載上的可信,也透露出傳統文獻所保留商史的不足,其中在人物記述上更是如此。有鑒於此,針對獨立人物的專題研究遂逐漸受到學者的重視。","categories":["06_族氏方国"],"year":2018,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI9_L15rsc9KLuKsZemxzvDEE1rx-Pdld3vTq7i7ujryQlsinEGrshxSTsiF2ndaoyFsjXLKDMAGCIyGJTTO0FNF5WC9crTlFfYLA706lFKZWuO9x8gN4LeHCboXgdKBQyEbHhEoGcxVilcfUSxj5SnJWBoa3-M1-QrsxidRze4mw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"176-213","volume":""},{"id":3464,"author":"辛怡华","title":"南宫家族姓氏问题研究","abstract":"南宫家族是西周时期重要的家族之一。但对于南宫家族的族属问题讨论,至今还没有一个令人满意的结论,或为姬姓,或为非姬姓。即使根据同一篇铜器铭文,也有姬姓或非姬姓之结论。造成这种情况的原因是由于有关铭文所涉及的吴国,传统认为是姬姓之国。南宫家族与之结亲,按照同姓不婚古制,自然得出南宫家族非姬姓的结论。但通过对金文研究,在西周晚期可能还存在一个非姬姓的吴国,从而证明南宫家族有可能为姬姓。","categories":["06_族氏方国"],"year":2018,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKm3QfrSArWOtPG_4Ax6j9dlvYaKETdA6HlWlIR3tCqqQNBc22TcNB8oRzUTF4upDpzUGUAmDrtU2LDtqt--6ZoGL7ajuf3HeiReWqiPiOjjZoEVCrMgMjfM4ByHA04-Ya7cc7YucorA64KestxGUF76MCa_a9Qof6JH-5MiVF77Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-49","volume":""},{"id":3492,"author":"徐少华","title":"丁儿鼎盖考略","abstract":"河南南阳市博物馆收藏的一件丁儿鼎盖,器身虽不知遗落何处,但盖内铭文对研究东周汉淮地区列国青铜器及古应国的历史、文化具有重要的意义,此前已有简单报道和初步认识,但仍有一些问题值得探索。本文拟结合相关考古材料,就丁儿鼎盖的年代、文化特征及作器背景加以分析,以期对准确把握该器的时代,认识姬姓应国被兼并入楚之后的情况,以及汉淮地区列国与楚人的相互交融关系,有所帮助。","categories":["06_族氏方国"],"year":2018,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIoEfrleb3zBoG8k3C1yy9pVc1RUjdy8NyAeiDPhFWd0xgPTv0F8krXlVCrN-9GH5DRY1yZP4W50P4GLfB9XApIiz2aSTT7kDOpBMaEGY0oKPCKCE_jvPboB7aluDKIGh0EREVZ4e4BJPiEnwAzrDM4B7YF16PVZ3RsnDALUFBCwA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"189-193","volume":""},{"id":3518,"author":"曹大志","title":"“族徽”内涵与商代的国家结构","abstract":"青铜器上的&quot;族徽&quot;是研究商代历史和社会的学者无法回避的问题,它不仅关系着我国早期的文字系统,也关系着我们如何理解商代国家和社会的结构。①笔者在最近的教学中对&quot;族徽&quot;的有关问题产生了一些思考。因为这个课题涉及范围很广,所以在此想先提出要点,以请专家们批评。以往对&quot;族徽&quot;的研究已经取得了相当大的成绩,归纳起来有以下三方面:其一,确认了&quot;族徽&quot;绝大部分是文字而不是图案,并且考释出其中一大批单字;其二,发现&quot;族徽&quot;是","categories":["06_族氏方国"],"year":2018,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0JK9YF6USi1s28CRU8t2Kj6MayMkfH_VvSiD9hjvsSw4Ss7IcOktXrOOlrwmE2g1GJ-TJcw4yH7XHZmWp5utZmrJ_seAPRlC7XowNiykUJt4zG432hrLnjLg_MTB80Nj2pwYRVp7T8zMeA8T-ERmBQDULZ8VUoJwp46FPQ9WIdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-122","volume":"12"},{"id":2160,"author":"赵茜; 饶胜","title":"馆藏商代“己并父丁”青铜爵铭文探析","abstract":"新乡市博物馆馆藏3件商代&quot;己并父丁&quot;爵,铭文&quot;己并父丁&quot;四字刻在爵杯鋬内的腹壁上。&quot;己并&quot;二字与山东寿光县出土的纪国&quot;己并&quot;青铜器上的&quot;己并&quot;表现一致,寿光县益都侯城出土大量的&quot;己并&quot;青铜器基本上证实了殷商时期纪国的地望所在。新乡市博物馆馆藏的&quot;己并父丁&quot;爵与寿光&quot;己并&quot;爵在制作工艺和表现手法上有共同点,并且两者在时间上存在延续性。因此,笔者推测新乡市博物馆馆藏的&quot;己并父丁&quot;爵可能属于殷商时期的纪国青铜器。","categories":["06_族氏方国"],"year":2017,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIz6t8sORhkqq2PBYypFTltlTGqAsWrFzw8yfsyDO-LRbXqs1uAJ1QxmJ408Nd0OzY2-Y6CNbSgdkQTmy_CbhuVh9K7QvO0U3W5yx1CoPGfFryqDiRkQQXOJn6KYO8JgeuAzQWHBtNCR-3MgkJph4oUsoFPVzdwrIKJccSHxR9xGfnlKGv4kQbA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-22","volume":""},{"id":2170,"author":"付强","title":"揭秘密国:宋叔方鼎试释","abstract":"宋叔方鼎铭文中讲到密伯赏赐了宋叔贝和铜,通过与相关青铜器的对比研究,发现密伯的权力很大,和以往金文中的王很像,这对认识西周时期密国的历史文化具有一定的价值和意义。吴镇烽先生编著的《商周青铜器铭文暨图像集成续编》(以下简称《集成》)著录了一件宋叔方鼎,编号为0218,据传这是郑州一私人收藏家的藏品。方鼎呈长方形,窄沿方唇,口沿两端有一对立耳,平底四柱足,体四角各有一条双牙扉棱。四壁各饰一对回首垂冠卷喙的大凤鸟,以云雷纹填地,柱足上部饰浮雕兽面。吴先生从方鼎的形制和纹饰,判断此鼎的相对年代为西周中期前段。","categories":["06_族氏方国"],"year":2017,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJU3kE8L2n6xt31stcslFduGVuxUK-c2r8JiyVhXaBinV5SrCsKE_lhNSrdoR7CMnih_7olJg503wFg2lalol1OKIbuAuwPhpBZN9FILlxjKBrB0ubEhKj393IRaNoQm5imT9l3xuc2bnLeFLZHF6BxwFqfjFMVsWc3ru0Cw3G_ZizZyjJCrazR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":2248,"author":"马军霞; 曹玮","title":"虢国综合研究","abstract":"本文在系统梳理前人研究成果的基础上,以考古资料为主,结合文献资料及金文资料对虢国进行研究。研究主要从四个方面展开:其一是以时间为序,以相关事件及人物为中心,分析虢国立国、发展、迁徙、兴盛及灭亡的相关史实;其二是依据组合关系明确的墓葬随葬品,分析虢国的铜礼器、兵器及车马器,进而了解虢国的礼乐制度、军事制度;其三是通过对虢国墓地墓葬形制、葬具、葬式、葬俗及墓葬关系的分析,了解虢国的埋葬习俗及墓地制度,并进而分析由于墓主性别不同和社会等级不同所产生的随葬品差异;其四是对虢国宗族各分支从居地、实力及关系等方面进行分析和总结,并归纳出西周中期到晚期与虢氏通婚的诸国族姓氏。通过研究,得出结论摘要如下:一、虢国是姬姓封国,在两周历史上占有重要地位。文献记载的五个虢国,历史上存在的仅有东虢和西虢。西虢居地有两处,一处位于宝鸡,一处位于三门峡一带。位居宝鸡的虢国,是王室的西部屏障。虢公在王室中参与对外征伐、","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKoCe6JJQpiQvFn3v3QyGbrxs2y1UQOeDrXZr6ZBPS8JIHcDfJKLdZReYAPRgDX3iie4CUlY0dbN8Pdv_cgGMLcAEXZVRtPwmAmv4ud3JQvJ9UWSbl2CWWLKdujH655uYjGaqyjy81K-YEBPwG-VQADqso4X8o8AaQpR_Ec1HEwByeeTVVn8nul&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2253,"author":"黄锦前","title":"公仲考论","abstract":"文章通过对有关铜器铭文的系联和分析,推定西周早中期铜器铭文中的&quot;公仲&quot;应为康、昭时人,系首任曾侯&quot;南公&quot;子,为第二代曾侯,还曾在王朝兼任职务。南方为其子,系昭、穆时人。","categories":["06_族氏方国"],"year":2017,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2017.05.004","pages":"27-29","volume":""},{"id":2279,"author":"李零","title":"帝繫、族姓的歷史還原——讀徐旭生《中國古史的傳説時代》","abstract":"古史傳説是個長期困擾考古學家和歷史學家的問題,本文試以帝繫、族姓的歷史還原作爲釐清這一問題的突破口。首先,筆者回顧了疑古運動後爲何許多學者不約而同,全都把目光聚焦於&quot;族團説&quot;,指出此説乃應運而生,背後有深刻的政治原因和學術機緣。其次,筆者討論族姓,把兩周常見的20個族姓分别歸入黄帝集團、炎帝集團、二皞集團和祝融集團,指出族姓制度是發明於兩周時期。其次,筆者把先秦帝繫分爲兩種&quot;五帝説&quot;,一種屬周帝繫,一種屬秦帝繫,指出前者是西周大一統的總結,後者是秦代大一統的預告。最後,筆者對上述討論進行總結,涉及古史傳説的層次,帝繫和族姓的關係,以及&quot;二重史證&quot;在考古研究上的分寸把握。","categories":["06_族氏方国"],"year":2017,"publication":"文史","link":"https://link.cnki.net/doi/10.19325/j.cnki.11-1678/k.2017.03.001","pages":"5-33","volume":""},{"id":2287,"author":"孙敬明","title":"齐境出土异国族金文通释绎论","abstract":"勾稽齐国境内出土亚醜、册融、纪国、叔龟、画、小臣传、师、过、斟、鄩、上曾、鲁、铸、陈、蔡、曹、淳于、宋、商丘叔、蔇、陬、吴、越、燕、韩、赵、魏等二十七国族百数十件带铭文的青铜器。铭文篇章所涉疆域东起自海,西抵周原,南达荆楚吴越,北逾燕赵山戎。藉对相关铭文内容酌为诠绎,以揆度每历史时期齐与列国之间文化交流趋向与融合之态势。","categories":["06_族氏方国"],"year":2017,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.issn1002-3828.2017.02.22","pages":"113-122","volume":""},{"id":2315,"author":"傅修才","title":"狐骀丘君盘新考","abstract":"《安徽出土青铜器铭文研究》著录一件现藏安徽博物院的甫以公盘,书中认为盘的时代为战国,是甫国国君所作礼器。通过考察盘的器形和纹饰,并联系和分析时代相近的铜盘,此盘的时代应改定为春秋晚期。通过对盘铭重新考释,纠正误释的字。&quot;虖丘&quot;原误释作&quot;甫以公&quot;,应读为&quot;狐骀丘&quot;,狐骀丘是周代山东小国。器主之名原释作&quot;&quot;,应是一从&quot;尚&quot;得声之字。器名修饰语原径直释作&quot;盥&quot;,应隶定作&quot;&quot;,读为&quot;浣&quot;,&quot;浣&quot;、&quot;盥&quot;音近义通。器名&quot;&quot;所从的&quot;舟&quot;旁可能由&quot;盘&quot;形初文讹变发展而来,也可以分析为&quot;般/盘&quot;省声。此盘应是狐骀丘君尚所作之器,传","categories":["06_族氏方国"],"year":2017,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKw4sGK2Q6HUFQBLmgK6yuvhKSYaJ6J0K_-1EgZRunN84dL27AWkFYgO1wbGpe1QQl7neT9hUsjqiDjlJi_gNYRYAmGLSmgzRQuOYKfyJOzbk5d0Sxzugd0l6zfHq3Zf9FWubpulzXUNyoEzZRKwS9GwTWwxDXS87xFPbS0jQjH4jkSzyqOMEa-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-60","volume":""},{"id":2321,"author":"邹芙都; 余霞","title":"西周黎国政治军事地位及姻亲关系初探","abstract":"西周黎国位于今山西省黎城县,与商代子姓黎国有别,当为武王戡黎之后由周王分封而来的姬姓之国。由于其血缘与宗亲等因素,西周黎国封为侯爵,黎氏族人曾供职于王室,具有较重要的政治地位。同时由于地理位置的特殊性,其承担有对殷遗民及北方戎族等少数民族的军事震慑与防御职责,军事地位彰显。西周黎国与妊姓薛国、妘姓琱国及王室官员等曾建立了姻亲关系,这进一步体现了黎国在西周早中期非同一般的政治、军事地位,也体现了周人等级内婚制原则。","categories":["06_族氏方国"],"year":2017,"publication":"史学集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIUg34ufHjzwgjeEyvDEDTqP3rbQYKe5rMNjxMfmL_OSn1jyOmCt3QIPLq9zBe-3gGHr8Ab-xykrzOQu5mD-bDjwBxHfxrPfdd7W_0_IZkE8RTuokVSOS9trES-qriXXd3c7Hdi56vgVyKPWkeurNJvQm5h3DeZP8OThIzd4JlBuMT1X4vF_1_0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-74","volume":""},{"id":2331,"author":"辛怡华","title":"甘肃灵台姚家河墓地与古乖国","abstract":"考古资料表明,甘肃灵台一带是西周时期一个重要的聚落中心,而1972年发现的姚家河西周墓地则为长期未决的乖国地望提供了重要线索。古乖国可能座落在今泾河上游,其支流达溪河两岸,从先周开始就是周人的同盟军,曾协助周人克商。与乖国有关的青铜器铭文则反映了周王朝与边境小国之间复杂而多变的政治关系,是研究周与西北边境文化群体之间关系的重要信息。","categories":["06_族氏方国"],"year":2017,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2017.02.04","pages":"25-28","volume":"37"},{"id":2335,"author":"黄锦前","title":"叶家山M107所出濮监簋及相关问题","abstract":"随州叶家山墓地M107出土的濮监簋铭文的&quot;濮&quot;字系&quot;仆&quot;之异构,在簋铭中当读作濮国之&quot;濮&quot;。据文献和出土古文字资料来看,西周时期的濮在南土,与曾、楚及蛮氏邻近。濮监簋出自叶家山曾国墓地,可能系赗赙或馈赠等所致,表明周初的濮确系为周人所褒封之国。M107的墓主应系高级贵族,不排除系&quot;曾伯&quot;的可能。另据金文材料可知,西周时期有一套相当完备健全的监察制度,同意路懿菡关于周初&quot;三监&quot;应同&quot;三叔&quot;无关说。","categories":["06_族氏方国"],"year":2017,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLulHilpaW69ju1PnlPNDqLkXVvTW4oozRQp8ApgsKmncO8IC1uJX9dwsDQqP3pN5htPzKW4vppH0XMnyPYVEix0X19MkjuwpQNq8WwxJ1UITYPg9c5xDhjqXn1slVk0g-sXoR4lT9EMUBmrRL96Mjrup7P-5F7_-nQC6UxBJpW-PcVkmfD-j0Z&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-75","volume":""},{"id":2361,"author":"孔华; 杜勇","title":"孤竹姓氏与都邑变迁新考","abstract":"孤竹是商周时期隶属中央王朝的一个古老方国。其国族既不姓墨胎,亦非姜姓或子姓,很可能是任姓竹氏,为黄帝后裔。所用文字和礼制多与商周王朝相类,当是一个遥居北方的华夏古国,不宜以游牧民族视之。在商代,孤竹可能族居于辽西喀左地区,西周成康以后则迁至今河北卢龙县西北,非如《括地志》所言在卢龙县南。武王克商之后,孤竹国与中央王朝的政治关系似有不谐,但仍然保持其作为一个独立的政治实体的地位,是西周统一贵族国家的成员国之一。春秋初期,曾与山戎、令支一道反对燕侯对北疆的治理,因而受到齐桓公的大举征伐,孤竹国从此消失于历史舞台。","categories":["06_族氏方国"],"year":2017,"publication":"中国高校社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6xsoBpvY1caNeXF3NtkceEq2bFA-_-ob-TDKYx7Nx-8gQVgSuFY-QOLpUxVO3URu-wsDKMtLkojTpKi3Q_P7bP9YFE-ZPufBQrmq-yXRoxJpROxkfjkKo47yNMJg5ehTGrLMw0DeFcICkkGbMUvpOIwacYLQDA9lohJpD2zBmF8KCfocGTsvK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-143, 159","volume":""},{"id":2376,"author":"辛怡华","title":"岐山贺家出土铜器铭文研究","abstract":"对岐山贺家一带出土的铜器铭文研究表明,西周时期这一带居住的族群以非姬姓居多,只有南宫家族与周王室同姓。墓地形成主要是受政治因素支配,少数带腰坑墓葬的族属不可能成为左右这里的政治方向,而嬴姓族群可能是周公东征时被迫迁徙来的。西周时期一个宗族规模平均大约为100人,姬姓宗族人数可能多一些,异性少一些。康王赏赐给南宫家族的17伯(宗族)中的一部分应居住于贺家一带,姬姓南宫家族是这一带的管理者。","categories":["06_族氏方国"],"year":2017,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIq8KTJqf4mhMvNLZHRpWxuVppkkPJid1Ftvx3z4m4rE0jhE0icdcMWSurBVyfo7rdcxJSDa1rUwbAuG73j4XtxjQlbT11cgU8I0qhNPiJEx16-dBzSWNMTJdrjpyRW0M5zukVBbJRN-Mwn5NF1Rzw_OQFM0a4Bz-rRKgYT9w00zcpTWmCIjXt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-25","volume":""},{"id":2379,"author":"张昌平","title":"从五十年到五年——曾国考古检讨","abstract":"曾国是在传世文献中没有明确记载、基本被考古工作所揭示出来的周代诸侯国。围绕曾国的考古发现从50年前的苏家垅,到5年前的叶家山,考古工作与学术研究经历了不同的热点和趋向。本文回顾了50年来曾国考古的重要发现及其意义,从曾国的国族性质等历史问题、曾国物质文化所反映的社会景观问题、到曾国研究对于周与楚文化的理解问题等方面,总结与检讨了特别是最近5年来的研究,以展望未来曾国等诸侯国的考古研究。","categories":["06_族氏方国"],"year":2017,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4aHj5iudqSm4jFO9mj9O5iQxf6ZSP_KuQFmd1RnkyatOqPv5U61NIQVlLOHdZYAyVPeBzOlIG9kA1CeJHIgY7IXzmy3hPohY3bogev2HgthKpE4m46pQaMpYvK2TtkNLaYcREA2-y_A4OrqJC8wfayf17QoXzc__dHu41iZ5_2KTnAFtlGecE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-67","volume":""},{"id":2386,"author":"孔华; 杜勇","title":"西周金文中北国的地望与来历","abstract":"河北涞水发现的北伯铜器,湖北江陵出土的北子铜器,不少学者认为均来自《诗经》所谓邶鄘卫之邶国。实际上,从殷墟卜辞所见北方国活动于水(嘑沱河)流域等情况来看,周初涞水北国应是殷商晚期北方国的后身,是同居一地而前后相承的一个古老族邦。北伯国只发现西周早期的铜器,可能后来为燕国所并。江陵北子国是来自殷人族氏的一支所建之国,约在西周中期为楚国所灭。这两个北国不仅来源不同,各为独立的政治实体,而且与周初三监封邑邶鄘卫之邶畛域分明,遥不相涉。","categories":["06_族氏方国"],"year":2017,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfhq47Ansz4NqvJ6zDW59CL47MW_Q7HC4zKhUsb6D7kWQ2MCiXq46ISymvMjgKs_ZrSvceKpNsNbVbU98zHclgnA0FSEResYnno9YSQjzOvNS1DitufLFL3aPAYTHIBnEDeCCBIKOEkrN4lFjHzKEuiNsG2mkDqpwfCc7xowW_8KZJF8169Nd6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46154","volume":""},{"id":2394,"author":"倪祥保; 周晨","title":"“句吴”是族群名号而不是诸侯国号","abstract":"&quot;句吴&quot;一词因为出现于司马迁《史记·吴太伯世家》,经常被当作春秋吴国的最初称谓,甚至是整个春秋吴国的正宗国号。其实这是一个很大的错误,也完全不符合司马迁的本意。基于先秦时代社会政治历史事实、相关文化规范和经典文史典籍相关内容,深入认真细读司马迁《史记》相关记述等,可以比较明确地知道&quot;句吴&quot;应该是泰伯仲雍兄弟初到吴地时临时组建族群所短暂使用过的一个原初名号,并不是诸侯国号,这就是它从来没有被先秦史学家、经典文献和青铜器铭文等著述的根本原因之所在。","categories":["06_族氏方国"],"year":2017,"publication":"东吴学术","link":"https://link.cnki.net/doi/10.16100/j.cnki.cn32-1815/c.2017.01.011","pages":"103-109","volume":""},{"id":2399,"author":"孙苗苗","title":"翼城大河口出土霸伯簋铭文“丼叔”身份试考","abstract":"山西翼城大河口西周霸国墓葬群M1071号墓出土的一件青铜簋附有50字铭文。铭文内容十分重要,其中提到的人物&quot;丼叔&quot;极有可能就是陕西长安张家坡沣西M157号墓的主人,即传世铜器曶鼎铭文中提到的丼叔采。","categories":["06_族氏方国"],"year":2017,"publication":"淮南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2i3aysM1U4SNWTT0KeFjUpztfr-Js5dbK5LatCBDwgyadXByC37NWJvRjh-5nYFGO1W2cdDSNdA-q9puHu7SiXkkkiVQNIOCly4csyVXn3VDQOJii0uhL5_NeY15jVzpd3yHP24458f2GsMLldc21g2yDSo_dxXWu1XHaTtJcGhTAXWpwR40C&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46244","volume":"19"},{"id":2885,"author":"馬軼男; 周忠兵","title":"芮國有銘銅器整理與研究","abstract":"2005年至2007年,陝西韓城梁帶村陸續發掘出保存較爲完整的兩周時期的大型墓葬。梁帶村南區墓地發現大量帶有“芮”字銘文的青銅器,至此,梁帶村南區墓地的族屬當爲芮國無疑。梁帶村芮國墓地的發現,爲研究芮國提供了豐富的資料。但目前爲止,芮國有銘銅器的整理、著錄和釋讀方面仍有進一步工作的空間。同時,對芮國相關問題的研究也有重新梳理和探討的必要。此正是本文寫作的目的和意義所在。本論文主要由以下部分組成:緒論部分。我們對梁帶村周代遺址進行概述,總結了芮國歷史與芮國青銅器的研究現狀,同時介紹了本文的選題範圍,研究方法與研究意義。第一章爲芮國有銘銅器整理和集釋。本章按照器形分類,將芮國有銘銅器分爲食器、酒器、水器、樂器和兵器五個部分,並在著錄和整理之後對部分銘文內容進行疏解和集釋。第二章爲芮國相關問題研究。本章探討了四個問題,分別爲芮國早期地望、“芮太子白”和梁帶村M27、M28墓主身份、芮國對外關係和","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLU_v2Sf1ROznnpwpotAS-eGI3PZbHtMY6PFe9_1l1-7lzzLk8oNhuVP1kjk6R9F6R97rTqL05sBsXcIgFKkQ-YYr8c_yRdvllxRZ6pnkkziqDZsUBSKoBroNWJM34HJHM0IaXN2SlebXnuHnroRCB42l-Erk4mdkOxNUuYWxBks7CRcu27KLc9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2887,"author":"孫元成; 周忠兵","title":"夨國有銘銅器整理與研究","abstract":"本論文主要收集整理公開發表的夨國有銘銅器共31件,對銘文及其相關的幾個歷史問題進行梳理。從有銘銅器看,夨國在先周可能已經存在,時代延續至春秋時期。論文包括幾個部分:緒論部分。對夨器銘文以及銅器的研究狀況進行梳理,總結有關夨器銘文反映的歷史文化問題。文末為本文的選題範圍和選題意義、文章結構和相關說明。第一章詳細介紹夨器相關文字資料和考古資料。第二章對以往的幾個重要歷史問題重新梳理與探討。本章包括以往研究遺留之問題:夨字釋讀、地望、族姓、余論等。附錄部分包括“其他可能與夨國有關的有銘銅器”、“資源著錄書目及簡稱”、“各家收集西周夨國相關青銅器資料與本文對照表”、“夨國大致有銘銅器編年”。","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJs86rDDbT94MOuSVj-PQDbCq8EwlfI4LfI31NMIXAXEfqjoYcxlNSlrAozvSaBZHeYFPpCBxGOczdFAuNHWY7hDB_W19rY7J65S187dElgLFVW3kk9q-iLcEODf8R6JbnsXZLN33deQgSpUjfdkbD5dVlAJU1Ww25l47g5jhFRmIFrWCScidTH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3169,"author":"杨晓丽; 宋亦箫","title":"两周狄族初探","abstract":"狄族是先秦时期最为重要的非华夏族群之一,尤其在春秋时期,狄逼诸夏,横扫中原,造成“中国不绝如线”的危局,但同时它又被华夏诸国视为一支平等的政治力量,彼此间会盟、通婚不绝,可以说狄族与华夏诸国在此消彼长的冲突、碰撞与融合中共同主导着先秦时期的风云际会;但在以往的研究中,基本以文献为中心,执着于对狄族中各个支系的考证,时段上集中于春秋,从观念上看,认为狄人都是北方民族,与华夏文明差异巨大,因此造成对狄族的研究,认识上存在偏颇,缺乏全面而深入的分析,也没能够在较长的时间段内把握狄族的内在关系和发展轨迹。本文以两周时期狄族的发展演变为核心,试图对狄人的来源、迁徙、内部关系和同华夏的关系做初步的探讨。除了绪论中对狄族相关内容作简要交代之外,本文以时间为线索对狄族展开讨论,狄族出现于史乘在春秋时期,彼时狄族势力已经强大到威胁华夏诸国,之前狄人必然经历了一个长期的发展过程,但这个过程并不清晰,有必要向前","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLiy7EbrQE36Z0MN_TOgbb3JtsXsktD8QiTkHaO7bH39e-PbWIEzl5R7x2e8gP-PmgadTRdWW0l28svTS_ah4m5bRmEIh8ZKMyHlqd4B0iNyc-b9yjnOBAhloSUglW7ocgN0dpT0fVQLPb3xEA6DQOyKOBc3VLCj0OVLlN3xOoWr8nbTS988NpM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3176,"author":"李鹏飞; 毕经纬; 张天恩","title":"宝鸡(弓鱼)国墓地出土商周青铜容器研究","abstract":"渔国是史籍失载的一个关中西部畿内采邑,根据考古发掘,(?)国位于宝鸡西部渭水南岸、秦岭北麓的凤翔、凤县一带,依山傍水而居,(?)国青铜器是宝鸡地区少有的科学发掘的铜器群之一。通过对(?)国青铜器的分析,我们认识了西周初期一个有着发达的青铜文化和创造精神的畿内采邑,(?)国在西周成王至康王时期达到鼎盛,穆王时期衰落,之后迅速灭亡。由于史籍史载,直到今天我们也不知道渔国灭亡的真实原因是什么。本文主要分为六个部分,从器形、组合、纹饰、铭文等方面入手,重点探讨了渔国青铜器的风格特点,对(?)国铜器的属性也进行了探讨。第一部分,绪论。绪论主要介绍了宝鸡的地理环境及宝鸡在中华文明特别是铜器文明发展中的历史地位,对宝鸡出土的青铜器及宝鸡青铜器在中国青铜器研究中的重要地位作了简要陈述,最后将本文的研究对象界定为(?)国墓地出土的青铜容器,并对(?)国墓地出土的青铜容器研究现状进行了评述。第二部分,(?)国","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjFVojAu1PDqUbRFovJ4WNYi6WIqB9Z3yz6FPvg-TcBcgwRQIkq6kosZolDULV6UJvYcvPxcRDS6HAhPUDzz-yCRzPGIqYiltF7vqVcuHBnqgzzpr97M5bn_g8omCUdpDO5p_sv4fh8d8GYQUY0GOQ096cvXGYb9_EnymYRhJuXCh41BP3yLrU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3185,"author":"许倩; 王富强","title":"周代南阳盆地封国初探","abstract":"南阳盆地是位于黄河流域与长江流域之间的一个具有南北过渡特点的山间盆地。其地理位置较为特殊,交通便利。这种特殊的地缘特点深刻的影响了南阳盆地的文化传统。从新石器时代到周代,南阳盆地一直都是南北方政治势力反复争夺的地区,深受南北方文化的影响。这种文化传统在新石器时代就表现为深受北方中原地区的裴李岗文化、仰韶文化和南方的屈家岭文化的双重影响。夏商时期中原王朝十分重视对南阳盆地的经营。西周时期,周王朝在此分封众多封国,继续对其进行经营,南阳盆地的封国深受周文化影响。西周晚期,南方的楚国逐渐兴起,南阳盆地作为周朝“南土”和楚国“北疆”的战略地位愈加重要,成为周朝和楚国相互争夺的区域。最终,南阳盆地被楚国吞并,封国深受楚文化的影响,被纳入楚文化的范畴。","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIiuDUcIJNljQO3KxLXQwsNARMMEMfeEDMyg0zbwwHyijEky7FiabmAR5SNwLnLDkfLuh0txblc6AJlhGTZDYkmps3eM_1xwLePogXVTIya4KT8BccE_b9APWG67hVV0BG8rx49C1f8Y282Y00hftsy82dUvtQfb0OB_KBKX6LdQyakH5-GLsL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3186,"author":"苟家容; 江林昌","title":"“汉阳诸姬”初探","abstract":"“汉阳诸姬”分布于汉水之北与淮水上游以南的广大区域,以姬姓为主,也包括一些异姓的古族古国。这些诸侯国有的分封于武成时期,但大多数分封于昭穆时期,逐步构建南土防线。当时周王朝分封“汉阳诸姬”当为防御淮夷,而在淮夷势力减弱之时楚却趁机兴起,转而又抵御楚国。随着楚国势力的崛起,以及其北扩战略的推行,“汉阳诸姬”面对楚国强大的政治与军事压力,已不能有效达到先前抵御荆楚,拱卫西周王室的目的。在春秋时期,王纲解纽,诸侯争霸的政治形势下,“汉阳诸姬”开始更多考量如何避免过早被楚国吞并的厄运。它们不得不委曲求全,在新兴大国楚国面前,通过上贡与贿赂、政治联姻、结盟、委质和附庸等手段,不得不出让自己国家主权,成为楚国北扩战略推行过程中的牺牲品。虽然这种委曲求全不对称外交策略在一定程度上延缓了“汉阳诸姬”衰亡进程,但却无法避免其最终被吞并的悲剧命运。","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIiuDUcIJNljQO3KxLXQwsNARMMEMfeEDMyg0zbwwHysH7WmjvR3a3XLugQl56J4Bew12jZQIpS61RVLcuKi07Sfw_0ifbJVls3F9U2aN3ww9o_61Emh5HWtKB9LYgq2R1vPpsyBwuA3Yy3vpQIuezP8oMtorj9YDONQSa6-fJo8UcqgdddIbW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3190,"author":"王珊珊; 周宝宏","title":"山东西部诸侯国东周青铜器铭文汇考","abstract":"本文为对山东西部诸侯国东周青铜器铭文进行汇考整理研究,研究所涉及的地理范围限制在山东西部地区,选取邿、铸、滕、邾、滥、虐台、费、薛、邳、曹十个诸侯国,历史时代限制在东周也就是春秋战国时期。本文共收集十个诸侯国东周具铭铜器六十余件。本文采用王国维的&quot;二重证据法&quot;,即文献资料与考古资料相结合进行考证。本文正文部分共分十章,分别对滕、邾、虖台、邳、滥、薛、费、曹、邿、铸十个诸侯国的铜器铭文加以汇释整理研究,第一章对滕国东周具铭铜器进行研究,得出的结论主要有:&quot;(?)&quot;即为滕国之&quot;滕&quot;,又作&quot;(?)&quot;;(?)字或释昃或释昊或释吴,结合滕侯吴戈乙器铭文可知此字应释为吴;&quot;艁&quot;字习见于兵器,为&quot;造&quot;字的异体之一,格式主要为&quot;器主名+(之)+艁(造)+(器物)&quot;,等","categories":["06_族氏方国"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHREgqOC-Apv5yDk1uUnOFuZzpDSzLyL4gZMKlswOmYm_X7l0BLExsBJNewi5YdJ4WKschJ-JYsDb2qFIIaPvDwCIgMTZ8hqmDOw8pBmM60wRFQEdpNLArOyKpLewCaBPEJaMptID35QoI8ksCPEekOBwzCVzD2YUP_hmP8jOzTDMs-AaNGJqp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3360,"author":"孙敬明","title":"邾国出土异地商周金文通释绎论","abstract":"钩稽邾国境出土庚、霝、鲁、郰、毕、昆、铸、滕、昶、鄝、徐、吴、宋、费、邳等十五国族青铜器，铭文凡三十四件;其篇章所涉疆域海岱之外，南达江淮，西抵周原。兹对相关铭文内容酌为诠绎，以揆度每历史时期邾与列国之间文化交流趋向与融合之态势。","categories":["06_族氏方国"],"year":2017,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISRiFGDZnRsg38-NwxUtePiC2ZhsaAgJgbAAZIMmTmpmWUIxOhFstseyvWth0CiJZMTVBrQo6RMQNLaSb3I71ofAWyJTkS5aW1_zc9Yk_VmZ9U2MEG_JsxjXviGcgu5PIIhILRGF8ZdHes-kXIIkdy2matSEYgsJUWgffIOjIBiw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-69","volume":""},{"id":3361,"author":"李秀亮","title":"新出伐簋铭文所见鲁国史事补证","abstract":"伐簋铭文记载了器主伐以王室使臣的身份，受王命聘问鲁国，是研究西周时期鲁国史事的重要资料。鲁献公对其的大量赏赐，并不是聘礼中的“宾”礼，而是以大宗宗主身份对小宗伐的特别馈赠。铭文中的小子■，或为伐的小宗，因同聘于鲁而受赐。器主伐虽为周公后裔，但他更可能出自凡公或祭公家族，而非君陈家族。通过伐簋铭文，我们不但可以知晓鲁献公勤王的史事，还可了解鲁国公室与王畿内周公宗族的交往情况，以及西周晚期鲁国与周王室的关系。","categories":["06_族氏方国"],"year":2017,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISRiFGDZnRsg38-NwxUtePiC2ZhsaAgJgbAAZIMmTmpmWUIxOhFstsXixamLILYaD9ef218TmUOr_mIUFp_t8xWzFdAD5y9A8UsF7yosnDxaTbKQuAQJ_AzXdoe42ZxFcs_xFAjB4msHnLVl-zXaWjdrM0VYW869LHu5I4YH8Rtw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-84","volume":""},{"id":3548,"author":"莫阳","title":"战国中山国中山三器的再观察","abstract":"中山三器包括中山王■鼎、中山王■方壶和(妾子)■圆壶,它们是战国中山国的礼器。镌刻于三件器物上的铭文,为研究中山国史和该时期北方诸国间关系,提供了信实可靠的依据。该文从中山三器铭文的内容、书体和对它们的观看三方面入手,分别讨论战国中山国历史、文化来源等问题,并尝试对其使用空间进行初步复原。","categories":["06_族氏方国"],"year":2017,"publication":"中国美术研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEegjBc5E-2DoJGj3myQlT4UAY8HDmW2AbWt6WJYJw60mbPAt7M7diKW7dszcKqCXnC-vjHgCUIuPO94FjYIX_r3piSf5emrOo_IO7-1fTT_LT2nb35dmQfWR1uXuLSmeQ7ms1PGVtqfDQ4PC9jYIo7Ec1ycz5NVFLpRx0ds_txg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-62","volume":""},{"id":3556,"author":"徐倩倩","title":"青铜器铭文所见两周时期山东古国婚姻关系","abstract":"婚姻往来是两周时期国家政治交往的重要组成部分。山东地区两周时期古国数量众多,婚姻交流是维系国家间政治平衡的重要方式。文献中对山东古国婚姻往来的记载较少,而此时的青铜器铭文可以提供补充资料。本文收集已经发表的考古资料、金文集录,将与山东古国婚姻关系相关的铭文青铜器汇总,梳理青铜器铭文,试图理清山东地区古国间的婚姻关系,为研究山东地区的政治、文化交流提供一个切入点,进而总结两周时期古国婚姻交流的特点与规律。","categories":["06_族氏方国"],"year":2017,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKoIPCLvyK-DwplYji5c1o-e_Q45iBJ3SVeRpVkITQ36CnAfYttdd132uYo6gK4MpYg0uiDFS0ElSuLepWGeaV6mNa-NBN0qHiEkdpgXzIYSA4HkYqMUpCq41STwgNohsOsZB9Iy6paDrMrHh30IvZRw8tgtjzA_AtcUA1UQOg7xA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-47","volume":""},{"id":3557,"author":"胡嘉麟","title":"东周时期的小邾国青铜簠——兼论小邾国墓地的相关问题","abstract":"小邾国是鲁南地区的一个小诸侯国,文献对其历史和世系记载较少。小邾国的青铜器在清代就有发现,曾毅公考证邾友父就是小邾国的始封君友。2002年山东枣庄市山亭区东江墓地发现六座小邾国贵族墓,出土了数量众多的小邾国青铜器。由于有四座墓葬已遭盗扰,对于墓葬的时代和序列众说纷纭。本文通过分析小邾国墓地出土和流传的青铜簠,结合墓地同出器物判定墓葬组合和年代,并通过铭文对小邾国的邦交和媵婚制度进行讨论。","categories":["06_族氏方国"],"year":2017,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIW7U9gB4vS1a5Ao0wLObO6Md7RJCD3P48hGqmx9lb4aX1-uNpEQacp_4GCzNhaixN5HdW7d8QS5i9qSNApBc-NwuBUCMQUXhOKcubpiftlaV7TZ_9ZowtrdWSW_OKcj9APx6EOP3xE_M90relq8ymw0nZEp5o-9zVNpHwGsAc5lw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-79","volume":""},{"id":3558,"author":"黄锦前","title":"■伯鼎考释","abstract":"本文对《商周青铜器铭文暨图像集成》著录的两件私人收藏的■伯鼎进行了考释,从器物形制、纹饰及铭文内容等方面入手,认为■与妊姓秦、华一样,系山东南部地区的国族,见于西周中期的金文,春秋早期尚存,与楚有婚姻关系。作器者&quot;■伯&quot;系春秋早期前段■国族的君长。","categories":["06_族氏方国"],"year":2017,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbOphUOW1cPlBOb5COclESdovE57rhq3cz_0n7RDqK7Aph47rr5whBIk1JWJVGWUiCC9akXHdw_S9BKDMjjbCPJOaW6mkcCfLXbegUtmXbZyu2AmNyfOR1x87SK9JNG7aa5mkweR4f8wlQT4F3-d9HonyyjbfW6cyoT5z_qyZgGQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"99-103","volume":""},{"id":3565,"author":"黃锦前","title":"从伯(爭司)簋谈到两周金文中的蛮氏","abstract":"本文对安徽博物院藏伯(爭司)簋及过去著录的同铭簋释文进行了订补,认为簋铭的&quot;峦伯&quot;即&quot;蛮伯&quot;,系屡见于金文的蛮氏的君长。其时代为西周中期后段。进而对金文中有关蛮氏的材料作了系联和分析,指出蛮氏或系文献中所谓&quot;荆蛮&quot;的支系。终西周之世,蛮氏皆活跃于今湖北界内的汉水流域一带。西周时期蛮氏的地望,应在今湖北境内的汉水流域一带或邻近地区。结合古书的有关记载可知,东周时期蛮氏已北迁至今河南汝州市西南至汝阳县东南一带,公元前491年为晋所灭。蛮氏的北迁,或与春秋中期以后楚人势力上升北上有关。战国时期,蛮氏的后裔仍活跃于楚。","categories":["06_族氏方国"],"year":2017,"publication":"洛阳考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQr5aPzM3CgSlKTF-J6Tztodh3JaEPD3acupf8mqj4UsGq42S6mzAOJGHfeu_6-wTsNP6CJoPvNZ__yV9CLsP1Vzyu8uFePLjLy9CNhpcfqBouNdcQF3_K7afOQaYoVurAfYsY3WwS0d1-TAsaOLNRZD3307wmjf3h3BJi4BN4eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-68","volume":""},{"id":3578,"author":"齐韶花","title":"商代商奄集团的青铜器特征探讨","abstract":"一、第一组铜器:铜器铭文中出现&quot;割&quot;铭与&quot;胡&quot;铭的商代铜器今天我们在文献中熟见的&quot;商奄&quot;之&quot;奄&quot;,原是以&quot;■&quot;&quot;害&quot;两字为本字的,而殷墟卜辞所见的多奄(多■)族,即是本文所要讨论的商奄集团。这个商奄集团中,目前可以确定的商代族氏至少有割(写作&quot;■&quot;,&quot;■&quot;)与胡(写作&quot;■&quot;,&quot;■&quot;),能与&quot;割&quot;族对应的商代族徽铭文中推测应有■、■,能与&quot;胡&quot;","categories":["06_族氏方国"],"year":2017,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFD97ObpqTFapXCJP4y3MpohM4OPbmZI80_MfM01CrfwXbP5gJUoTASmiwXKIusxEFVOkkW2XV1AOCBCvMbODMJgreDs9LSdtPsMAV9vn3doyd8DAr5SlkYXa5s104mIi0HEOb3_9HkRuOA22SdQnBI-hMQ93Yylwp7gjcVF1mbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"148-164","volume":""},{"id":3586,"author":"周宝宏","title":"■簋铭文“者子”考","abstract":"本文研究了■簋铭文&quot;者子&quot;,认为&quot;者&quot;是国族名,读&quot;诸&quot;,商末亚丑族氏者(诸)国族的后裔,&quot;诸子&quot;即诸国族之国君。","categories":["06_族氏方国"],"year":2017,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgmKa9FS3jXgW4JhhFlsEcbV9oojJRU8BUrRUpzLA5E2iW5mtMoP2FNSjWl60F2wToTLN7PLnjzZBTPL353x8_Gx6LRXKW8NQ6jBm71OiIm4BKL6SuxeuizGMg5iD01U6pLg9SU6HODUhjFF3MV7XmFCq59ie1vYZcjrkDxcs6Sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46212","volume":""},{"id":3616,"author":"程浩","title":"《考古發現與古代姓氏制度》、《先秦人名的幾個問題》讀解","abstract":"發表於上世紀九十年代前後的《考古發現與古代姓氏制度》（以下簡稱&quot;《姓氏》&quot;）以及《先秦人名的幾個問題》（以下簡稱&quot;《人名》&quot;）,[1]是李學勤先生在先秦歷史文化研究領域的名篇。兩文共同構成了李學勤先生對於先秦人名的系列研究,分别以&quot;姓&quot;、&quot;氏&quot;與&quot;名&quot;、&quot;字&quot;爲側重點,探討了先秦時期的姓氏制度,並對商周時期的人名結構進行了系統總結。我們這則讀解,擬從兩文的寫作背景、學術價值及其後續影響","categories":["06_族氏方国"],"year":2017,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsCR_kvlnSRcGVBHIV7j2yg7tAX0vbrQrMXcIelnvfQsrKZ6AgYfJ2MJWdW3wihPXp0i-Md5SjUaiP5qiEylU_Bdlc92yVMHqlxBODgwsLiML7OozeXzk2N2nn5j20FkNNaxp5sP7WutlLLcv9CVlEY9reaJ_TLOqC31p-mkHEeQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"291-305","volume":""},{"id":3630,"author":"劉麗","title":"銅器銘文中所見兩周時期曾國的婚姻關係","abstract":"曾國一直是學術界討論的焦點。傳世文獻中有鄫國,是一個依附於魯國的姒姓小國。然而從宋代開始,出土的零星青銅器材料表明,在湖北隨州還存在着一個曾國。1977年隨縣擂鼓墩一號墓發現後,這個曾國得以呈現在世人面前,引發了學界的廣泛討論。1978年,李學勤先生提出“曾國之謎”,認爲曾、隨一國二名。隨後很多學者都有討論,但一直未有較一","categories":["06_族氏方国"],"year":2017,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJBEWXuGEh6SSJ-xVSDNj1GnqE-egUgqwEaNBt6Jvbo7XO4bnpE4tILAYmzMAjDnaBKJ3EYXXNO4g5Xhqyed77TGP0UTEk8Wv0q2U-hjcBWqRDZlExRRnzShwX4lSGJ2OEU4nV399_Y8iIxBXZKKD2DR-nh200G9UwLklsToqFjbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141-165","volume":""},{"id":3636,"author":"風儀誠","title":"西周早期中型墓葬中銅器銘文群綜觀——從寶雞石鼓山西周墓出土銘文說起","abstract":"2012年在寶雞石鼓山發現了重要的西周早期墓群,出土了大批青銅器。其中M3和M4兩座墓葬保存較好,是周原地區少見的、保存完整的西周墓葬。M3爲中型墓葬,出土了不少帶銘文的銅器,引起了很多學者進行探究的興趣。專家從銘文内容聯繫到傳世文獻及其他出土文字資料,來探討墓主人身份、族屬及與其他族氏的關係,在各方面都已取得了值得關注的研究成果。筆者想從另一個角度來研究這些銅器銘文,把石鼓山M3出土銘文群與其他類似墓葬銘","categories":["06_族氏方国"],"year":2017,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHEJ2-nUws1giAQz8bj8XXxjeRCCgdzPZaq4ADGz3gZEgjkSiVec9PSB0oQwmvnAkAW2FTR_vZ4Ovtrg0LO8AX6-mWTbt0uSSlN3CW4AE0FTxEzKrZ21S3XvU9K9YvQhCb7_3u822b00KsveyH7Db7K40CAugL3zA2jynZW2gh0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"348-387","volume":""},{"id":3640,"author":"亓民帥","title":"蘇州博物館藏吴王餘眛劍銘文與餘祭、餘眛史事","abstract":"2014年底,蘇州博物館徵集入藏了一柄吴王餘眛劍。在劍入藏蘇州博物館之前,曹錦炎先生曾於私人藏家處見過此劍,并撰有文章對其銘文及其相關問題作了研究;[1]李學勤、朱鳳瀚等先生曾對劍作鑒定,并發表過意見。吴王餘眛劍入藏后,蘇州博物館召開了“兵與禮——吴王餘眛劍學術研討會”,邀請了李學勤、李伯謙、曹錦炎、吴鎮烽、李家浩、周亞、張懋鎔、董珊、程義等專家學者參加會議。會後程義、陳偉先生發表了《“兵與禮——吴王餘眛劍","categories":["06_族氏方国"],"year":2017,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLScuxvkJ5Y8VpmXDoXQyseD6GMZ46axsSTbpVvUVsd1fQ2yrZm7o_TDua8Ijio_r71K8Z_vfkGW1Ti75eKT5skgE7Xky-3JnLADwiWBvEKVdKPnKlXmNnji1p3lMPlDcVLxnPMyv093cpTzLSIkVrQ6Uqc5mxhu5mIrtPfFBFbA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"598-606","volume":""},{"id":3667,"author":"马赛","title":"铜器窖藏所见周原遗址贵族家族变迁","abstract":"周原遗址发现的大量铜器窖藏早已引起学者们的高度关注,其中所出铜器上大量的铭文资料,更是学术界常年持续关注的热点问题。研究涉及的内容除单个窖藏铜器铭文考证、窖藏性质等外,亦包括很多通过贵族家族姓氏来探讨周原遗址性质问题的研究[1]。本文试图通过对周原遗址铜器窖藏的埋藏年代以及所反映的贵族家族变迁情况,对周原遗址西周晚期之时的社会变迁进行讨论。","categories":["06_族氏方国"],"year":2017,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4WYsWtFvogTEWq6e3aYAJxSOBJQt5h5xwBjF2gHIF29rN24faUxmW18RkPsH8J0vu8VbkSd5rD4M-03_Rohua8kw0YG-7vZIGAPP0WFnjl3o_zKgXsshv7jU_LdKNam3d07pGgFzGUpph-QFPMK0qQbZxVZOWsemrNwjU7tehbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-120","volume":"11"},{"id":2413,"author":"田成方","title":"申氏铜器与楚申氏的族属","abstract":"申氏是楚国望族,春秋时期涌现出申舟、申亥、申包胥等一批名人,然其族属却一直颇有争议。前些年发表的两则铜器铭文,内容关乎楚申氏的来源,有助于解开申氏族属的谜团。一1990年,湖北郧县肖家河一座春秋晚期楚墓出土一批青铜器,计有鼎2件、簠2件、缶2件、盘1件和匜1件。发掘报告根据铜器的形制、纹饰特点推断其时代应为春秋晚期[1],与河南淅川下寺丙组M10出土的铜鼎（M10:50）、簋（M10:44）、尊缶","categories":["06_族氏方国"],"year":2016,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJGiNdeUjn4flN_7ZcCqIE-9ZXU8E_o2FPTB0YyyDNGmNajRnoxj0mbhmq6LvGCEOZgELSqR8dNQ4fbGs7bl3tuDNDIa1NcrriFkYlcjYS_iVcNT1UiqhBb_m7oDDesise7cUA3SWXX7C6fZ1lqoCNRmcCv8-bQLI7vvY1gsRZ0Z1rnjidf86p1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-89","volume":""},{"id":2421,"author":"张丹","title":"南阳地区出土铭文所见春秋时期楚国联姻考述","abstract":"传世文献所见的春秋楚国联姻关系中,楚国多与独立主权国联姻、没有固定的联姻对象、楚王担任了联姻的主力。南阳地区出土铭文中所见到的联姻与此有别:联姻的主力是楚国的公族,主要是一些附庸国与南阳地区楚国两大家族氏、彭氏之间的联姻。二者的不同主要是由出土铭文的地域性决定的,但总体上看,联姻关系都是为了建立以楚国为中心的邦际关系新秩序。","categories":["06_族氏方国"],"year":2016,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkxoeXrND8FlXauWcgmwrL3N1YfzEdozH6eziBikjEZVBsHGow3mMt8Mkpo9n0dC7XUH6VUY26vfYSsLlNze1-F_DlN5rSQqcYuG-iEOuiId9VnNdF04T2o7GGDHcpkvQ-PupEjqwb4-AhNijL8XeYoZAIui10wBYdCbFWXLpeo3rIIr1fJLrQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-78","volume":""},{"id":2424,"author":"叶先闯","title":"关于荣簋等五器与西周荣氏家族联系的一点意见","abstract":"金文研究中出现相同人名的器铭,学者多根据人名系连法进行铜器断代和释读。但此法如使用不当往往有碍于正确解读铭文含义。在井侯簋、荣簋等五器中出现的人名&quot;荣&quot;普遍被学界看作是周初的荣伯,但根据称谓、世职、赏赐等多方面考虑,认为这五器中的&quot;荣&quot;和周初荣伯并无必然联系。人名&quot;荣&quot;应理解为个人私名,与西周&quot;荣氏&quot;两不牵扯。","categories":["06_族氏方国"],"year":2016,"publication":"文史博览（理论）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICqIX522Lwyk5XWk8ncFVl7vYMJbVt_WOQz-ThYfaPgA3pcffRuZFIDzMX9W7ihxF2jyr9vyr_G3lHka9gYrE3RknggGK75egJEOS5k_8zHvNbmhikoP-E2E3lN9Pp__B1g4nOhmrSFKJU3wBCY-ZhFJMb3LekQ6reGTD5de8BAljwFgonDw5v&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-25","volume":""},{"id":2440,"author":"王长丰","title":"新见族铜器兼及相关盟姻族徽的再认识","abstract":"通过新见铜器族徽铭文,阐释了盟姻族徽在形式上是由基本族徽通过累加或缀联等形式形成的族徽类型。利用盟姻族徽本质上就是由国族姓氏之间以&quot;同轨&quot;、&quot;同盟&quot;、&quot;同位&quot;、&quot;外姻&quot;等途径形成的&quot;结盟&quot;或&quot;外姻&quot;等关系的血亲组织特点,解决了一系列相关青铜器铭文的释读与历史认知难题。","categories":["06_族氏方国"],"year":2016,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK7GgZftLcrKIDyGzUMTY4_QVTzAbEK6XqXUbe_AMOTP8AZGQL2WzkIN0sf92v-tPfMECTxAnY77dPxy05554BzXzqZKEB5NyGQBK4soUzasQA8CG5oSjMXS5x5V8IuCKfzEB-GdF5qAzJutXDxHiLPknAF_WegJ7R6BCCj14URdOsnfTP3azWW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-43","volume":""},{"id":2443,"author":"曹斌; 康予虎; 罗璇","title":"匽侯铜器与燕国早期世系","abstract":"关于燕国早期世系,传世文献语焉不详。本文借助对西周时期匽侯铜器的辨析来重新梳理燕国的早期世系,本文认为召公留守王室一支的世系可以排定为:召公—召仲—召伯父辛—伯宪(伯穌)—召伯,对应的前三代燕侯分别为匽侯克、匽侯旨以及某位不知私名的匽侯。","categories":["06_族氏方国"],"year":2016,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHr195XGHp4LPHYEtkMUB0OVM8VzrOcatInbn3l5GjJ9wf3t7z1OHwj9F_aIqsfjAUEw0jXbQyGMlBo_LQErLy-ZzeFY23RcN-yaTXzOzHW-cT3vzZQ4B7yJxow7g6zgdYuNQfkKckEdskYda5DpcQqu7XqY74LckR_0Hlw1WOxSUvzCaLxdQk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-76","volume":""},{"id":2444,"author":"于薇; 常怀颖","title":"叶家山“西宫”爵与两周金文“三宫”及其相关问题","abstract":"本文对叶家山M107出土的&quot;西宫&quot;铭文爵等相关材料进行梳理,尝试探讨西周金文中&quot;西宫&quot;&quot;东宫&quot;&quot;南宫&quot;的问题,并结合相关材料分析M107及叶家山西周墓地的特征。本文认为&quot;西宫&quot;长期为寝、庙之称,用于人名或族姓名的情况不多,且地位不详。&quot;东宫&quot;则多为高等级贵族之称,亦有作为宫室名之情况。&quot;南宫&quot;为族氏名,极少用于宫室、处所名。&quot;东宫&quot;铭文较集中地与王室活动相关,而少见于各封国,&quot;西宫&quot;的情况与&quot;东宫&quot;基本一致,仅有两个特例都出在曾国,&quot;南宫&quot;器物则散见于各诸侯国。基于现有材料,将M107定性为曾国一般公卿贵族较为稳妥。","categories":["06_族氏方国"],"year":2016,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1S8PKLI48d4DyOmA0zNwFl0Qt0N8-Fl3SwT-P42ZGzURHZANlIf2jmtbT0wb26sT7Nf7rddhRkIuQPm0hcwEsKgfOzoatquyOVGmmggjza40MlcVe6K1Jj_Siw2OwTjstsioF7pnDzJAnU9yb1FPxPbLzJWDtpqF5jNfnM7ayw9ubkEyUghdC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-85","volume":""},{"id":2454,"author":"李晶","title":"铸国史事辨疑","abstract":"利用考古资料与青铜器铭文研究先秦时期的方国,是近年来学界关注的热点问题。铸虽是小国,但目前所见的相关有铭铜器已达十余种,能够有效地补充传世文献记载之缺环与不足。同时,铸国史事仅零星记载于典籍,史料有限,且颇多相互矛盾抵牾之处。故以往综合研究铸国的专题论文比较少见。此文结合相关铜器铭文与考古资料,对铸国史事进行重新评判,材料比较丰富,为认识铸国历史提供了资料。本文除了直接引用史籍的相关记载,还注重利用《春秋》书例与《左传》辞例进行考证。如利用《左传》辞例&quot;娶于某&quot;皆是娶于某国之意,以证臧宣叔娶妻之时铸国尚存,进而证明今本《竹书纪年》对铸国于春秋初年为齐所灭的记载有误,弥补了直接史料记载不足的缺憾。由于资料所限,该文所讨论的铸国历史和相关制度还不够详细,比较细碎。","categories":["06_族氏方国"],"year":2016,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIzBLwfIyAd8Cr0VejeBJ5SLujdChYJq_CI6fnMKK0PF_mfWhqAlvohmOvdSSehmhRnBEy8rZnz9Tg8FZTL8y82bApv_RsSfeHSjVrtevGPx18sxtrWX0HEzk-ZXTrA9RwaegDCfXQ8jaHCvW_DJUmUjY7hJGoSsh3DhdEoAO5VoigKQuw-Fnaf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"237-240, 209","volume":""},{"id":2472,"author":"赵平安","title":"(女菐)盘及其“■君”考","abstract":"(女菐)盘的作器者&quot;(女菐)&quot;是随州义地岗文峰塔33号墓的主人。她是■君的长女,曾在周王朝为官。根据上博简《成王为城濮之行》和《左传》僖公二十七年的对读,可以判明&quot;■&quot;就是子玉治兵之地&quot;蔿&quot;。君作为楚的重要封君,把女儿嫁到曾国,是当时两国关系的一个缩影。","categories":["06_族氏方国"],"year":2016,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIyJAAnrH40hrN_q7VPJTUoWn22XHJdNKzIzxvuwd8F9q7htrU7y7T5Ao6_UDeZzhFZJAQSexx9yXS_QJjAY6biRVrLJ4ns-qnztcC3UiKYN-Nf0ml-43onKkWnBWg39XYDtPn7Caj_jV1nidiPki0vC9Hd07ghzUVJJLd9i7_4P1MgKDofK-N&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-48","volume":""},{"id":2473,"author":"谢尧亭","title":"发现沉睡3000年的“霸国”山西翼城大河口墓地","abstract":"山西曲沃天马—曲村墓地曾出土一件霸伯簋,铭文为&quot;霸伯作宝尊彝&quot;;传世的西周早期霸姞鼎、霸姞簋,铭文为&quot;霸姞作宝尊彝&quot;;吴镇烽《商周金文资料通鉴》著录有一件霸簋……在古典文献中,并没有&quot;霸国&quot;或者&quot;霸族&quot;的记载。不过在传世及出土铜器的铭文中,偶见有&quot;霸&quot;,这引起了考古学家和先秦史家的注意。&quot;霸&quot;是国家名称,还是族属名称?&quot;霸&quot;人的生活如何?","categories":["06_族氏方国"],"year":2016,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrIEBIN2ZHWKuzctBUb9ml2UjRCsipovzKxkDNnPlpKPgT9i_uJSilTlJUfRb6HmqNsnHpc9Gvxn3gSfaTSUjU4RmZwvbkQnKuRN6mxuOTA5nhiCK44Hbh1PVkoMsIrONS9cLoK0we5PZeTkcmWtvf2OGZC0j08m4fn4B-ln0AKFKAOVPgzdHT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-44, 98","volume":""},{"id":2476,"author":"陶亮","title":"新命楚王戈相关问题考","abstract":"淅川下寺M2所出的新命楚王戈,涉及到的楚王之名学界多以楚康王当之,然而根据铭文的考释推断,结合当时的楚国史事,戈铭中的楚王当以楚平王熊居为是,戈铭恰就像是《左传》&quot;弃疾即位,名曰熊居&quot;及&quot;使子旗为令尹&quot;这两条记载的金文印证。","categories":["06_族氏方国"],"year":2016,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOiO80_QZRkYA8PETWNXDtaTftfdueWxN3PFaigOtx_p_BvtP76m6F3sX-8dahHEvpYyon0JFZnwwbnLyEadznawJGY4r_Ac3hKNneBH-aVUn7g8ZSTdZSgZ-8QxcSbR9403uCCm2q22x1Vc5VYCJ9zPRuH9pQbDIb72gKM-NM-u-ha7-x5mxI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-91, 95","volume":""},{"id":2488,"author":"董越","title":"鹿邑太清宫西周大墓墓主研究回顾和指迷","abstract":"简要回顾了鹿邑太清宫西周大墓发掘及墓主长子口身份的几种见解,指出了各位方家争论的几个关键问题。结合甲骨文、金文等出土文献和传世文献肯定了长子口是辛甲后人的说法,并进一步认为长子族是一个智慧的民族,古&quot;长&quot;国在商周的地位不可小觑。","categories":["06_族氏方国"],"year":2016,"publication":"周口师范学院学报","link":"https://link.cnki.net/doi/10.13450/j.cnki.jzknu.2016.04.022","pages":"85-88","volume":"33"},{"id":2491,"author":"赵燕姣","title":"西周时期的淮夷及相关族群","abstract":"淮夷作为西周时期一个重要的族群,并非淮河流域的土著居民,而是经周公东征和齐、鲁分封后被迫南迁至淮河流域两岸的东夷分支。而与之相关的&quot;南淮夷&quot;主要是指西周中期遭受周人重创后,再次南迁至淮河南岸的淮夷分支,而所谓的&quot;南夷&quot;盖为南方之夷的总称,应涵概淮夷、南淮夷在内。","categories":["06_族氏方国"],"year":2016,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2016.07.021","pages":"164-171","volume":"37"},{"id":2493,"author":"丘山代; 刘文阁","title":"河南正阳出土“禽”铭铜器初探","abstract":"禽族是晚商王朝的一个重要方国和部族。他们的文化面貌如何、他们的聚居地在哪里、他们与商王朝是何等关系。这些都是值得探索和研究的问题。在以前的著录中也有部分&quot;禽&quot;或&quot;亚禽&quot;铭文的青铜器资料(1),由于资料少而零散,且没有明确的出土地点,并没有引起学术界足够的关注。最近几年,在河南驻马店正阳县发现一处商代墓地,出土一批商代青铜器,其中有相当比例的青铜器上都有&quot;禽&quot;或&quot;亚禽&quot;铭文,为深入探讨该问题提供了重要资料。本文将以","categories":["06_族氏方国"],"year":2016,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbnELdKLF5aBPZgiIv8oGLPcSu_j9uBLcpnU8s1WeKhB4gqP-W1c5En9uswG0aIvj8JTYsMem36gIsug71v4yhHC0gPQtrxluX2IYW-nGsFN1XfHXL4BmnZkWBydXfutnbeqkT7ROz3vzgGuWy9BxYla7sXfV2ZFxHB6KHR5NT7puXfm4v2vlL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"167-177","volume":""},{"id":2518,"author":"丁堂华; 秦昌林; 方文","title":"试论古噩国及“鄂”文化的相关问题——兼论鄂国与商周王朝、楚国、曾国的历史渊源","abstract":"关于古噩国及&quot;鄂&quot;文化的形成与发展等学术问题,由于历史文献只有零星的记载,加之数十年考古没有或很少涉及到鄂国城址、墓葬的发掘及研究工作,使古噩国及&quot;鄂&quot;文化的&quot;脉络&quot;问题成为&quot;千古之谜&quot;。文章通过全国范围内征集、出土的鄂国青铜器、墓葬资料等,结合文献资料,从鄂国产生的历史背景,古噩国的建立与&quot;鄂&quot;文化的面貌等方面进行了较为全面的研究。","categories":["06_族氏方国"],"year":2016,"publication":"鄂州大学学报","link":"https://link.cnki.net/doi/10.16732/j.cnki.jeu.2016.03.001","pages":"46154","volume":"23"},{"id":2529,"author":"王坤鹏","title":"西周异族邦伯考","abstract":"异族邦伯作为一类政治团体早在商代已经存在。西周时期的异族邦伯品类复杂,部分与周关系密切,臣服较早,在伐商过程中立下功劳,故或进入王畿担任官职,或被置于边关要地,承担镇守之职。这类邦伯作为一个团体,参与周王朝的祭祀大典等政治活动,王朝则通过聘礼或劳慰等方式加强与邦伯的臣属关系。部分邦伯处于边域,叛服不定,遭受王朝的武力打击,成为周王的&quot;王臣附庸&quot;,供周王驱策或赏赐诸侯大臣。西周时期分封的地方诸侯对封域内的异族邦伯亦有因治之责,至迟到西周晚期,这种因治已形成一种比较成熟的模式。","categories":["06_族氏方国"],"year":2016,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2016.02.004","pages":"36-44, 112-113","volume":"10"},{"id":2530,"author":"赵庆淼","title":"芮姞簋与古芮国探微","abstract":"台湾&quot;故宫博物院&quot;收藏的芮姞簋,学界通常将其视作姞姓&quot;&quot;族与姬姓芮国之间的通婚证据。实际上,依照商周时期女性作器的金文通例,簋铭中附缀的族氏铭文&quot;&quot;,所标识的当系器主夫家的族氏名号,而&quot;芮姞&quot;则为出身芮国的姞姓女子。芮姞簋所见的这一姞姓之芮,很可能就是商周之际活跃于汧陇地区的古芮国。","categories":["06_族氏方国"],"year":2016,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2016.02.008","pages":"98-105, 161","volume":""},{"id":2538,"author":"胡湛","title":"西周初邢侯国的甲骨与青铜器金文","abstract":"邢台曾是商祖乙的都城,西周初又被封为邢侯国。邢台西周甲骨文为新中国成立后于山西赵坊堆村、陕西长安张家坡、北京昌平、陕西周原四处发现的西周甲骨文后的又一处甲骨文。以《邢侯簋》、麦四器为代表的邢台青铜器亦为我国金文之珍品。但已有吉金书法文献却鲜见著述。邢侯国甲骨金文书法的研究,具有填补缺如和丰富西周书法文献之意义。","categories":["06_族氏方国"],"year":2016,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9FA0KqpA31iBFYZh3pA9zpGAg7nm6qKlalQTzLeUsfW6XpusI6XVpriv4P6ZuBIeKKi1qgjAjGFZXj26zvRDMABU8Pv6Tx8ZHw6S9KVF_N8O3OFK0wD10nNjcGzUurV2hLs-qZ36NU1pO97fUWSVf8e_EZ0lA1B62YguTMw0dg6RXYBKvd5Ip&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-139","volume":""},{"id":2553,"author":"张懋镕","title":"皿屖方座簋和皿天全方罍","abstract":"本文旨在对陕西陇县出土的皿屖方座簋、旬邑出土的皿戟与湖南桃源出土的皿天全方罍做比较研究,认为它们是一个家族的器物。从形制、纹饰、铭文等方面论证皿天全方罍的年代未必如以往所认为的在商代晚期,很有可能已进入西周初年,并在此时从陕西来到湖南。皿方罍出土在湖南有两种可能:一是随分封到湖南的诸侯来到湖南,一是随南征将领来到湖南。说明在西周早期,处在陕西关中的周王室与湖南的国族就有密切的往来。","categories":["06_族氏方国"],"year":2016,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2016.01.01","pages":"46149","volume":"36"},{"id":2564,"author":"孔华; 杜勇","title":"国地望新探","abstract":"国是商周时期一个颇有实力和影响的古老方国,但它和文献中的杞、纪、莱诸国各为独立族邦,没有等同关系,不可混为一谈。商末周初族的封地距周初的燕国不远,应该是符合实际的,只是其确切地望还有待今后考古发现进一步证实。族与燕侯有主从关系,实为燕国的附庸。两周之际,国为避戎祸将都邑迁徙到山东黄县一带,而非莒县北部。虽然前后两个国在时空上有所不同,但他们同为侯爵,并与周王室保持婚姻关系,若非同一邦族,绝无如此巧合。周朝统治者经略北土,对于国族众,采取承认爵秩、实行政治联姻、屡加奖赏等多种安抚措施,有效地增强了族对周王朝的向心力,使之成为归服于周并称臣纳贡的异姓诸侯。国臣服周王朝后,与周王朝一直保持密切合作关系,对于维护周人在北土、东土的统治发挥了积极作用。","categories":["06_族氏方国"],"year":2016,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcFOBXnK9piWGmA23Ky6_i67-jhIZB-Yr7Zfz_vzjugXY2hK-AMXwRYDEBbkGT90georcdXTEQC9t6AspGMv9CoBwwe8OXmj5lVXOvW_2ZMgowDj55Un4c4yv3AfsL64PPhJyWUSuvgHeRYjBl6CqrSpT_1KKYAaVtSWhyuWVKvV0jsa5PX-Rm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-49","volume":""},{"id":3196,"author":"曹斌","title":"青铜觯研究：商周青铜器的考古学和礼制文化研究第六章青铜觯的铭文","abstract":"青铜器上的铭文是铜器研究的重要方面,其内容往往包括史实、礼仪制度和族属特征等。但是,铭文同样可以帮助我们为铜器断代,确定族属以及探讨相关族群以及族群的迁移等问题。因此,本章主要从青铜觯的铭文内容入手,在系统收集铭文材料的基础上,概括青铜觯铭文的特点,并对其体现出的族群及族群迁徙、时代性和族属等问题进行归纳和研究。","categories":["06_族氏方国"],"year":2016,"publication":"青铜觯研究：商周青铜器的考古学和礼制文化研究","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2016.001414","pages":"83-94","volume":""},{"id":3198,"author":"朱凤瀚","title":"曾国墓地大墓之墓主人身份与曾侯■钟铭","abstract":"湖北随州叶家山西周曾国墓地的发现与发掘是近年来西周考古的重要成绩。该墓地的几座大墓,从北至南大致在一条线上(图一),据已发表的资料,其中墓主人身份可大致推知的是M1,M65、M2,M28、M27,M111。叶家山几座大墓的年代(下葬时期)与墓主人身份大致可以表述如下:","categories":["06_族氏方国"],"year":2016,"publication":"北京论坛（2016）文明的和谐与共同繁荣——互信·合作·共享：出土文献与中国古代文明分论坛论文及摘要集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoYa1ESYA4kI9MGD4kAIA6R-4hG82tW9V2NtiyGhkGU-15656TfQpI6oncJtgNFcdjEeanmtTx6OoF8TLsjLExnFe-6gcLAM9poqFgvEU5y53ar2jooM415Z2gHwKPNifQPWKWqNworKXV23uY7c86OrWFRrh5MU40O8lPvrX-0Z1ZSGVNiwX7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"224-236","volume":""},{"id":3207,"author":"陈民镇","title":"也谈“句吴”之谜","abstract":"","categories":["06_族氏方国"],"year":2016,"publication":"中国社会科学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKT1P8pLr8vRXBEbJNqCJaq4r3neCYdQwaVVodfWB9gWt7tRvfAvQzyFU8rSHQ8GVNw8jjP5he3q2rAc2ejtF3iUc2yrLdG0pYietW3sSgDXxqLvD6oBU0Wf_zvrDXx__U9m7GiVTPj79aWj1xUYN_uhwVCYOFrY8BNfhwl5N4GwofxzZhUMNF7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"4","volume":""},{"id":3212,"author":"贾一凡; 袁俊杰","title":"小邾国墓地综合研究","abstract":"小邾国是西周晚期至战国晚期邹鲁地区的一个小国,受考古与文献资料的限制,以往学者对其研究不多。2002年山东省枣庄市东江村小邾国墓地的发现与考古发掘,对小邾国历史研究有着重要的学术意义。该墓地虽然遭到了当地农民取土破坏和不法分子的严重盗掘,但仍出土了一大批珍贵文物,其中带有铭文的青铜礼器达24件,极大地弥补了春秋时期小邾国历史记载的空白。本文基于该墓地考古发掘出土的墓葬资料、金文资料,并结合文献记载,对小邾国礼仪制度、相关古国族以及小邾国历史沿革等问题进行研究,主要观点如下:首先,通过小邾国墓地的墓葬资料和金文资料,对小邾国礼仪制度进行探讨。丧葬制度方面,小邾国的丧葬制度与姬周、东夷、荆楚墓葬皆存在差异,具有明显的兼容并蓄特征。究其原因可能有二。一是小邾国地处东夷与华夏、荆楚和中原的交汇之地,丧葬制度必然有兼容糅杂之处。二是该墓地时代为春秋早期,此时小邾国尚未受到册命,葬制并不规范;媵嫁礼仪","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJcYRv6R1gSJ39DHLdt5gqRPb-TH_ZmoSArha6Kxp8Jmj9cgKvEo6v1s1dbtacp1sRlWQAWHr3pEnZ_IaNhII9Ozcmsh8EWvd19nbAL-i-BDVVGytqheUzPF2cAPfDdroWdrHGgvIAdc3GkzQziiYFnVyxTd9882f5eMKqRxPQOdAYWa_re77g_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3213,"author":"柴春椿; 張世超","title":"隨州葉家山西周墓地銅器銘文與文峰塔曾侯與編鐘銘文綜合研究","abstract":"2011年,湖北隨州葉家山墓地開始發掘,該墓地是全國首次發現的西周早期曾國墓地,經兩次發掘共揭露了140餘座墓葬,出土了大量青銅器,規模龐大,並且部分銅器上有銘文,銘文內容也很有價值。2009年,在距葉家山地不遠的文峰塔搶救發掘了三座墓葬,此次發掘的曾侯與墓出土了一套編鐘,其中多件編鐘以及部分殘片上有銘文。這兩處墓葬出土的銅器銘文內容意義重大,為認識和解決早期曾國的始封、曾國的族屬、曾隨關係等一系列疑難問題提供了新的資料,引起了學者的廣泛關注,各家先後發表了有關兩地的相關研究文章,都具有很高的學術價值。本文以葉家山西周墓地、文峰塔曾侯與墓出土的銅器銘文為研究對象,搜集各家之說,分器匯釋,同時略陳己見,在匯釋基礎上,對古曾隋關係、曾國族屬問題進行一些探討,供研究者參考。搜集資料截至2016年3月。","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqptELvRvWvmNLyw1FuPAOvo4XPeoug6UdaT2Y9ElrhXYmaulFDqNlcWCnufdvyfdhRlt5iH4UQ-23lHPQCEEZKXRype6XnoXx87KQcPm8oIqGtAhId3bTMhkly_TlB11kincPTWtWESD3swHcCwHqVizziGfmi8P6Pi6BsiyF_YENtARRVyrv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3217,"author":"白晨辰; 袁俊杰","title":"从文献及考古资料看殷周鄂国的历史变迁","abstract":"鄂至少在殷商时期就已立国,进入西周,鄂国成为周代南土的重要诸侯国,占据着对西周王朝有重要战略意义的随枣走廊。在传世文献中,关于鄂国的记载却非常少,殷商时期的鄂更是只言片语,这对我们深入了解鄂国造成一定的困难。后世学者主要依据一些传世或出土的青铜器对鄂国进行了比较多的研究。本文依据传世文献、甲骨文、青铜铭文、考古以及历史地理方面的资料,对鄂国的族源、历史沿革、对外联系等问题进行了探讨。首先是对鄂国的族源和殷商时期地望的探讨。依据《史记》等文献的记载,鄂国早在殷商时期就存在,并且是当时的重要侯国,鄂的起源非常久远。&quot;鄂&quot;是传世文献中的写法,在甲骨文以及青铜器铭文中均写作&quot;噩&quot;,这是个象形字,象鳄鱼之形,因此推测鄂最初可能是一个以鳄鱼为图腾的部族,后来便以&quot;噩&quot;作为自己的国名。由鄂侯簋铭文可知鄂国为姑姓,目前所知的几个姑姓诸侯国例如杨国","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQuGABWhzlCIRJ2T9EaDnnc_a01yrckw0WGrbMDYMCnsjbVrBdFNtqrsiXOlECZ_Z8W6VXvxRtqro-GLB3uEFProyTaYASs9JfS22JU1InRUpvnxJCLw_a4nY20oS4yw91M8Vx4ib4ThPOIFgF6J6AvpkmYRGY4PT-xhRbKaNzH6ePiducqRhC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3218,"author":"姚佳昌; 韩炳华","title":"古唐国初步研究","abstract":"古唐国屡见于史籍记载。从文献资料中可以分析得出关于古唐国主要涉及到了帝尧时的唐国、商代的唐国、晋始封地——唐以及春秋南方之唐国等概念。对于这些概念的认识与争议,可以说贯穿了整个学术史的发展过程。随着诸如陶寺遗址、天马—曲村遗址、洪洞坊堆—永凝堡遗址以及湖北郧县肖家河春秋唐国墓等遗址的发掘。还有文王玉环、(?)公簋、清华简等地下资料的出土和发现,学术界对古唐国的认识也不断的深入。本文主要以历史文献中所记载的古唐国为主要的研究对象。首先,从古文献的记载出发,理清各时代学术界对古唐国的认识,对关于古唐国的文献资料加以梳理总结,作为古唐国研究的学术史建构。其次,随着新的考古材料的发现以及学界对于古唐国的新认识的不断深入,对相关考古材料加以分析研究,以此为基础梳理出学术界对于古唐国的认识进程。再次,运用古文字学等方法,从甲骨卜辞等出土文献资料出发,侧重分析商代古唐国的地望及其政治经济形态,并由此总结","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpdzAxX0vPI9u5xfuJamZ8ugzMy8oP_t6DKr3oUmkFEjuVHVZ2jFc9GN71Y11p3tKYzezM7JC2fA5VblgzqgDL-nyumXkOYO8yROkcE1y8DxZNs0YH-0CbUXP7t4ZCt4jhPRuAtigBrLKeFbF6CIJ5tMDZlg5tfpWhO6SlT_noaFOLwv_x2x6K&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3242,"author":"徐海燕; 俞志慧","title":"徐国史影考述","abstract":"虽然徐国经历了漫长的历史,并且在徐偃王时期有一定的影响力,然而关于其文献材料却十分有限。即便如此,我们在面对有限的材料时,也不能急于使用,而首先应当判断这些材料是否可采信。目前大部分相关研究者,在对徐国进行研究时,没有注意到这一点,随手利用上这些材料,导致了其研究结果的不可信性。鉴于此,笔者首先对徐国的相关材料进了了搜集、整理与判断,并以附录的形式放在文章末尾,作为徐国研究的基础性工作。在做好基础工作之上,笔者对徐国展开各方面的研究,包括历史纪年、人物研究、历史地位论述、地理考证,等等。笔者将所作工作归纳为两大类:基础性考证与发散性研究。基础性考证包括历史纪年与人物研究,这部分工作的目的在于对徐国有一个整体的把握;发散性研究包括论述徐国地位,探究徐与淮夷概念模糊问题以及徐国相关地理考证,这部分工作目的在于对徐国整体把握的基础上,能对其有更立体、更形象的了解。","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEI5boRjD6V9VwR5Zsi7HhbH5HUTjOrizIytEbYBQD67n0DSD4zJGmBfylwp3DI4lOQjmO-NukYhGxb6FzR-c1saVnv_8kFIVErmpYD-V49q11-ADUn5vSMnYpKNnYt2yfhZO4J_M3AQ7dv5YvQhUzVsVw_8MzfnM1W54GoiqK0y842PNNwYYE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3251,"author":"溫皓月; 馮勝君","title":"出土文獻與傳世文獻之伊尹材料整理及相關問題研究","abstract":"伊尹作為著名的古代賢臣,是歷史上輔佐君主的典範。隨著《清華大學藏戰國竹簡》的逐步公佈,有關伊尹的篇目也得到更多重視。本論文主要以伊尹為研究對象,以出土材料為主要內容,圍繞甲骨文、青銅器銘文及簡帛材料,依托傳世文獻,對伊尹及相關問題作出整理。本文主要分為四個部分:緒論:主要對有關伊尹的甲骨卜辭、青銅器銘文、簡帛及傳世文獻中所見之伊尹研究進行概述,著重對甲骨文及簡帛所涉及伊尹的部分進行梳理。簡要介紹本文的選題範圍、意義及研究方法。第一章:商周甲骨卜辭、青銅器銘文所見之伊尹。分為商周甲骨卜辭部分與東周銅器銘文部分。甲骨卜辭部分,主要對所涉及伊尹的卜辭進行分組整理、歸納,用以對伊尹身份及地位作分析。第二章:戰國、西漢簡帛中所見之伊尹。主要對清華簡所公佈的《尹至》、《尹誥》、《赤鵠之集湯之屋》、《湯處於湯丘》、《湯在啻門》篇進行梳理與分析,并對簡帛中所涉及伊尹的《清華簡·良臣》篇、上博《容成氏》篇、","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbk0bOpw0VufXFuI62NR58IJmYP2XoZWczqAkQMDDuMZYzEXP2FNl5QuTcKrUERV10V_IFwXZ1NUBCNY0cUMhoTq6peE8JAVXHvFdh6-aqatU16RIaTuLOHA44RbougP0KkQ1D2NHJo28n5Bz7GIGBUrwU62xDpQY8E9SQQkKt9IuGHbWUxFt6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3252,"author":"高明英; 杜勇","title":"商周（己其）国研究","abstract":"蛇国建国于商代祖中之后,一直延续至春秋中后期。(?)国先祖包括业其、业(?)(?)侯亚(?),亚其、业(?)均是其侯,生前在商王室“叶工事”,祖甲之后业(?)去世,亚(?)族的一支子孙被封于(?)地,称为(?)侯亚(?)。商代晚期、西周早期的(?)国地望在今北京一带,西周中后期(?)国迫于戎狄压迫进行迁移,西周晚期、春秋时期的(?)国地望在山东黄县一带。(?)国是一个独立的国家,它不是杞国也不是纪国,不是蓟国也不是莱国,(?)国亦非箕子朝鲜。商周王朝实行统一贵族国家模式,(?)国居于被支配地位,服从商工、周工统治,履行相应义务,商周工朝也保障(?)国统治秩序。","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbk0bOpw0VufXFuI62NR58IJmYP2XoZWczqAkQMDDuMSo8GFqBwVlskSXDv_ojm7U3ICFDrRnYGnO1HbW9i3fpC4D19hFYGPjYv-nf2jYs9VQkd7xOFRXaUrJYXq_h58TooqxZMTQc9tNCaUJNI1bI0HYK8QOlksvyx_7NTYGVmxPyTq_AJQBa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3253,"author":"高雪; 黄爱梅","title":"两周之际东迁封国转型研究","abstract":"本文共分为三章。第一章论述西周末年宗周与成周的形势。宗周渭河流域一带从西周末年开始便呈现衰败之象,王室与贵族间的摩擦不断,再加上犬戎给予的致命性一击,宗周一带彻底沦陷,周王室与畿内贵族只能另寻出路。这一时期可供王室贵族们进行集体性大迁移的居住地已经非常有限,成周附近成为他们唯一的选择。这主要得益于整个西周周王室都对成周保持着直接控制的关系,成周便成为此时王室与畿内贵族们的希望之所。第二章论述王室与西部封国东迁的过程。有些封国是由于宗周沦陷而被迫随王东迁,而有些封国却早在幽王年间预测到王室将颓,提前谋划出路,郑国与虢国就属于后者。但东迁之后的地理位置却日益成为他们发展的桎梏,周边一带虽无大国,但却东临卫、宋、陈、蔡等早期分封的诸侯,成周附近还有许许多多小的封国,土地向外扩展的可能性不大。另外,从宗周迁移而来的人口,大都属于位高权重的阶层,为争夺土地、人口与东土原居民之间的冲突摩擦不断。第三章","categories":["06_族氏方国"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJXdxIyBEDiGaTBPin2Czd4VwcB3pBtOpwC6V-hi_Y4M1a0YY56lIpPlcMdBaHUNjBgiv7ThkZIQWsQUq8cyWVefqNNBPj1k1V0T5h-vtCKFHhJ_aC9m7U0HlR349FeE_UwCRGuEhri1NMopmZPJ2d_tpYZbnIFnj_ZY769TC-R-EkvYh5264yH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3659,"author":"孙敬明","title":"莱国出土异地商周金文通释绎论","abstract":"先秦古国众多,《左传》哀公七年（前488）所谓:&quot;禹会诸侯于涂山,执玉帛者万国。&quot;《吕氏春秋·用民》:&quot;当禹之时,天下万国,至于汤而三千余国,今无存者矣。&quot;商代晚期见于甲骨文、金文的地名、诸侯名,以及与族名、地名相关的殷商王妇名等,据台湾学者丁骕《诸帚名》文章统计约共698个①;又据《史记·陈杞世家》记载,西周武王时期的侯伯尚有千余人。山东商周时期古国,见于文献和青铜器铭文者,六十","categories":["06_族氏方国"],"year":2016,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNYSmcFVHYw6QC-qYrYfWB3h8bmjn7bWm1p8hSxVQqy36aBwBG8b0go98_2cNik9TDRI1ZWLMd-_SptYqklVfKtY8n6QRAIICOEfRNM2SPBhUM8l_aNrtsCCZtuPOsn9Zmpxyrau8albkdjq1wh9ZeJl0thdZ9zL6ixnmPdBPVgg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-52","volume":""},{"id":3665,"author":"尹盛平","title":"宝山文化与荆蛮句吴族","abstract":"分布于汉水上游城固、洋县境内的宝山文化,与京当型商文化相互交流影响,与宜昌路家河二期后段遗存文化面貌基本一致。宝山文化的族群应是弓鱼族,即吴太伯、仲雍所投奔的句吴族。句吴族原居在湖北荆山下夷水流域,后溯汉水而上,迁徙到汉中东部的城固一带,故称荆蛮。荆蛮句吴族人追随吴太伯、仲雍在今宝鸡市吴山之下陇县境内建立虞国。武王灭商后,求太伯、仲雍之后,得周章,此时周章已是吴(虞)国之君,因此追封他为诸侯。周康王时,又册命周章之子熊遂到宜地(江苏宁镇地区)为诸侯。","categories":["06_族氏方国"],"year":2016,"publication":"苏州文博论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8byIHuybOsCjj7gQSds2gbSES5oBoaOftNsabwryqwgp1RfyivoChZrZ7VpX5NWbh5PUH-LNmc6Ev5px5mVXLUNOeYwETmZmPPNP4LxP9BfNGrJiQwtCcSOKERfCeWmTWusjtYeQK5hBf4jvVKtJK9hTiSHBlY3icMz2P8w8Qew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-46","volume":""},{"id":3677,"author":"陳穎飛","title":"清華簡《良臣》散宜生與西周金文中的散氏","abstract":"清華簡《良臣》有&quot;柬（散）宜生&quot;,係文王的賢臣。散宜生多次見於傳世文獻,是著名的文王&quot;四友&quot;之一。作爲西周初年的重要人物,散宜生的後人,傳世文獻缺載,但西周金文有不少散氏的材料,[1]一定程度上可補其缺失,據此或可管窺西周散氏這一世族的興衰。","categories":["06_族氏方国"],"year":2016,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLKyq95YDl6NsuTI0b3NPRU2bLQLdP3iUEuF0Q7IgP1HwMauN52WBqQeEHKqplEuWetvNYoju8MlbmLv816yLvpDWGzJV52bX_j1M-xTxVb98VtocwM5NO5hkkS_XhBTOvlbnQOYJJ0LZNL5DOZofgtCVDi04nmpZproTTFGjMTqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-88","volume":""},{"id":3689,"author":"丁慧萍","title":"出土文献中的古钟离国","abstract":"一、绪论江淮地区位于长江与淮河之间。由于长江与淮河的泥沙沉积,形成了广袤的冲积平原。这一地区河网密布,水资源丰富,土壤肥沃,加之地处亚热带和暖温带的交界处,自然环境优越,农业发达,自古以来就适宜人类繁衍生息。江淮地区地理位置上承东启西,连接南北,其南部又有着储量丰富的铜矿资源,","categories":["06_族氏方国"],"year":2016,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0HuRzUKokrhHm8zgOn02OsyIRQpG31WhM20Rso-QQOarDzp7dO3VFf-j3-7vCjsdGqHNvRMbT7AIBi6TkP-AjiQpd8uG-oItyjPxNOsnsuZbqBqFX0y8Rs6ZmGS5g3gR6rkqBE0o0zrHvHYubZrV8a7wSCs7nJNU1LyRjJpc7qw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"232-239","volume":""},{"id":3826,"author":"黄益飞","title":"曾侯■钟铭文研究","abstract":"随州文峰塔东周墓地新出曾侯钟铭文涉及曾国始封、族姓等,内容重要,本文兹就相关问题略作考述。M1:1曾侯钟全铭共一百六十余字1,铭文内容如下:唯王五月,吉日甲午,曾侯曰:伯适上(哲),左右文武,达殷之命,抚奠天下。王遣命南公,营宅纳土,君此(庇)淮夷,临有江夏。周室之既庳,吾用燮謞(骄)楚。吴恃有众庶行乱,西征南伐,乃加于楚。荆邦既爝,而天命将误(虞),有严曾侯,业业","categories":["06_族氏方国"],"year":2015,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpjuLodqvDseTiqw1UpJbqIFHYmKZojrK_43_PiXzdl34UIxzTCePP-k3hJtYeEWbjm2AlRhJV2EUAO5G7UbI3qkeTseoUeGryu_7BBF9vS7gqjimXk2tksbxonRt_ZiaqOntgaup8JNxzSLOtyl90kjLR_oel4HdnhMeVZAS-U28JbQhs2Tuw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"207-210, 206","volume":""},{"id":3827,"author":"张宝明","title":"从甲骨金文看殷商族图腾崇拜文化","abstract":"很多人都在寻找&quot;商图腾&quot;,但大都在典籍文字之间徘徊,很少拿出&quot;考古实物&quot;的证据来。现在我们展示出来请大家欣赏商图腾的考古实物证据:■【图1】。这是商图腾的符号,是商民族崇拜的对象、族徽。沉淀储存着商民族的一切古老的信息,是穿越时空,打开商民族思维方式、宗教信仰,乃至社会实情、实景的锈迹斑斑的钥匙。这个神秘的图腾符号从诞生之日已经静静地沉寂了几千年,现在,当我们把她擦拭清楚时,","categories":["06_族氏方国"],"year":2015,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2015.06.001","pages":"46344","volume":""},{"id":3829,"author":"方辉","title":"商周“夷式簋”的传播与族群变动","abstract":"夷式簋是商及西周时期分布于鲁北地区一种独具特色的陶器。本文对夷式簋的研究历史、出土背景、器物组合、流行地域及年代进行了梳理,对夷式簋的来龙去脉及其背后所隐含的族群流动做了研究,指出了商末周初夷式簋的西向传播可能与以秦人为代表的东夷族群的西迁有关。","categories":["06_族氏方国"],"year":2015,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2015.04.009","pages":"60-72, 147","volume":""},{"id":3834,"author":"刘明科; 刘莉","title":"宝鸡石鼓山西周墓地三号墓墓主之谜","abstract":"2012年6月22日,考古工作者在宝鸡石鼓山的3座西周时期墓葬中发现大量青铜器。目前考古学界多依高领袋足鬲这种典型器物的考古学特征,推定其为姜戎族户氏家族墓地,并认为三号墓(M3)的墓主是西周早期的高等级贵族。M3为南北向的长方形土圹竖穴墓,一共有6个大小不一的壁龛。除5号龛","categories":["06_族氏方国"],"year":2015,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWGl_4qXteX7JANyTTMHrRLyqnNOapNHDqOYEzHd3uWqRqXHPvNnSCOjcwjPQVz0QzwjquSlcT_hqc2pyBXO8sK42SlY8x2elPtQY_kWVwobUMg2WKVRsUenu354wKtmUidHalx1ymHH2BuqrRj6gdqM5Zb84OgABrvzZUp8FtxTq7uYSVHiOJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-38","volume":""},{"id":3840,"author":"王泽文","title":"文峰塔M1出土曾侯舆钟铭的初步研究","abstract":"本文分析了文峰塔M1出土的曾侯舆钟铭所反映的曾的始祖&quot;南公&quot;的族属、与周王室的关系,认为其可能不是周王室嫡系后裔,曾的始封可早到周武王世;结合《春秋》经传,讨论曾侯舆钟铭中反映的东周以降曾国和周王朝、楚的关系的变化;将钟铭中的历日和《春秋》经传历日对照,分析当时的历法情况。","categories":["06_族氏方国"],"year":2015,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKO4DG9Zfqqw-8zeYDF0dEFQv_ZE3_C9g8fdQ8Nk-9agO03eNqT3IRZxOEE3kMfSJkEHgoYi3LDzdXO0oECOj7VcAY6ew6SKfJ8iHypirxDa8fp_1FMuVBT2KIy6Scv6Ntyie_ZTRLRngVdWlmowiOPTxAH_UctLqlaasCFKeXiQ9q-U32CoPS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-111","volume":""},{"id":3843,"author":"杨清慧; 王进锋","title":"商周复合氏名意蕴新解——从古文字中一类特殊人物称名说起","abstract":"商周时期的古文字中有一类特殊的人物称名。它们往往以一个人名中包含两个国族名的形式&quot;A+方或爵名或职官名+B&quot;出现。根据相关辞例的证据,它们可省略为&quot;AB&quot;。其中,A是称名者的父族氏,B是称名者的母族氏。这种人物称名对认识商周金文中的复合氏名有启示意义。商周时期由2个族氏名号构成的XY型复合氏名中有不少和AB一样,是&quot;父族氏+母族氏&quot;。AB型人物称名的变体ABC对认识由3个族氏名号构成的αβγ型复合氏名也有帮助。","categories":["06_族氏方国"],"year":2015,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAaxqDxVIF4pj6twvjrtqqKyCz6SbKLo7DTw2Dl6k9GJ8LMx4uhb_azWNTEq36h0OnEjlVAdfIDLHydK1FGfW9Z21-meTj5qiRQl_iKeOt20FU_xLNDccXvoxG8SaxMOCfhbQDSqkieBg4KNFQ7AwSoVEpI9X1pij1H2uJdB9B8SgacmDtuvVh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-40","volume":""},{"id":3847,"author":"仝晰纲","title":"《杞伯簋铭》的地域文化解读","abstract":"清道光、咸丰年间,在今山东新泰境内出土的杞国铜器,其铭文具有重要的文献价值。从地域文化的视角去审视杞国的历史,会发现许多有价值的文化信息。杞是夏的后裔,夏时本在东方,商灭夏后,散亡四方,在今河南杞县一带或封或绝。周克商后,封东楼公于杞,春秋时期,杞为宋国所逼,东迁淳于国故地,依附齐国以图自存。齐国的霸主地位被晋国取代后,杞又受莒、淮夷的逼迫,迁到晋鲁之间今山东新泰一带,依附霸主晋国,为了自存,与晋、鲁、邾结有婚姻关系,&quot;杞伯每匄&quot;的姻家即为小邾。至春秋后期,杞为楚所灭。杞是小国,无力自存,为了自存多次迁徙,周旋于大国之间,时有灭国之虞,杞人忧天也就不足为怪了。","categories":["06_族氏方国"],"year":2015,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJO_DDo611Ttp6LujNRLA9LZ4DDKU1Qeke4fB7KDZjHAzCjn4tTzHg02ygrGOSgmuVozkZrVOyh_Obox-HQYxYiqOiG-e0r6AWO0kWm5LW7uHUIAIGn3eVd4gU48198nmK8I5cn7xePGBLHdTC-_P6OLQnfjxP6_TmUGygew6s_mg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-81","volume":""},{"id":3857,"author":"罗运环","title":"新出金文与西周曾侯","abstract":"姬姓曾国不见于传世文献,研究姬姓曾国历史难,研究西周姬姓曾国更难。新出金文提供了珍贵资料,本文据此,探讨了西周初年曾国的开国史,西周时代曾侯世系。考证第二位曾侯或当名&quot;周&quot;,第三位曾侯名字应为犭立(戾)。对曾侯仲子游父及曾侯絴伯的关系及世系进行了审慎地推论,使西周时代曾国的世系及相关历史线索有较清晰地把握。","categories":["06_族氏方国"],"year":2015,"publication":"陕西师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInb3_6NBWEVi2Lt20FjvT-jbvnxLdZ-Gj4yt2y9QvN041HTtW7NMpjCIUblENVXbK6TvnhImAXt6OYcrb58FwvdzDUdJC7bsmieERNZ5gHpdJX9CP-wbC9UUO0LYU05ZLO5MMsITqvY-ERPuw4SzWtR_5aZhlB7-n2e839JzZ_Qyo7CeXSjPuE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-22","volume":"44"},{"id":3868,"author":"辛怡华","title":"西周裘卫家族初步研究","abstract":"赢姓裘卫家族在西周中晚期近两个世纪中,虽然政治地位不高,但经济实力却非同寻常,他们广占田地,其影响遍及西周社会的方方面面。从裘卫靠掌皮裘小吏起家,到公臣投靠权贵虢仲,旅伯官居膳夫一职,展示了裘卫家族不断上升的新兴世族的发家史。","categories":["06_族氏方国"],"year":2015,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKk2JgrFhXg2mxY7Syqoj_0nk2eSUt5mmtlgIkUTqPjH4l_3eEvUFOa-jggOybTvtFPonsQyG66KD27syDQbNHsG341GmIOUDoBPK3jqKEAGt20u196bP71ZNQlsWl9Fx_CJBexAYOcUSscezyP8_iA3ZlT1jrLF9fKmj1k5NHJ-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"185-194","volume":""},{"id":3874,"author":"王正; 雷建鸽","title":"柯史簋与柯国、唐国","abstract":"本文通过应国墓地出土柯史簋铭文的解释,揭示了西周晚期柯国贵族嫁女儿于唐国的历史事实,并对柯国、唐国历史进行简单考索,同时提出了柯史簋辗转流传于应国的可能途径与方式。","categories":["06_族氏方国"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbslNh9t18iI5pnZU9RHrEL-cIxg4MotnVpd8Z2ZUCO0YjzpxTcpHT3ViKndcCaL8ls_3xPTNcUF6ZzP-oeow_q7XzQnMDI2fO5LCSKa3uKjAuUbymM3xF-K66EfROkYkefunt2O74ByHhHhmoJwn0s4YmMJ-DHrWlv0ctzoxJRgLuT9QCgI5P&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-28, 44","volume":""},{"id":3875,"author":"李伯谦","title":"金文族徽研究领域的可喜成果","abstract":"见于商周青铜器上的族徽铭文,从宋代金石学兴起伊始即受到学人关注,搜集、著录、研究代不乏人。关于这类铭刻的性质,学界说法很多。氏族说、姓氏说、图画说、文字画说……不一而足。至1931年郭沫若发表《殷彝图形文字之一解》提出族徽说,倍受推崇,几成学界共识。然细究起来,其中仍有许多认识远未统一,例如这类铭刻究竟是不是文字,其含义是什么、都包含哪些内容,所谓复合族徽究竟是两个或两个以上族徽的合署还是族氏分衍的反映等,都需","categories":["06_族氏方国"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4S9gV82Jmcb1sGDzQT-LTK1VhgM8P5WPiQMVdxkOkaTvLHCJhYDyNRO4RSsWQxMw95mn6IiLFbtk-R3vbJ_AaS-zg783abHz5tq1Yb5TAgOCgI6R98DhrhUWnEe1NS2ffUYGXH3WjtWXZRL26AqcG5lpzyUEygWfsttCCZnjWgxJ2Opv7Qq7x&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-126","volume":""},{"id":3878,"author":"黄锦前; 张新俊","title":"说西周金文中的“霸”与“格”——兼论两周时期霸国的地望","abstract":"本文主要通过字形分析并结合相关文献记载,认为西周铜器铭文中作族氏称谓的&quot;霸&quot;与&quot;格&quot;所指实一,之前所谓的&quot;霸国&quot;或&quot;霸族&quot;与以往见于铜器铭文的&quot;格国&quot;或&quot;格族&quot;所指亦同,即为文献所载的春秋时期的潞国之前身,系殷商时期西落鬼戎的支系,其地望西周及春秋早期在今山西省翼城县一带,春秋早期以后约在今晋东南的以潞城为中心的黎城、长治一带。","categories":["06_族氏方国"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKez0SEV9b01nZGJdpdMGmahQwzzUpmb9UV8woD4_-7dSQiVLvAijfbmu3FnAMURnrYKV-v9C20egICNDYw3W_uHo-VI9e1F7irNQWYnteIxXs6c9aqTeSyOczQLm2NieaMP23BQxQoW-cYNSsr_EiIqQOOsYTeq-qC1_LLJzWw_bP4EqYjg8qC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-111","volume":""},{"id":3906,"author":"李伯谦","title":"《殷周金文族徽研究》序","abstract":"日前,我国著名古文字学家王长丰博士的《殷周金文族徽研究》一书已由上海古籍出版社出版,该书为北京大学震旦古代文明研究中心学术丛书之三十二,全书上、下两册,内容捜罗丰富,涵盖面广,资料齐全,既是一部学术性著作也是一部资料性著作,是一部学习、研究殷周金文族徽必备的工具书、参考书。这是殷周金文族徽研究的最新成果,也是填补族徽研究多项空白的科研巨著。本书由我国著名考古学家李伯谦先生作序,经本书作者同意,现将序文转载,便于读者了解本书之要义。","categories":["06_族氏方国"],"year":2015,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhIvGFsEqW735tgx2NdVVNpqRK26JDHcCW8DWXe0CpBZsnzmJIdvpma_NGke5LO9QL1YXqglyrFe2_k4IdCWFSWXqQJm_16n_ZFH1lfOaVcsT3gBVVwVghe-IuzJdUT99ihIRKdIU9kAKhPXVvEVYP8epFf2P007bbe3wbW0V9IistkBpK1cXA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"112-113","volume":""},{"id":3924,"author":"张宝明","title":"从甲骨钟鼎文解密周图腾的真实","abstract":"周民族图腾最复杂。但到目前为止,并没有一个得到学界认可的周民族权威图腾。甚至连权威的历史教科书也回避这个问题。现在我们可以从甲骨金文中,证实古典文献记录的真实;来求证真正的&quot;周图腾&quot;。一记载周民族先祖起源的古典文献,一般都追溯到女始祖诞生了男始祖:最早最原始的典籍是《诗经·大雅·生民》:厥初生民,时维姜原,生民如何?克禋克祀,以弗无子。履帝武敏,歆,攸介攸止,载震载夙,载生载育,时维后稷。","categories":["06_族氏方国"],"year":2015,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2015.04.001","pages":"46342","volume":""},{"id":3932,"author":"刘波","title":"曾姬无卹壶铭文再探","abstract":"本人在前人研究的基础上,进一步梳理了铭文的内容,由此认为此壶当为楚宣王为其已经过世的祖母所作的宗庙祭器,其后随考烈王迁都而被带至寿春一地,并与酓前、酓诸器一同埋葬在朱家集楚王墓之中。","categories":["06_族氏方国"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrNZ8Rgcui-Es0cW2aEdfTxXnCjAxb4_7i4rY4pf7CtDjBvX2DrySoFuYTqIjieFoOm8oiwNZgoCmTItNTdLmXsIc3-xsqHQ7jbeKMZZHaK1TFwruIVAdDaJ9buziHZZGacClxRCP3eGtxwgZ1PlpXvjOxnuR1n_oxnNjx1CUsF5_tT9YTbIIO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-106","volume":""},{"id":3944,"author":"李学勤","title":"正月曾侯■编钟铭文前半详解","abstract":"春秋晚期的湖北随州文峰塔一号墓,出土编钟三组。依青铜器命名惯例,其中的一组可以称为&quot;正月曾侯■编钟&quot;。作钟之年为公元前497年,编钟铭文内容关涉重大历史事件,特别是追述曾国始封经过的铭文前段,补充了周初古史的空白。现在学者大多认为,曾侯与曾侯乙墓所见的曾侯是同一人,该说虽存在用字方面的疑点,但从年代上来推算,还是可信的。据铭文,伯适(南宫括)曾先后服侍文武两朝黜除殷命,以安定天下。后又受成王之命,在汭土建立都邑,这是曾国的初封。周朝封南宫括于曾国,一是为了加强对淮夷的控制,二是为了监临以至占有江汉地区。","categories":["06_族氏方国"],"year":2015,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2015.16.002","pages":"16-20","volume":"3"},{"id":3959,"author":"杨海青","title":"虢仲铜■铭文及相关问题","abstract":"1990年在河南三门峡市虢国墓地M2013出土的青铜器中有一件虢仲铜■,器内底部铸有铭文3行17字,具有较高的学术研究价值。该文对虢仲铜■的制作年代、铭文中涉及的虢仲与醜姜身份及二者的关系、姬姓虢国与姜姓互婚等问题进行了初步探讨,并提出了一些看法。","categories":["06_族氏方国"],"year":2015,"publication":"洛阳考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIJLC7TvkKJM9xfqTzOiyjCQLZ3YF9AqBkGzE0E5rHSEwE4CiXH336EYWMCT_IAaAOF3x5UkRRqI7ywDy0Bh_SUZ95Ch-aBHXaN1IQEfUc69y6U2n34v0VDy4Ib0iv-5fa17GHHIOzk-1nKEPxKWfMaRxtDB9yBXjcYrs0M7Zx6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-75","volume":""},{"id":3972,"author":"曹斌","title":"青铜觯铭文研究","abstract":"本文在系统收集青铜觯铭文材料的基础上,归纳出青铜觯铭文的自身特点,并利用这些特点,探讨相应铜觯的时代性和族属问题,以及商周时期的族群及商周王朝更替引发的族群迁移等问题。本文的研究不限于铭文本身,希望通过分析铜觯上的铭文现象,为研究相关问题提供思路。","categories":["06_族氏方国"],"year":2015,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2015.03.002","pages":"14-22","volume":""},{"id":3974,"author":"张志鹏","title":"钟离迁徙考","abstract":"通过相关考古资料、金文资料以及传世文献,发现钟离国先祖绝非子姓比氏,为赢姓;旧址在今山东枣庄峄城,先因周王室东征迁至古州来之西,后因楚国东进淮域再迁至今安徽凤阳、蚌埠市一带;此后,长期为吴的属国,吴亡后为楚所灭,以其地置钟离县。","categories":["06_族氏方国"],"year":2015,"publication":"蚌埠学院学报","link":"https://link.cnki.net/doi/10.13900/j.cnki.jbc.2015.03.042","pages":"172-174","volume":"4"},{"id":3985,"author":"高士荣","title":"从秦公器看秦人早期的历史文化","abstract":"不其簋、秦公簋和秦公壶是研究秦人早期历史文化的珍贵实物资料,具有很高的学术价值。为了探索秦人早期历史的发展脉络,文章利用这三件秦公器实物资料,从考古学的角度,分析秦庄公、秦襄公、秦文公的主要历史功绩以及秦人早期的历史文化。由秦公器可以看出,早期秦人偏处西北的陇右地区,在与周人密切交往的过程中,秦人的文化水平不断提高。早期秦人的青铜器表现出对周文化的传承,同时也注意发展创新属于自己的文化特点。","categories":["06_族氏方国"],"year":2015,"publication":"西安财经学院学报","link":"https://link.cnki.net/doi/10.19331/j.cnki.jxufe.2015.03.018","pages":"96-100","volume":"28"},{"id":3995,"author":"蔡运章","title":"商周倗国铜器与河伯冯夷国族——兼谈山西降县西周倗国墓地的族属问题","abstract":"河伯冯夷是夏商西周时期居住在黄河中游沿岸的著名国族。冯夷本是远古时代用葫芦来泅渡黄河的古老国族。&quot;冯&quot;应是&quot;倗&quot;的假借字,古史所谓&quot;冯河&quot;本应书作&quot;倗河&quot;。因倗国的得名与河伯冯夷国族的名义密切相关,故商周金文中的倗国,实指河伯冯夷以及后来的媿姓赤狄国族。冯夷国族生活在以今山西垣曲诸冯山为中心的黄河两岸,在今山西垣曲的商城遗址,可能就是冯夷国族早期的都城。山西降县西周墓出土的&quot;倗伯&quot;鼎诸器,说明这里当是西周媿姓蒲国居住的地方。","categories":["06_族氏方国"],"year":2015,"publication":"湖南科技学院学报","link":"https://link.cnki.net/doi/10.16336/j.cnki.cn43-1459/z.2015.06.003","pages":"46090","volume":"36"},{"id":4007,"author":"王文轩","title":"浅析前掌大墓地出土扁足鼎兼谈“史”族","abstract":"&quot;鼎&quot;是所有青铜器物中延续使用时间最长的器类,其器型演化多样,形制随时代推移而多变。滕州前掌大墓地出土的两件扁足鼎形制特殊,为现存商周青铜鼎所仅见。两件扁足鼎上铸有&quot;史&quot;字铭文,结合前掌大墓地出土大量带有&quot;史&quot;铭的器物,探讨&quot;史&quot;族迁徙分布情况及大量出现于泗水流域的原因。","categories":["06_族氏方国"],"year":2015,"publication":"西藏民族学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIguI6Zn4wxuBcCoIaevUXRa6RczzKRIkzUtY2H74L-n3iBv3tGt_i8lIrafWHJQnFi3xGs52M6b3MoE0oQtmTg5tVbYW3cc3Gs60xk7gb2IhsXPw6C0W6OgNs0QxtEAGfdqmn4eswFrpVYTcZuk0R0GJcFramut9eKCWnzit9v-wg0Zl3uf2wX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-104","volume":"36"},{"id":4028,"author":"王庆光; 张爱冰","title":"群舒文化比较研究","abstract":"群舒文化的研究始于20世纪70年代,已经跨越近50年历程,从群舒族群考订、群舒青铜器界定、群舒青铜器分期断代等皆取得丰硕的研究成果。据史料记载,群舒为偃姓,皋陶后裔,始据山东。周初,南渡汶、泗,跨淮水,进入淮南,建立若干小国,如舒、舒蓼、舒鸠、舒龙、宗、巢等。山东南部地区也同样散居一些小国,如薛国、邿、小邾国、莒国、鄅国等,群舒与山东南部诸国皆为东夷古国范畴之内。近年以来,随着两地材料日益丰富,两地青铜文化面貌及文化编年序列逐渐清晰,为我们进行比较研究带来了可能。因此本文将在前人研究基础之上,尝试对两地青铜文化进行比较研究,以期对群舒文化渊源、文化交流研究上有所推进。本文共分为五部分：前言,介绍两地之间文化渊源以及进行比较研究意义所在,确定研究对象和时空范围。对群舒文化研究学术史进行简要回顾之后,阐述本文主要研究目的、思路和方法。第一章,群舒青铜器的类型学分析。对群舒分布范围内青铜器进行全","categories":["06_族氏方国"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIXKjPc63RbAbVUYjkoWhhv2kXk0KwkV5Kgh6ryKYjxZ6FB2rlS7pY0HJBwtp7y5nP8baYcrQ57N9n1e18iUf0QWhHtnf7D_5NuwvfxTpqWm7DfE6NgG7q3WvTpzAW-FwKrNvXiXpeXUX-hN5d2KkLZUGtH-PzroFG-v52Z1w7QuAYfAp0sa7AE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4033,"author":"劉麗","title":"出土傅世文獻所見鄭國婚姻關係探討","abstract":"據《史記·鄭世家》記載,鄭桓公友是周厲王的少子,周宣王的庶弟。宣王二十二年,友初封於鄭。後鄭桓公聽從了太史伯的意見,向王請求,東徙其民於洛東,再加上虢、鄶獻的十邑,鄭國就此安定了下來。[1]鄭國在西周晚期和東周早期對王室貢獻較大,故周桓公曰:&quot;我周之東遷,晉、鄭焉依。&quot;[2]本文擬通過對傳世文獻的記載分析,結合出土有銘銅器材料,對西周至春秋時期","categories":["06_族氏方国"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIN2JZhn_OTJbatL1MBj0eXe2HOpLVfifgddocd0L3n_yuxnpSIK5XUFL-hflNygXA1Yv6h0WOXAf11EKTfxiE0X4C0XCnfepXtjL8OwtUtBeBVKEfOjy9R9Hw9pgOf6HfwRxqG1J-d8VCY5IRXhOhZ2CmQE_1UvUhDe0Ypwl3T0Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-54","volume":""},{"id":4046,"author":"张庆; 方敏","title":"王子午鼎不是“楚灵王好细腰”影响下的产物","abstract":"学术界普遍认为王子午鼎束腰鼓腹的造型与&quot;楚灵王好细腰&quot;的审美习惯关系密切,通过分析鼎内的铭文,考证王子午鼎的铸造时间,借助相关的文献资料和最新的考古材料,并参考装饰艺术的发展规律,王子午鼎的造型特征应是受到楚庄王审美观念的影响。","categories":["06_族氏方国"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKta3bD_XFAeZ1720YN8t6Kj_PrvQ5ZyVyEjVUdPoX5yw091WN0EoB-YFD4pL2Tj7BYiMwuRsNb1ivG6LJNLlE1JCktjBQJoYvtITOtFDjDVz_LYXF78s6qhojj5Igo1oT5901ymiekvwCO94JujXb7_bvddbV-K6ZgZBk1P2v40K8V-Uz61_Fx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-67","volume":""},{"id":4055,"author":"歐波; 胡長春","title":"金文所見淮夷資料整理與研究","abstract":"淮夷是指三代時期生活在今淮河流域的部族。據文獻記載,其在夏王朝初期便與中央政權有了交往。出土的金文文獻有大量閱於淮夷的記載,這彌補了傳世文獻的不足,同時為較為深入的研究淮夷創造了可能。對淮夷的系統研究,有助於我們暸解華夏族和漢族的起源、發展、組成。有助於我們了解古代民族的融合過程,為今天中華民族的融合提供借鑒。緒論首先回顧了淮夷問題研究的學術史,其次討論了古代的淮水。淮水在今天王要指淮河,金文文獻中大量出現的淮夷當指生活在今淮河流域的部族。對淮夷進行了界定,討論了周代的時空範圍,最後介紹了金文資料的來源和主要採用的金文资料。正文對金文材料進行了整理,將其按時間劃分為西周、東周兩個時代。西周時代最早的金文材料屬於穆王時期,主要是伯雝父組銅器銘文,其銘文記載了伯離父率领軍隊在今河南郾城及鹿邑縣抵禦淮夷的入侵,並與淮夷在今河南叶縣交戰。夷王時期的敔記載淮夷入侵到西周的腹地洛水一帶,直接威脅周的","categories":["06_族氏方国"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJT9awwYpNCuOKnXTI1CUTC-nKQ0uxx5x3Uu6dFAE9yZxNmh25Y_UVYkWVp4zd8ghQNLP-1SZFM2R6Y4_06BGNw4s5r59-pkTQB9bfvNxXX5cBfCj5PXqYmHj_8Khv5EZA8lQBv-CuACB_HvIUP16tLsm6me_MAoUg4xcMvfvYJjQaGrA0eTl6q&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4057,"author":"王琢; 袁俊杰","title":"曾国历史文化的考古学研究","abstract":"本文运用多学科交叉研究的方法,通过综合分析传世文献、甲骨文、金文、考古资料,对西周早期、西周晚期、春秋早期、春秋中期至战国晚期曾国历史的相关问题进行了比较全面的考察和深入研究,在已有研究的基础上又做了三个方面的研究,主要观点如下:一是对西周早期叶家山曾侯的家族、世系、身份、始封者进行深入的研究。以叶家山曾国墓地曾侯家族的“日名”铜器为突破口,认为曾国的始封者当是南公,南宫适、聃季载、南公、伯适当为一人;叶家山曾国墓地出土铜器铭文使用日名祭祀南公与武王发,在日名铜器铭文中两人被分别称为父癸与父乙;理清了叶家山诸位曾侯的身份,发现叶家山诸位曾侯都是兄弟,叶家山曾侯在君位继承上实行的是兄终弟及制;总结出西周早期南宫家族与曾侯家族的世系,根据两个家族的铜器铭文记载的史事,认定南宫家族的地位高于曾侯家族,二者是大宗与小宗的关系,都是姬姓周人。二是对曾国职官进行历时性研究。整理各个时期曾国的职官资料,","categories":["06_族氏方国"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISLgbD6tTJrnJPgez23mDbMWowmnYbzvGuLG6k8yxf1CTeVFqU3z8md0PP6Hj4YU2z6P67E4jzDPPU4WwUvuAFr6_Z_zxX06k0QxQxQyRwfWb-iGuXl5TjtmVk7IA7hD8znuK6KBIEOohD-tHD5hqPtnJ2zs7tpKIRVpPn6q7gM8Gp6KnuRQmd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4076,"author":"曹斌","title":"■国小考","abstract":"在对过往材料梳理的基础上,重点利用高青陈庄出土的金文材料,指出陈庄一带原为东土■国所在,在周公东征被灭国后,齐太公封姜姓庶子至此筑城戍卫边防,并从此以&quot;■&quot;为氏,在康王时期还因其特殊地位被称&quot;■公&quot;。这样在对考古材料做合理解释的同时,理清了不见于文献记载的东土■国的历史脉络。","categories":["06_族氏方国"],"year":2015,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2015.03.028","pages":"165-169","volume":"36"},{"id":4094,"author":"王宏; 权敏","title":"贾国青铜器及其重要价值探研","abstract":"据传出土于山西的一批贾国青铜器对于研究贾国的历史十分重要,弥补了文献记载的不足,明确了贾国的地望,反映出强烈的周文化特点。从这批铜器的本体出发,还可以探讨贾国的财力、爵位、外交政策以及灭亡的一些史迹。另外贾子叔子屖盘不是西周姬姓贾国的器物,具有强烈的海岱文化特点。","categories":["06_族氏方国"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPcrgj--nhF-2G8b0J0pb4K2BiJ3jmNbr0Co7qXzHbcRKI_edxJofRR8vRVdJy0kfJC7pTH5bLGEv9bL-vJ7LTcIdFC3y5KWFiy3NHEyX7A_7LrZn2OkCNijOyghdocNRq41cY_S6qTa4anVgnRALITo1usvgCQ1bgLn_qhGxRrHU8Mrbc0FuK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-71, 74","volume":""},{"id":4100,"author":"王琢; 袁俊杰","title":"叶家山曾国墓地日名铜器研究","abstract":"出土铜器铭文所记史实,曾国为姬姓诸侯国,其始封者当为南公。如果将南公与聃季载联系起来,则有许多新的发现,颇能解释曾国墓地出土日名铜器这一罕见现象。根据叶家山日名铜器使用规律和文献记载,不仅可发现曾国的始封君南公即为周文王第十子聃季载,聃季载当为父癸,周武王姬发当为父乙;还能发现叶家山曾国墓地中两位已知私名曾侯,一位未知私名曾侯和一位疑似曾侯之间,应该是兄弟关系,早期曾国的高等级贵族有多父之称的习俗,在王位继承上实行的应是兄终弟及制,而且曾聃一国,聃、曾、随都是同一诸侯国的异称。","categories":["06_族氏方国"],"year":2015,"publication":"长江大学学报（社科版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLstsbOrMOn313uT9x0gUxuA-NBsL639kD71tAyk94yipS7YMvLIjzSwNR5dE7bLSmXlLJCUWapVl4rzsjvPAoApAK6unu41VDGBvte_3oi1SqrfheFFDzRNfztdQr6wQiKN-_mKNqkx9rW5cb1_-CiNGCwaNqeJR9qYqHuRwj-huYz_KvCdV9i&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-16","volume":"38"},{"id":4105,"author":"黄尚明","title":"从考古新材料看鄂国的历史变迁","abstract":"鄂国原是商朝的一个重要方国,商代之鄂方在今河南沁阳。西周早期鄂被周王朝分封到江汉地区,周夷王时期楚国熊渠讨伐鄂国,封中子红为鄂王,又建立了楚国所辖的鄂国。周厉王派军队消灭了周所封的鄂国。春秋战国时期楚所建立的鄂国变成了楚国的封君鄂君。关于西周鄂国和楚封鄂国、鄂君的地望,学术界长期存在西鄂说和东鄂说之争,西鄂在今河南南阳东北,东鄂在今湖北鄂州。根据随州安居出土的鄂国王室墓地资料分析,西周早期到西周晚期的鄂国在今湖北随州,这是一个新的认识,已经突破了传统的西鄂和东鄂二说。南阳夏响铺鄂国王室墓地的发掘表明,这个鄂国王室并未完全被消灭,却在西周晚期又迁徙到南阳东北,在此建都,直至春秋早期可能被楚所灭,因此西汉在南阳郡下设西鄂县,史称西鄂。楚熊渠所伐的鄂国即随州之鄂,所封之鄂国开始亦可能在随州附近,后来可能迫于周厉王和曾国的压力,迁至今湖北鄂州,春秋战国时期的楚封鄂君封地也在鄂州,于是西汉在江夏郡设","categories":["06_族氏方国"],"year":2015,"publication":"华中师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIX7VjSqTJ_oT3Zv8TgeF2yxKz5rGqh-lt707H8MNsd7PDDxlbXOoAvd0WgFJgp2gszkVFpKkM3b085W3_Oi_ZnBFsGHmz1l2eKWs2i9NpyI6E6fS8k75noPqVMv8ksjt08A3n-tLHUWIuiplEvOIk10LrqDSCdjGhW-aR9jOZxIWPPfUql0pW3&amp;uniplatform=NZKPT&amp;language=CHS","pages":"144-149","volume":"54"},{"id":4132,"author":"燕生东","title":"考古所见“费”国及曾子里籍问题","abstract":"周代山东南部地区到底有几个费国（地）,其具体位置又在哪里,学界素有争议。陈槃先生曾详细列举了历代对费国方位、姓氏、爵位、存灭时间以及&quot;费&quot;字写法、读音的不同看法,并提出了自己的倾向性意见①。大体看来,山东费国（地）之&quot;费&quot;,或写作&quot;鄪&quot;,或写作&quot;弗&quot;、或写为&quot;粊&quot;;其音或读为&quot;蜚&quot;,或读为&quot;秘（bi）&quot;、&quot;柲&quot;;其地一在今费县,一在今鱼台、嘉祥县之间;其姓一曰姒、一曰嬴、一曰姬（即鲁国季氏）;一费国曾在春秋中期被鲁国灭亡,成为季氏封邑,但另一费国延","categories":["06_族氏方国"],"year":2014,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8ogpbTObJ04m4bRh3wIY3UGKwQ6s8nwhyCL_p_1q9258UAr5ZWaG3kmXPH9c1kB0VprkbQUbGf2M2cj9PVWXPBYs2f-2rmtZ4X8YFXdZyz3T1vOmToBViOpiQ39McqYggD6CAKLudhsQtoY2KSuJROcxWga0r-DbVZlBjz_8Dcw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"151-166","volume":""},{"id":4142,"author":"熊贤品","title":"《越王差徐戈》铭文与越国徙都“姑苏”补论","abstract":"《越王差徐戈》铭文是目前所发现的记载苏州地区名&quot;姑苏&quot;较早的文献资料。对铭文进行汇释并就&quot;得&quot;&quot;居&quot;&quot;居乍金&quot;&quot;司&quot;的用法及&quot;先王&quot;所指进行讨论。越王翳迁都吴地,越王差徐承袭之并都于姑苏,其原因与越国北上扩张与齐国势力南下的冲突有关。铭文中的&quot;姑苏&quot;可能在今天苏州城西,其可能并非越国新建而为沿用春秋时期的木渎古城而来。由木渎春秋城、越王差徐城至秦汉以后苏州城址的变迁来看,前两者均在今苏州城以西,表明苏州早期地址的发展经历了一个由西至东的过程。","categories":["06_族氏方国"],"year":2014,"publication":"苏州教育学院学报","link":"https://link.cnki.net/doi/10.16217/j.cnki.szxbsk.2014.06.022","pages":"46185","volume":"31"},{"id":4167,"author":"李筱","title":"试论安徽九里墩龙虎纹鼓座的年代与国别","abstract":"龙虎纹鼓座是舒城九里墩墓中的一件特殊的器物。这件龙虎纹鼓座在雕筑、纹饰、铭文、国别等方面具有显著的特点,值得研究。通过对龙虎纹鼓座的探讨得出,九里墩墓主是偃姓的贵族,其祖先是很可能是从蔡国迁徙到舒国的。此鼓座应该是在春秋晚期这位舒国的墓主所得的一件钟离国器物。进一步探讨龙虎纹鼓座,对探寻舒国的历史,群舒与周边国家的关系具有重要的意义。","categories":["06_族氏方国"],"year":2014,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLp7qdo3wsRsttCVQ43WwZ8vKF9MKOxsKRPifx_mCp6pTZXyC5RrSGQMiYy0ZDry0Fl4NEwxn3Fy1ODtb50EFCR6jslh9pz6khpHsrBM9VVQVo3asI7UgLuA16B42vrhQ46vyQIbq3OVnBJ8hHwGaHUrpCAj1IIe7u63mcX3HbVjZCf5S28hawt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-67","volume":"36"},{"id":4185,"author":"程平山","title":"秦子器主考","abstract":"秦子器是春秋时期秦国的铜器,&quot;秦子&quot;的称谓独特,秦子器对于探讨礼县大堡子山秦公墓墓主、秦国继位制度以及相关史实有重大意义。30年来,许多学者探讨过秦子器主,尚无定论。近年来,随着研究的深入,我们对于秦子器以及相关史实有了新的认识。一秦子器的发现目前,已发现的秦子器有自甘肃礼县大堡子山秦公墓地考古发掘所获及盗墓走私流传出去的秦子器与传世秦子戈、矛。1.礼县大堡子山秦公墓地出土秦子器在礼县大堡子山秦公墓地M2西南20余米处发现有青铜乐器坑、人祭坑等祭祀遗迹,乐器坑出土编钟8件、秦子编镈3件等,器物时代为春秋早期。编镈铭文作&quot;秦子作宝龢钟,以其三镈,乃音灉灉,秦子峻岭在位,眉寿万","categories":["06_族氏方国"],"year":2014,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2014.10.004","pages":"49-56","volume":""},{"id":4188,"author":"张娟; 刘社刚","title":"丰伯簠铭文及相关史实考","abstract":"河南三门峡市虢国墓地M2006出土了两件制作精美的青铜器单叔盨与丰伯簠。单叔盨是单叔为其女儿孟姞嫁到虢国所做的媵器。丰伯可能来自姞姓丰国,丰伯簠极有可能是丰伯为媵单国之长女孟姞所作之器。这两件器物反映了西周时期的媵婚制度。","categories":["06_族氏方国"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZiv7U1mPOHTmuPnTe_eJyTKB0yI5GoWpJoLWHdm6IbJ1_PPI2Dc3TOBMS6elH8W8f2FoRBZAol13S06BXJvDcURpOIBu3pX9T00QcgDnOAJoUZzGofhATKgAxfs06JU4fGAf15aoh4OIONo8srE8kfdn3q2EDOigjjPRRCvePJg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-71, 86","volume":""},{"id":4192,"author":"王戎","title":"陈庄西周遗址与齐国西周史的几个问题","abstract":"高青陈庄遗址众多重大的发现,对齐国西周史研究具有重要的补史证史作用。陈庄遗址应为齐国始封地营丘。陈庄遗址形制特殊的祭坛应为天坛,而近似方形只有一个南门的夯土围墙应是拱卫天坛的坛墙。M18出土丰器的器主为乙公得,&quot;齐公&quot;铭文所指即齐太公,M35出土70字长铭铜簋应定名申簋,器主为齐献公山。周王伐齐的战争起因与齐哀公祭天有关。因为齐国早期的国君墓葬在营丘,&quot;五世返葬于周&quot;的说法不成立。","categories":["06_族氏方国"],"year":2014,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2014.03.006","pages":"28-33","volume":""},{"id":4195,"author":"黄凤春; 胡刚","title":"再说西周金文中的“南公”——二论叶家山西周曾国墓地的族属","abstract":"叶家山西周墓地M111中&quot;犺作烈考南公宝尊彝&quot;的铭文首次将曾国与南公联系起来。而文峰塔墓地M1所出曾侯與钟铭文提供了曾国始封和族姓的关键证据。我们在《说西周金文中的&quot;南公&quot;》(《江汉考古》2014年第2期)中曾指出&quot;南公&quot;即武王弟聃季载。本文在重新考释铭文的基础上,结合铭文中有关&quot;南公&quot;的记载,得出如下意见:南公应是南公适;曾国应是南宫适的封国,其族姓为姬姓,始封于西周的成王或康王之世,与东周曾国应为一源。","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKc0dh8pTGOp6_V2PZWCvLmPZS6cPSAOW7KoyezNo8gtVLOZOiSKYli2SzSdBEu5mGjap9mCsIsx-ac4nCrleNw0Esc8PJmVLvp6wUzRQINCVKQdqq_oWujRph0HpagW_DHBjFtQxgQjlTEsbNeAtFMsQrkIMX9VYGkuRWc3FLv_g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-45","volume":""},{"id":4202,"author":"徐少华","title":"曾侯昃戈的年代及相关曾侯世系","abstract":"2001年,在襄阳梁家老坟十一号墓中出土的曾侯昃戈,具有十分重要的文物和史料价值,发掘报告虽未正式刊布,但已有几种图录先后加以著录和说明①,对学界了解、认识这件器物的时代和意义提供了方便。这里结合相关器物的形制和铭文,对该铜戈的年代作进一步的讨论,并就曾侯员与曾侯乙等的关系加以梳理,以为今后的深入研究奠定有利的基础,错误之处敬请师友指正。","categories":["06_族氏方国"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzccui10FOEF6zf8Ru0a6K7bUMEALthuCL_qp2NcwyyP2p1GPg4q4g_w0_KnIuEt1R8LGwe07X4iFqje7h7YaY_C0yfOXlih-8brOyQKdOfgMLb_rK3yZNomX2gg3GhWnh2FTIA0TkSeO8gagk0qWQ_LqAZqFrw-qYMKD-6_A6WA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"218-222","volume":""},{"id":4218,"author":"陈曦","title":"关于铜器铭文中西周后妃“王姜”的考察","abstract":"西周各王均有后妃,西周铜器铭文中对有的周王后妃的名字有所记载,我们如果能够确切证明某一后妃之名为某一周王配偶之名,如果能够确切知道西周各王后妃的称谓,对于有铭铜器的断代将会有一定积极意义。但目前问题是某些周王后妃之名,究竟是哪一个周王配偶的称谓,学术界还有不同的看法,有的曾有激烈争论,分歧较大,最典型的是关于王姜。","categories":["06_族氏方国"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0wCCA8b_ZfySK-bS4uhGHbdx-t0id0vqu7u3jqXuywtHW2bzFeuefd357DG6i9Gx7TMLqRywH24fgpP5_5mQI-pk7hRYR5I71NEwnOLFWJ_A0h81ZMARpJ6fRNBCTQsbHksQR5Aqy_l5VtHBHnQhlelarB5-JlwxR8Yhsp-9Flw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141-145","volume":""},{"id":4256,"author":"李学勤","title":"曾侯(月舆)(舆)编钟铭文前半释读","abstract":"2009年在随州文峰塔出土的曾侯(月與)(與)编钟,铭文前半位于钟的钲部和左鼓,所记历日相当于公元前497年,周历正月甲午朔。器主曾侯(月與)追述先祖伯(即南宫括)辅保周文王、武王伐殷,后受王命建国于汭土,君临淮夷各族和江汉地区。这是西周早期的重大历史事件,也为曾(即随)国公室族属等问题提供了珍贵论据。","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK7MwGcgD1L0XMHMKmqTD8_LfUc5Pb2OsM9YKMmkyxp_nzCe6039i65jDDu8T2XWpliXrmkBk7iu96gvVf_UY5b5X9kaJ0kLyopTWKRNtyrFCQHrCqLnjTxnJrwzrFlSnGizrDhmxx2MSAnlbAJpM15sF7pq5Hb3lEq2ZPL2uDGoA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-69","volume":""},{"id":4259,"author":"徐少华","title":"论随州文峰塔一号墓的年代及其学术价值","abstract":"随州文峰塔一号墓所存留的部分资料、尤其是编钟铭文的内容十分重要,具有多方面的学术价值。资料表明,该墓墓主即器铭所见的曾侯與,其时代约在公元前480年左右的春秋末年,可与早年曾侯乙墓的出土材料互证。铭文记载曾侯與自称&quot;余稷之玄孙&quot;、&quot;伯适上庸(用),左右文武,……。王遣命南公,营宅汭土,君此淮夷,临有江夏。&quot;不仅与早年季氏梁出土戈铭曾穆侯之子又称&quot;周王孙&quot;的资料相呼应,又与叶家山M111所见&quot;犺作烈考南公宝尊彝&quot;的器铭相关联,说明叶家山墓地所代表的西周曾国与东周曾国一脉相承,为周王室支系所封,属姬姓小宗。器铭&quot;伯适&quot;、&quot;南公&quot;,当曾国始封之君,表明曾国应是成王时期被封于南土,以镇抚淮夷,统领江夏,与文献所载周初分封齐、鲁、燕于东土、北土,藩屏王室的情形类似。钟铭有关曾侯复楚","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJr01glmZgDwT7J8AVOFh6Cp8pUwguoFw033nxGSsFVX60iAio1OqMzdcOivTLJdqvygMW34pQScv0gxpyW6TxGuGd-vgnwFdySKIAKG9bnKt101C1kqpgP9I58PdrJCu-CIeUBsxBxA5I6RO1rZCkbCUhSDdzzVlpR4v1-vMi-dQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-84","volume":""},{"id":4260,"author":"方勤","title":"曾国历史的考古学观察","abstract":"本文利用考古材料,分析探讨了曾侯编年序列、曾国都城的变迁、叶家山曾侯的族属等问题,对曾国历史进行了较全面的考古学观察。","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLRm5rt3WClnHup490aXguPA0mRtrSm1uRl8nbVVuMQssqWJFFM1K_OhXoMWgVRhqjksQHwUozGHjBkdYCkUSaJPnLNcR61hGhqJfWG_knqjYPfk2scaLlRV7HuU8QsrpHxjVoskjKTYyx5uQtcF75cFfBGs5lskKJCRQgdjr4NLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-115","volume":""},{"id":4296,"author":"金荣权","title":"周代番国青铜器及其历史地理论考","abstract":"番国,为祝融八姓中己姓的一支,春秋以前在中原北部立国,至春秋前期南迁至淮河上游的信阳市平桥区一带,或称&quot;鄱&quot;、&quot;潘&quot;。后世出土为数较多的番国青铜器,铜器铭文多自称&quot;番君&quot;、&quot;番伯&quot;、&quot;番子&quot;等。番国在春秋时期较早归于楚国,从信阳平桥区向东迁移至固始县。公元前504年吴人伐楚,获潘子臣,取番地,番国最终消失。番国贵族在春秋中期便入楚王室为官,如潘崇、潘尫、潘党等。尤其是潘崇,在春秋时期楚国历史进程中具有举足轻重的地位。番国文化呈现出中原文化、淮河流域文化与楚文化的融合。","categories":["06_族氏方国"],"year":2014,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2014.02.007","pages":"60-67, 125","volume":""},{"id":4303,"author":"侯东泉; 仝晰纲","title":"郯文化研究","abstract":"郯国，少皞部落后裔建立的古国之一。据前人推断，郯国的历史最早可追溯到远古时代。西周时期，通过对古青铜器铭文的研究发现，郯国是西周初期成康之际周王室军队的屯军处，这里有周朝的军队长期驻守，作为防范东夷、淮夷部落及殷商旧势力反叛的军事基地，其战略位置非常重要。春秋早期，郯国国力还比较强大，境内比较和平。到春秋中后期，郯国实力急转直下，先被莒国所欺侮，后被吴国所侵占，今天还是齐、鲁的朝拜国，明天又成为吴、越的附属国。朝不保夕，苟存于大国之间，最终于公元前404年之前被越国所灭。灭亡之后，郯文化逐渐融入到大一统秦汉文化洪流之中。全文主要分上古时代和西周的郯国的历史、东周时期的郯国、东周郯国的文化和郯文化的历史积淀四部分。第一部分探究上古和西周时期郯国的历史。郯国是否建立于上古时代，现有的文献并未指出，发现的考古材料也未发现远古时代郯国的遗迹。而西周青铜器却记载了郯国的历史，这说明郯国最早历史可以追","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDwL9pqN-wGIQFAOrbd5vWLszoU77rTd2kUOK4InJtP_7KdyJ7SuVdNFv3cksx0EuEpGfayby_lWNuLduOICXPCd_oHbkyotD89lNXM9a5ylCzsJ78Rbwxqsm1L3oHoXEkd9bN0xsleF2OIGyZqCOzx8x8FHwfJaDfb9FvJW7to080qL87NXgi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4326,"author":"陈晓; 燕生东","title":"周代山东诸国族属及相关问题研究","abstract":"本文利用文献资料和考古发掘材料、借鉴国内外有关研究成果，运用族属认同理论，大体梳理了周代山东诸国的姓氏、族属来源，探讨了山东诸国的分布特点和规律，并在此基础上对周代“东夷”族群问题及山东诸国的文化特点进行了简要分析。本文第一章中，介绍了商末周初山东地区的文化、古国及族群分布态势。商代末年，山东地区就已经存在了许多方国和族群。这些存在的方国和族群，有些是商王朝东封的方国，有些是直接来自殷都安阳的族氏，有些是东封就国的、地位很高的王族。他们与山东当地土著同时存在，在文化上表现出二元对立、互不相容的格局。第二章重点梳理周代山东诸国的姓氏、族属、来源与地域分布特点、规律。这一章依据族属认同理论，以不同的族群为出发点，梳理了近四十个山东邦国的姓氏和族属，这些邦国分属于姬姓、姜姓、姒姓、子姓、风姓、嬴姓、妊姓、己姓、曹姓、妘姓、妫姓、女白姓等十多个姓氏。除此之外，还有些不知姓氏和族属的邦国或族群。山东","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzn0fOeEvsbwe1EGyPk78Nf2dN75P8A-w5PKa5PIvtNMr0UqEJvHIoteC_cbn7CQQ5X7tX8KkZEdRCUdwyeNbk85dZ9JdgP-0Lz_IQUPRpxOssJQtsxK2aYLMGodb4pz_jeRi12Jjk1YlKwfoCeTbMyUSkxiWaxRJPTI28IOhvaWFLGcVBCzaN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4356,"author":"孫麗君; 胡長春","title":"漢水流域出土春秋方國銅器銘文整理與研究","abstract":"漢水是畏江的第一大支流,也是上古时期文化繁榮的地域,在清通东西部文化上发挥著極其重要的作用。静多出土傅世文献资料及考古发现也记载了漢水流域早期的人类文明活勤：城背溪文化、大溪文化、屈家嶺文化等。春秋时期漢水流域方国之多,從傅世文献典籍中亦能窥见一斑。这些方国的遗址中也出土了大量的青铜器,铜器上的竿川豐富铭文也为考证古代歷史文化提供了豐富的史料。文中探用窮盡式收集的方法,较为全面系统的收录了漢水流域出土春秋方国的有铭铜器。根据古文字学、文献学及歷史地理学等相关學科知识,结合先秦传世典籍记载,封漢水流域春秋方国的銘文进行整理舆研究。以迹些出土的銘文资料为基础,封漢水流域春秋方国的歷史、文化造行力所能及的探封和研究,力求遗原遣一时期的歷史實貌。根据《中国歷史地圖集》(谭其骧主编,中華地圖学社1975版)及《春秋大事表列国爵姓及存减表譔巽》(陈槃,上海古籍出版社2009年版)等著作,及铜器铭文所记","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImCy2KhX7A4uavE-OWDC5wssKXPGd03EQOWDaGdwL5oe2nCDxcJs3Wvnr2VPt8jxyw76_UfzI00JDNhSk7Bs867wMQaGDxBA700FmoPLxg-exRQyatzpkK_BU_jSzSXDUBPo-6Ixb0C_ABmg3NOBs6qHZ0G0lYxjf6e1mw21Mrjx_hlwo0agok&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4359,"author":"馬超; 胡長春","title":"春秋時期淮上方國金文研究","abstract":"淮河上游山三條支流組成：汝水、穎水、淮水。春秋時期，該區域有金文出土或傳世的國家約有十四個，分別是：敖國、鄭國、應國、蔡國、許國、陳國、沈國、養國、胡國、江國、息國、黃國、蔣國、番國。在先秦時期生產力不發達的情況下，青銅彝器對於各國貴族來說也是一種“奢侈品”。當時之人作鑄銅器，除为了满足日常使用之外，往往是出于歌功頌德、祭祀先人、餽赠賞賜等目的．所以銘文中往往會標明作器綠山以及器物領主，這對於我們判斷其國別是非常有利的。經過收集與整理共得各國(不含江、息、黃、蔣、番五國)有銘銅器二百七十餘件，涵蓋了從西周早期至戰國初年，近六百年的歷史時期。其中既有銘文短小僅一、二字者，亦有蔡侯申盤、十月敔簋等長達百餘字的央央巨制。可以說銘文的内容是十分豐富的。除了鄭、陳、蔡之外，其餘各國在典籍中大都記載不詳。而大量出土与传世的青銅器銘文則為研究各國的歷史文化提供了彌足珍貴的資料。這九個國家的銅器銘文，前輩","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6Rd2CiLcsvqw3_fQKtuT-Csa2vUp7X9U-j6yRxd6QQUiOTsgwk12ooJHS1QAB3GAu1nmgoevXSbSPn2pa85Y9J530gw7C5mQGmcwE8sMjPbDolCdYjvf8XCFJIDuqGS_qTub32K_6719fXnSnu5CGWhMOkYIvVfRN4OLjZGmcPkl4OigWv2p5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4361,"author":"姚磊; 雷紫翰","title":"先秦戎族研究","abstract":"戎族在先秦时期相当活跃,对该时期的历史产生过不可忽视的影响。然而学术界却至今缺乏对戎族史的足够重视。本文在回顾、总结海内外前贤有关研究成果的基础上,从传世典籍、考古资料、古文字资料中细致梳理证据,首次对先秦戎族留下的历史信息进行了比较全面、系统的探究。本文总共七章,概括起来,主要包含三个方面的内容：一,全面梳理、评价海内外学者对戎称谓、分布、族属等问题的争论及其贡献；二,对甲骨文、金文以及典籍所见戎人历史信息的系统考察；三,对戎人历史文化若干重要问题的初步考辨。海内外学者对戎称谓、分布、族属等问题的争论,是本文的起点。通过对百年来的戎族史研究进行全面回顾与总结,并逐一梳理学界对41个戎族分支的争论,发现：该领域的争议与分歧明显大于共识,这充分说明要进行先秦戎族史研究,就必须得面对其复杂性和相当艰巨的困难。对甲骨文、金文以及典籍所见戎人历史信息的系统考察,是本文的主体部分。逐步考察甲骨卜辞、","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhGLklxFheUZym2Bv9HFJy2vTm0Urd8Ui-iMNZHGXzr7C0Vr7Yk-NsDQEPx-4rYZGHRvPfLvCmq5ymKc8E1VJkMpJ3SUD9kWNiR1H48MGHSRWfXgOEvsG29gnXjYiIXgfmxGmODLaL5PY_gfYapqrvwZJ7mVEdJM4fXZg3QHapVw1zO8A5T8jP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4362,"author":"杜赟清; 杜斗成","title":"从白草坡到周原","abstract":"1969年和1972年,甘肃省博物馆文物队对灵台县白草坡发现的一批西周墓葬进行了考古发掘和清理。经过这两次的考古发掘,共计清理出土器物1230多件,这其中仅青铜器就出土300余件。如此大数量且制作精美的西周铜器的出土,在学术界引起了巨大反响。同时,也再一次让人们把眼光聚焦在了一个已经消失千年之久的古国身上。古密国,又称密须,商周时期的一个方国,其当时的统治中心即在今灵台县境内,后为西周共王所灭。而白草坡西周墓的年代则为西周康王到穆王之间。也即是说,白草坡墓主在密国所统治境内生活,并且在墓主人去世后密国仍然尚在。如此,白草坡墓中所出土青铜器也当可以代表同时期的密国青铜文化。此外,在古密国所统治地区内,即今甘肃省灵台县范围内还出土了诸多西周时期的遗址和器物,这其中不乏一些西周早中期的青铜器。同样是在上世纪六七十年代,陕西周原地区的大规模考古发掘工作也正式开始。作为周人的发迹地,周原所出土青铜器","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvAR9iv0JgqZuy-dIT7EQ-Znpxp3mLRV3RJa1HIGtr6NewAx2oT9dFrXTWATdQke544IxlgFqU8HjJ4mKzBSdPXCzAS3HqmLHBoY5FgLUSmOhRFQi8-JdeGkw9IYcFg1wmExgQAznXpfG1QT0E7mL6VG6aAldjpzkM9eo7sTJHGQ9Ome7keQUm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4369,"author":"王长丰","title":"蔡公□宴戈考","abstract":"本文针对新近发现的错金铭文&quot;蔡公□宴之戈&quot;铜戈,系联了目前所见的蔡公系铜器铭文,探讨了蔡公□的家族谱系。","categories":["06_族氏方国"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqbBUynW0TnkZKJEDgpjgZrZmQMDxpUS514o-ONfPJcRuZi1WcEbU1JoXy1fQzTzRmBhyOV7TS-ONWYM_i8aDdnYPgmn-7_3Nvz4OJj3xLK3SKJs72sskQFtrQWrvFk0SbSHXPlTjpLmRQprkpZLUXfdDn6DmdH97PU4ogIdycRw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-68","volume":""},{"id":4374,"author":"孙合肥","title":"试论钟离","abstract":"钟离是春秋时期淮河中游地区的重要方国之一,文献典籍中有关钟离的记载不多。近年舒城、凤阳、蚌埠等地区相继出土的钟离国有铭青铜器,为认识古钟离国提供了重要资料。","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLprDy9GB9G5WGcvnh3wXaXrrueAabNTtRwO1R4x-7MDc3UP0BBBSdfr_7e-ComLpAwVJ8q2Clo1yPw3SJtwxoP-LnLnrXbBHj_C2cZdgXjTc4o36H2l5XYBbomW1qrSLW9yflKyhSEJ_cM3WdqbnVsfWszqQx-Cv5hSs3VQHhzXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-71, 126","volume":""},{"id":4375,"author":"黄凤春; 胡刚","title":"说西周金文中的“南公”——兼论随州叶家山西周曾国墓地的族属","abstract":"&quot;南公&quot;见于大盂鼎、南公有司鼎和南宫乎钟等铜器铭文,学界一般认为&quot;南公&quot;之&quot;南&quot;应是&quot;南宫&quot;的省称。根据《左传》及《白虎通》引《诗传》而知,南公有可能就是周武王十兄弟中最小的聃季载,&quot;聃&quot;与&quot;南&quot;为通假字。称南公应是原居于周宫中的南宫,又封于南土的采邑而得名。叶家山M111中再次出土了一件&quot;犺乍剌(烈)考南公宝尊彝&quot;的铜簋。&quot;南公&quot;铭文在南土的再次发现,对探讨其族属提供了非常重要的文字依据。从铭文可知,&quot;南公&quot;为曾侯犺的父辈。结合大盂鼎铭文并综合年代分析,曾侯犺与盂可能为叔侄关系。如此则叶家山所发现的西周早期曾国应为姬姓。","categories":["06_族氏方国"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKBYW9u8KG9yaqDEugo-MJMh6P8IlHpaELgpa6PRxaW9I1lFIqfJxW5BZbzt5OQG9cYQApzcwpiDQuhbC2kWGBEtocFHbOVuICQahyYpxcyHkFzoQmPY6oND9Y4JKKtDV7voQ7S3b6U8_Xs_1APvTL-gC0esyVi0SsF--xq1XkCbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-56","volume":""},{"id":4381,"author":"赵利鑫; 涂白奎; 黄锦前","title":"虢国铜器铭文整理与研究","abstract":"虢國是西周初年分封的姬姓諸侯國，公元前655年為晉國所滅。有關虢國的史跡，文獻記載多有抵牾。傳世著錄和近年考古發現的多批虢國有銘銅器資料，則為研究兩周時期虢國歷史與文化提供了切實可靠的依據。由於這些銘文資料在考古學、歷史學等方面都具有較高的學術價值，因此，學者們針對這些銅器銘文進行了廣泛而深入的研究，在有關虢國歷史發展研究等方面取得了較大的成就。但是由於各家成果散見於不同時期的書刊雜誌中，尋檢起來有所不便。故本文在已往學者研究的基礎上，将歷代相傳與近今出土的全部有銘虢器集中在一起，運用科學方法加以綜合整理，并結合文獻資料，對銘文所反映的內容作進一步地分析，就顯得十分必要。具體而言，根據銘文所反映史事、人物、族組等內容對其進行分類、分組、斷代，進一步梳理清虢器銘文本身內部的聯繫，并對銘文中所見人物進行考述；依據文獻記載和考古材料，對銘文中所蘊含的歷史信息進行分析，就虢國的分封等問題作進一步討","categories":["06_族氏方国"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXAFk9bwG_eOgJy5w22QN-plRdzOjYvjKxLjrtABmJoa-64NcdN6QVFqAzVm0VuACHpiPzNZxjb56_q1IbYi5U8ijqYpMBpmeOyPzhi6t7GD0GbDJG1wDqr1vdaRrTH_6OkX9b16ncFNpjQp08GyOpojaUdEH5sUwOg7XLzabgPln8Qhi2AwAX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4399,"author":"白海燕; 白军鹏","title":"论长子沫臣簠的国别","abstract":"上海博物馆在上世纪60年代曾收集到一件!,马承源先生著文指出!当为晋器。此观点得到了学术界的一致同意,如吴镇烽《金文人名汇编》等均认为器主&quot;长子沫臣&quot;为晋人,而搜集楚器较为著名的如刘彬徽《楚系金文汇编》等亦未收此器。本文对长子沫臣!进行综合研究,通过此!中出现的&quot;芈&quot;姓,初步认定其当为楚国器;再考订铭文字体的特点与南方楚系文字接近,而与中原同期文字字形较远;由铭文右行以及&quot;!&quot;类器在中原及楚系中出现的频率及制作的精粗等,论定此长子沫臣!实为楚器。最后,联系鹿邑太清宫长子口墓及湖北黄陂发现的长子狗鼎等,认为此!铭中之&quot;长&quot;与长子口、长子狗之长实有相承关系,由此初步推测了西周时期长国、厉国的迁徙方向。","categories":["06_族氏方国"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-oKB2ngCjR1RZcbqAi9MOIgnAZy_E-Dp46P-XOLCfgfad08kr2XnQoNwpFcdMls6Dtptb6TVvsrRSM2Ha6gkf6rOG9_c_sbSDfcgbm_CGm32kIytLhhZqbR83nMKS1OfB9UQh1SMq7RFPog07Ys1wSicU387JhTVC1Hi6AE2Vxw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-68","volume":""},{"id":4470,"author":"李宝军","title":"西周早期的召公家族世系——以青铜器铭文为中心的考察","abstract":"关于西周早期的召公世系学者聚讼已久,本文通过对青铜器铭文的分析并结合传世文献考证,认为西周早期的召公世系主要有三支:长子克的燕侯支——成员有燕侯克和燕侯旨;次子召伯父辛的宗周支——后裔有召伯虎和生;居于成周的太保支——成员有、父乙、叔造。至于伯宪、伯乃召公的孙辈,其父均已不可考。","categories":["06_族氏方国"],"year":2013,"publication":"洛阳考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlcdcWirpOjHn7qoI13HVTTEUPKBkuxA922rzNE0hqjnQHG9E8v20YPXnTkHB-99lJvUr5zMOLgXwAVT06GU7WaOLAzsuW-UODcX1Me8WYMw0s5-d5v7OFFrCy8RUZk5rBFx68WI-zzt6kGi8smgIpck7s6DR1h7RMhkD2uqR1BA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-70","volume":""},{"id":4477,"author":"王进锋","title":"金文所见商周时期的臣辰史官世家","abstract":"目前所知,商周时期铜器大约有二、三十件带有&quot;臣辰&quot;铭文,其中绝大多数的铭文比较简短,如下引铭文1～4、9～12;但也有一些的铭文较长,如下引铭文5、13。之前学者的研究,有对单篇臣辰铜器铭文进行释读的[1],有对多篇此类铭文进行综合考察的[2],还有从考古学的角度对臣辰铜器进行综合研究的[3]。据之,臣辰铜器铭文的文字已经基本清楚,器物的数量、收藏和年代等情况也大致明确。然而,这些研究关注较多的还是文物和文字本身,对于臣辰铜器铭文背后所涉及的历史情况的考察则有限。实际上,臣辰铜器铭文蕴含着丰富的历史信息,非常值得研究。本文将在前贤研究的基础上,重点考察臣辰铜器铭文所反映的历史情况。不妥之处,敬请方家指正。","categories":["06_族氏方国"],"year":2013,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIAnpbhoG6Uh2JqHb7eYYUTfxVfAB0CBY9_Ak5sMfItb5WWHhLCSV6Sgt0wnaGd37PxX3NCn_3tp5mUKHaitVViFJ6nSXo66BmCP8BlN98Vfgg9ALbvkuDoO4dV3czPSyUaaUFpBRAxzH-yLkuqQ0RcKqFvi9bHD8BZTVaFtTRRJQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-71","volume":""},{"id":4486,"author":"李学勤","title":"由清华简《系年》重释沬司徒疑簋","abstract":"清华简《系年》(清华大学出土文献研究与保护中心编:《清华大学藏战国竹简》第2册,中西书局,2011年)是一部久已佚失的史书,以二十三章的文字篇幅,概述了周朝建立以至战国前期的历史大事,学术价值弥足珍贵。《系年》最前面四章记述西周史事,第四章讲到卫国的初封,说:周成王、周公既迁殷民于洛邑,乃追念夏商之亡由,旁设出宗子,以作周厚屏。乃先建卫叔封于庚(康)丘,以侯殷之余民。卫人自庚(康)丘迁于淇卫。","categories":["06_族氏方国"],"year":2013,"publication":"中国高校社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIP258eqkw3BrieFlp21ToNaOutesE0wYL5ahwbwdRxu1sRe4wppLYxssy0cSNAdYXPkiX15IbB9AyLlIRkx2WJw_m2Dgtabsjzl1HcdcsyO4RdbQ6ZHYP4zm4LcFbrCZ9duMYtkuMDkDz-sXGW51WlgRCDz3xpM7a10AxR0pUAXA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-85","volume":""},{"id":4523,"author":"趙平安","title":"宋公■作■叔子鼎與濫國","abstract":"宋公■作■叔子鼎,■即瀸字,讀爲濫。■是由邾分化出來的小國,此鼎是宋共公爲二女兒出嫁所鑄。鼎的出土地棗莊徐樓村一帶是古書中所說的古濫國的地界。","categories":["06_族氏方国"],"year":2013,"publication":"中华文史论丛","link":"https://link.cnki.net/doi/10.16837/j.cnki.1002-0039.2013.03.003","pages":"31-36, 396","volume":""},{"id":4555,"author":"袁广阔; 马保春; 梁宏刚","title":"“妀善鼎”的年代、国别、地理及相关问题","abstract":"本文从年代、国别和地理等方面探讨了&quot;妀善鼎&quot;的相关问题,我们认为&quot;妀善鼎&quot;可能作于春秋早期,作器者是&quot;晏生之孙&quot;,他应该姓国的姜姓,而受器者为妀姓,所以不可能是父女关系,妀善只能是晏生之孙&quot;孙哀&quot;的妻子或母亲,这是夫为妻或子为母所作之器。该器铭文中&quot;晏生&quot;可能与传世文献的&quot;晏&quot;有关。&quot;会鼎&quot;当是带盖的鼎。","categories":["06_族氏方国"],"year":2013,"publication":"首都师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcqljbjhNVyaF3ESr2WPFzoEMU4TWfKMn27oD3DGHP7Kp_c7wXPvR6a1Mwl_6QFIZsRAoEkpUaO-1UNbLJGGfDJzzCuj9X5CmXP_TAYY1O88Vq3Wq6_j4T8wGcC4s_w5QeXNFjgmcEGXQl7LJlKYz6GDAxDSbbWJBEjyk1ZHYSOw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-40","volume":""},{"id":4564,"author":"王进锋","title":"春秋宗妇鼎与列、■二国","abstract":"春秋宗妇鼎铭文中的&quot;王子&quot;是姓氏;列公意即列国国君;宗妇是指同姓大夫之妻;■馨的称名形式是&quot;父国名+本姓&quot;,指代■国的馨姓女子。宗妇鼎铭文大意是:■馨——她是王子姓的列国国君的同姓大夫之妻——作器保治国。列国和■国过去没有引起学者的注意。对于宗妇鼎铭文的考察,使我们开始关注到这两个侯国。列国位于战国邯郸附近的列人地;■国先位于陕西鄠县,后迁至蜀中的临邛。它们的姓氏分别是王子、馨。","categories":["06_族氏方国"],"year":2013,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnRTOh7PQ8QT8PV2WdbdGfcqEDFXQ7hqh2lepzEJ70hRyb5EoB41vttBiJCgaw4haDynlm4tnrDiYANZ5lBhQbHpsfKs1HfO1LUiexTxOtQuQVnPxrfdfC8kGtbdQb7McNsq2-W8NzO2geJ257SRzYxhGyzx131wvgVaP-gIv0iw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-68","volume":""},{"id":4569,"author":"聂凡; 王安坤","title":"流散海内外的应国铜器","abstract":"1979年12月,河南平顶山市郊北滍村滍阳岭上出土了一件邓公簋,铜簋铭文记载了邓国国君之女适嫁应国的政治联姻事件,平顶山应国墓地因此被发现。据文献记载,应国是周武王的庶子应达所受封的诸侯国,是在周成王时期接受分封的姬姓国之一。据西周铜器铭文记载,西周初期分封的应国国君最初称为应叔,后称为应监,亦称为应侯,还称为应公。或因平顶山应国墓地的大型墓葬被盗的缘故,西周早期的应公铜器自清代以来陆续不断面世,其铭文拓片虽传播较广但相关实物图片或散见于国内外的图书上,或前所未见,终不能窥其全貌。兹将应公诸器搜罗集中在一起予以全面介绍,以供读者赏析。","categories":["06_族氏方国"],"year":2013,"publication":"收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFjEpAdGg-t4fW6GM3aGEe654GfUyQSDo155MGLzKwRX8CfhzmFPzOnsNeoWUv3KgRJRlzCCojyCvxPuRHOQjf6mhUHSXF-T-lgGSTNtWHJPvs9Z4eAB4caEbrG3K6fpbEITOZqnvdAQ5bR3UU7Z_TGQu4A5C8wsZZ2SdD3ZWDzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-93","volume":""},{"id":4595,"author":"王治国; 刘社刚","title":"上阳城M44墓主身份及焦国相关问题考","abstract":"虢国都城上阳城遗址M44墓主身份是众多学者关注研究的对象。有的认为是姬姓焦国人,有的认为是姜姓焦国人,还有人认为是姬姓虢国人。在梳理、分析相关学术观点的基础上,提出了M44墓主&quot;追夷&quot;应该来自姬姓焦国,但不一定是召公之后。","categories":["06_族氏方国"],"year":2013,"publication":"三门峡职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ5gppc190pu-CPzA_SpCvoLf9UAYTVtLViqZ_fVa-4Kc-68EtqrUTBUxA2z6Rtn-gSotFSiSCeh7HWxJFC6q0vV6Zy-A_3iLTs4CXoDdRfmFeBDj3xIwMOMnb8wRWWzyUk6tVGtJ0vjqKzAOSU6YtZ24cZ9sN9YSjplelK3npqxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46308","volume":"12"},{"id":4613,"author":"雍际春","title":"秦公簋及“十又二公”考","abstract":"传世秦人早期青铜器秦公簋,因其铭文涉及秦人早期历史及秦先祖&quot;十又二公&quot;,故确定秦公簋作器者就成为认定&quot;十又二公&quot;的关键。学界现有讨论虽然提出不少观点看法,却均未得正解。通过对铭文信息的深度解读,结合秦人早期历史和天水地区新出土秦人早期青铜器进行综合分析,证明秦公簋和盄和钟俱为秦襄公建国立制时所铸告祭礼器,十二公为中潏至庄公十二位秦君。太公庙秦武公钟、鎛系武公为新都雍城竣工典礼所铸礼器。两组礼器内容相近、用途一致但年代不同,共同成为十六代秦人早期建国辉煌历史进程的标志性见证。","categories":["06_族氏方国"],"year":2013,"publication":"社会科学战线","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiz31LOnZNngM7WbW7GUsVlik4lkQgKS12F9KV7Ea3wuTU5BSdIUiSMokk_6hYM02eu-5tNH7QEpwXc7Eb5Qpm9hEPUCes2QclLUe-8yHKqOr7Uxon3FVG164_YqikxGa3tKNMRt87qlVTdBOCPVbdtzGdMYiqHodihb3VDrBxCw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-121","volume":""},{"id":4623,"author":"徐少华","title":"邓国铜器综考","abstract":"邓国铜器以西周早期至春秋早期的比较多见,其形制、纹饰及铭文均有浓厚的中原文化特色。文献记载中称邓君为&quot;邓侯&quot;,铜器铭文亦显示邓于周初后长期称&quot;公&quot;,可见邓国的地位与实力。楚虽于春秋早期兼并邓国,但并未使其亡国绝祀,而是被降为附庸存于楚境。这一史实,有助于加深对中国上古社会从分封制到郡县制转变过程的认识。","categories":["06_族氏方国"],"year":2013,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPQwZ5EWiRUO2HM7Q1Qay5wj1KsXdmxGuiNt_4n3POovOytr6DhobHWTIk1FnIzZcmyWGY6j9jbM-Zvf8B3GrgdBR1v4gx4RIyDJxhIHY_hoidTkNME2xzZob4rtMuwc2nJO8Ig_o9Qme4vPbtS5MNZDVOiDqudWx7sCvEIn4Zdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-75, 2","volume":""},{"id":4636,"author":"刘树满; 张懋镕","title":"霸国、倗国青铜器整理与研究","abstract":"史书记载的山西周代古国甚多,异姓国族不计,与周室同姓者除晋国之外,尚有虞、霍、杨、韩、魏等。在大河口墓地、横水墓地问世之前,我们并不知道在今天的晋南地区还尚存在霸国、佣国两个如此重要的国家。它们的发现,为霸国、佣国的研究揭开了序幕。霸国、佣国青铜器是宗周文化、北方青铜文化以及地方土著文化相结合的产物,作为中原文化和北方青铜文化交流的纽带,其独特的环境,使我们不可回避地对此进行研究。本文运用考古学的理论方法,在前人研究的基础上,对霸国、佣国青铜器进行搜集、整理,并进行综合、系统地研究,试图全面了解这两个国家的青铜文化面貌。本文从青铜器入手,旨在解决霸国、佣国青铜器的时代特征、发展演变规律以及两国的文化因素、族属、其它地区青铜文化交流与融合情况等几个问题,现将文章内容简单介绍如下：绪论部分对霸国和佣国的历史地理进行简要的介绍,整理、总结霸国和佣国研究现状,并进行了评析；简要说明本文的选题缘由、","categories":["06_族氏方国"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-30EA4mrP5hlO88g9z0Mrd5V1cxyigjFGwHhQw0ILAt0887SNyyYxJQ1t13dr6Zw-3KMHCPY2hW5o58EU9Maz6HBi9m69CeCySa5KXQdR1-zxTPzxzt0RGRl3WSYLKB0y2UoPVo8RupROhWwFwGcnh07Q-E_2iY-rvjVX0ZynWogl6hbwirhc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4641,"author":"范学谦; 王晖","title":"西周殷遗民分布、影响及其同化问题研究","abstract":"先秦时期的战争多以达到“服之而已”为目的,很少会发生灭国绝祀的现象。商周牧野大战使商王朝一夜间灭亡,导致大量殷遗民留在了新政权。而此时周代的整个社会体制刚从方国联盟制向王朝国家转变,无论是人口数量还是生产及文化水平均远远落后于商,周政权如果想要生存和发展就必须依托商王朝遗留下来的大量殷遗民。研究周初殷遗民的迁徙分布及影响等相关问题,不仅可以全面地了解周初殷遗民的发展轨迹,而且能够从整体上把握周初的历史。本文主要结合传世文献、铭文资料和考古发掘成果来研究殷遗民问题。研究有关殷遗民的四个问题,即殷遗民的迁徙分布情况；西周对殷遗民的管理政策；殷遗民的影响及殷周文化间的相互作用以及西周中后期出现殷遗民被周文化所同化的现象。在文章的研究过程中适当地运用了绘制地图及添加表格等形式以期论证更加清晰明了。通过研究我们认为：无论从传世文献还是铭文资料和考古发掘成果中,都向我们展示了殷遗民在周初分布范围相当广","categories":["06_族氏方国"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIYccDCsrnNmfb5uONVLDSsXR07is5TJZMuPSqebil4lc40W1R_uXn6wVqV0X76vwdR7Qdyj7WWk3rlIqbtQTxHa3RP3cF7lqpQ_LU9FLwG-MMRN43ZvX0cvnoTjdslR2-hdyl_xmuYOij6F2MfTia4iZk4X1_XSsLnW9KXvB2WafGuSluuF9RU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4642,"author":"欧阳怡婷; 张懋镕","title":"西周时期曾国青铜器研究","abstract":"曾国是周代南土方国之一,位于今天的南阳盆地、淮河上中游地区。这是-个很特别的国家,西周时期的曾国在文献资料中无明确记载,在考古资料中却出现了大量带有“曾”字铭文的铜器。由于考古资料与文献资料之间未能对应起来,因此曾国给后人留下了许多未解之谜。2011年上半年湖北随州叶家山墓地出土青铜器达325件,特别是铸有“曾侯”及“曾侯谏”铭文的铜器的发现,使曾国青铜器的上限年代上溯至西周早期,为解决“曾国之谜”提供了新的契机。与此同时,叶家山曾国西周墓地的发现,给学术界带来了许多争议和待解之谜,比如叶家山西周墓地的族属问题、叶家山西周墓地中墓葬年代的判断、西周早期曾国的文化性质问题等等。因此本文有必要运用考古学的各种理论方法,在前人研究的基础上,对西周曾国青铜器进行搜集、整理,并进行综合、系统地研究,试图全面了解西周时期曾国青铜文化面貌。本文主要由七个部分构成,择要如下。第一部分综述前辈学者对西周时期","categories":["06_族氏方国"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj-aOSWJNatx_2PWqxzb_pWv0H7JT3vhbDdQZSUUuQH9UEPgyDXKfS514SsIwY8z38srBv5YY8NPryBjLk6PN_olUOHGl8-j5IDUwLIFphuMwzAjFQ6nZspnMHVsnKdxeaeKOxyWSS7CMCjiIqpglFgl3nceZclFwgecPXNpe445eBgw07iALD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4670,"author":"孙敬明","title":"从莒地出土两周十四国金文看莒文化的交流与影响","abstract":"莒文化是齐鲁文化的先声和前导,是中华多元文化体系中深具特色的重要地域文化之一。本组文章对莒文化从多视角进行了较深入的探讨。尹盛平的《莒文化源远流长》一文认为莒文化的直接源头是大汶口文化,在其后发展中与龙山文化、商文化都有密切的关系,认真发掘和研究莒文化,不仅对于认识中华民族大家庭历史、文化的发展史有益,而且对于中华民族的振兴也具有重要的意义。孙敬明《从莒地出土两周十四国金文看莒文化的交流与影响》一文介绍了莒文化区域内出土齐、鲁、诸、莱、郈、曹、陈、徐、吴、越、樊、黄、邛、楚等十四国(族)之有铭铜器,这对探索莒文化交流与影响大有裨益。蔡运章《大汶口陶罍文字及其相关问题》一文认为目前所释大汶口陶罍文字应是大汶口先民祭祀天神时&quot;制器尚象&quot;习俗的产物,可名之为物象文字,这种神秘文字的发现和深入研究,对探讨中国文字起源和形成等问题,都具有重要意义。","categories":["06_族氏方国"],"year":2013,"publication":"山东师范大学学报（人文社会科学版）","link":"https://link.cnki.net/doi/10.16456/j.cnki.1001-5973.2013.02.008","pages":"122-129, 138","volume":"58"},{"id":4707,"author":"王进锋","title":"商周时期的俞国史事考析","abstract":"根据彝器铭文,商周时期有个俞国。参考其他&quot;小臣X&quot;的用例,商代的俞国有军事首领小臣俞。通过考证研究,我们知悉在由三个族氏名号构成的复合氏名&quot;俞舌&quot;中,俞国与族是通婚关系。商周时期的俞国拥有林、类的附属国。上古时期有两个与&quot;俞&quot;有关的地名,分别在今山东夏津县和四川南江及其下游的渠江,商周时期的俞国与夷方、地相近,当位于山东夏津县。西周时期有个西俞国,当即《史记·赵世家》的&quot;西俞&quot;地,它附属于周。从地理分布来看,西俞国和俞国是两个并立国,但二者之间有一定的关系。春秋时期的俞国和鲁国之间有通婚关系,根据同姓不婚的原则,俞国应不是姬姓。","categories":["06_族氏方国"],"year":2013,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2013.01.007","pages":"11-14, 151","volume":"45"},{"id":4714,"author":"金荣权","title":"番国青铜器及其历史地理论考","abstract":"番国,为祝融八姓中己姓的一支,春秋以前在中原北部立国,至春秋前期南迁至淮河上游的信阳市平桥区一带,或称&quot;鄱&quot;、&quot;潘&quot;。后世出土为数较多的番国青铜器,铜器铭文多自称&quot;番君&quot;、&quot;番伯&quot;、&quot;番子&quot;等。番国在春秋时期较早归于楚国,从信阳市的平桥区向东迁移至固始县。公元前504年吴人伐楚,获潘子臣,取番地,番国最终灭亡。番国贵族在春秋中期便入楚王室为官,如潘崇、潘尫、潘党等。尤其是潘崇,在春秋时期楚国历史进程中具有举足轻重的地位。番国文化呈现出中原文化、淮河流域文化与楚文化的融合特征。","categories":["06_族氏方国"],"year":2013,"publication":"信阳师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImdKOvLE1qdu6sRbq-rm3wsNlA5cfaPbEXBKkAhvfhRziKHNebVLC3vtJzIFq-seH9FSFGgPD3GDmLqLBQMHccl_o26QWiGlAjBWIRhKTw1IEOZ_KR8vMdbdCv1fch2QYSwQKZGjMne_pK1oRfcG-vT-Bblbt5mk2Zkfut_aoyVw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-137","volume":"33"},{"id":4715,"author":"于薇","title":"西周封国徙封的文献举证——以宜侯夨簋铭文等四篇文献为中心","abstract":"西周一些重要封国的封地曾经发生过变化,这种变化对西周封国格局和国家的政治进程产生深刻影响。虽然之前已经有学者提醒注意,但一直未能举出文献中对于徙封直接记载的条目,也不清楚文献中是否有关于徙封的直接表述。分析可知,宜侯夨簋、邢侯簋、《诗经·閟宫》、《诗经·崧高》四篇周代文献中&quot;迁侯于宜&quot;、&quot;■邢侯服&quot;、&quot;俾侯于东&quot;、&quot;于邑于谢&quot;就分别是对虞、邢、鲁、申四国徙封的明确记述。这些文献还揭示了西周封国徙封的一些细节和特征。找到了文献例证,未来可以在更稳妥的基础上探索西周封国徙封问题。","categories":["06_族氏方国"],"year":2013,"publication":"中国历史地理论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIrEa4RvMLx0lq-TWGZBgzqZZRgM-b4j_xMF8yducLJPPggIfjuw4q0DUZwdab_MUGsyd3TOeIHV9Rz1APPjgUeJtVVQfd7mzYeX6FRVG2QKrrNEVKl8jKYrjgjpFoH_XEYHZRmYM42BuRnAp2S8H2y03jyhOLuxBkKrIbcx-bLzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-33, 39","volume":"28"},{"id":4734,"author":"赵燕姣; 谢伟峰","title":"仲爯父簋铭与申国迁徙","abstract":"南阳盆地的申国见于仲爯父簋铭,因其地位于王畿以南,故以&quot;南申&quot;冠之,以别于留居陕北西土的本支&quot;西申&quot;,至于信阳一带众多以申命名的地名,或与申亡后申人后裔徙居有关。","categories":["06_族氏方国"],"year":2012,"publication":"中国历史地理论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDhYkYm8mdOmSxcUq9fgkjUDB7hexT345VRH6O8HLi-PEfvoDkdjO7lQXLf7qHdDIhed1tW8DJB8KktZ8o39QHF7j49CGFUNOQdm8LbrW9n-Fr0nkS-bZjp6PQY8l3tV9hIs3ahOEH_of8GSHp30qYKoK4fyP0B0MhcPNvaQpmvA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-46","volume":"27"},{"id":4735,"author":"刘攀峰","title":"金文姓氏制度研究简述","abstract":"人们对金文的研究由来已久,宋人和清人的研究多侧重于字词的考释,而对金文中的姓氏、族谱则没有系统地梳理研究过,仅仅对其中一些姓氏的用字作过一些考证。从20世纪30年代以后,金文的研究进入了一个全新的领域,研究的范围也日益拓宽。1932年郭沫若的《两周金文辞大系》问世,该书将西周金文按时代(王室)、列国金","categories":["06_族氏方国"],"year":2012,"publication":"兰台世界","link":"https://link.cnki.net/doi/10.16565/j.cnki.1006-7744.2012.19.040","pages":"20-21","volume":""},{"id":4738,"author":"朱国伟","title":"句鑃国属新考","abstract":"句鑃是中国先秦时期的一种乐器,它主要流传在南方是学界公认的,但已往学界对句鑃具体的国属或族属多存而不论,或笼统冠之&quot;吴越之器&quot;,这是因为从句鑃的发生情况确实难以确认其所宗归谁。但笔者认为,据现有的句鑃资料及吴越墓葬材料,应大致可确定其为越国乐器,即为&quot;于越&quot;族的本地特色乐器。本文从多个角度及理由试对此论点进行了论证。","categories":["06_族氏方国"],"year":2012,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEcDxExTlOVIjGWIORLkm8m69kYekg2KwdCTqIEaErA0U9o6GYX966zfe3hkcy3ZtE2USPCU7ONirnyxSTcHnEOkomzk5jND41kmpxYE7mIn1fqunyta7MzbETm8jb3crKTJUqEKNL9c5ALhiIiZgGLVosYa4E67I0yAwas53aPg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-80, 208","volume":""},{"id":4767,"author":"刘树满","title":"浅论洼刘西周墓暨“举父丁”鼎","abstract":"本文对郑州市洼刘遗址发掘的一座西周贵族墓及墓中出土的&quot;举父丁&quot;鼎进行了探讨,结合管国的历史状况,对&quot;举父丁&quot;鼎的年代与&quot;举&quot;族进行了分析,推断该墓主人为商代遗民,可能是舌族的成员,且与&quot;举&quot;族有密切联系,这对研究&quot;举&quot;族的历史演变具有重要意义。","categories":["06_族氏方国"],"year":2012,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2012.02.011","pages":"46308","volume":""},{"id":4769,"author":"张丹","title":"薳、(■)、(■)、逺关系考——兼谈楚薳(芳)氏家族发展脉络","abstract":"《左传》等传世文献中记载有大量薳(■)氏家族的信息,南阳浙川发现有■氏家族墓葬,楚简等出土文献中还包含有■氏家族及速氏(学界以为即薳氏)家族的信息。结合传世文献及出土文献,并运用考古出土材料和业已取得的研究成果,对上述几大家族作重新认识和考察,可以发现,春秋时薳(■)氏家族在楚国的地位很显赫,至战国时开始衰败。传世文献可见,薳氏即■氏。薳与■,作为邑是不同的地名,在金文及楚简中,■地即■地。薳与■,作氏称可互通。作氏称时,在金文及楚简中薳另作■;■则另作■(■)、■。","categories":["06_族氏方国"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnPgRAHKysfNFZxWaE0fB04sPlb1bLEvQ4ww5gBHCd-oOPMFWr2bPKd5N1qrtR4kCVHO4O70oqxfmKTGvO8xlS6W5UvFDTVfz65D7QPxkDfTkf1JOp75hxS5iAqw8h_W7P41pnvAPbBFrGgOqemxolV3lUNOpRsAPq6oFnFH4ZwA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-62","volume":""},{"id":4789,"author":"陈颖飞","title":"清华简祭公与西周祭氏","abstract":"清华简《祭公之顾命》所记祭公出自西周时期重要的世族祭氏,本文试从简本《祭公》切入,系统梳理与考辨西周祭氏材料,讨论西周祭氏的若干问题。主要包括:一、祭氏的来源及相关铭文。二、祭公谋父与西周金文中的其他祭氏。三、综合以上论证,排列祭氏世系谱。结果表明,清华简祭氏确系周公之后;第一代祭氏即祭季,官居太史;第二代祭氏有两位祭公,前者与昭王共没于汉水,后者即祭公谋父,他可能是穆王伐东夷某些战争的主帅,对某些东夷氏族进行了战前动员;金文中的祭俗父与伯俗父、师俗父并非同一人。","categories":["06_族氏方国"],"year":2012,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLH2b4PSJbH9s6VpXDeecdTSIMGV4RnkFL9MAD8lQs1fsArbVZ9jHWL7gA9HBpb4iMekinxFewTuNYdv8q8bYr5pI2i6Cw4X4mTvmFoEydV6N9nlMP8RrLftIk2WdtvGPgSEqsKfBkUOhhM2iE-0tpBT-LNqg9ZiAarOfMBOt2SKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-106","volume":""},{"id":4790,"author":"牛鹏涛","title":"清华简《系年》与铜器铭文互证二则","abstract":"新近公布的清华简《系年》,内容涉及&quot;上起西周之初,下到战国前期&quot;的许多重大史事,除可与《春秋》经传、《史记》、《竹书纪年》等相对比外,许多地方还可与青铜器铭文相互参证,给人许多新知。如李学勤先生已撰文重点指出《系年》简文可与大保簋(《殷","categories":["06_族氏方国"],"year":2012,"publication":"深圳大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4RU1XlcS6CdbPRLAUUjZ9MIQ5rJvc9qWn44IcE0W7ZY5VUy3OHZXMd9Ly1KLlEv1_7vw5YgYkYp7adB1wD305vLu3KuzUYNKA1z3RM8s-dZrv4R_XWAqJ36sXkqGMxcm6c5L4jWa2-S9MMDYU8FB7PQOVAdb4a63qq5Xd_5OgCQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-49","volume":"29"},{"id":4808,"author":"吴镇烽","title":"秦子与秦子墓考辨","abstract":"传世有秦子戈、秦子矛等数件青铜兵器,上世纪九十年代甘肃礼县大堡子墓地出土了一批秦子青铜礼器,其时代均属春秋早期,专家们看法基本一致,但秦子是谁,研究者却众说纷纭,各执其词,莫衷一是。我在1985年《金文人名汇编》中就主张秦子是未即位而去世的秦文公长子,死后文公追封其为静公。近几年又有一批大堡子出土的秦子器发表,以及乐器坑的发掘,给我们提供了新的重要的资料,笔者根据这些资料,结合文献进一步论证秦子就是秦静公,同时进而可以确定大堡子2号墓就是静公墓。","categories":["06_族氏方国"],"year":2012,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqvNSTO9QlM1Dm_zLeSLBczXVQ5BUHyBCdWmxrkj3rO0NZdAS236jffPAot4aFuE99E09KN14BmAlosVxdf-WDiGkh1pozHlfekflEycQglKU51OOKThwT2pqWLscLEbOFFM0sNb4awRfM5Wnao9X-_ZFVzvEZpPi_fjFdgQyOtQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-30, 18","volume":""},{"id":4816,"author":"朱继平","title":"金文所见商周逢国相关史实研究","abstract":"20世纪七八十年代,在山东济阳姜集乡刘台子墓地相继发现并发掘了几座西周时期墓葬,发掘者对其年代与族属进行了考订,初步认定该墓地属文献所载姜姓逢国所有。随后,有学者对其中几座墓葬的年代与墓主身份作了进一步讨论,商周逢国的历史问题也不断受到关注。然而,","categories":["06_族氏方国"],"year":2012,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLMtPYpLCSAUJuClEbwaWBzVnVQDhLzPlnbrF5qTBN4iBvy-uSc2ybnw7gwFqpJeALdvBBHSeai5o5Pwo7s9EbLaqrX6yyJkU7RSlTHH_X5gL5Pn1JP5KNJ_QJwV6V2lGRMXfEXdw9fnXFNDKxVoa6JVxaOc-_Sf0JjrtDj3skkcA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-71","volume":""},{"id":4824,"author":"王峰; 李鲁滕","title":"近见■器铭文略考","abstract":"《首阳吉金》刊布的3件■器,应系滕州庄里西89M7散失之器。其中■觯、■簋铭文对于周初分封的滕国史研究具有非常重要的价值。本文对上述二器铭文略作考释,力求廓清作器者■与滕国之关系。","categories":["06_族氏方国"],"year":2012,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1bz_GZuxdnWsiAa3zr9c7YQfjCxBNE-eWoq5RGYbPnb9EH6VWs9OKnuAnzHUbD8xG6wq77S6RMbRIAR2kGWiwZPRWsbHA9V9m7KTt0FWB9vF_5oZbHGKD92PXj66v_uZhczGZKsS-yrVovz-d2-NMdjl31ybCPjognqinPQsEtw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-111","volume":""},{"id":4910,"author":"张卉","title":"■公簋与晋国早期历史问题刍议","abstract":"■公簋的公布对重新认识晋国早期历史问题带来了契机。该器称燮父为&quot;唐伯&quot;,此&quot;伯&quot;不是排行或爵称,而是方伯之&quot;伯&quot;,唐叔虞亦可称&quot;唐伯&quot;,这为唐叔虞和燮父在周初任方伯重职,藩屏周邦,增添了新的证据。此外,■公簋铭并不能证明&quot;唐伯&quot;燮父由&quot;唐&quot;地迁封至&quot;晋&quot;地,&quot;唐&quot;到&quot;晋&quot;只是国号的改变,目前晋国早期都邑的地望还不清楚,迁都之说仍需证明。","categories":["06_族氏方国"],"year":2012,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvl7d2GehOpDIDP3Y6rsjQJH5eaTebYuBTN9EWq90hmTdaH7qdsTxqsMypga5035izv6wPNmcn9xJoXUnwKkWtqgYxuQ8zIQKT2CUm7JdbA15rnKtGDDaJLySiWXxYpVYFpsxNqXi-Gpj3XC85G8PpVcqY7HLI8YdsjlcesL31Og==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-74","volume":""},{"id":4911,"author":"苗利娟","title":"关于商代金文中族名的界定与思考","abstract":"商代金文中出现的族名主要有单一族名和复合族名两类。古代氏族名号有称二字者,或称其为复氏族名。复氏族名与复合族名较难区别。复合族名是在同一器物上铸刻两个或两个以上的单一族名,其出现的原因有多种,或为标识母族,或为某种性质的联合,或为通婚,或为同宗祭祀等等。复合族名中还存在着私名、地名、职官名等成分。","categories":["06_族氏方国"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKl2Csvl9T__fFdDLljpo-MU767BkAa2hoKcdixgTivyLZsDsVtuyKohuBWMhNY0w852zlk4EQHRLwcWePND4OulR1Vc_AaQVNQBIJiYN0sDAepmEZTEuEvzsWcTlB-3dUut_H3e3GA-bAUdzZWRRwi909MWTZywdMlA92F49apOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-66","volume":""},{"id":4926,"author":"郭德维","title":"楚季宝钟之我见","abstract":"枝江出土西周晚期&quot;楚季宝钟&quot;。同辈人中最小者称季,楚季当指楚国君最小的儿子,季循的可能性最大。&quot;乃献于公&quot;,楚武王前,楚的国君称公;孙子称祖父为公公。此器应是熊徇尚未为国君时献于祖父熊延的。","categories":["06_族氏方国"],"year":2012,"publication":"江汉论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUVqhLZp2AUDbNHmUG2p8sm-sZMTG9szr8aNtbqroxOYvmebvCy-eCudUEavDXu23rCP5qEUMqe5zddSdxWR1pCTgovvya_wTwWcEKY4E2UVQobPSKyP1cwvWn26Kek0xAu11QAwhHLcIHoDwEDv1a4b1oUGA-Rg6S-FvcmZHhYA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-119","volume":""},{"id":4927,"author":"胡安莲","title":"应国青铜器及其历史、地理论考","abstract":"周代应国在今天平顶山地区,今天所见传世和新出土的应国有铭青铜器达78件之多,为我们研究应国历史与文化提供了可靠的线索。周武王时曾在商代应国设监国一职,称为应监;成王时灭掉商之应国而在其故地设姬姓应国。故城在今天沙河与彭水交汇处的沙河北岸,即今天平顶山市梁庄之南、白龟山水库以西地区。应国在西周中期以前颇受周王室重视,应侯曾为周王室卿士。它在春秋中期亡于楚。","categories":["06_族氏方国"],"year":2012,"publication":"信阳师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6mEkizHGRLf5C1qEcgFroADYAknnN9KukUj1MAoqxw3HZ3U43RIc48gOtZw7MkMpC4wXJc5kZnEPOgyPYykeaTRpg-vidEoa6CYvs3t5_s9t1uqMnU94iLerN5TgIdP0iP3kCgOv7u4_ph96Qw7j2pbIWzpBMGkk1mEZbBeGgbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-125","volume":"32"},{"id":4950,"author":"李久昌","title":"60年来虢史与虢文化的发现与研究——《虢史与虢文化研究》前言","abstract":"虢国是西周初年的诸侯封国,虢仲、虢叔为周文王的弟弟,他们分别受封为东、西二虢,东虢在今河南荥阳,西虢在今陕西宝鸡东。周平王四年(前776),东虢被郑国所灭。西虢后东迁至今河南三门峡黄河两岸,《汉书》等史籍中称之为北虢、南虢,前655年为晋国所灭。西虢原地有小虢,前687年被秦","categories":["06_族氏方国"],"year":2012,"publication":"三门峡职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCrS73ntVJLbRBZrKJKJ2gTPFHQgKsBqlFpq3ipRpFtsnJfIYvzp8CHTK_U2583oLnF6knPrKSHCdwukGbdL0Y5mXHU8k-POMZt8L-pTNesYlhgN2nEQ3RYBq1UpZkvdn9ClHsoWP32acyauuIm59ESB9zqoOyqwqcviaj0JmxOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"4-12, 14","volume":"11"},{"id":6261,"author":"安普义; 蒋刚","title":"周代曹国考","abstract":"曹国,是周代的一个重要的姬姓诸侯国,屡见于经传,故址在今山东省菏泽市定陶县附近,始封于西周初期,国土较小,地处中原,国力较弱,春秋末期被宋国所灭。而对于曹国相关历史,还没有较为系统和全面的研究结果。刘雨先生通过对近年出土的曹国青铜器铭文的分析研究,详细地考证了铭文所见的周代曹国国君的世系。徐向东先生通过历史文献和方志的分析和实地考察,在《菏泽以“曹”名地考》一文中,阐述了周代曹国的历史渊源问题。文章主要采用考古学材料以及历史文献资料相结合的方法,并借鉴已有的研究成果,较为系统地考证和论述了周代曹国的族姓、爵位、都城地望、国君世系、历史进程、疆域及其与周王室的关系等基本历史问题。通过考证和研究,文章的研究结论主要有:周代曹国始封之君为武王之弟—叔振铎,是为姬姓国;国君爵位至少初封时为侯爵;认为曹国初封在今河南滑县南白马城,周公东征以后,又东徙至定陶县西北四里左右;对世系的研究结论,在《史记》","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSKI-KdPQpApkTvpQ1g8E2oJFmnJveVJxUr2FPAbqGh2DSGCwt7UH2iiMu5XzSMHwsjjadJhfelKxPD1fA-sh085ccOUOhrI8GQm2RUasJ1AT0PAaQ1TTkpscKmoThvKiFf70-6NK_D59h2QBW5oXBda4sfWNjv7Rr97qRyDMfbsofKRSfsIgb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6263,"author":"丁军伟; 叶正渤","title":"毛国铜器铭文汇释","abstract":"毛国是周代的封国，其始封君为文王之子毛叔郑。毛国公族世代为官，为周王朝的发展稳定做出了很大的贡献。毛国虽为周王朝重要的封国，但春秋战国时期随着周王室的衰微，毛国亦衰落，公元前516年毛伯奔楚，标志着毛国灭亡。随着毛国的灭亡，毛国在历史文献中也渐渐销声匿迹。从宋代开始，已经有毛国青铜器出土，其后不断有毛国青铜器出土，尤为引人瞩目的当属道光末年出土于陕西岐山县的毛公鼎。自从毛国铜器出土以来，学者不断对其进行研究，解决了与毛国有关的许多学术问题。对于出土的毛国铜器铭文研究来说，以往很多学者只是就单篇铭文字词以及铜器所属时代作了研究，很少有人对出土的毛国青铜器作全面系统的整理。基于此，本文对出土毛国铜器进行了全面的整理，并根据整理出的资料结合传世文献对毛国史进行了有益的探讨。本文主要包括三部分：第一部分为绪论，主要就本文的选题意义、研究方法及目前毛国史研究现状等方面作了概说，使学者对目前出土毛国铜","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTYOm_eAvSTYToNQWaA69zs7B2lOd8jIK7nfyRtQDnxkGs2Uxc6gKLp1_0BRfL0FzhyPOk1OsEWd9nhB19nvaPLqF0oHK1BPgwTPWaxH0y4ahTMdzi0hpzIUaDRL2x5kgaosLbelZoYcZSwV9aTpcu7aN23as9nH4Bb6srTAslX6F1wNPG8pps&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6281,"author":"张丹; 罗运环","title":"南襄盆地出土两周时期铭文研究","abstract":"南襄盆地在西周时期是周朝的南土所在，有申、吕、蓼、养、鄀等方国。至春秋早期，这一地区开始完全为楚国所据有，并作为腹心地带由楚国经营了近四个世纪。对南襄盆地所出土的两周时期铭文进行整体性综合研究，以探讨这段时期的相关历史，具有非常重要的学术意义。本文分上下两编。上编共分六章，是就南襄盆地所出土两周铭文进行分期集释。以时代为纲，将同一时期的铭文归结在一起，依时代先后顺序分为六期。因南襄盆地的铭文最早见于西周晚期，所以西周晚期单独作一期。春秋时期、战国时期都可分为早、中、晚三期；但因为战国时期出土铭文不多，所以将战国中期和战国晚期的铭文合为一期。总的分期如下：西周晚期；春秋早期；春秋中期；春秋晚期；战国早期；战国中、晚期。在集释中，对铭文中的一些疑难字进行解读；并对铭文中涉及到的一些存在争议的历史人物的身份及时代，进行了重新定位。如：下寺出土铭文中，关于倗之氏称，有三种写法：、、。有学者以为，当","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhy8DR5AWSyFg9oh0oK__fJEYyoAA81RgGymopUDeDJYbz7-Ti0y2BpY_abmSdULcwSs6jNGoa7PcMYhJs9peYgOAtL94ZzSyRE4e5HNgmPaM0IgmvHpCLBQGOlGeBtp2qaGbjVVWyrODJFee1OoBA-r8MI7DOscj5OEw1vgz6JsZmmdoea8zB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6295,"author":"詹金明; 胡长春","title":"豫南地區出土商周方国铜器铭文研究","abstract":"中原文化自古以来源远流长，独具魅力，位於河南南部的豫南文化更是别树一帜。这里出土了大量文物，尤其是青铜器铭文等考古材料，为我们考证古代历史文化提供了丰富的史料。本论文在总结前辈学者研究成果的基础上，利用古文字学、文献学及历史地理学等相关学科知识，结合先秦传世典籍记载，对豫南地区古代方国的历史进行整理与研究。本文力图详尽搜集从建国至今河南省南阳市、驻马店市、信阳市辖区内科学发掘出土的文物考古资料，以及关於各个方国古城遗址的考古发掘报告和调查材料，并结合相关的文献记载、地方志等基本史料，探讨商周时期豫南地区各方国典籍记载缺失的古史真貌。本论文共分为五个部份论述。第一部分，绪论。阐释论文研究的时问与空间范围，豫南地区出土商周时期方国青铜器概况，研究现状，以及研究的目的和方法及意义。第二部分，豫南地区方国青铜器铭文研究。尽可能详尽的搜集所有这一地区科学发掘出土的青铜器，分国别类，然後对铜器铭文进行","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIe_OqcPJj-HNd9nhQARvjgkTbDjBQHEkz28JVtDEZBA8MM-MTp47a6pU-912wwZ3bS1Tg3cGe-2MpvJ1ePpimczdGu3lGOeB5mye97_yqwon75IhuIlNlpzPyFJX8Anc4tICqVGix8qGTjrleEFi23hptcjOJRMFfWLLnmWmWwoUr0Sm1x9wo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6297,"author":"乔鑫; 王晖","title":"从出土资料看秦的文明化进程","abstract":"秦文明作为我国古代文明的主体组成部分之一,对我国传统文化的形成产生了重要影响,并奠定了中央集权政治制度的基础。然而,长期以来人们对秦人的民族属性和文明程度存在着误解,视秦人为“戎狄”。西周初年到战国中叶商鞅变法期间的秦文明研究往往囿于“秦人落后论”的怪圈,这主要是因为秦人偏居西部一隅,受戎狄习俗文化浸染、影响,不用华夏礼仪习俗制度所致。本文以新出考古资料为依托,结合前人著述和《左传》、《史记》及《国语》等文献资料,对秦人从西迁陇右到进军关中,再到最后崛起于我国西部的奋斗历程做一分析和探讨,以求进一步弄清秦人早期文明的发展演变历程,更好地认识秦文明的历史地位。全文分为六个部分：第一章,绪论。简要阐述了选题缘由、研究综述、研究目的和方法及创新之处四个方面。文章在前人的基础上对有关秦人的考古资料进行了全面的搜集和整理,并以此为基础作了详实、系统的研究探讨。第二章,秦人传说历史探索。本章详细分析和","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXPOtJG9k2tUKP5kybZPjL-lN0r8kxB1uQVxPGmvJkVCbRaXNyniwadZVrfQ6wAFHufAwsc11fd5-qCEa87cAiGgprFqPZKqBKd8I2sdS-l2Is-p978-AT2SNSojBa8zlEBQboFFTUi-WchJSpYmkFkAVvUXsixB_QzSivHtrhjrfH0txef0_V&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6302,"author":"劉新民; 喻遂生","title":"甲骨刻辭羌人暨相關族群研究","abstract":"羌人是我國古老的族群之一,羌人與其他族群的互勤、交融,促進了中國古代社會的發展和燮遷。在中華上古文明的形成發展遇程中,羌人是不可忽视的一支重要力量。羌人的問题比较複雜,儘管學界已經封其造行了很多探索和研究,但是封羌人的認識和了解至今仍然比较模糊。殷商甲骨刻辞是我们所能見到的最早的成系统的可靠文献材料,這一批材料數量鹿大,富中有很多舆羌人有阴的刻辞,为我们系统地認識羌人提供了寶貴的参考资料和重要依據。封殷商甲骨刻醉中的羌人资料進行系统的整理研究,既有助於我們系统地認識殷商時期的羌人,也有助於驗證、修正學界以往封羌人的推测和模糊韶識,使我们封殷商時羌人的認識更加清晰化、條理化,促使我們在现有條件下最大限度地追根溯源,從而更清晰地梳理出羌人的燮遷、發展,促造封上古文明的了解。全文分四部分：绪論部分,闡述了選题缘由舆選题意義,回麒了已往的研究成果,分析了研究的不足之處和尚待研究的地方,提出了自己的","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfDuVJXDf7VlhJmu7MeWUifKJgorRTCFOtpRRRA5t-QitiFTVb5B7cWPd-6qQBvIgrjG54zqG8Zq4oFf_Xyh_O76daCL9Sbsp9n3A_UFyiaZHhs6zynWUxPkWesINQ5xaIvw1eu-xKr2l3KQZZsdn1sIR4mpUlJksvfz8n7qOxsC_P8M-JMMwv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6316,"author":"张志鹏; 朱凤瀚","title":"吴越史新探","abstract":"笔者综合利用传世文献、出土文献和考古资料，并充分吸收相关的最新研究成果，对吴越两国的若干重大疑难问题进行了深入研究。在讨论的过程中，首先对有关吴、越两国的传世和出土文献以及考古资料进行全面收集与详细整理分析，去伪存真，力求研究资料的真实可靠。全文由吴史新探、越史新探、吴越关系研究三编构成。上编吴史新探首先讨论太伯之吴和苏南吴国的关系，就太伯之吴的地望、苏南吴国之姓以及太伯出奔的原因和路线等进行了考辩和探讨。我们认为太伯、仲雍为避祸出奔所建之吴国为苏南吴国的传统认识是可靠的，此吴之最初地望在今江苏南京江宁和安徽当涂县交界处的横山一带。吴王世系及称谓在学界的研究中一直纠葛不清。历代吴王的称谓常常表现为一人多称，笔者认为这种一人多称实为名、字、号之别，并对数位吴王（如寿梦、诸樊、余祭、僚、阖闾）的名、字、号作了考证。此外，对历代吴王之间的承继关系和数代吴王的在位年代中存在的一些问题进行了澄清。关","categories":["06_族氏方国"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL4kYt8WR34Pa_rtZWk20uXX3hVWtgwTYm0bruCpgmZfgpKeAvDWVPixoLYnBOPBCBQEyDs3gozyoW9AQ-VTK-imaNXCLgxNLvdY2Bwo--Ak7RBFuZSit1v19DMDTE0NeAAcB31pskigz5bircW-AwmNHm_xplArfkoGGflOyka2roooqArEF6v&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6582,"author":"冯峰","title":"枣庄东江墓地出土金文人名三题","abstract":"本文主要讨论了枣庄东江小邾墓地出土金文三个与人名相关的问题,包括霝父君的性质和霝父(丘)的地望,邾君、霝父君、(?)君所显示的淮河流域诸邦的称谓传统,滕侯(?)之文考滕仲的身份及所反映的君位承继关系。","categories":["06_族氏方国"],"year":2012,"publication":"齐鲁文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI952OPbQUN40RqkPpPamSO-XOLfmCxVlpN1Do2H3Wg3iVSHQw8HETGcOGLfia2QmkejdgS0yBZOSELviARwBpGUswIe6sq0ei5AgzVjhm0ei9Wdek6QEdnlJB_qllK5Und8Ys0umVw7WgbQ1_vBtmnX8QDuGvapYjgfj_6H-2zHw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-55","volume":""},{"id":6598,"author":"王进锋","title":"金文所见商周时期的臣辰史官世家","abstract":"商周时期大约有二三十件带&quot;臣辰&quot;铭文的铜器。之前学者的研究对于臣辰铜器铭文背后的历史考察有限。①实际上,臣辰铜器铭文蕴含着丰富的历史信息,非常值得研究。本文将在前贤研究的基础上考察臣辰铜器铭文所反映的历史。一、臣辰与商周之际的臣辰家族臣辰铜器数量众多,为讨论方便计,我们可以先看下列一组铭文:","categories":["06_族氏方国"],"year":2012,"publication":"文化复兴：人文学科的前沿思考——上海市社会科学界第十届学术年会文集（2012年度）哲学·历史·文学学科卷","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLlNtKrI9pOwDExv0mMptw75Jhs7O5Dc4IOMYCFl28mn_c6btU7sDXSfHac8ojnGsL8eGUhqf5bGszodZN2JKX5fKfqNR6eFoGiRLfyMq4pvm8Pm4kEGiywdoXP1OWCmvSH7fzfTA12om-qMbwrN-nGtzaohabcsZ7q1oVUySQ8O666DNsXlggc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"214-217","volume":""},{"id":6609,"author":"秦潼","title":"金玉璀璨忆华年——陕西韩城出土芮国文物暨周代封国考古学研究国际学术研讨会","abstract":"为了庆祝上海博物馆建馆60周年,陕西省考古研究院和上海博物馆共同举办了&quot;金玉华年——陕西韩城出土周代芮国文物珍品展&quot;。在展览闭幕之际,作为整个展览活动的组成部分,&quot;陕西韩城出土芮国文物暨周代封国考古学研究国际学术研讨会&quot;于2012年8月13—15日在上海博物馆的学术报告厅召开。来自国内外的专家、学者90多人参加了会议,部分文博单位","categories":["06_族氏方国"],"year":2012,"publication":"上海文博论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdY06YHe58T1Vtt8evp_WUjP5ltbV2lKJXV7mGto5cQWxkA06JYTShQiT4PQtRl0XsV61LaDDVodwpJf5-I3famvVjR_GPq3pYEYkXuBCZfjfmJCWeqjd4N66lkgpYNwqcPQ-c3Q2HA0W-9QW8ilVVPllnxNO5QTSLASUub6AUKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"8-17, 4","volume":""},{"id":6625,"author":"史党社","title":"西周金文中的“秦夷”问题","abstract":"&quot;秦夷&quot;一词出现于传世师酉簋以及1959年发现于陕西蓝田的询簋和新公布的师酉盘铭文中。对于&quot;秦夷&quot;的身份和族属,已经讨论了大半个世纪。本文对此问题的研究历程做了回顾和述评,并倾向于否定&quot;秦夷&quot;和秦人的关系,对于相关的&quot;戍秦人&quot;等问题,也提出了自己的看法。","categories":["06_族氏方国"],"year":2012,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3ZkkI7MIMMyboKAnHuHT5YrKavPWN5nfUlg8i1Gc873SEaDYj09LeqjrK1mehmSiBHWuqFVv-gWwxVX4nhHAPicz4V6IAHTdHJjZZsw5ap-5Z54Fj-ntk13bm-2ui_UVFJg-PGyt3xDN1eS7ZJmlRB98jLs8a8mIncPCVB2FK_w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"239-267","volume":""},{"id":6629,"author":"风仪诚","title":"安阳商代墓葬中的“族徽”","abstract":"一、前言金文除了一直是古文字学者的研究对象以外,还常被历史学家和考古学家在其研究中所利用。本人近年来的主要研究方向是希望依靠考古信息来进一步研究青铜器铭文。我认为,这些信息对于了解内容简略的商代铭文,特别是&quot;族徽&quot;,有很重要的意义。在此我们就以安阳出土的族徽为例子。1.近几年来研究概况族徽的研究已经有很长的历史,发表的学术论文也很多。2007年张懋镕先生在《新史学》","categories":["06_族氏方国"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxES1kN1Q4DSIeYK7nrqdK3yNb65vFQx6sgrFr9-Mqg8PW69F0JplUigcTgWai3znTn9Kd_wzcrxwCcqNxXinMOtixJZrtdXcoycPmQ9o2Zfo-zoG-j6iYby7r8rReafWSnrV6QsYKP0va5IMBfsFW5RUfNo0zWIBRGjG4FEYqBg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"213-236","volume":""},{"id":6630,"author":"严志斌","title":"商金文中所见的诸子共同作器现象","abstract":"考古发现,商代存在大量的诸子。董作宾、胡厚宣、岛邦男、孟世凯、张秉权、饶宗颐、宋镇豪等先生都对商代甲骨刻辞或金文中的子某作过统计分析,据《甲骨学一百年》统计:甲骨文中有称&quot;子某&quot;者124位,称&quot;某子&quot;者31位,称&quot;某子某&quot;者5位。共160位①。这大体上反映了甲骨文中子某的大概。笔者核对甲骨,发现还可补充2例,在新出的花东甲骨中还见有3例。如此,在甲骨刻辞中可能有子某126位;某子30位（其中7位可能与子某重）;某子某5位","categories":["06_族氏方国"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDU0JfAbpf-SZb0GEN5cxpx-u2TmBgswHltIK7TwM4HgI_y8tUTbhDajvT6Q-1vCD_voQT7PEsBgEqFf1jofLIDd2M7RDROKRsQ7EK3wlQpQXwN6rfPgyujWi9MZWGtSsPeGmlCku3kVFM4UnF5SRKG3Q5_N9uU7DCm0zlONL9vA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"248-258","volume":""},{"id":6662,"author":"孙敬明","title":"商周吉金与纪史新谭","abstract":"商周都城位于今山东寿光境内纪国之史,最早见司马迁《史记·齐太公世家》,载周室所封齐国之第五世国君因&quot;纪侯谮之周,周烹哀公&quot;,文献所记与后世作注者以为事在周夷或懿王之时;《春秋》、《左传》所记纪国之事则始于春秋早期,旋即纪国因齐国侵倡而&quot;大去其国&quot;,后则不知所踪。迄清乾隆年间寿光西周晚至春秋早期纪国都城纪台下出土著名的纪侯钟,民国《寿光县志》载钟初属益都举人李廓,继为诸城金石","categories":["06_族氏方国"],"year":2012,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjNViDVYWBLUF-wWLAMhvkFTCFzVboKdGWb9VRPQhaJOW8TxSWVAa29frwDUWiwMK1QORtbuEPUQYcqWYDaaUkWiRtfqokaT8da6icRRSQbaDL_wum219_MqYQ416kZh_30kaSUE31Db4RKOnRt1zVVgc69851soO2HP5nIWaxRQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"243-259","volume":""},{"id":4834,"author":"陳穎飛","title":"清華簡井利與西周井氏之井公、井侯、井伯","abstract":"井氏是西周時期最重要的世族之一。由於史料的局限等原因,長期以來,對於整個井氏的瞭解比較模糊。二十世紀八十年代,井叔墓地的發掘極大地推動了對井氏的研究。近年來,清華簡《祭公》、■簋等新材料的發現,為井氏研究的深入推進提供了條件。清華簡《祭公》所記周穆王的三公之一井公,即井利,位列畢公之後。傳世文獻中,西周井氏的材料較少,“井公”、“井利”、“邢侯”見于《穆天子傳》等文獻;而西周金","categories":["06_族氏方国"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIItQx4Dk7P-7r7XsFZ6V_Me4GkZPsEVpGhUveVuNk-kV4oANe3yUTu8sS9IOqsA79uRpYCBGQUxKdWt6qUxJ2S1MbDekW4ZkcpfWn4xW47N02o8axk51jvKWc2PPiJeQiHVJeSWYre6RmSqL2IwKZVn6BFye28z5pqX_o8tLdI33Q2-Jve7rdl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-54","volume":""},{"id":4976,"author":"曹锦炎","title":"“曾”、“随”二国的证据——论新发现的随仲嬭加鼎","abstract":"新见的一件楚王所作嫁女儿的&quot;媵器&quot;青铜鼎,器主名&quot;隓仲嬭加&quot;,表明夫家是&quot;隓&quot;。&quot;隓&quot;国即汉东之&quot;随&quot;国,随仲嬭加鼎的发现,证明&quot;曾&quot;即是&quot;曾&quot;,&quot;随&quot;即是&quot;随&quot;,并非一国二名。","categories":["06_族氏方国"],"year":2011,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxLVS1MSkiL5k3F-FIGktR6Gk4kK-q6VQ-jVsvPTAkL7RYmeFSq9_OpPEP5DhRfWG8H_sSLYryImx384K0mWq5CIEV4aCrMuMuwBHYBF1qLogcFPKj8_0dbi1bKC4zh016C0Xoq_SU_xYe4h5_GmffTO6pXNN2IJJtp64UCLOceQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-70","volume":""},{"id":4979,"author":"王进锋","title":"亚旨铜器、苏埠屯一号墓与小臣旨","abstract":"传世和出土器物中有&quot;亚醜&quot;铭的铜器,学术界一般认为是醜族的文化遗存。这从考古上也得到了验证。殷商时期的醜族应是旨族。甲骨卜辞中&quot;小臣旨&quot;的得名与旨族有关。从卜辞内容看,小臣旨是实力很雄厚的军事首领,应当就是旨族之长。山东青州苏埠屯一号墓墓主人的身份、所处时代与甲骨卜辞中的小臣旨相当,其可能就是小臣旨。","categories":["06_族氏方国"],"year":2011,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsefPtDjfZ5JPcGROh6g7j00XQ_8HKC_QfZW6MRiwHaW353W5EbwCFd4hXsQ8y8BRH1LbN6zGf9dp3gmMf5zRkmTSwvfqljS4Lz_18c76_j-hiq1pmnEDEr8ZLo85MzyQp9Vh8BsoWWD-hlhrTONtC3Neaz-vdcJnwYpOOxkN3OA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-71","volume":""},{"id":4983,"author":"吕茂东","title":"解读高青县陈庄西周遗址","abstract":"高青陈庄西周遗址是2009年全国十大考古新发现之一,铜器铭文所载的&quot;豐&quot;,是殷末东扩建立的子姓&quot;豐国&quot;,&quot;文祖甲齐公&quot;是周初僭号称王的&quot;豐王&quot;,城址、祭坛是其天坛。豐王被周公征伐,从而臣服于齐,称为&quot;齐公&quot;。卜骨的数字符号是《周易》六十四卦中的《艮》和《噬嗑》,是&quot;豐&quot;归齐所遵的天意。两座甲子形的大墓,是齐国公族的墓葬。引簋铭文中的&quot;幽公&quot;名&quot;庮&quot;,食采于薄姑,是乙公得之子,胡公静之父,作器者引之祖父,哀公不辰之叔父。周夷王&quot;烹哀立胡&quot;是&quot;夺位&quot;之争,与纪侯的策动和豐族的&quot;天坛&quot;有关。引簋与史密簋可谓是&quot;姊妹篇&quot;,记载的都是周夷王&quot;烹哀立胡&q","categories":["06_族氏方国"],"year":2011,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2011.04.025","pages":"110-118","volume":""},{"id":4992,"author":"雍际春","title":"■族新考","abstract":"■及■族在已知的甲骨文、金文资料中都有较多记载。在■、■、■、■、■诸字中,为本字,其余俱为之衍生和派生字;而为畢之本字,义即田网,也就是&quot;形小而柄长&quot;的捕鸟兽之网。读毕,亦读禽,又通费,以及衍生字俱为捕鸟兽之义。及族既是商代一个部族方国,也是拥有爵封的诸侯世官,曾广泛参与商王之出使、征伐、祭祀、狩猎、巡查、垦田和纳贡等活动,其足迹涉及黄河中下游和淮河流域广大地区。及族作为一个善于捕鸟兽的部族,其事迹与活动与秦人早期先祖多有契合。这为我们了解秦人起源与西迁,秦人在商代的历史概况,提供了新的重要线索。","categories":["06_族氏方国"],"year":2011,"publication":"陕西师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLlvQyFOtS6cdllgd7EW1uuT5YKV_80FRXdCCA1Psa7mp5lK1tbjAZsU8Lwtf-lDMaTK1z6J7R0Iwa6z5FBkSWDNQOpoJIlpavNSQrpMdfMiKsGKckCA7T9kp_UiJOZSTFDslzmX6hh1hm4UM4NTCg5jvfnFC2xfkJ7LNS26Qf-8Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-105","volume":"40"},{"id":5004,"author":"田成方","title":"鄝子妆戈的年代、国别及相关问题","abstract":"淅川下寺M36出土的一柄铜戈上,刻有&quot;鄝子妆之用&quot;5字铭文[1],对于研究古代蓼国的历史与文化有重要价值。关于这件戈的年代、族属,目前还存在较多分歧。本文在以往研究的基础之上,结合相关文献记载和出土材料,主要讨论鄝子妆戈的年代和族属。","categories":["06_族氏方国"],"year":2011,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIR3tInR06Oy41MxZHy4enk826LNbtOSk1cua8qmgVIL-MKBOdLJ0NKncWMPVVD-stytoOpc6fIb6vUxwurx2eF-7A-qUUXRjeXDebl9OUbyHWamr2d6rTiX6XUh8-6hupsylyCpKPp96-HWMA19l7tPwnAiLLfXEOXqluoOxuFog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-99","volume":""},{"id":5014,"author":"李清丽; 乔红伟","title":"从金文看虢国女贵族的称谓","abstract":"先秦时期的姓氏制度及名字称谓与后世有很大区别。通常男称氏,女称姓。通过研究与虢国女性贵族称谓有关的铭文,总结出虢国女性贵族称谓形式可以分成两种情况:一是妇女自称;二是他称,包括父母称呼女儿、丈夫称呼妻子和其他形式等三种情况。","categories":["06_族氏方国"],"year":2011,"publication":"三门峡职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQqQwcQDxpZTxbGIZVO2Rzr5qC7Lo9ZPIjmLQ8z-5HmhdLAnAWCAhUaxyF9JuaXQyISfSwFiY2OkXtkbpFKl8QeISKUiLJYMHOR6msIzURLZFpyjouJ0JnlCNJU86dxzgo3Y9v8wrNVymAtB8wNaxI1NRiYIFfsZiH5JvyIfPJVw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-60","volume":"10"},{"id":5017,"author":"朱华东","title":"钟离国历史与文化的考古学观察","abstract":"近年来有关钟离国的考古发现证实了春秋时期钟离国的存在,从中可解析出大量相关历史文化信息,弥补了文献的不足。从钟离国遗迹、遗物出发,结合文献材料,说明春秋钟离国可能为楚之封邑,在金文中可考世系仅有五代。钟离国埋葬方式另辟蹊径,殉葬风俗根深蒂固,用土颜色意味深远,文化上深受阴阳五行观影响。其文化表明该支钟离国族可能源自东夷地区。","categories":["06_族氏方国"],"year":2011,"publication":"安徽史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIAVaEeD7vHQlBEqhXbcipG_Yqj82Gt1P5SqnTGPKAVt90Rqdj4Umk08cShuYC3QJRNK0abXnIlgLhxSdF5i7z5bR39JSer4LqPB8awiFylnCatKDrm4yRqImm-DMXCWqM9bklOn1HLRE7JEr1-N6d00rhzl3XBZobE6ufae1g_Pg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-122","volume":""},{"id":5018,"author":"周书灿","title":"由姬姜姓族论及“周人尊夏”说","abstract":"文献与考古资料透露的信息表明,夏、周二族与传说中炎帝神农氏、黄帝轩辕氏之间有着一定的渊源关系。夏、周二族出于传说中的炎、黄二帝,包含着不少后人的&quot;缘饰&quot;与真实的史实。随着时间的推移与民族融合的扩大,各种大量的后起的传说与真实的史实逐渐被后人&quot;认定&quot;为真实的&quot;信史&quot;,在上古传说与真实信史真赝混杂的背景下,夏、周二族与炎黄二族之间的渊源关系逐渐得到周族认同,并日渐成为&quot;周人尊夏&quot;观念的文化与历史基础。","categories":["06_族氏方国"],"year":2011,"publication":"人文杂志","link":"https://link.cnki.net/doi/10.15895/j.cnki.rwzz.2011.05.006","pages":"135-140","volume":""},{"id":5024,"author":"严志斌","title":"楚王(今頁)探讨","abstract":"一楚系铜器中,有关楚王(今頁)的讨论曾是学界的一个热点问题。楚王(今頁)先前仅见于楚王(今頁)钟。此钟为钮钟,螺形枚,篆间与钮上饰斜角对夔纹,鼓部饰象鼻对夔纹。正面证间、","categories":["06_族氏方国"],"year":2011,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLa01k91TEaJSbKgwOg5AePHd2Y9Z6bjxx5YOTR21lqU4xwIk0MiPm_K4ysAdZIm_2kHgBs6XlyG2FkWQVeP8i-N5r2y6iq_V6H_8VsxGJEBcizDKu38kFHGCV68JO8dYYlIp0Ki1SvmWlAM3WB4u2uk2pKIONKj9krCfbvzQ7ZAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-96","volume":""},{"id":5038,"author":"张志鹏","title":"滕国新考","abstract":"滕国为周文王第十四子叔绣的封国。叔绣初采错地,武王克商之后,被封于今河南卫辉,建立滕国。成康之际,滕迁封于今山东滕州。滕初亡于越,后乘越乱复国,然终亡于宋。从始封到初亡于越,滕国历三十一世。滕复国至终亡于宋,期间仅有滕考公、滕元公父子二世见载。","categories":["06_族氏方国"],"year":2011,"publication":"河南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15991/j.cnki.411028.2011.04.006","pages":"75-81","volume":"51"},{"id":5046,"author":"张俊成","title":"■公簋与商周■族及其称谓问题","abstract":"■公簋及其铭文对研究晋国早期历史具有重要参考价值。文章认为■公所属族是作为殷商遗民而随唐叔虞封唐迁徙而来,并随晋侯燮夫迁徙于晋。族为商代重要族氏之一,与商王朝联系紧密,其地望近于戈族地望,在陕西泾阳附近。■公簋中的唐伯和■公均非爵称。","categories":["06_族氏方国"],"year":2011,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2011.02.005","pages":"130-133","volume":""},{"id":5051,"author":"陈立柱; 阚绪杭","title":"钟离国史稽考","abstract":"钟离古国,文献有记载但仅只言片语,不成系统。近来钟离国君墓的发现使人们对于钟离国史产生浓厚兴趣。本文将文献记载与考古资料相结合,对钟离国缘起、地望、氏出及其春秋时期的有关史事进行辨正考察、综合研究,提出钟离古国灭亡不晚于春秋中期、钟离君柏墓葬可能要早到春秋中前期的新认识,并就《左传》和《史记》中几处有关钟离地望的记载,重新做了推定。","categories":["06_族氏方国"],"year":2011,"publication":"武汉科技大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIx1B2sVQhgGiqGwwfsjMEswe1b_VXwU091rPmnBFjTBKEVA1sSOs_NewpI5w4C-4sjNgjoimJfwSaZbVxHukOt7l-ed7eHlrsCP6bmTtpNDuk5YgP9HV6sLcnplBvHR2hwjM_m11Kvz5o4VkdsFrkE3f6Si7jfRCxRNaL4J3AMrQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"274-282","volume":"13"},{"id":5056,"author":"王树明; 张光明","title":"山东省桓台县史家商代箕()国都址东夷旧部薄姑说","abstract":"本文根据桓台史家殷商文化遗址与高青陈庄发现周公东征设防薄姑的相对距离,位置及其遗物、遗迹有关情况推断,所谓桓台史家商代文化遗址,是周公东征设防陈庄一带,以继续威慑、监理东夷旧部中的主要敌对势力&quot;薄姑&quot;国的一个都址。又根据桓台史家发现族姓徽文方面的资料,并证以文献资料、金文资料推定,有商一代居住在桓台史家的&quot;薄姑&quot;国一族的本名,是一个与商代王室通婚、关系至为密切,为现代学者称其为亚其或箕()的一族。至于亚其或箕()的族,所以又有&quot;薄姑&quot;即矢镞&quot;僕姑&quot;一名,原因在于亚其或箕()先民,以箭神、射神夷羿为宗神,有崇武、尚箭之风,或因此族有崇拜矢镞、弓箭类射具为神灵的习惯,也或因其与敌交锋临阵,有披挂矢镞、弓箭类射具的风习,故而得此别名、混称。","categories":["06_族氏方国"],"year":2011,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2011.02.026","pages":"121-128, 131","volume":""},{"id":5066,"author":"黄国辉","title":"江陵“北子”器所见人物关系及宗法史实","abstract":"1961年,翏湖北江陵万城西周早期墓葬出土了17件铜器,其中有铭文者共7件,①作:翏作北子乍簋,用遗(馈)②厥祖父日乙,其万年子子孙孙永宝。(《翏簋》,《集成》③03993)","categories":["06_族氏方国"],"year":2011,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgWYu4OX9hrD6zb2RmIMyEJ35zEGaqB5LSMlH4NxOAGitHa4VehDwgzjr4xz-FoQvQIMXSOe-0pO3_WJFezSr5KK1gEpRc9lqxDzDyfdqRUgG3KYfd0Z601G8mbySwnUqLVFYji_VHV77jVSna5OcqBkEbuuDILvdc0UqabCkp6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"173-178","volume":""},{"id":5072,"author":"傅山泉","title":"“妇(女桌)”组器考","abstract":"20世纪50年代在新乡辉县出土的一批带有&quot;妇(女桌)&quot;铭文的青铜组器,是一组商代贵族使用过的青铜礼器。其铸造之精、形制之美、纹饰之华丽令世人赞叹。文章通过比照、研究,尤其是对该组青铜礼器器物上铭文的考证和分析,试图揭示&quot;妇(女桌)&quot;组器使用者的身份、时间和地位,印证在商代晚期辉县一带&quot;妇(女桌)&quot;一支贵族的活动范围,以及他们同殷商王朝贵族们密不可分的血缘关系。这一支被封在商王京畿一带活动的贵族群体,对维护京都的安定以及王朝的政治稳定起到了较大的作用。","categories":["06_族氏方国"],"year":2011,"publication":"新乡学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK17ul_zKCD1NOPZyuGTulV-QkWBTjdGucooZj59TbxtTiN5oOP8IZiGjY-gRmUzKqzRi_s30tovhuSVYN3IV9NWfcqByUC1fHibO7kwxAJ8axqAU0Md8oBgTptbDBZJKH1GnMtnEKsufuBjRJrBgutmlDIHs3kzgUa0Xv27WvDSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-105","volume":"25"},{"id":5079,"author":"刘一曼","title":"甲骨金文的“■”与殷墟“■”墓","abstract":"将殷墟甲骨文、晚商铜器铭文中的&quot;■&quot;与殷墟出土的两座&quot;■&quot;铭铜器进行综合研究,可知&quot;■&quot;在商代是一个较重要的族氏,生活于武丁至帝辛时期。该族氏的族长或重要人物,世代出任武职,在殷王朝的对外战争中,发挥过重要作用。","categories":["06_族氏方国"],"year":2011,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2011.01.021","pages":"46029","volume":"32"},{"id":5093,"author":"耿超","title":"浅议姬寏母豆与师■钟作器者关系及族姓","abstract":"姬寏母豆著录于宋《考古图》。该书称为&quot;齐豆&quot;,言于宋神宗熙宁年间得于扶风(图一、图二)。其铭文曰:","categories":["06_族氏方国"],"year":2011,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_q_Dnjlrnmm94KRWlxopPGutjM8a5sdJTRaunQJDiwbfeRg8X09XUTCG7NnTwKTMeMEdO0-f49QO6nGFq5bti2Lxzhp67lGoZIIzi3DaA1gkhdnyL48gOtY5yTJO7BShW7n1iiJxmm-sLvvLfou71JXpS5oQ7mdXjq4d-fj7qBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-103","volume":""},{"id":6325,"author":"于艳龙; 曹玮; 赵丛苍","title":"芮国铜器与史料综合研究","abstract":"韩城梁带村墓地是近年来陕西地区发现的保存较为完整的两周时期畿内封国国族墓地。2005～2008年考古工作者对其中40余座墓葬进行了发掘,出土了铜器、玉器等十分丰富的随葬器物。出土铜器铭文确定为芮国国族墓地,墓地的性质对研究两周时期芮国的政治、历史、地理位置以及周王朝的分封、墓葬礼制等问题具有重要意义。本文主要是对梁带村墓地出土铜器以及传世铜器、文献中芮国史料等进行综合性研究。本文共分为六个部分:第一章为绪论,主要介绍了梁带村遗址的地理位置、墓地的发掘以及研究现状、本文的研究思路与方法;第二章为梁带村墓地出土铜器的分期与年代,运用考古类型学方法对梁带村出土青铜器进行研究,在此基础上将其作四期,并对出土铜器的墓葬进行了分期,附带介绍了其他地区出土的芮国铜器;第三章,对梁带村出土有铭文铜器、其它地区出土芮国铜器、传世芮国铜器的铭文进行归类总结,对传世铜器的年代进行了重新考定。对铭文中提到的人名信","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIltGkQX_AmpCbxzZva6TZjL5FuxDZ7nUOmTWuwQFVqYIeI98tgmSHQCFTYASjQllthh2sreEWzA9KHr6vU17QvWLhV56eQP8Hxs27ZWoCBuLmYDgdKySfznpRrYjclax1paKnYleNJQsTDzUzWJThxYI_zxA0KSLkVqPAj7Maaot-o1b2oscYD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6342,"author":"罗小华; 陈伟","title":"战国简册所见车马及其相关问题研究","abstract":"自1951年以来,相继出土的五里牌筒、信陽筒、望山筒、天星观简、曾侯乙墓筒、包山筒、新蔡筒等戟国筒册中均有關於卓马及其相關器物的记载,封於研究先秦楚地“卓马器”、“卓载器”、“卓马制度”具有重要意羲。本文就是以这些材料为研究封象的。在搜集各家之说的基础上,封一些学衍界有所讨输卻没有解泱的问题,本文当试提出新的见解。本文共分“前言”、“正文”、“附録”、“结捂”四个部分。前言部分是封各批记有卓马及其相關器物的戟国筒册的发现、整理、公怖、研究等方面造行介绍,並封本文的選题意羲和研究方法造行筒要说明。正文第一、二章是關於战国简册所记“卓马器”、“卓载器”的“分类研究”。在第一章中,“卓马器”被分为“卓構件”、“車器”、“马具”、“马饰”等四个小節。在第二章中,“卓载器”被分为“席蔽”、“兵器”、“旌旗”、“雜類”等四个小筋。相關讨输先收集各家之说,然後结合傅世文献、考古實物封各種器物進行研究。正","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLAEEuCBTiep98PQxtJocqE0J-eu4EuKH_ZQKIH6lKEaZ0336nLzKV41dPy62pOYBwh4tzQ166c_6D8iw3UpgnTcF3Kko6Mtul-gLz09MPeHIv5mheNcRWU4PZtD_9mBj-Tu8Ti7H20T2QP4zJXQQi3r2_9LKkcwcw1NdEAHH1PrIIHsX1Dof_9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6350,"author":"黄树余; 李民","title":"周初殷遗民去向研究","abstract":"公元前1600年,商部落首领商汤率兵于鸣条之战灭了夏王朝后建立商朝,经历了17代31王,末代君王商纣王于公元前1046年在牧野之战中被其治下的小邦周首领周武王率诸侯联军击败而亡国。商政权顷刻倒塌,而大量的殷遗民留下了。周人为夺取政权可以灭了商,但周人想要稳固政权,则必须妥善处理好殷遗民,特别是商王曾直接统治之下,商王畿之处以及以商为正统的诸方国的殷商遗民。周武王灭商之后面对如何处理这些殷遗民的问题,多方垂询方略。最终采纳了周公“各安其宅,各田其田,毋故毋私,惟仁是亲”的策略。武王让殷遗民留在原居住处,让其旧有首领纣王之子武庚继续充当其首领而领导他们,此外武王为殷初定未集,乃使其弟管叔鲜、蔡叔度相禄父治殷。但是这种处理方式没能让殷遗民从此安生,服从周人的统治,却导致了武庚联合三监的叛乱。周公在东征平定叛乱之后,在总结武王时对待殷遗民的经验教训基础上,对殷遗民使用新的管理策略,以政治力量对殷遗","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKJnfZlk0TItK9dvcjSWH_ntB4Blfj_QxefzVcdrwy4z_CN_gBaL-m5HBSMdqCP_-D28PO78O6VhK9jQ5PUiQ2ECeIJBrGyJ_A2JYTAlvttzMBAa0NuZNJgXAIfp768tC9xZlRyLfFcNwb7s2ZzjWbz0lWD9OqgNdQNzfRxwR-POl047gjjlCyz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6355,"author":"赖彦融; 冯时","title":"早期齐彝铭研究","abstract":"回顧前人討論齊彝銘,東周以前齊金文的研究長久存在空白,零星的早期齊金文探索亦多有惑疑,說不可必。本文鑒識及輯集晚商至兩周之際齊銘彝卅六器,四十一銘,逐一考釋銘文並斷代，因見西周晚期偏晚齊彝及齊文字已呈現地域特色。又山東高青陳莊墓地新出齊彝銘,18號墓所出組器,器主之名「」於西周金文與「豐」不為一字，器主當為丁公伋嫡子。35號墓所出引為宣王時器,銘言周王臨危授命引,承祖業率齊師抗禦外敵。本文通过輯集及研究早期齊金文,補證文獻所載晚商至兩周之際齊史。","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHOnCjqYP7p4Ejf5rFOJOxTuqm-OmasyKiPQnPEvW7eP5zdUzG2ttMFM-EoE5Cok_I7eZpLnyV_joIMsHdFMq-qI39IXgIQMswL-t5HMmLt5UfjhkX701uW7hT5WNxp0FKuN_KO9-V0Sn3up5PKNST1PcSOZZ9T4h1ayZCoGV2nKDNjHhlDLPT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6372,"author":"田成方; 徐少华","title":"东周时期楚国宗族研究","abstract":"近几十年来,有关楚宗族的出土资料日益丰富,为重新审视楚国宗族史中悬而未决的问题提供了契机,同时也有助于拓展许多新的思考方向和研究领域。本文共分四章,前两章探讨楚公族小宗的一些问题,认为：第一,薳氏可能出自《楚居》记载的季连次子逮仲。薳氏因速仲之后代受封,封邑薳命名,地望在今河直浙川西南。楚薳氏至少分出有三支——薳氏大宗,古文字写作(?)；小宗蒍氏,古文字写作(?)；小宗(?)氏,古文字写作(?)。从传世文献和楚简资料看,薳氏分出的几支是并行发展的,但其族墓地都位于今河南淅川龙城遗址以西的下寺、和尚岭及徐家岭。和尚岭M1墓主应是(?)子辛(即克黄),并非斗克黄。徐家岭墓地围绕位于最高处的主墓M9规划,其周边地势越低,墓葬的年代愈晚。第二,若敖氏包括斗氏、成氏。成氏是若敖的直系后代,并非斗氏小宗。斗氏因邑得氏,其宗邑可能在今南阳盆地偏东的唐白河流域。成氏的始封时间大概在前7世纪上半叶偏早,其宗","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEpJXvTGM3u_gzOf70JUwtFBC88RApIIDI-MjdjwMs3zkjc8K6ywzGftexxJP9Epo2dKjPBkzL7B5S1lX2AwK0fNTNbwTxcpGz7C9LsIXKSQrGdvOVo74cbfY07K8o0WTNG14T8Bzs1fUDLzB07bdKlU71aqmwJmkh-rD2BC-SYzexfYhRSnEh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6384,"author":"杨博; 沈长云","title":"河北地区所见先秦时期有铭兵器调查与研究","abstract":"相传早在夏时河北地区易水流域就有了有易氏和河伯氏部落存在。商王祖乙曾迁都于邢,今之邢台市和藁城市台西村,都留有商时的墓葬和遗址。当商人定都殷墟时候,今河北中南部乃是王畿之地,北部多为归属于商的方国部落。其中,箕、燕亳和孤竹都是很古老的方国,虽孤处北方,但和商王朝有着政治、经济的密切关系。周人灭商分封开国重臣召公于燕,着意于屏藩拱卫周王室。成王时期,又在齐、晋、燕大三角之内,分封邢国(今邢台市)和韩国(今固安县)。燕国虽孤悬北方,却始终保有中原文化的本色,至燕昭王时燕国成为粟支十年、车逾千乘、骑近万匹、南临齐赵、北领五郡的北方大国。随着周人的东迁,河北滹沱河流域出现了鲜虞、肥、鼓几个方国,在大国齐、晋(后为赵)、燕间夹居而立。到战国时期,鲜虞中山已经华化为小而强劲的国家,但国运坎坷,亡而复兴、兴而又亡。晋卿赵氏家族,早在未与韩、魏分晋立国之前,就已占有邯郸与代地。赵敬侯迁都邯郸直至赵武灵王“","categories":["06_族氏方国"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIETJRFdHuNPHPIr-P8YSBy_3OQDlKbyNCQgYIiGBe8AwjJlh6CBNOMIvSSW-E0dsnMZXCrt9dr-q8stiVGEGouESBs_ZLN1bH8vZbYOP8gJymoaqgChtp4o1HpofvKELhiHUrt5ypxYP78utrIuFr6Xi5mXKkNkkdQF8znPObtc86iGKzNJfNr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6386,"author":"王长丰","title":"殷周“戈”族铜器整理与“戈”族地望探讨","abstract":"本文通过出土的殷周&quot;戈&quot;族铜器铭文与甲骨文史料互证,结合传世文献,考证&quot;戈&quot;方国族氏始封于夏,姒姓,少康灭之,其后以国为氏;商周时期之&quot;戈&quot;地地望在今商丘与新郑之间。","categories":["06_族氏方国"],"year":2011,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSulOnW5Fda1pUwPuW8QRlv2I-aiYJiA5BNr1IrAEgjjPytSkWlkfubZP6PQkw8RECJV-ZsyyXVt_bIyDfJgRXhh_ZieS7hpvEjW7LqV_R2bp59MA5eXPb4it7HcGB70mNLrL5mI3Wlhby_WI0jxS15BpS7iu4jEKcic6Q-36uew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-73","volume":""},{"id":6664,"author":"张丹","title":"楚彭氏家族研究","abstract":"本文结合考古发现的申县彭氏家族墓的资料,以及《左传》及楚简中的彭氏家族人物信息,做了一些基础性的综合研究,分析了楚彭氏家族人物的世系及时代、楚彭氏家族的来源以及他们的聚居地。春秋时彭氏家族居于楚国上层政权中,战国时彭氏在楚政权中的重要性较春秋时有所下降,这与南阳彭氏家族墓只从春秋早期延续到春秋晚期的现象是符合的,可能与彭氏渐渐衰亡有关。根据申县发现的家族墓判断,彭氏家族的聚居地在今南阳地区的汉宛城范围内,也即故申国都城所在处,其家族墓地在宛城的西北方向。","categories":["06_族氏方国"],"year":2011,"publication":"珞珈史苑","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIx8RJ6lKF8aW7nlS_iqJ6n7P7KtyELRbQipoytYJerqX3GWB1kvJrS_Ebn7AWQ7dpzuk-S0FQl4mh_vGSEjr3zIE-rX3cJtniBdqlKbBTJMiK7jXm8E_kot8iYRm5vAbhtidRnxFNjz1H4hTSbeQeSMDwQoNkY64xc_oehMtAkLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46049","volume":""},{"id":6693,"author":"孙华","title":"晋侯邦父组墓的初步分析","abstract":"晋侯邦父组墓,也就是山西曲沃县北赵晋侯墓地①编号为M64、M62和M63这组墓葬②。这3座墓位于晋侯墓地南排西端,由东至西分别为车马坑（未掘）、M64、M62和M63。M64和M62均为南面有一条斜坡墓道的甲字形大墓,M63为南、北各一条墓道的中字形大墓。这3座墓紧邻,靠近车马坑的M64死者为男性,出土有成组的编钟、编磬和铜兵器,5件一组的铜列鼎的铭文中有&quot;晋侯邦父&quot;的记名,肯定是一代晋侯之","categories":["06_族氏方国"],"year":2011,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxiMySYqpLAEqwJy3Pi8eeGwQstnAVX_9UfIXrwfn6gK8ihVDvw1LexW4A8I5j6_g5ac30pN1rsqWRlljIMRZ3ebcC9OFivMkYlGK-885TIXOjhbQ6h0kRh1-hTV3GZBkJZmD4tEMm74bYO9XODGLHpWAVvaiH4duTzDyxMsMVKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"249-266","volume":""},{"id":6700,"author":"方辉","title":"高青陈庄铜器铭文与城址性质考","abstract":"陈庄考古入选“2009年度中国十大考古新发现”,乃实至名归,相信随着资料的全面公布及解读,对于陈庄考古发现的意义,学术界将从多个方面加以解读并揭示。现根据迄今发表的若干组件青铜器及陶器等遗物,尤其是有铭青铜器,对城址性质加以讨论。不妥之处,敬请指正。一、铜器铭文与年代","categories":["06_族氏方国"],"year":2011,"publication":"海岱考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKaLvKcaEG_kbb8KOwFAK2dyVscsmRlkjrxPLtrLU9zphkvrQbffFtCGcWpFX7WZpNcyjb6MAsdbqJyKyIZ1UyAIc1aT2mpjeNfSOKbEAY5OfGOKHWXXmBdFfiflsKp2OiK6lu8i3NMwvl41pPY9BJiC1Mc0y2COry2gI109mKxTA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"404-408","volume":""},{"id":4842,"author":"李家浩","title":"章子國戈小考","abstract":"《殷周金文集成》著録的11295號章子國銅戈,[1]是1981年湖北省文物商店在枝江縣收購的,其上鑄有銘文。黄錫全先生曾撰《湖北出土兩件銅戈跋》一文（以下簡稱“黄文”）,[2]對此戈的銘文、國别和年代加以研究,提出了一些好的見解。例如此戈的年代,黄文定在春秋中期,比起其他說法,就要合適一些。本文擬在黄文研究的基礎上,談一點不成熟意見,作爲補充。據《殷周金文集成》所印拓本,章子國戈援長16.6釐米,内長7釐米。援略上揚,","categories":["06_族氏方国"],"year":2010,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKihuanlzGXvm3Fbhf64SeWawGFjvvz4dJR1xU8xL93kAc280oZhlNr2O6eQ6Zczlco1JjAaMFXufl61oHwav0waeyj3vQgAn8UJGLBUFQ1h4s05jpxwDZOVMhmYc2IO-s95O5aDY9UHAICv2scVzPsH0vrQVzm18RpkP4tXbpJRkvX1dDFtF13&amp;uniplatform=NZKPT&amp;language=CHS","pages":"158-162","volume":""},{"id":5111,"author":"杨栋; 曹书杰","title":"禹铸九鼎传说谫论","abstract":"《逸周书.度邑篇》有&quot;九鼎&quot;的记载,说明至迟在周初便有九鼎的流传。考古发现证明夏代已经进入铜器时代,&quot;禹铸九鼎&quot;传说是对这一时代的反映,古史辨派对这一传说所持的&quot;近于神话&quot;的态度不可取。九鼎所刻图案可能是螭龙一类的动物,夏民族尚九,从古文字字形分析,&quot;九&quot;当是&quot;虯龙&quot;形,这些可能都源于夏民族的龙蛇崇拜。《逸周书》中有两条关于商周之际九鼎变迁的资料,具有可信性。","categories":["06_族氏方国"],"year":2010,"publication":"中南大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAEigC9AdmnGm5Dx8hAHbj4XxY4S_4_gIqyerwZ09ZdIGooNhfR7jTFqlBG-G0-es6v8XEq46zkBloA6QOUTHoBwWZNJVcrg98qJrIKS0spKmLt-MYFIw1QtQjdIhJa9XyCkJC9nOyFnuJDOgsHtuj-TsG5H0FjVoy4G2BWrLdOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-109","volume":"16"},{"id":5121,"author":"刘社刚","title":"虢国为何又称郭国","abstract":"虢国是西周早期分封的诸侯国,其开国君主是周文王的弟弟虢仲、虢叔。虢叔被封于今陕西宝鸡一带,后人称西虢;虢仲被封于今河南荥阳一带,后人称东虢。公元前767年,东虢被郑国所灭。西周晚","categories":["06_族氏方国"],"year":2010,"publication":"寻根","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCirrUNEb9DbBDTsPbxEJ5flHqTVjozn3WutywkJjzGC7tCwURTY5Qqf4D5V9wMlrEQDtpc7FS69wKEvDgjG-En0dxMEpDLLFi2HnOZyyCPARVdeMow06fQK63VHWr0koMgDl3ImBIx0r9xmdGJUPHibx8xKXnq_Z_R0c6zn-R3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-121","volume":""},{"id":5122,"author":"张富祥","title":"逢国考","abstract":"古代逢族为豢龙族的一支,源出传说的祝融部,因与姜姓族群通婚而为姜姓。夏代后期,其族居于今豫东鲁西,商汤灭夏后归服于商,被封于齐地,取代斟氏为诸侯,国名齐。其都邑初在今邹平境内,后迁于青州附近,商晚期为斟氏后裔所逼,再迁于今高青境内。商末助商王朝平定东夷反叛,周初复支持商王室嫡裔武庚起兵反周,与薄姑氏同为周人所灭,其国族亦被迁徙于今济阳境内,成为周王朝新封姜齐政权的附庸。","categories":["06_族氏方国"],"year":2010,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2010.04.029","pages":"117-125","volume":""},{"id":5132,"author":"刘凡超; 李世宇","title":"“俎侯夭”与“作册夭”关系考","abstract":"关于俎侯夭簋的作器者&quot;俎侯夭&quot;与夭令方尊、夭令方彝、作册夭令簋的作器者&quot;作册夭&quot;是否为同一人,学者间尚存分歧。本文在前人研究基础上,通过对作器者的身份、族徽的使用以及铭文所反映的地域三个方面进行分析,初步得出结论,二者并非同一人。","categories":["06_族氏方国"],"year":2010,"publication":"前沿","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOMXlcKfdH_xMjyUlRubUJxauUIWqoQjTNkr_p0JtKqKMY3HQKcNl3jkkABpf6pQ2II6KTBO-f9vBG_iG1nmra3wntmoz9mWB6DJkz6m0WC29h9OZ9v3vRHF4O-CenZvfP7ndSmy6lnFh3qvEAcx7ziRpdPIpr-UREoS0eWBmvCQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"133-136","volume":""},{"id":5137,"author":"李学勤","title":"论西周王朝中的齐太公后裔","abstract":"史籍中关于周公、召公以一子就封,另有子&quot;世为王臣&quot;的史实比较明确,但对于同为开国重臣姜太公是否有子&quot;世为王臣&quot;则文献无征。通过近来出土的西周青铜器师■钟、师■鼎、即簋、师臾钟铭文考求其世系可知:姜太公确有两子世为太师,留侍王室,同周公、召公家族情形相似。","categories":["06_族氏方国"],"year":2010,"publication":"烟台大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13951/j.cnki.issn1002-3194.2010.04.013","pages":"99-101","volume":"23"},{"id":5147,"author":"杨博","title":"北京市征集商代“戈”戈考源与研究","abstract":"北京民间征集的&quot;戈&quot;戈当属晚商戈族器物,而北京地区&quot;戈&quot;戈的发现可为北京地区一带为晚商至西周时期戈族的重要的分布地区的旁证。","categories":["06_族氏方国"],"year":2010,"publication":"吕梁教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDoBcg-UcfTiHKHt21hH6os8DTCDKTCJexPviak-UFxjQXTzxGmLMC64PuD3m0T2LmmPD9UhY3wxjAm4r7PTIPTod4qu-9tsJCOWV37-aYDXRYmd3yWRAmIamZJ4ExxMNyTOMT6EWtJcuhe1MiZ8wgMYlgjYQfGwsH_cMrUgjRHw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-125","volume":"27"},{"id":5160,"author":"王恩田","title":"高青陈庄西周遗址与齐都营丘","abstract":"高青陈庄西周遗址内发现的两座诸侯身份的甲字形大墓,证明陈庄遗址应是都城,不是邑。M18出土的豐簋铭文中的&quot;齐公&quot;,应是齐国始封君太公师尚父。太公日名为&quot;甲&quot;,可补史籍记载的阙佚。太公之孙豐即太公之孙乙公得。乙公名得字豐,M18应是齐乙公得之墓。陈庄城址应是齐国早期都城营丘。圆外有方、方外又有圆,层层相套有9层夯土堆积筑成的夯土台基,应是相传太公所筑的营丘,其主要功能是祭天的天坛。","categories":["06_族氏方国"],"year":2010,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2010.03.018","pages":"98-101, 0","volume":""},{"id":5161,"author":"方辉","title":"高青陈庄铜器铭文与城址性质考","abstract":"山东高青陈庄西周城址及墓地的发现对于西周考古与历史的研究意义重大。本文根据迄今所报道的资料,对两则铜器铭文做了解读,并对陈庄城址的性质做了推考。文章认为,陈庄墓地从西周早期成王开始延续到中期的昭穆时期,其间未曾中断,与城址的存续时间相吻合。陈庄城址规模较小,不大可能是西周齐国的都城,其属于齐国贵族封邑的可能性较大;而这个封邑,应该是豐。","categories":["06_族氏方国"],"year":2010,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2010.03.019","pages":"102-105","volume":""},{"id":5179,"author":"雒有仓","title":"商周考古所见族徽文字与族氏关系研究","abstract":"商周考古常常发现青铜器上铸有族徽文字。这些材料由于具有较明确的时代和器物组合关系,是研究当时族氏关系的重要资料。从现有考古材料看,族徽文字所反映的族氏关系主要有三方面:(1)","categories":["06_族氏方国"],"year":2010,"publication":"文物世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2sYzNcsLWPn29OSDN9cNqW3WF7KnuGzFpkYJSFZbdPbEJdU8-Edqqn2z-kpqg0HBU-Vm90KR4uaJdM4odGiFFXSheLzgdAQzL9R4ZVcjn4IUs0zaoNAyXuTNRNuChRTTHjFzR0j_pQlLru9ZRvkjTUtMIeUim_VLT6LNpbcS-lg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"11-15, 32","volume":""},{"id":5180,"author":"王长丰","title":"殷周金文族徽的类型与判别原则","abstract":"殷周时期的金文族徽是殷周族人族属标识性的徽记,族属不同徽识各异。经过比较研究,按照归类分析原则,殷周金文族徽可分为简单形式族徽(六种形式)和特殊类型族徽(四种形式)二大类十种形式,这对深入研究殷周金文族徽具有重要意义。","categories":["06_族氏方国"],"year":2010,"publication":"书画世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJkQ28cTccZ6r_RJYVuPZHDRXIbrg8cfabJ0_L0kuEdUB3dznLQ2KwinT6u1Pq308hNkqaAGeMdKVd_AjcvUgUOPLFlenQgGcrDxsEhr_9-VanwgJUZCRzsgk0Uoz-UFn6eNGpBcwy1HmrPGm7pioDcQczZ6cnoUrxaEiNMtVV8mg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46122","volume":""},{"id":5191,"author":"耿超","title":"邿召簠及相关问题初探","abstract":"邿召簠出土于山东仙人台周代邿国贵族墓中的M3,由其铭文可知,此器为男性贵族邿召的自作器,用于宴飨&quot;诸母&quot;、&quot;诸兄&quot;等亲族成员。而M3墓主为成年女性,其身份应为邿召的妻子、宗族的宗妇,此器应为其生前所用并随葬墓中。该器的出土一方面体现了两周时期宗妇在家族中的职责与权力,也从另一方面表明除宗妇外,家族内的&quot;诸母&quot;即各小宗宗族长之妇也有权力参与家族内的宴飨活动。","categories":["06_族氏方国"],"year":2010,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzXR8G5SvhMBYmeIHuJZh8ztPndCgh0ee3qdtHrgDaWpYwz1-ucpq-CJTLMDNe5IujmyEcLOwOgyz1Sb3L2BmisCzwxA6-5GHC1QvYwAXo99ro6idrVkp1gqU8aPDL31wD3XuIZNNSngphpWdBlpu0nNwF-J-ZkI9C08AW3NzlUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-66","volume":""},{"id":5203,"author":"周书灿","title":"邢侯簋与西周服制——兼论西周邢国始封地望及有无“迁封”问题","abstract":"邢侯簋铭对于研究西周王朝服制及邢国历史具有重要的史料价值。该簋铭所记西周时期邢侯对周朝王朝的主要职责记载于平定戎狄,稳定西周王朝在北土的统治。考古学资料表明,西周初期邢国始封之地就在今河北邢台市一带,学术界流行的西周邢国迁封说,缺乏考古学方面的证据。","categories":["06_族氏方国"],"year":2010,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjbKQMkJYA0A8MlyfSNiy8v8Vxy02lhaoB95MKaTEdYNwHSfBkHuOuuvLp3_JJugH1FI4VxQ6ya4HF0zjdDGXvgl_ovDCwz0HjStDS2p3Ei23LAezD8NEqknMCRFw7mgyD6cMgvjF2irvnWrlcyA4FLsyvvKRv3lx99yvF-XcGiQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-50, 69","volume":""},{"id":5205,"author":"陈青荣","title":"从传世山东藏家的藏品看高青出土的青铜器","abstract":"山东著名金石学家吴式芬所收藏的传世青铜器《引尊》,是引为其同宗长辈所造之祭器,金文资料反映,《引尊》之引为西周中期人,是商齐裔胄,其生存年代与生存的地域均与陈庄出土青铜簋中的&quot;引&quot;相同,他们是否是同一人?值得探讨。","categories":["06_族氏方国"],"year":2010,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2010.02.022","pages":"103-106","volume":""},{"id":5225,"author":"孙进","title":"青铜器中的古莱国与中原王朝","abstract":"莱国是地处胶东地区的商周时期古国之一。通过对有关青铜器铭文的考释与梳理,并与传世文献相印证,更便于对西周时期地处偏远东方的莱国历史进行探讨。从这些探讨中也能看出莱国与中原王朝保持着密切的联系,并参与了一系列周王朝所主持的军事活动。","categories":["06_族氏方国"],"year":2010,"publication":"烟台大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13951/j.cnki.issn1002-3194.2010.02.003","pages":"94-99","volume":"23"},{"id":5230,"author":"孙进","title":"莱国与周边国族的关系","abstract":"莱国是胶东地区的古国之一。大量考古资料证明,西周至春秋时期的莱国与许多周边国族一直保持着往来关系。通过对相关出土青铜器铭文的研究,可以初步廓清莱国与纪、莒、蒲姑、过等国族的联姻或交往关系,从而为胶东区域文明研究提供新资料。","categories":["06_族氏方国"],"year":2010,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2010.03.012","pages":"89-92","volume":"31"},{"id":5244,"author":"王建军","title":"殷周时期的“举族”及其相关问题","abstract":"~~","categories":["06_族氏方国"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJc7hzSmcNKKfemaM9-_pC0Sc5F9r5aSYjVtNVQ4Ujzh5Z1hlfsn1JvgqcR8t4MCex6AtPQE3FPgbn75-LNICD1ZI7L1MGYTRitmR2uzzX00yOiqlBH70uFg5GoBVLCF5QP8mDX8H_raoGWJPBTvvZ-6w8jToeqoimsnXDJTVTS9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-62","volume":""},{"id":5261,"author":"徐海斌","title":"先秦中山国史研究综述","abstract":"河北平山中山王墓葬群的成功发掘为先秦中山国史研究提供了新的契机,出土古文字的考释、考古实物的定性以及相关传世文献的重新解读成为学界一时之盛事。中山国的族属、相邦司马赒的身份、中山伐燕回师的时间等问题曾引发热烈的争鸣。","categories":["06_族氏方国"],"year":2010,"publication":"井冈山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJL0sMezr9vRxi1Mb5Ag_Hc3mIlP216hByX4vwtTDVYD0nDAbPMJ5Ay3GYvyW-tUwjX-o68o3tCRJrjZ6TG_Bbv7HSmuBfbK7q2ZgZIlnnLWh2UIxV1baFpqIMjPpQ_vnbNgb-oRnyIrZOzmTEHYlEJxFrhOCIy2QJEFS6Mru2bcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-121","volume":"31"},{"id":6397,"author":"高玉平; 黄德宽","title":"建国以来所见商周青铜器窖藏研究","abstract":"解放後,青铜器窖藏的不断出土,尤其是周原地區湘江流域大批青铜器窖藏的重現天日,引起了人们的關注。但截至目前,還没有任何一部著作将解放後全國范圍内所發现的青铜器窖藏作为考察封象來進行整體上的研究。本文著重從宏觀上研究“窖藏”青铜器這一现象,運用個體考察和整體觀察相結合的方法,從共時和歷時的角度分别造行描寫和分析。全文共分七章：第一章“緒論”。對文中涉及的幾個概念造行了界定,對青铜窖藏造行了分類,回顧了青铜器窖藏研究已取得的成果,明確了本文的“青铜器窖藏研究”的研究對象、研究范圍、材料的選擇和處理和研究方法。第二至第五章,分为四個專题,分别为“商代青铜器窖藏研究”、“西周青铜器窖藏研究”、“東周青铜器窖藏研究(上)”和“東周青铜器窖藏研究(下)”，是從歷時的角度對青铜器窖藏進行(?)分。而每一章當中根據青铜器窖藏的出土情況,包含三節或四節,一般是分为“遼河流域”、“大小凌河流域”、“黄河流域”","categories":["06_族氏方国"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJK7UxgVOnRZwjC3-Gdxkbspsog1KeV60clHZyq6QZ41mbmpBO726BzA0i-3sxQl3QgByOK88pM_KSrIQmFxZkARGIDYgiZadotT79Enq1ScfjCvjTdGXldz6BW_phOw5w5FKeiI6w7iKnBbV3Ka8UUxnAGTcYiSOLGGRZYLWadrW7ajXnEkCfF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6418,"author":"黄益飞; 肖小勇; 冯时","title":"应国具铭铜器研究","abstract":"本文在对应国具铭铜器资料进行全面搜集和对相关铜器进行辨伪考证的基础上,通过对具铭铜器的年代学研究,建立应国具铭铜器的年代学体系,构建应世家世系。全文分为五部分：绪论主要介绍选题背景、研究现状及本文的研究范围与目标。第一章对应国具铭铜器资料进行整理研究,重点考订应国具铭铜器的来源、数量、款识及辨伪,力求对应国具铭铜器的现状有一个全面的掌握。应国具铭铜器有三个来源：1、应国墓地和其他地区考古出土,51件；2、传世品,20件；3、近年收藏机构购藏的流散品,13件,共计84件。第二章对应国铜器中的4件伪品,即应公剑、十六字应公鼎以及首阳斋收藏的应侯簋和上海博物馆收藏的应侯视工鼎进行辨伪。第三章对应国具铭铜器进行断代研究。主要利用考古类型学方法,通过形制、纹饰、字体诸因素的综合分析,判定具铭铜器的年代关系,得出以下重要结论：1、属应国国君器的传世具铭铜中,应公尊A属成王时期,器主当即应国的始封君应公","categories":["06_族氏方国"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXJZIZ8vwJHPJr7W81ISYN6X1rm8gUXo0pSDdPwdx7MUG_onAEe0gzcG7do4rOUU9BVh9S2cBeSk2Bftyn1BDyAqsdEaESKGvThPNc7-SoYkbLPyjtCkzAUkd3JJEcOAgGfe13XQ_W0eDUROJwQT2GBZB6JxAW_GcJr1FoWC0kri4OxiqTWb_s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6423,"author":"苏勇; 吕文郁","title":"周代郑国史研究","abstract":"郑国是西周晚封的采邑,两周之际东迁河南,成为采邑转变为诸侯国的典型,国祚绵延四百余年。郑国始封与东迁的史料较少,本文将文献与金文材料结合,在前人研究基础上,集中探讨了郑国早期历史中几个备受争议的问题:认为始封君郑桓公为周厉王之子;证明郑国始封之地在今陕西凤翔雍水以北;阐明郑国的东迁之君为郑武公,他于东周初年将郑国从陕西畿内郑地迁往今河南腹地,开创郑国发展的新篇章。春秋初期,郑庄公一度成为春秋小霸,这主要得益于四点:郑国开国三公为王朝司徒的身份;内政稳定,虽有叔段之乱,却未对郑国造成很大影响;与齐国稳固的同盟关系;没有大国的侵扰。然而周王朝与郑国的矛盾逐步加深,最终决裂,郑国失去了政治优势。郑庄公去世后,国内五公子之争,使郑国在国际舞台上退隐多年,待局势稳定之时,齐、晋、楚相继兴起,在力量对比中郑国的势力急转直下,对外扩张完全被遏制。在大国争霸中,郑国不得不首鼠两端,国力渐弱,虽有子产中兴,","categories":["06_族氏方国"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8rzZUVujAZHb6q_XGFCC-Kza3hyuP6I1N34lT56OIi0yjqIFQmKw5I24DkLjA1Q83T_fbd_ww79yck754AS4XYgk-QEhx3ZWZRDBsUdCp_eqoc6zhV66SgmQKeXGeZg1jD2vtStq0Zz1iQ3RmUKh12EmW5ue4BqXlPhAqxvYg7_GFLf6nFrpI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6709,"author":"刘彬徽","title":"楚系青铜器研究续论","abstract":"本文是在拙著《楚系青铜器研究》一书基础上,对近二十多年来的楚系青铜器研究略作续论,主要有关于西周时期楚国青铜器的研究、春秋早期枝江百里洲青铜器和新见楚太师钟的研究,关于楚束腰升鼎的渊源问题,关于楚金文研究新进展及其他相关问题的研究。","categories":["06_族氏方国"],"year":2010,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLutXSjG5yJ7mGivkNH1ZUxq7J7le-0mBv8II83OiFpjUYRhId-r6T0TUsH05PnR8VUOtIlxQzFu8A5lIP3DRJeQJrPYy2IGqSU96S3SWXGxg03NGGpy7XiL42xASRGB7xkxDLkWZl5UxKXMUUy2KVvaqLtnJ9Mzj-znGqDTTuC3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"175-195, 45","volume":""},{"id":6736,"author":"缪鹏; 张爱冰","title":"钟离国青铜器初步研究","abstract":"江淮地区处于长江与淮河之间,由于长江、淮河与汉水形成了广袤的冲积平原,河流众多,水资源充沛,加上这一地区处于亚热带湿润气候与暖温带湿润气候的交界地带,历来农业发达；又由于江淮南部地区丰富的铜矿资源。在商周以来一直是中原王室地区所争夺控制的主要地区。自东周以来,随着周王室的统治地位的下降,作为春秋时期南方诸国北上争霸与北方诸国南下称霸的必经之路,对江淮地区的争夺也就此开始了。这里既有原本就根植于此的土著文化,又有北上争霸受挫转而东进的楚国,还有与楚进行争霸战争的吴国。在这场争霸战争之后,江淮地区原有的许许多多的小国都走向了灭亡,其文化也都消失不见,最后剩下了统一的楚文化。在2006-2008年和2007年安徽省文物考古研究所先后在安徽蚌埠地区发掘了两座规模较大的春秋时期墓葬,分别是蚌埠双墩一号春秋墓和凤阳卞庄一号春秋墓,这两座墓葬以其独特的圆形墓坑迥异于这个地区以前所出土的其他春秋时期的墓葬","categories":["06_族氏方国"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHmaNIRcyqpqrgbPdZDP1hzeTFnofSHuwVVKb65JRh8I5Uh1qmD8nBwVIJCCkM9lLF2Dg6FscMuLeWtTGPdjuN11DXip3NM6XOpbpFX3vw8upklrXa7bO-zIinYHedaTys8jrSYSZM9ixRFbVhPDKJ12pSCWjt_JZ9O-ubAF1Hk3mo8gUmydOp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":5263,"author":"刘晓晖; 张振林","title":"西周铭文中的“■”族为“妘”姓考","abstract":"见于西周中晚期铜器铭文中的族徽符号&quot;■(周)&quot;,根据周人不用族徽的通例,可知铸器者必不为姬姓周族人。铭文末尾署''■(周)&quot;的铜铭,根据其铭文内容可知,其作器者都为周氏,器主之氏与器铭末所署的徽识如此契合,应该不是巧合。通过考察分析所有的■器铭文内容及与其相关的其他铭文,此&quot;周&quot;氏族当属妘姓氏族。","categories":["06_族氏方国"],"year":2009,"publication":"湖南科技大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3RsGNNlbcnP4KjjpfZs21WFsMLx5-Cs_gziY_oLUeGysR2N8hohWKBptHwWWOkHC0PLOI3iYPg1odoPVAKahI1UPXtb9n-AAwaJdd-bLxzUQrmheuB4tXxHDuP884-QQZJ0FDPZmQzHRm4zHSuYeQvwE10suGur8JY68D3hgYtA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-108","volume":"12"},{"id":5271,"author":"商艳涛","title":"西周金文中的族军","abstract":"","categories":["06_族氏方国"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbJGHDWEjAUHw6l8NwuXVzadoHS3OYjWaPWgR4k8KuBU0-MWj9bq4nab9Qw_6Bdu40NxqXK4aqmG3PXuROMIWa8DeVylt7z9R9XQPDnP_ixflxeMrypaBHoil5xH5235UIupB5kh8XS8JrAa8RFsU8E42oBJVMuR5h4BQS_kASRA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-101","volume":""},{"id":5290,"author":"陈絜","title":"鄩氏诸器铭文及其相关历史问题","abstract":"周代金文所见之鄩氏,应该是文献失载的子姓之国或子姓之族,乃殷商王族之支庶,或为殷末征人方的直接产物,其地望大致在今山东济南附近。周人入主中原后,鄩氏臣服于有周,甚至直接成了齐国的附庸。两周之际,该族曾经与曹姓之邾、任姓之吕或曹姓之莒等小国联姻。春秋晚期,则为强齐所吞并。而传统的莒国改姓之说,尚有疑点,曹姓之说或更为可靠。至于鄩仲匜铭中的&quot;(?)&quot;,实为&quot;吕子&quot;二字的合文,其中的&quot;(?)&quot;符,是借笔合文的指示符。","categories":["06_族氏方国"],"year":2009,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2009.02.004","pages":"13-26, 157","volume":""},{"id":5308,"author":"张俊成","title":"殷商己族及其相关问题考论","abstract":"己族是殷商时期重要的族氏之一,通过分析甲骨文和商代青铜铭文可以看出己族的主要居住地应在今山东省寿光一代,己族与竝族合署而构成的复合族徽的含义应是族与族之间的联合关系,而非是主支和分支的关系。","categories":["06_族氏方国"],"year":2009,"publication":"洛阳师范学院学报","link":"https://link.cnki.net/doi/10.16594/j.cnki.41-1302/g4.2009.01.022","pages":"105-107","volume":"28"},{"id":5350,"author":"刘兴林","title":"莒城·莒墓·莒鼎——莒文化三事","abstract":"在目前已知确切面积的春秋战国都城中,春秋时期的莒国故城算是面积最大的一个,并且在城市布局结构上最为规整,完全合于先秦时期&quot;择中立宫&quot;的都城设计思想。但我们并没有在今天的历史文化的研究中给以应有的地位,应当引起重视。故城西的&quot;莒子墓&quot;,时代可能在战国晚期至西汉初期,墓主有待考订。现藏南京大学考古与艺术博物馆的传世&quot;莒太史申鼎&quot;,可能是春秋早期的莒器,流传有序,是莒国和莒文化研究中的重器。","categories":["06_族氏方国"],"year":2009,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2009.04.028","pages":"121-125, 2","volume":""},{"id":5384,"author":"王沛","title":"“狱刺”背景下的西周族产析分——以琱生器及相关器铭为中心的研究","abstract":"关于西周时期家族财产的占有与传承问题,传世文献记载十分简略。根据传世文献记载,宗族发展到一定阶段后就会分衍。其中是否涉及财产析分,相应的规则又是什么,则难知其详。通过分析传世琱生二簋和新出土的琱生尊铭文,以及其他反映西周家族、世系的金文资料,可以发现近代&quot;分家&quot;式的继承方式,虽然是在战国以后形成的,但于在西周时就已具备初步之形态了。这种分家是以&quot;立氏&quot;的形式出现,只不过立氏并非每代进行,而是间隔两至三世而已。立氏后的小宗,获得一定的经济独立性。","categories":["06_族氏方国"],"year":2009,"publication":"法制与社会发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJboZSk_thRA4wAhXNzXYq4emBA3CBBGHAvZmViLt6Qey3Kx3qCyzsE-Vdf4IZu1qs7g6Z97GSKKyN5S41SAksf91CkEg8DKlHHj_BxAq9-YNzJCiluMhFoznmxW_lBagEG2wfupRAAeEXw5UYDYszkkTey1QbjcpDpYsGIkjExAA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-47","volume":"15"},{"id":5400,"author":"吴良宝","title":"平安君鼎国别研究评议","abstract":"学术界对平安君鼎的国别尚有不同意见。通过对已有意见的分析可以看出,官庄M3所出漆器上的&quot;三十五年&quot;等纪年刻铭实为秦文字,《战国策》中的&quot;卫必效单父&quot;也不能作为秦昭王时单父一定是卫地的依据;单父归魏的时间不在魏囚杀卫怀君之时,卫嗣君&quot;独有濮阳&quot;是指卫君只掌控濮阳,并非说卫国的领土范围。产生分歧的关键在于学者对单父在战国时期的归属存在争议。钩稽史料记载可以看出,战国中晚期单父的归属大致经历了&quot;卫(或魏)——宋——齐——魏&quot;的变化。平安君是卫或魏国贵族的可能性都存在。","categories":["06_族氏方国"],"year":2009,"publication":"吉林大学社会科学学报","link":"https://link.cnki.net/doi/10.15939/j.jujsse.2009.04.010","pages":"81-86","volume":"49"},{"id":6447,"author":"潘明娟; 王社教","title":"先秦多都并存制度研究","abstract":"多都并存制度是指同一个王朝或政权在同一时期设置多座都城的制度。先秦时期存在着广泛而普遍的多都并存现象。根据《现代汉语词典(修订本)》对制度的定义:“制度是指在一定历史条件下形成的政治、经济、文化等方面的体系”,表明“制度”可以是成文的,如西周时期对营建洛邑的成文记载,春秋时期晋国对曲沃“下国”的说法,战国时期燕国下都、上都的对照以及齐国“五都”的记载等;制度也可以是不成文而约定俗成的,包括夏商政权的多都并存以及春秋战国时期大部分政权未明确记载而实际施行的多座都城同时存在的制度。因此,笔者认为,先秦时期多都并存已经形成一个“体系”,由现象上升至制度层面。先秦是多都并存制度的滥觞时期,其都城设置和都城功能对后世都城制度有着深刻而广泛的影响。本文的研究共分三个部分:第一部分即第一章绪论,通过对选题的简要分析和研究现状的深入总结,提出本文的研究思路。第二部分是本研究的主体部分,包括第二章到第九章,","categories":["06_族氏方国"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPUNI-JHbwHAlrAIPSTcc5W7rBgKKzD-Cx_N7lHpNmfFUjAtBLHHB-8-KbpXzFqLUICC_SH3G2xmgGJlm6DMTJOQCyzAJTlNhVPyPL3xYmXY8MKrntWmtxWR0ZmziCowt7JIF3hBHufzRTvO8dB2juuRhpFECUW-N3RCAl4mTjgF5MYMAzyEV_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6718,"author":"罗运环","title":"甲骨金文所见商周与楚关系问题发微","abstract":"商周时期的楚国历史,文献记载极为贫乏,且多系传说,实属楚史研究中一大憾事。然而甲骨文、金文对此有所印证和补益,却又是值得欣慰的。本文打算从周楚关系的角度对有关甲骨文、金文资料中的问题进行一些研讨。一殷墟甲骨文中所见的商楚关系(一)商王武丁时的卜辞:乙未[卜],贞:立事[于]南,右比[我],中比","categories":["06_族氏方国"],"year":2009,"publication":"人文论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWF9ixfhw-OtIF32O5IlCPHI7ozO0KiGWj_PXCkv6NiuyDs_px6j7nJkOZY3Fyq4INz-3g-3Ki89CS7CG_RIROZffdLdg8sGq8eCxPBqi7jk6l8KUWX2QXIN2zL1PLupTGRz32jhR2AETqKBeOL-_QkRxgugL8ecE9Ofk6n_aZlA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"126-140, 5","volume":""},{"id":6748,"author":"辛怡华","title":"宝鸡市区附近出土商周铜器铭文研究","abstract":"考古资料表明,今宝鸡市区附近商周时期的文化面貌是比较复杂的,至迟在商末周初至少有四种文化:以桑园堡墓葬为代表的日名文化;以峪泉墓葬为代表的姜戎文化;以★(音yu)国墓地为代表的巴蜀文化;以矢(音ze)国为代表的姬周文化。本文通过对该地区出土的商周铜器铭文的研究,探讨了这些文化的兴衰与迁徙,以及它们之间的关系。","categories":["06_族氏方国"],"year":2009,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlk5DVHdM2_b6jxAEk0p0AdubNMfvD6kxAkhmVSFOWE6SqNIgPv8-5S3sf8NCYQKLsi35Q9ofpS7qT5iYvbODYkZPNa6cek01g3hVb13OE8KglRU8E4Dj0z2qWbciX3Q5lR3oO-NDvyKAOOavPkh0ibZAWzcuxNKJLaUqwvt_0yg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-134","volume":""},{"id":6753,"author":"王辉","title":"秦族源、秦文化与秦文字的时空界限","abstract":"本文从出土秦文字的角度探讨、观察秦族源、秦文化,又反过来分析秦族源、秦文化对秦文字发展演变的影响。秦早先为甘、青间西戎部族,其族源传说溯源于周。从西周末至春秋,秦有强烈的脱离戎狄倾向及靠拢华夏意识,杜撰其有华夏色彩的先世故事,是政治、外交的需要。&quot;秦人&quot;是一个动态的概念。秦文化吸收西周及六国文化,对之融合、整合,并根据秦国的实际加以发展,创造出富有秦国特色的全新型文化。秦文字上限为西周晚期,下限为秦汉之际。秦文字上承西周文字,下为汉文字所继承。&quot;书同文字&quot;是随着秦的军事胜利而逐步推广的,其代替六国文字是一种历史的必然。","categories":["06_族氏方国"],"year":2009,"publication":"秦俑博物馆开馆三十周年国际学术研讨会暨秦俑学第七届年会会议论文(会议用)","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1092VzN61WcVhiCK7pIqVt8BR7sQB4p4MKjcNoqHZg6jZgkM8n63v8W_AMNRla2-4C4DrL0SrCSvREesBLDghSxPksi6OneuvhR_xYf0uBjANZe257bBKRKVxSxCRdFJPucTgf17WU5ymT9gCZB4t1M7LwPSRm3Gla15L8JxTT3mCb5W3aZqH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-42","volume":""},{"id":6754,"author":"辛怡华","title":"礼县大堡子山大墓墓主及其相关问题","abstract":"通过对秦国的早期历史形势的分析,考虑到两座大墓的形制、规模、主次关系及所出器物铭文字体风格、铭文的制造方法等。笔者认为,大堡子山&quot;目&quot;字形大墓(M3)墓主为庄公,&quot;中&quot;字形大墓(M2)墓主为襄公。M3规模大,但等级低,这是由于修建陵墓时庄公还未称秦公,M3出土的器物有秦公字样为庄公死后临时錾刻上去。秦人自非子被周孝王召&quot;主马于汧渭之间&quot;,到庄公被周宣王封为西垂大夫,约六、七十年,一直生活在今宝鸡市区一带的渭河谷地。文公墓不在西垂,与宁公墓应同在&quot;汧渭之会&quot;附近的&quot;西山&quot;,即所谓的&quot;衙&quot;。&quot;衙&quot;在今宝鸡市区附近渭河支流金陵河西岸的陵原一带。","categories":["06_族氏方国"],"year":2009,"publication":"秦俑博物馆开馆三十周年国际学术研讨会暨秦俑学第七届年会会议论文(会议用)","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0iNhQ91zUL45eis0D9CXp-Nq9_5P-sLBixhJBQFNvu-95Crats9Tv4gkG5KIzYNS2pJJRxlZVmRH_CsmaYs2-q1djjmO-TQtLcWrGykp7q4mg4aYdzTP4LxZpZK_feWhA4uQFqm0C5dCg5suGgXglvM7wBPLhIG5QdENrqbryXcbfafqD3B_B&amp;uniplatform=NZKPT&amp;language=CHS","pages":"268-275","volume":""},{"id":6755,"author":"史党社","title":"“秦子”续说——从称谓的角度","abstract":"传世与考古发现中的&quot;秦子&quot;器有多件,对于&quot;秦子&quot;之所指,学者们还有不同的说法。本文结合文献和金文,从称谓的角度探讨后认为,&quot;秦子&quot;应是春秋早期的文公太子静公。","categories":["06_族氏方国"],"year":2009,"publication":"秦俑博物馆开馆三十周年国际学术研讨会暨秦俑学第七届年会会议论文(会议用)","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIDxmI9pl_RU2CB0CvDMa2xOxANTXfIxHjHgd0M0BhNWnqCHqVhSCtnR9QIj7cNjcrDX0qQsQM7Zzhlg4JA0ivtc8ohpKggDnCH13_Pb8ASb9m_29B87_FZUMKTqnim_SHspawMVuPza7u1TUxYVZrSH0qpUPw20QjCj2mB75kF8kmR-M1jp53c&amp;uniplatform=NZKPT&amp;language=CHS","pages":"317-323","volume":""},{"id":6759,"author":"岳洪彬; 苗霞","title":"试论商周筒形卣","abstract":"铜卣是商周时期常见的盛酒器之一。从形制上,主要有圆体壶形卣、扁圆体卣、筒形卣和鸮卣等四大类。其中筒形卣虽出土数量较少,但制作精致,花纹繁缛,颇具特色。多年来学术界对筒形卣的研究多有涉及,但由于资料的局限,多数研究都集中在筒形卣的型式分析和时代判断上,其他方面涉足较少。近期有学者对筒形卣的祖型、分布范围、年代上限和存在的文化背景都提出了新的看法,但因考古发掘资料发表","categories":["06_族氏方国"],"year":2009,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iII9ZbjM1trsRVE8WNEqLPT0agmqmRNFWCLldu-MnPsWcZgCATDPRx8XgYiLgcoPpJX0_lkPUuXLkMWP1glkRSQ6C0TOEl9AN2MKHRIbNNrQ_GhX4SpKOHM984JGOEH5sUQ8Yyx9zemH-x8Mb92hhWqzaFVowfm2vHvkDo3zI0uGg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"308-321","volume":""},{"id":6797,"author":"徐世权; 吴良宝","title":"出土商周时期青铜器铭文中的国名考察","abstract":"本文通过集录《殷周金文集成》(十八册)、《近出殷周金文集录》(四册)、新收殷周青铜器铭文暨器影汇编》(三册)以及相关资料中有明确出土地的各诸侯国的青铜器,作成表格的形式,其中表格中分为器物、著录、时代、出土地、现藏五项,希望能够反映出这些可判定国别的青铜器的基本资料。并且通过对文献中关于各国地理位置记载的梳理,我们认为这些出土地资料有两方面的作用:一是可以补充传世文献上关于这方面的记载,例如:湖北省随州市出土的大量曾国青铜器说明这里春秋、战国时期存在一个十分大的曾国,可是文献上记载这里是随国的疆域,这样我们就知道文献中随国在青铜器铭文中称曾,也就说随国是他称,而自称是曾国。山东烟台上夼村出土的纪国铜器中,铭文上关于纪国的记载既有“(己其)侯”又有“己华父”而且山东黄县又出土的带有“己侯”铭文的铜器,使我们知道纪国在铭文中有两种写法,“己”和“(己其)”。而且。二是许多资料可以和传世文献的记","categories":["06_族氏方国"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIiaghxGG21oC7w0rlvmkN0tNRioDVbPmDn8G3-Zg7X7s-iPTGXCoJQNRjEbp4kCEjaFqUHvBRHLSjWCyeGlwu67PdgAdpj0IB6uPOSz7-hrJQxWSiouCeqJTuBTiWoCzMT7IhhcxqAfuaq0JTyOBwYpoy4mZ2XKN-RknXe2bPCBF_9kwGIAAzX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6992,"author":"祝中熹","title":"秦西垂陵区出土青铜器铭中的“秦子”问题","abstract":"秦西垂陵区所出青铜器铭信息的陆续披露,为&quot;秦子&quot;问题的深入研究提供了新的依据。应将古文献记载与器铭内容结合起来,对秦子身份作出判断;再立足于出土器物显示的时段,联系秦公大墓的墓主进行考察,探索秦子究竟为何人。对秦子作一元化解读的思路是不对的,不同器铭中的秦子并非一人。两座大墓乐器祭祀坑所出钟、镈铭中的秦子,当为秦宪公;澳门珍秦斋所藏簋盖铭中的秦子,当为秦武公;而几件传世戈、矛及一件新发现戈的铭文中的秦子,当为文公的太子静公。","categories":["06_族氏方国"],"year":2009,"publication":"丝绸之路","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5z2_32DFVUciu83zJiDhjyL9fS0LBTQvtPvxOv-JujwXowx9POiaRiKimldugApX7oePf6vS_FHL9IobGiUHll4EExASWqp_275HOLjoZ5TjonWlB9UuM3Upg73QRD8ef4uH6wia0nYlcL8J0sTJICAm33BH1rOGDFELffyGsuQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46152","volume":""},{"id":5424,"author":"李學勤","title":"論周初的鄂國","abstract":"西周曾有姞姓鄂國,於厲王時被王師攻滅,是熟悉金文研究的學者都知道的。最近出現的一件鄂侯鼎,進一步證明周初已有鄂侯存在。從鄂國青銅器的出土地點,以及昭王南征時金文地名的考證,可以推定鄂國確在江漢會合處的今湖北鄂城一帶。","categories":["06_族氏方国"],"year":2008,"publication":"中华文史论丛","link":"https://link.cnki.net/doi/10.16837/j.cnki.1002-0039.2008.04.001","pages":"1-7, 389","volume":""},{"id":5432,"author":"穆海亭","title":"穆海亭先生学术遗作三题","abstract":"&quot;夨国&quot;引述夨国的方位地域,当年宝鸡的考古工作者卢连成、尹盛平在《古夨国遗址墓地调查记》中写道:&quot;结果表明,位于汧水上游陇县南坡和下游宝鸡县贾村都属于古夨国地域??它的南面是国,东南是散国,东面是井国。但对于夨国的族姓,却认为是姬[1]","categories":["06_族氏方国"],"year":2008,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZ3vIuza7o54OHc2jhtx2x07MxRSH8wWLgPeTSykdnL5KiWh6GX-UAKq255B9LsPKCsORP_Sx4Z3qGULlmdcL5ZNHtd9SmD73m56w98cJV4v5pykSvpKSVBY-hdxI1DXSCT0tjW7-AbkfO6tM3v0rw-u-1FfX1ZV2JUTLIjiZ5sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-92","volume":""},{"id":5433,"author":"张军涛; 席奇峰","title":"殷商舌族考","abstract":"舌族不见传世文献记载,从甲骨文、金文及近年考古发现可知其是殷商时期的一个重要氏族,与殷商王室有密切的关系,其贵族有在殷商王朝为官者,其地望应为今郑州市西北郊一带,其族长为卫爵。","categories":["06_族氏方国"],"year":2008,"publication":"三峡大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK_CJ520p1USDyh39IHsncTSFz6z7aji9tuIC0ADaI5Bg_TBt6M56GK_CdTEIhznU0EoABCfAD0cLbLa48i6BWTTi8-Gcl20J4WsSl6jmnhCpAEClmNaKgVh8uPX17I6VeUHWCKwRIXP3ftVgc2ghJZn2-BzqFauN89dzhxKk4dJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"208-210","volume":"30"},{"id":5436,"author":"张俊成","title":"殷商己族及其相关问题考论","abstract":"己族是殷商时期重要的族氏之一,己族的主要居住地应在今山东省寿光一带,己族与竝族合署而构成的复合族徽的含义应是族与族之间的联合关系,而非是主支和分支的关系。","categories":["06_族氏方国"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.04.029","pages":"46087","volume":"29"},{"id":5443,"author":"何景成","title":"商末周初的举族研究","abstract":"梳理&quot;举&quot;族青铜器的出土情况,结合相关的甲骨文和金文材料,可以对举族在商末周初的分布、活动状况等进行分析。商代&quot;举&quot;族铜器集中出土于河南安阳、山东费县和长清,西周时期的&quot;举&quot;族铜器则主要发现于北京琉璃河,这些地点可能在当时都分布有&quot;举&quot;族的成员。这些情况与甲骨文和金文所反映的基本一致。","categories":["06_族氏方国"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLFaBre135tv7xuwPRgWiTajew_mJoEqOtKSp87LpHSwkgfWeKwjA1k5Jb-97JO-Cw5qVwA064CQkZhy22HJgVdtuk9LnQk15pd8YzH-9MCBFZ3bDesKhdxZwQXZ05YFgQSKViUw-DyqoYboCL5sxDb71_wyJrGqbsMk_lqIm5YUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-70, 2","volume":""},{"id":5448,"author":"朱凤瀚","title":"卫簋与伯■诸器","abstract":"新见卫簋二器,与此前从海外购回的伯■诸器年代相近,约在西周穆共之际。卫簋与伯■诸器,为同一宗族成员所铸祭祀祖神的礼器。伯■与卫乃兄弟关系,其中■为长兄,系大宗族长,卫为弟,乃分支首领,是为小宗。兄弟二人均任职于王朝,先后受到周王赏赐。卫簋与伯■诸器在铭文格式、遣词造句上存在高度的一致性和重复性,表明大宗对宗族祭祀活动及相关祭祀礼器有主导权和决定权,而且同一宗族内部在祭祀礼器的制作与管理上有一套统一的制度。","categories":["06_族氏方国"],"year":2008,"publication":"南开学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQ8VJUgCPe1bS-c4Uity1WHkbxK8HDPQckKLeKbomdpM3_Q0DlvGqPZygitEcdEHocNlqKMClQ5TUR1QdISJV0iQPNavdYx0FnbjKQh50bKQUWMQWDyaEhWol6_nB2Snp2cWsvlTxDuPFxKsmeQeO57z20uG81g81l16FTqCcboQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"1-7, 141","volume":""},{"id":5461,"author":"许齐平","title":"八系氏(吉刀)簋考证","abstract":"八系氏(吉刀)是周代诸侯国的后裔。研究和明确八系氏(吉刀)簋的历史,可填补文献记载的阙失和空白,为汉唐以来至现在研究周许国史出现的悬案,提供了答案。","categories":["06_族氏方国"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIMcOxfKN2j6O6nzni19cFKsyQQsPyHCYgWwk8Gw4-XxTBcxS6edwTPpraUaa1LEaUprNMZLRO1zPFRisuRffdu-MAJO5GZCdKioQ4S-s0JNt4-IewZwicnQppdLGqZOwE4xUpHQgZuhYFQa0u6VfQUu2YZNERkwv8rhgNy9E5xIA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-65","volume":""},{"id":5465,"author":"朱爱茹","title":"邢令戈与两周邢邑","abstract":"本文对邢令戈铭文做了补充考释,并结合有关文献记载和金文资料,就邢令戈铸地邢邑的若干历史问题进行了论述。","categories":["06_族氏方国"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKBqJE64cXDcCYqCLBbQXd56Y8qHgAYepRsFyBEwubzIneM116qyi3timhBbqR0j0iLV49BZFtYRpsz_xwIrrh8o8-KLwUiQSRWfhnUEsV6DCuwBYVPuieesVkEMA8egQ-fJV9dsj_i8ExeyL37_9vjUkMz-9umevOQmJyToxA_xQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-78","volume":""},{"id":5480,"author":"吴镇烽","title":"先秦梁国考","abstract":"《路史》载伯益为唐泽虞,是为百虫将军,佐禹治水,封之于梁。但较早的文献缺裁。1993年陕西岐山县京当乡贺家村东岐山县周原博物馆东墙外西周窖藏出土一件梁伯敔簋,为西周中期之物,说明赢姓梁国的建立最迟也在西周中期之前。经研究,我们认为伯益受封梁国当是事实。商亡后梁国首领归附于周,迁封在周原,梁伯敔就是其后裔,西周中期之后可能为周所并。平王时又将其后裔秦仲的少子康封到夏阳(今陕西韩城市芝川镇西),仍称梁,以续伯益之祀。因此,梁伯敔簋对于梁国史的研究有着重要的意义。","categories":["06_族氏方国"],"year":2008,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuaAARPjQOumsN_zJqbBEFFIlUbtQPmyb2u3T7uF6MTmfdCMoMfAZzC29vEmWbPMYLByisv79m-tt1gjFol7bcSNZXkl4T4Ats4-zv6wGfOHRTN02wSISER_S9mz41ZXpvvl0HT0Y3jCoMGOxYj5ZxSZVLQ5GHt33bvwpUplt_eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46087","volume":""},{"id":5488,"author":"王蕴智; 陈淑娟","title":"应国有铭青铜器的初步考察","abstract":"应国是商周时期的一个诸侯国,其地望在今豫中平顶山地区。根据目前所刊布的发掘报告,今出土所见有关青铜礼器已达116件之多,其中有铭铜器计46件。此外传世的、收购的和出土于其他地方的应国有铭青铜器还有32件,总计有铭青铜器78件。它们对于研究古应国的兴衰及其历史文化面貌,具有重要的学术价值。","categories":["06_族氏方国"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqlanYn0KNYkz0-TzQznI7PXrurfT0eR6ygHh_oY3hfnFG-QW1bIpmFHZCyZNac8pmt-de1fyxA_WYwqbBK7TJIKgZtGT62ZhqVCrQSK4y3Ah_FJAyvqYuIdiZg4A1EROa4CNJjFCl9itUOfQUqUOUhxrAFDHRumlc5NuaEbrIIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-72, 86","volume":""},{"id":5514,"author":"王进锋; 邱咏海","title":"五年琱生尊与琱生器人物关系新论","abstract":"2006年底陕西扶风出土的五年琱生尊与过去著录的五年、六年琱生簋内容正好衔接。其铭文为理解琱生诸器错综复杂的人物关系带来了极大的方便。对琱生三器的铭文进行了分析之后认为:琱生诸器的作器者琱生就是伯氏;召伯虎就是君氏,是召族的宗君,他又被称为召;琱生是召伯虎的宗族庶长兄。妇氏是召伯虎的母亲;召姜是召伯虎的妻子;妇氏是召姜的姑姑。琱生诸器铭人物关系的明了有利于我们进一步理解琱生诸器的铭文内容。","categories":["06_族氏方国"],"year":2008,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2008.03.008","pages":"45-49","volume":""},{"id":5525,"author":"袁俊杰","title":"胙国史事探析","abstract":"胙国始封于周成王四年,始封君为周公第七子。据金文可复原出胙国国君世系四代。柞伯簋铭柞伯为胙国第一代国君,康王称第一代胙伯为小子也是合乎宗法的。柞伯鼎铭柞伯为簋铭柞伯的直系后人,铭中的幽叔很可能就是第一代胙伯的谥号。西周时期的柞伯武功高强,能征善战,深得周王赏识与重用,具有较高的军事地位,胙国虽为小国,但在西周时期也是一个以武力著称的军事强国。小邾国女子嫁为胙国夫人,这既说明生存在大国夹缝中的小邾国出于战略考虑,不得不通过婚姻外交来攀附高枝以自保,也说明在春秋时期的兼并战争中,胙国随着军事实力的下降,讲究门户的贵族婚姻原则已不再严格遵守。","categories":["06_族氏方国"],"year":2008,"publication":"河南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15991/j.cnki.411028.2008.03.013","pages":"108-113","volume":""},{"id":5541,"author":"刘华夏; 刘克甫","title":"“伯”、“仲”、“叔”、“季”与西周晋侯世系","abstract":" 近年发掘的北赵晋国墓地为研究西周考古、历史等提供了极其宝贵的资料。该墓地中出土的大量铜器,引起了专家学者的广泛关注,研究成果涵盖很多方面,但仍有若干问题悬而未决,北赵墓地中墓主身份问题","categories":["06_族氏方国"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1-kIhf2AEDasJq93NBYxjj5sSnCxhU-gsMfKO-FHqo4peKPsJaNoAkdFO64tgqN32ldW_hNzV6xbpvGgCTk26pdQCvi8_709cQ8U3fQTK_kJ8pDBSeHDm_MsH1bATDopZ1CAXd0SRtglNIfT22be4Ku5XA5hftzRVthwKlJVF9A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-77","volume":""},{"id":5544,"author":"庞小霞","title":"西周邢国二次迁封说辨析","abstract":"目前有些学者提出的邢国先始封邢丘,后又迁封邢台的说法有诸多疑点,青铜器铭文、文献、考古材料均不能支持这种观点。周初的邢国只有一次分封,其分封地就在今邢台,与河南的邢丘无涉。","categories":["06_族氏方国"],"year":2008,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2008.02.003","pages":"26-33","volume":""},{"id":5545,"author":"刘雨","title":"两周曹国铜器考","abstract":"两周时期曹国式微无闻,过去曹国的西周青铜器也从未被发现过。本文将近千年前扶风出土的姬寏母豆铭文和1992年同地出土的师■钟铭文对读,发现两器铭文完整地记录了曹国公室西周时期的世系序列,并以其与《史记》的《管蔡世家》、《三代年表》对勘,修正了《史记》的缺漏和错记。同时这一研究也顺利地识读了千年不得通解的姬寏母豆铭文,以及近年出土的师钟铭文的释读问题和断代问题。本文还对金文中的曹国铜器、曹国地望和曹都地理沿革作了初步考查。","categories":["06_族氏方国"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwk72BoEJPQW9cTYgWWoVIOX3_AuUlsRxOagDhTsPuh60YbX6f4s9DsjrlwU-s4pdyLps3YpcCAu3R4C1lPAb7XD0O0EdkFA8GH_Fcca6G0cP5URiyScJcv60xFERGYpYWKGrIjZv4f5rLynl0_mHXPDr7C1EU6SRzKRCh1hn4PA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-46","volume":""},{"id":5546,"author":"王长丰","title":"略论殷周金文族徽研究","abstract":"本文综合论述了殷周金文研究的成果及现状,对目前所见的殷周金文族徽进行了数量统计,并就殷周金文族徽的阶段性成果加以述评,分析了现阶段研究中存在的问题,并讨论了殷周金文族徽的性质以及研究方向。","categories":["06_族氏方国"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHs2xf8mt_RMYv3qxW79QCbpgMmcSsNpszahiGjcj7FrJGo2Jnijr004WlmRuy8ZFQ9Q7vPQFd67ypI_w-xWanF8IPESsuH02U6LmuiM8ZOhWr1idij4ZPZoBvbWq3T29E_XmKnKa799W2lelLfr8theYYskvqTxK70WiX7j6cLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-95","volume":""},{"id":5556,"author":"吴镇烽","title":"競之定铜器群考","abstract":"澳门出现的一组楚器,数量大。组合比较完整,且大多数铸有铭文,是近年来楚国青铜器的一次重要发现,它对于研究春秋战国时期楚国的历史、楚王世系、青铜器铸造,以及楚国与少数部族之间的关系,都有着重要的价值。根据其形制、纹饰以及铭文等方面所表现出的特征,其时代应在春秋晚期后段。盘、匜的作器者楚王酓(熊)恷,金文首次出现,亦不见于史书。经考证熊恷就是楚平王熊居,恷、居一名一字。您读为休,休,息止也。居,也有止息之义。名与字意义相因。鼎、簋、豆、鬲的作器者競之定是楚国的一位封君。盘、匜是楚平王所赐。","categories":["06_族氏方国"],"year":2008,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKjj0Cc4D0oGdno2VFc-ReRq6M5Z94jMQfNsozCvGiHRU_01cha82s5Dpw2E0V9rK4AwmQLXTxRCssYEwBgGqPSFT-rd6SNuX0N8jCpQU3iLsvlFysa0ip4pyPGpSswWZJwF1-v5B-H5_jnx8d4KUvTtDrtJjIKQm5b31rfsZzdA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-89, 145-146","volume":""},{"id":5559,"author":"何景成","title":"■卣和■族族姓","abstract":"通过对■卣铭文的分析,可知丙族是和商王室同姓的贵族家族,属于子姓。丙族铜器集中出土于山西省灵石县旌介村,以旌介铜器群为代表的青铜文化系统,具有浓厚的商文化特点。这一文化系统所代表的方国,是商王朝分封王室成员建立的,是商王朝在晋南地区建立的一个据点。","categories":["06_族氏方国"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.01.026","pages":"23-25","volume":""},{"id":5561,"author":"任伟","title":"西周燕国铜器与召公封燕问题","abstract":"","categories":["06_族氏方国"],"year":2008,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIqWRiLHhycKoCOdeQQhLyjzxAU-UFQnkop_nyr1NViODvfut8I7rKic2vHSdP47nwDJTAVYPV4jkIY3UpCMhTCBJ-iUBT3aGx1SkazCmgcCgsTiJV7-8ZEBK7HetnkqbDqOMZ__j54nfjhgK4sTSMKCuicjPIo5m6zN6l1xMnjSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-63","volume":""},{"id":5578,"author":"刘社刚; 王延敏","title":"■、■氏与虢氏关系考","abstract":"在西周金文中,有名为(?)的贵族,也有字为(?)伯、(?)仲、(?)叔的(?)氏贵族,特别是在班簋、城虢(?)生簋和(?)叔盨的铭文中,(?)字又与虢字同时出现,他们间的关系如何,各代表什么意思,学人多有研究,但又众说纷纭。笔者在读书当中,偶受启发,就此谈点个人看","categories":["06_族氏方国"],"year":2008,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPkxpPNjH80Cf5V6C04H2EWnwnD28lPNLFEUChuQxQNhVCn-PIuyu1_gyRTMzeU5uEOBfSZUMloWYimSB6vekpfXkm70oCs_xrMte2GU3apDO2ZScRKj2_5mZ1DgaLu1fEzIll6QM4Vg_znT6yBofv56lOPzI_xL5UF8qhvZaJNQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-35","volume":""},{"id":5583,"author":"金河钟","title":"殷商金文中复合族氏金文的内涵初探","abstract":"殷商时期青铜器金文大部分都是1—4个字。1字或3字的部分是单一族氏金文,对于这一部分许多学者取得了相当多的研究成果,但是对于2字或4字部分的研究却是非常不足的。我们认为2字金文部分中大部分具有氏族间结合的意义,作为复合族氏金文,其内涵如下:第一,氏族间巩固的结合关系。氏族与氏族间关系紧密有形成新氏族的可能性。第二,氏族间单纯的结合关系。这可认为是为了纪念氏族间发生的某种事件,从而在青铜器上铸刻记下来。我们认为这种结合关系无法实现新氏族的形成。第三,相关联的氏族间的结合。氏族间的结合关系有一定规律,这样的相关联的氏族间有实现结合的可能性。","categories":["06_族氏方国"],"year":2008,"publication":"山东教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJNOI_LAKtJp-qCyxKyVKpHnY4vwv9buDGV9GbrtG9PK-zWgai0TSXfFMK-gv7aFcDvK8wkTY8PE2zDMlnSofd2AWkv4_mEoZvN1B9IWt-fTjc_PqlxjE3tvYIO44O3zP1dPgivaHHRp7A6Wx0mmj3oMdYJAwXtEUgGHvvp4lhrMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-43","volume":""},{"id":6460,"author":"邵晓洁; 崔宪","title":"楚钟研究","abstract":"楚钟因楚人、楚地、楚国、楚文化而得名,在中国青铜乐钟发展史上占有极为重要的地位。本文选取楚系钟为研究对象,全面搜集了著录、传世、出土的500余件楚系钟材料,并对前人研究成果进行了全面整理和深度分析。针对当前楚钟的研究现状,鉴于楚钟的多重属性和丰富文化内涵,本文以礼乐文化为背景,将楚钟作为先秦历史文化中的一个文化事项予以看待,从外部特征、音乐性能和组合形式三个主要方面进行了分析。本文通过类型学分析,归纳了楚钟形制的基本特征,阐述了楚钟形制变化与音乐音响之间的紧密联系;通过对楚钟纹饰、铭文的分析,概括并梳理了它们的基本特点和变化过程,并由此阐释了这些外在特征所反映出的内在礼、乐文化内涵。就楚钟的音乐性能而言,本文以楚钟设计音列、调高及其特点为主要切入点,在对单批楚钟分析的基础上,梳理了楚钟音乐性能的历史轨迹,把握其时代特征,并发掘楚钟音列设置中的基本架构以及音乐性能中的核心元素。同时,以此分析","categories":["06_族氏方国"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJp4CNFcBmzViMaGwcTthZn6qPfRFAXpjjJv-EvYiN3bf6oEYPzHOrp-LxqplTjitWpbH7SFiXXfLpKXKe7hbgT6p-hCAk83WtECovrcm1YvRy1hLEtaSD47tWwv7lpUpSOPAS8etRv3yaAKTiGdHAhET020iSwbkooi3DD2883q5a9f2RYcvpv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7005,"author":"周先林","title":"了解徐国族系的钥匙——释读俦儿钟铭","abstract":"徐国是我国历史上一个十分著名的、&quot;早熟&quot;而又&quot;早衰&quot;的国家。它虽有一千六百四十九年历史,但有关徐国历史的记载却语焉不详。&quot;俦儿钟铭&quot;出现六个人名,而且人物关系明确,可谓了解徐国族系的钥匙。","categories":["06_族氏方国"],"year":2008,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsSDn6pT-1ibf0z3UESxQBRil2Bd9CWbdj9WjTG3GMIcZO6XLgwt46mov9bpkMp_bwpzdL0p_y5sK3SxO8IjtoXuhfU7ivCD8xu0y6c2K8ZT8PPfFjTOeeupPHksDnaH8B39_0FRQZZQvHv0QI0GNor9R2gj9mekk1ISwAr4k2UQvq3OpmX9JF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-68","volume":""},{"id":7009,"author":"韩嘉谷","title":"孤竹国名及相关问题","abstract":"一、关于■、■、■孤竹国是先秦时期燕山地区的一个重要方国,曾在历史舞台上发挥过重要作用,是燕国历史的重要组成部分,也是先秦时期燕山地区土著部落历史的一个缩影,更是了解周人燕国政权和当地土著部落关系的一个重要侧面。然而对于其历史至今知之甚少,甚至对其国名在金文中的释读至今犹在讨论之中。1973年,喀左北洞村在距地表30厘米深处发现一窖藏,出土5罍1瓿共6件青铜器,其中一件罍有&quot;父丁■■亚（框）■&quot;6字铭文①,其中的■为竹字,目前释读已比较一致,大概是因当地有曾是孤竹国故地的记载,因此尽管在&quot;■&quot;字还未得到释读的情况下,报告作者和唐兰先","categories":["06_族氏方国"],"year":2008,"publication":"首都博物馆丛刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVlpuPFRjrNsmlE-HnAPNIRSAZ7ocPdghHQ4y3G1lmdARy06kPkJ5bEr2739nJsHd_wngY-3YSG1BMv2qmjWpPLvSO9y7xydV8e834uF2QxP6McCk2AS8YJkOD_EUxb-HX5txG7q7qw7Pslxcgknl_CpTKubYjxv4p__0riY9y6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-23","volume":""},{"id":4846,"author":"杨亚长; 呼林贵","title":"南宫氏家族史迹概说","abstract":"文献资料与日益增多的考古发现表明,在西周时期的王畿地区曾经聚集着许多大小贵族,这些贵族的出身除了姬姓而外,同时还包括有诸多周之异姓。当时贵族们在王室中分别担任着不同的官职,而王室则在畿内颁赐给他们相对固定的采邑与寓所。由于这些贵族的官职和采邑基本上都是世袭的,即实行父子相承或者兄终弟及,因此,这种现象被研究者们称作世族世官制度。","categories":["06_族氏方国"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJC4gi_16dawJOU-DslxFbQno1u-B87hsJEtmdqBYCVPJ8jSkUTPL3TO6qr5Gaui8Bah26bY2RzxEXjcrAghT9BHNk6AARmY-aNk74bURWzFw6rdtN5fjWt6h9rfav3nIDP7Lb5FWuYWC7uoIxIo2JGE0hesuf2BFLuBYe5Z9dzfx0DSU9uzwm3&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141-144, 155","volume":""},{"id":5610,"author":"王泽文","title":"对琱生诸器人物关系的认识","abstract":"本文主要讨论五年、六年琱生簋和2006年11月新出琱生大口尊形器三篇铭文中的人物关系。结合文献及金文材料分析认为,召伯虎即伯氏、宗君,兄,是大宗宗子,代表公。妇氏即召姜,与召伯虎为夫妇。君氏为召伯虎之母,在五年簋和五年大口尊中尚在人世,但年事已高,在六年簋时已去世。幽伯幽姜为召伯虎称其先父先母。琱生即弟,与召伯虎为从兄弟,是小宗。烈祖召公即召公。","categories":["06_族氏方国"],"year":2007,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-ZdAkAMrxrODVw2G9fsqSJTv58OYipINc3KGZoxuyQYrf7V7kv7ziNOHR3osTu4_IXieYgF4v8PEAhyBK1hOil68pozclD9QY-Oss8Rkp6sc9AHOqoacE0UOCcxqzIfpZZeEWAI6Zcp6Q85NGZmZVsEMzr9cXJIhYogHHDILubg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46095","volume":""},{"id":5617,"author":"杨文山","title":"青铜器叔■父卣与邢、軧关系——两周邢国历史综合研究之六","abstract":"西周初青铜器叔■父卣的铭文,记载了邢国臣谏抗戎援軧后常驻国为軧国执政,又记载了他晚年对执政接班的安排。本文根据铭文和有关金文资料与文献记载,就邢国抗戎援軧之后的邢、軧关系,以及軧国的居地、族属、族姓和受封立国等有争议的历史问题进行了考述。","categories":["06_族氏方国"],"year":2007,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2007.05.006","pages":"25-30, 44","volume":""},{"id":5620,"author":"杨亚长","title":"夭国与散国族姓问题之辩说","abstract":"夭国与散国曾是西周时期两个较著名的方国,对于其各自的族姓学术界存在不同的看法。但依据相关铜器铭文和文献记载,夭国为姜姓、散国为姬姓的观点应较为符合实际。","categories":["06_族氏方国"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQ1QSdI5_-o8HlmOQ08Lta-e-gBQbEbQVczkOrVNAMoY7tj2bkHLIs7GssXWq8IEviJczr7v3oxsuoNrVpEcoIx5ZzNiH7z5hm_TetzxUUnnLhwg0jEM4sQuZ8_AWbyoQtxN867InreSIK7SlqjrFLoDr3dfv8N1rmWVOYQs3DTg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-41","volume":""},{"id":5637,"author":"吴良宝","title":"十七年坪阴鼎盖新考","abstract":"十七年坪阴鼎盖的国别,因铭文中有&quot;视事&quot;一职,学者比较一致地定为魏器,但对坪阴的归属、器物的年代等问题尚有争议。本文对诸说进行分析之后认为.坪阴属周、后一度归魏的可能性极大,鼎盖的铸造年代则有魏惠王、襄王两种可能。同时,对新披露的&quot;二十九年叚阳库冶戈&quot;的国别、年代进行了考证。","categories":["06_族氏方国"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJic4tZR4UbXt0q-fwhuK90_lel5AAdrEN9tdgKjoTpFnQe6hhjwriyhetrOkkJBRTW7uVV3lUHJ9y1m1gtzv5Dp5q_cwnXd5m-ku_kJOuGRJK4LZ0WZwFEZGfcbecaYiWtAz5Y90IBYuGJQB4WHjgZeVI5joCWgdq4-uipDFnNKQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46119","volume":""},{"id":5641,"author":"张莉","title":"登封告成春秋郑国贵族墓研究","abstract":"河南登封市告成镇友掘出土5座春秋时期贵族墓葬,其中2座墓内出土的青铜器铸有铭文,它不仅对该墓葬群时代断定、对墓主人的身份以及春秋时期郑国历史的了解有较大帮助,而且依据史料进行观察与研究后.认为该墓葬群可能与郑国初期公叔段的墓葬群有关。","categories":["06_族氏方国"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLH3ICpfp3rf55qs3kgKPsw78PcLcqetpnu4oyLZD3BLrINRdCIdx0ZD2qHj45UyycdGn5z9Jgc1UZ6s0UuyqaHfH8eNLRFw65g7PKBUD1QFq91CzzFvNHNveJaWEhcOTXNdbVCdrPbrIl7nkRV1kPqQ9W_gGa-2MuKrqHEYLlLqw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-80","volume":""},{"id":5646,"author":"梁宁森","title":"从青铜铭文看虢国贵族姓氏名字结构","abstract":"虢国是西周至春秋时期姬姓诸侯封国,虢国贵族的姓氏名字历史悠久,结构复杂多变,但总体上仍遵循周制。","categories":["06_族氏方国"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsTT6ZrOtan_UzEI_mo5YXhHmkZVXn1YPP-A28MLPFlWdifggZGiDwQNcXT2DAU6Kjd9egKndmx7twmewjZstJjmA7IOX3ik2dEyHJo9bJ6vGP4dlI5y42HONV1F15vs_rncthIt9_QUSrMSF6z-KqjRwvx2yv5NZczOBl7adnLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-101","volume":""},{"id":5650,"author":"韩巍","title":"眉县盠器群的族姓、年代及相关问题","abstract":"","categories":["06_族氏方国"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIHwvwvACmWTWwlLBx9axYUqHddEeMQG4lVoLyzfqTZQKbnaMLOtWEPsYA2DcFCNi46fNfI34Wt7Zj1uygO0hLZaiIvqr3lFS7ShoRaFS_4WW2sX_c8ra7ML6vltyppP-pygY-naHWpkQUIDf7BQuBkF5R9JntHAYRGkMsvX56-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-21","volume":""},{"id":5661,"author":"何景成","title":"商代史族研究","abstract":"本文根据甲骨文、青铜器铭文中有关商代史族的记载,结合文献中薛国的记载,认为“史”应该是商代薛国的族氏铭文,山东前掌大墓地应该是薛国的贵族墓地。","categories":["06_族氏方国"],"year":2007,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2007.02.012","pages":"102-104, 106, 105","volume":""},{"id":5663,"author":"庞小霞","title":"二十世纪以来商周邢都、邢国、邢地研究综述","abstract":"","categories":["06_族氏方国"],"year":2007,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUlgbxEH7Pslh7bYJ_Eo-8Syb8OPwrEnqEVLS0MfKdrPvDmcszXOixc_qUsF1b3YcW-WoagzXcJ9tyMxRSQMuoJWrQP6YvU6j7t79Vg_aBPCXqTNfACqnXVdOeJats69UgICN_nGwSNOvc9PW9BJkkeLGl4DYXiW-BBSuyTpEmAA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46311","volume":""},{"id":5679,"author":"田亚岐; 张文江","title":"礼县大堡子山秦陵墓主考辨","abstract":"自上世纪末甘肃礼县大堡子山春秋早期秦墓惨遭盗掘的十多年来,学界对劫余后经考古发掘清理的两座秦公大墓之主多在襄公、文公、宪公及夫人间考虑,迄今认识不一。本文拟以文献所记和考古发现资料作为考证依据,认为大堡子山必有以秦公礼制而葬的静公大墓,通过M2是在M3连同车马坑建成后夹挤其间的奇特葬格局;两座大墓连同车马坑在内的整个墓地统一大面积覆盖纯匀的五花土,表明两座大墓是同时埋葬或同时封填墓口的遗迹;随葬器型、纹饰尤其铭文书体的差异只体现在M2一墓所出的器物上这一奇怪的差异以及十多年来国内外相继出现的各种迹象表明是出自大堡子山的秦子器,尤其秦子簋盖夔纹确切证明秦子簋是大堡子山的出土物。“秦子”,即秦文公太子静公等考证,认为两座墓之一M3为嬴秦第二代国君秦文公之墓,型制较小的M2则是未享国而卒的文公太子静公墓,即以秦公礼制而葬的秦子墓。","categories":["06_族氏方国"],"year":2007,"publication":"唐都学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJC73RGJms0VqGrh24y2Zig_e0k-0yDYJuwKpSIbSjfPcJKpblHV0jTf04A2eNGU5p7yqhIbnAQrQKDu38h-mG5IBOwDsz21QBirjB6eJ8Pdykh4boEV8z9m0OZu_LmiOyTnfvcwZBcQbRasmmdF4S9SgokeNuCBgKpTvFu-pzcjg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-76","volume":""},{"id":5680,"author":"韩巍","title":"周原强家西周铜器群世系问题辨析","abstract":"本文对周原强家窖藏青铜器群的世系问题重新进行清理,将学者以往认为属于这一家族的师望组铜器排除出去,进而重新推定了该家族世系。作者认为强家器群属于虢叔氏,该家族在西周中期从虢季氏分出,一直延续到春秋初年。同时,还对西周中晚期虢叔氏家族的世系做了尝试性复原。","categories":["06_族氏方国"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPtkEsR3gsKEXKiNeLjsgGtEbN_qoJd71RCf01mf9qLx0Nexi4gSun42DT7td341soTJJBLnWq6KsJnLb5zCuUPzATxkDKOI34aeaAPBAjqbVhatKcR08iU7SKF-MfMnWgJtjIbf8eJM-1lz3R7qI4NV1EWC2VDPd72CTcc2f2dg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-75, 78","volume":""},{"id":5683,"author":"王长丰","title":"“息”方国族氏考","abstract":"甲骨卜辞就有“息”字,殷周金文也有不少与“息”相关的资料。周代息国是姬姓贵族袭居商代息国故地而得名。周代息地在今息县城西南十里青龙寺附近,“息”、“鄎”是两个不同的地理概念。","categories":["06_族氏方国"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKM6xAJuL9OzqJiN28fLmzC5dHWjWiSATV2Ayi166TY78kn6yr3DyQ5roSGiZ9UAaiiTeZQK7EEp30l6d7S15EDdgVnhaaTUkWvryOsV0gvAo1MR_fJha2ozf3XDaWFqSMFPe6v13NQyU15HiZc_uW_3MpsEcFu46eXlOsspRt4tA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-65","volume":""},{"id":5689,"author":"王长丰","title":"“令支”方国族氏考","abstract":"从字形上对殷周甲骨卜辞、金文族徽进行分析,例证了金文族徽文字“■”、“■”即是“令支”的合文,“令支”为殷周时古国,地望在今河北省迁安县西,古有令支县故城。","categories":["06_族氏方国"],"year":2007,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVHQApYa3PNqJYqw-hHJkI0wKQ6SGBXCpNvLQ0Bc1wqRRE9kkIZQTPkogLy-XWFGVIRcufqxgLd9ziQFVachkBAjugVKWJu-z1rYxRDnuHsh20FfA181tiVd8_Rr71FcT6fFu-0WuhP9fstJeGLfCFSvECy-ti4wPmtuos5KiUCg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":5704,"author":"雷英","title":"小议养器与养国","abstract":"桐柏月河墓地出土的“■”器和“■”器都应该是养国的器物,“番昶”器与“■”器性质是不同的。所谓“番”(或沈),其封地当在今河南信阳固始县境,“番昶”器也主要集中于信阳一带,故“番昶”应为番(沈)下的一个分支,而与“■”无关。","categories":["06_族氏方国"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4vJ50U2PdX4j6SiIf1Xz4kDGIplRXYqSqbEnZQqzS2dZgh38a6aU--bO6Qk3r_xEqxXC22cmKyv9FHiv-2bRss1bkZ0rZ729bGl_dAKz_38S5VSqwoL98RsWMnQExfL0ZjSjqXN6L4Vy59AEKh__5Yi4xpEPcb_nCbpsQOMGPxQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-63, 68","volume":""},{"id":6473,"author":"雒有仓; 张懋镕","title":"商周青铜器族徽文字综合研究","abstract":"族徽文字是研究商周社会家族结构、家族形态、族氏关系以及文化礼俗的重要资料，但由于材料零碎分散、考释不易、分期断代困难，目前对其史料价值的认识和利用，尚存在较多的歧义和困难。本文是对商周青铜器族徽文字的综合研究，内容主要包括族徽文字渊源与性质、族徽文字分期断代、族徽文字分类以及族氏关系研究等四个方面。全文共由六部分构成。首先为绪论，在绪论中我们对一千年来族徽文字研究的历史与现状进行了回顾和总结，具体说明了当前族徽文字研究已取得的主要研究成果及存在的主要问题。然后，在此基础上提出了本论文研究内容的四个方面，阐述了有关的研究思路与方法，以及研究的意义所在。第一章为族徽文字渊源与性质研究。关于渊源问题，我们主要从两个方面进行了考察：一是族徽文字在青铜器上出现的具体时代；二是族徽文字出现最早能追溯到什么时候。我们考察的结论是：前者在商代早期，后者大约在公元前6000～前5000之间的贾湖遗址时期。关","categories":["06_族氏方国"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYLvhCfrGch7igHMzUWQkRTolCD5YIVv6_I-IHwsi_PnQ0Bfuq9rZQ6wZrSKpRDti4m1MpfbxdFwTe5k1RnYG3cGB9Buvv0Ljo8-G4rRbw6ZGCO_iDOetlCu-7fQRmB1AZ5mFNDhpEpflRGAwZSamy8opxh6mVGyKuubJHmq6XttupDBoVu-S0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6827,"author":"赵燕姣; 臧振","title":"从《墙盘》、《（來辶）盘》看西周世族政治","abstract":"眾所周知，後世的政治制度大多濫觴於先秦之際，但囿於史料和出土文物的匱乏，夏、商兩朝的歷史多不可考。幸而考古發掘的不斷進展，特別是1976年底扶風莊白一號窖藏和2003年初眉縣楊家村兩大窖藏的發現，使得我們得以對西周的政治制度展開進一步的探討。各方面專家、學者的研究成果不斷深入，成果斐然，但略顯不足的是據銘文研究西周家族史進而探析世族政治的力度不夠。所有這些問題，都很困難，需要反復論證，才可能趨於一致或逐步清晰。筆者不揣陋見，就教於同仁。但由於學識所限，難免挂一漏萬，旨在抛磚引玉，以期引起學界對此問題的關注並進而深入。簡而述之，本文主要從以下五個部分進行了探討：前言部分，簡要概括了兩大窖藏的出土所產生的不可估量的價值，進而對學界的研究現狀做了條理概括，主要涉及銅器斷代、相關地名的定位以及銘文通讀和文字的隸定，如此等等。盡管成果顯著，但據金文追述家族史進而探析世族政治力度略顯不夠，此乃本文的寫","categories":["06_族氏方国"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyoumRvMyKNX-V-M1b1ZdEAkJk6ntA-R799eNr0toAwQH5zHFABEZ_VdGLZaUH2YNcMr2xJ_ExP7yMkCaW2km4kZ944jUOhRusLLTwgEwbmtCj6_aKDWy86SD5oel4vx3zU7qxbeTSllPAMzVLfi0aJuTT3DR6XxkFZZKjd0qclXxl0M2S8u7r&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6841,"author":"刘传宾; 冯胜君","title":"西周青铜器铭文土地转让研究","abstract":"本文是關於西周時期汲及土地轉讓的青銅器銘文的專題研究。對西周土地問題研究的重點，以往一直停留在傳世文獻上，由於這方面資料十分匱乏，所以研究工作本身受到了極大的束縛。銅器銘文的大量出現無疑為西周土地問題研究重新開啟了一扇大門，學者們也適時的將這部分材料應用到研究工作中去，取得了一個又一個重大的成果。但是這些研究工作或只作零星介紹、淺嘗輒止；或作通盤考察，但漏蒐或誤蒐部分銘文；再者，新的資料、新的成果不斷的涌現，因此有必要對這部分内容作一下綜合的整理和考察。本文就是本著這樣一個目的，蒐集歷年來學者們的研究成果，並結合新材料對西周時期汲及土地轉讓的青銅器銘文作綜合性的研究，使我們能夠對西周土地問題有進一步的認識。本文分為兩大部分，第一部分對汲及土地轉讓的青銅器銘文逐一作進一步的研究，主要是在前人研究成果之上，對銘文中重要的、釋誤的詞、句加以補充。第二部分是在第一部分的基礎之上，結合史料對銘文所揭","categories":["06_族氏方国"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLHgrI6ZZt9GTLpzOiYkdGEmMOLUVVJ7tGhCJe8U4MpB-o5Zic52m93ELPXUrs9Ju8A-fZn_7sLgzWzPL_k_W2xIMQaPrQNY3OnRM8dB1hKqFnlY_F6YLgUO8r7K3WGi0Ql33cl9Ksu5gToybiwri-aY96RZv4syeGva9Twj6C07ZmjSkjN90LV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7038,"author":"李鲁滕","title":"“虖台(丘)”略考","abstract":"滕州市博物馆藏有一铜戈,其援窄平,中起脊,前锋呈三角形。斜角长方形内,内有一穿。长胡,三穿。形制为典型的战国早期器(图一:1)。胡上铸铭文一行&quot;虖台丘子休之俈(造)&quot;(以下简称&quot;子休&quot;戈)。1979年出土于滕州市西约7公里的姜屯镇庄里西村滕国贵族墓地。戈铭简单明了,例为地名(或国名)+作器者名之通式。唯地名(或国名)&quot;虖台丘&quot;,鲜为史家涉足。故笔者不揣浅陋,试为之解。","categories":["06_族氏方国"],"year":2007,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKH3M_-XpzVUup2VwFZbjwxPqRvfTphq9rCCyRca3HB-vpS_mZK7FjMHLmzSPy95Xdg38--DKmd38fWpad9WlBvms7dOGr6O2gzfb7L0_MQZvMFJ8190a1GhLZaYbzmhb8wwf5Ggi9zroVGB-73xyP2aGcEiX5qJ1t_6SHBfDp9Fw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-205","volume":"6"},{"id":5775,"author":"王长丰","title":"竝方国族氏考","abstract":"本文运用殷周甲骨卜辞与殷周金文方国族氏徽文字互证的方法,对殷周时期的“竝”方国进行了综合研究,考证出“竝”方国的地望在今河南固始附近。","categories":["06_族氏方国"],"year":2006,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKAtQbaP1izCWskYisgdci6iup2hgUB6N9RVvzgROevA6jDM7_mkqV2GNWbVlTlL8vD3iz4VW-TRmakMba_GKRFFeNus28rllP-280zDCpUzt7PVhds6WyvqoUOcvMJQh5gA107uDhIE-cmAHLGJK-956GqCBC3RYDcqx6taIYgBg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-68, 92","volume":""},{"id":5780,"author":"赵平安","title":"邿子中■的名称和邿国的姓氏问题","abstract":"本文讨论了邿子中的名称和邿国的姓氏问题。","categories":["06_族氏方国"],"year":2006,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvsFPYM00eOOhjNwV2oVym6boZYYsxFz6b8h1loXGf8GDkvN6p80DSfAZ1vj13PxjOK_W9y-dy51S9vmzUAI9yssNE7b7Jvs6YOUYBiwRNyB7yQegH6q4AEHONSFKoNk6Y2FI_ESXEp1_wHHvn822EQp-6L7HJgTgtYkiDOgCQMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-28","volume":""},{"id":5785,"author":"张应桥","title":"西周卫国国君康伯懋事迹考","abstract":"康伯,名懋,是西周成康时期叱咤风云的人物,卫国第二代国君,卫康叔元子,“八师”统帅。传世文献和金文均记载有其事迹。文献中又称其为康伯、王孙牟、康伯髡,金文中称其为伯懋父、康伯。他生前曾统帅“殷八师”又称“成周八师”南征北战,东讨西","categories":["06_族氏方国"],"year":2006,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzj8v1ETuvef3WKb9k2BV9mhY-BD7jRm_rYQVliwQSVdkI9DVF86LcT1f6XAhWtnSCa48vPYTdN_2gZDoe96a0YVZ3WmSahWv-hABJWZuo-iF6UwDtUGBJrAduecOuVOQuTiOM2WOiW0RlsjmAeiwSprteaPew0EbdveKkFnJ96A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-96","volume":""},{"id":5796,"author":"杨玉生","title":"论召公封燕及其对燕文化的影响","abstract":"召公封燕及其这一问题的研究是燕国历史和燕文化研究中非常重要的一个问题。根据大量考古资料,主要是殷墟甲骨文的发现和一大批青铜器铭文的发现,结合史籍的有关记载,特别是北京琉璃河考古发掘的成果,可以确定,西周燕国的建立是在商代子姓燕国的基础上建立的,西周燕国的历史始于召公奭之封,地点在北京琉璃河董家林古城,时间在公元前1042年。召公封燕的确定对燕国历史和燕文化的研究具有重要意义。","categories":["06_族氏方国"],"year":2006,"publication":"河北大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIWFZ1ti8BjBMAFScbGXM3gu0eOeg2_N_Kug0zAvAnfTTCwmd_FLzS1TxIE016vfHy4ikpoaWN81IZNPA0OMYCjRZBKB8kzpiXS0CP2ypqieM--kVgkBQHNnvu2x-ybJEz9RKK3o_Gn9Ah5JypCgesm_d4SYFW4MszWEaj4PC5mQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-59","volume":""},{"id":5797,"author":"袁俊杰","title":"作册般铜鼋所记史事的性质","abstract":"作册般铜鼋是一件珍贵的商代末期青铜器。其铭文所记史事和器物造型所展现的史实是射礼,如果把它与田猎挂钩,则有许多疑窦；如果把它与射礼相联系,则颇能印证文献和西周金文的有关记载。可以说西周辟雍大池的水上射礼很有可能渊源于商代晚期的洹水水上射礼。周礼“三番射”中的某些仪节和必射四矢之寓意,在商代晚期就已经存在。射鱼也是当时常见的一种射礼,射鼋则是射鱼的一项重要射礼内容。本文还对鼋铭作了考释,并认定该器是铭功的庸器、再现商王射艺的实物模型。铜鼋的铭文与造型构思所反映的史事是商代末期王在洹水进行的一次水上射礼活动。","categories":["06_族氏方国"],"year":2006,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2006.04.002","pages":"39-44","volume":""},{"id":5807,"author":"吴长青","title":"寿县李三孤堆楚器的研究与探索","abstract":"本文介绍了李三孤堆楚墓所出青铜器的流散和收藏慵况,回顾了自20世纪30年代初至今学者们对这批楚器的研究历程及成果,并从铭文释读、器物形制、器群主人及其埋葬环境几方面分别阐述了各家之说,最后通过回顾和分析总结出目前这一研究中存在的问题,提出了深入进行这一研究的重要意义,并指出了今后的研究方向。","categories":["06_族氏方国"],"year":2006,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2006.06.010","pages":"117-127, 159","volume":""},{"id":5808,"author":"陈青荣","title":"厥子尊与厥史探","abstract":"厥,是商周时期海岱地区的一个东夷小国,由于传世文献奇缺,人们对其历史和文化面貌知之甚少。据甲骨文和金文知其在商代已经建国,西周被封为子爵国,大约存有400年以上的历史。","categories":["06_族氏方国"],"year":2006,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2006.04.026","pages":"100-103","volume":""},{"id":5822,"author":"王冠英","title":"子龙鼎的年代与子龙族氏地望","abstract":"子龙鼎是目前发现的商末周初形体最大的圆形青铜鼎。该鼎通高1.03米,耳高22厘米,腹深43厘米,足高36.5厘米,体积仅次于陕西淳化县出土的蹄足鼎(高122厘米),但年代要早于淳化鼎。子龙鼎立耳外撇,大口,折沿,深腹,下腹微鼓,圜底,三足粗壮呈蹄足型。上腹部饰三组","categories":["06_族氏方国"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpuMYkv7aHFvBRNllNZg1YqFSl-Idk8UiNaOIDhWTGwh6HqvPa_olXukF3w3MNzWbh7rA4bEoGfilMJfNrbQudXYg4zstZ-MxZantffLe6M4GU2EfoodVhqAUpxJTT5BBw0EWxAi9cInbBxOPZwpQ83lTqlCcXApVv3F3MB_UQtg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-17","volume":""},{"id":5825,"author":"张经","title":"西周金文中的土与田","abstract":"According to the inscription on bronze in the Western Zhou, aristocrat were award several kinds of land, such as Cai, Tu, Tian and Li. In this thesis we discussed the difference between Tu and Tian.","categories":["06_族氏方国"],"year":2006,"publication":"农业考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWUzDGFhXcZDxV7cR-ax-eIgjlY_dqHgWuNN_1H-7Tno1lQIoMi2CtRC0-es-TxNM1j3tLowBkTPa9NOiK2G_uOlmAeaHFY3Lo705zMJ3LhjWeORyOuKqybzvRxmS9x3erZZxGkM3JHzMUmF7XP9fi9ePv-QXVvNZ2m7Ry3PKY5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-151","volume":""},{"id":6491,"author":"王长丰; 王蕴智","title":"殷周金文族徽整理与研究","abstract":"本论文在全面总结殷周甲金文释字、证史等研究成果的基础上，利用考古学、古文字学、文献学及历史地理等相关学科知识，对殷周金文族徽进行了全面的统计、整理与研究。本论文主要学术观点及创新点表现在以下几个方面：首先，我们对殷周金文族徽的研究状况进行了历史性的回顾，就当前的学术研究及学术趋向进行了概述；并对目前所见的殷周金文总数进行了统计，在全部14000余器金文中，西周中期以前铭文总数为10000万余器，其中带有族徽铭文者约7200余器，占70％以上。然后，我们对殷周金文族徽的类型特点、判别原则与整理方法进行了归纳与研究，总结了10类族徽铭文存在的形式和判断标准；提出了8项科学地整理与研究殷周金文族徽的方法。其次，我们对目前所见的全部殷周金文族徽进行隶释、分类、统计、系联、整理与研究；殷周金文族徽总计有2025种不同形式，按族徽龙头字系联，初步分为370余类族徽字群；在隶释、分类、统计、系联、整理的","categories":["06_族氏方国"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxXitQM99QKm4eB1jkK_U5jpAGyZQQUWf02vskY622xFCQIuAlYonQNVYCAeNeNojVOy1FUl4UoHlbE7HXeYBuhnhd77gOOx8bOSx3KSFD0Ry4-t_XREtzkkdRnUtcEorBr-dw5v7ZeIvBOXeEeOMqM_icUvS-3Bhec4--mJYYVax-fNRKPMmo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6851,"author":"杨亚长","title":"毛氏与毕氏家族史迹概说","abstract":"毛氏与毕氏家族是西周时期的世袭贵族,其史迹不仅见于文献记载,而且见证于青铜器铭文以及甲骨文。出于兴趣,笔者曾对这两大家族的来源、谱系以及封邑等问题颇为留意, 并对相关资料进行过辑录与初步梳理。现作毛氏与毕氏家族史迹概说如下,希望能够作为今后进一步深入探讨的参考。","categories":["06_族氏方国"],"year":2006,"publication":"炎帝·姜炎文化与和谐社会国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgJj3bRsk1th0JwpY2euYRfTb14Wa4oMI7MSbichRYzb9JozYb3_CSoMaBi3jHhsOyXBEBCiDi9prVCtOGkDoPIZukrLX7576gkqocLy89WSSGq8yVTDbfeAvVl4aQhFwckv00O1nAY8FKohvzR7DYDNzwcE1i-_Gj5pzCSVW8EOwHvj_B8PLY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"320-324","volume":""},{"id":6860,"author":"孙永珍; 黄天树","title":"两周媵器铭文研究","abstract":"青銅器銘文是鑄刻在青銅器上的文字,又稱金文。金文對研究我國古代歷史尤其是先秦歷史具有很重要的意義。在我們研究青銅器的數百年歷史中,前輩學者已經在定名分類、銘文考釋、斷代分期等領域爲我們奠定了堅實的基礎,但是,有一類青銅器至今還未有系統細緻的研究,這就是本文要探討的媵器。青銅器有許多的類別,其中有一類是古人專爲嫁女而作的,統稱爲“媵器”。在已經出土的上萬件有銘青銅器中,媵器只占很小的比例,但是卻具有非常重要的研究意義。在探討兩周的婦女稱謂、女性地位及權利、婚姻制度以及國族聯姻等方面,媵器銘文都起著不容忽視的作用。","categories":["06_族氏方国"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCYrqqHikmsxPGgOdYQgS6JIPNP1hJa4rzpX4Z53nX14SrLibofmK94NuKyvRb2YXnjNjAFJQJnxCbaheDZYkep_mGwcqFwuH9q9tfcGUfRFMWM_tqCYFngKZnC_o1ezc87bLugmHBzi9DTnYQXegpapodM2Hx7OJsFG2KyM4eL5HH4pNb2zpN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7065,"author":"董珊","title":"论春平侯及其相关问题","abstract":"战国晚期的赵国封君有春平侯,见于《战国策·赵策四》;《史记·赵世家》、刘向《列女传》卷七作&quot;春平君&quot;。目前发现&quot;相邦春平侯&quot;监造的铜铍多达16件。本文从文献记载和器物铭文两方面讨论春平侯的年代和事迹。以往关于春平侯铍的讨论,常常羼杂了很多民国时代的伪刻。今除去伪刻①,可以根据纪年高低把相邦春平侯铍分为两类,第一类共有10件,纪年全都是十七年（图一、图二）。这里举&quot;邦左库&quot;与&quot;邦右库&quot;各一件铭文为代表:","categories":["06_族氏方国"],"year":2006,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKS9EaWdLa8BCpmtz2yShQ5hIcDWqEOsPzjVcstTv77wN8P8f8mpVNFhYhnnwxx-kkXPoW_bT67XiVuXU6DpIbLqVYcKAF_U54yTehUXddqDzbwlDCMeykfuvCuD4iozve1gDsVMuqOt_ab7oVL63LYcouTbZYimjGnx6eDiJ4_jg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"446-460","volume":""},{"id":7066,"author":"牛世山","title":"西周时期的楚与荆","abstract":"商周金文和先秦典籍中关于国或族的称谓有&quot;楚&quot;、&quot;楚荆&quot;、&quot;荆楚&quot;、&quot;荆&quot;、&quot;荆蛮&quot;之名,其中&quot;楚&quot;应指芈姓楚国族,现无疑义,至于其他称呼,或以为全指楚国或楚族,是其不同的称呼,或认为并非全为楚国或楚族之称,有的应该指荆族,并涉及楚、荆地望及文化关系等问题。本文在前人研究的基础上,试就楚与荆之别、西周时期的楚与荆族地望及其文化关系等作进一步探讨。","categories":["06_族氏方国"],"year":2006,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKS9EaWdLa8BCpmtz2yShQ5hIcDWqEOsPxPBQl2KO4rlETH78fwQnQEYdsZ0OTxRsFOmXCaw1TBxvAvMoGuX8QZHHStGS22ewlJAVAy0AksDuj5UfDiqv5xFBimSDBj29_FBKxewJfIOL1gS_kkC3WOdeoqTmRdUQYmYe_s7w1FJg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"285-299","volume":"5"},{"id":7067,"author":"李伯谦","title":"从殷墟青铜器族徽所代表的族氏的地理分布看商王朝的统辖范围与统辖措施","abstract":"在中国上古史上,自公元前16世纪初汤灭夏建立商朝,至公元前11世纪武王伐纣商朝灭亡,商王朝在长达五个多世纪的历史进程中,学者们根据其势力的强弱变化,或以武丁为界分为商朝前期、后期两大阶段①,或以汤都亳至仲丁迁隞,仲丁迁隞至武丁即位,武丁即位至帝辛（纣）灭亡,分为早、中、晚三期②。在商朝前期或商朝早、中期,根据考古发现已经知道,以黄河中游为中心,商文化往北以拒马河、北易水为界与夏家店下层文化为邻,并曾一度突进到河北宣化盆地的壶流河流域;往西最远已进入陕西关中平原;往南的分布已濒临长江,影响所及已过江南;往东随着对岳石文化的逐步排除,已推进到山东淄、弥河流域。在东西、南北各长约1000公","categories":["06_族氏方国"],"year":2006,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKS9EaWdLa8BCpmtz2yShQ5hIcDWqEOsPzjVcstTv77wN8P8f8mpVNFfWoG0GiZXc_jvaXyHEL4Y1tRL1u4iTuKOCWGFOVqPTQIqJ7GKRk-KntmCeDH50ygBGd3dTcl30XNLrn32iBW6iZ0sUtoNoJfq6vNDNqHminoQO_rgOAadA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-153","volume":""},{"id":7094,"author":"严志斌","title":"殷墟西区墓地所见铜器铭文探讨","abstract":"殷代的墓葬迄今已发现不少,但时至今日,成片成规模聚集的大型墓地发现和发掘的还不多。殷墟西区自1960年以来已发掘墓葬近2000座[1],绝大多数墓都较有规律地集中成片分布。殷墟西区墓地因其发掘面积大,发现的墓葬数量多,自从其发掘报告发表以来,就成了研究殷代社会,尤其是社会组织形式的最为重要和典型的考古材料。殷墟西区墓地所见各区铜器铭文,尤其是其中的族徽铭文,对探讨殷代社会关系、家族形式无疑具有更为直接的作用。殷墟西区墓地材料发表后,陆续有学者发表","categories":["06_族氏方国"],"year":2006,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaDAunEE3Y9xeqPbND1SERStEID2xcBWRMC1wAKvlQjRzSeBfV7ynRNbpYNHFcQSZ1uoV-AJwjFQEip3HF3BsxOINiDjeNMlftS9LRJFrlCn04yOq5hvSNxpNRItbqh7ipEwkKaIoUOgSQ91MKgx-j2ksU1jQcTtYeH7kzYHu4sg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"450-458","volume":""},{"id":7095,"author":"唐锦琼","title":"鹿邑太清宫“长子口”墓国属问题的一点思考","abstract":"1997年在河南鹿邑太清官遗址发掘的&quot;长子口&quot;墓[1]是近年来商周考古的重要收获之一。这座墓葬丰厚的发掘成果也引起了学者们的极大兴趣,并对墓葬内反映出的许多问题提出了有见地的看法,特别是对墓主的身份及国属等问题展开了热烈的讨论。作为后学者,现就这一问题进行了一些探讨,以求教于诸位方家。由于这座墓葬所具有的浓郁商文化因素,所处的西周初年特殊的历史时段,学者们普遍认为这是一座殷遗民的墓葬。加上墓葬形制、随葬品等反映出墓主身份相当高,","categories":["06_族氏方国"],"year":2006,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaDAunEE3Y9xeqPbND1SERStEID2xcBWRMC1wAKvlQjRzSeBfV7ynR6F7U94sNtZVJOFP4C70oHFln0owO6uU7jFhN9mRuPt1OVKy_ea9H3UjBTgNI1zV9MHxNEwLzaeJlzjmDdf-DTJimUGod5eBX6Z8lvCpDS1YLz9UE-2cRzg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"472-482","volume":""},{"id":4855,"author":"杨亚长","title":"毛氏与毕氏家族史迹概说","abstract":"毛氏与毕氏家族是西周时期的世袭贵族,其史迹不仅见于文献记载,而且见证于青铜器铭文以及甲骨文。出于兴趣,笔者曾对这两大家族的来源、谱系以及封邑等问题颇为留意,并对相关资料进行过辑录与初步梳理。现作毛氏与毕氏家族史迹概说如下,希望能够作为今后进一步深入探讨的参考。","categories":["06_族氏方国"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhhIY2yd4HdFceFNlMfZ3C-4Sjpw-Rbv5EHIKILwF9MNSKLW-Zz7R2cVNe4-XTu5qdyh9Fb3W3Uu5sIYsTs72NXvV2JPuMKl8joPjodPNsOT7ZVx_KN61REY1rnEIMVBwIyKml2bHOmD3tu688h1Lqm3awHVKXs24TowW1cVZQxICHJaRQY4T6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-93","volume":""},{"id":5841,"author":"周润垦; 王书敏; 张浩林","title":"宁镇地区土墩墓的族属","abstract":"以往的考古发掘和研究结果显示,土墩墓分布的范围东到上海金山,西至皖南屯溪, 南至苏浙交界的太湖沿线,北达长江以北的六合、仪征,而以宁镇地区的土墩墓分布最为密集。","categories":["06_族氏方国"],"year":2005,"publication":"中国文化遗产","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKztTCmn_gm_U9E72WsOsMWK0XnqgSHIwMcBXfyP04l1shlcExmJLcaS6Jw2QmKlyNFzkMoBY20FGjvbPqFsIx5d5cw7nzh9khekN648x7bvq5DJDZzmTnTWRTg42D4h90cUaHfJAjaPH-aqT58sHc-Yad6rUtG0whs0UDMAhTusQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-43","volume":""},{"id":5848,"author":"杨文山","title":"青铜器臣谏簋与“邢侯搏戎”——两周邢国历史综合研究之五","abstract":"青铜器臣谏簋铭文涉及到邢侯的“搏戎”,是研究邢国“迁封”之后,援“軝”抗“戎”战事的重要材料。本文根据有关金文资料和文献记载,就邢侯对“戎”的抵御与“戎”的族属等有争议的历史问题试作考述。","categories":["06_族氏方国"],"year":2005,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2005.06.003","pages":"20-29","volume":""},{"id":5852,"author":"李学勤","title":"论秦子簋盖及其意义","abstract":"新出现的一件簋盖,已经残缺,但盖内文字基本保存,系全铭的后半。由铭文释读知道,器主为秦子。盖捉手内的纹饰,与甘肃礼县大堡子山秦公大墓M2所出漆匣花纹相似。结合近期所见秦子钟、戈等考虑,秦子年代当定在东周初年,很可能是秦文公太子静公,他比文公早卒两年。这给推断大堡子山大墓的墓主提供了前所未知的线索。","categories":["06_族氏方国"],"year":2005,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2005.06.002","pages":"21-26, 155","volume":""},{"id":5879,"author":"秦进才; 张玉","title":"由“长信宫”灯铭文说“阳信家”铜器的最初所有者问题","abstract":"出土于满城汉墓的长信宫灯是阳信家铜器中的一件,关于其最初的所有者目前至少有三种看法。本文从汉代尚主制度与如淳注,刘揭父子与汉初列侯制度,没收赃物制度与阳信家铜器,长信宫与阳信家铜器等四方面,再次申述长信宫灯与阳信家铜器的最初所有者有可能是阳信侯刘揭父子。","categories":["06_族氏方国"],"year":2005,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2005.04.003","pages":"23-30","volume":""},{"id":5882,"author":"周言","title":"也谈强家村西周青铜器群世系问题","abstract":"陕西扶风强家村西周青铜器群发现于1974 年12月,虽仅7件,但包括了著名的师(?)鼎、师望鼎、即簋、师丞钟四件有铭文青铜器。因其铭文相互关联,被证明为同一家族所有,非常重要,因此一出土就受到考古和古文字学界的密切关注,资料公布之后,学者们对此进行了分类研究。两年后的1976年12月,与此邻近的白家庄又发现了庄白一号窖藏,所埋藏的也是家族器群,共出土铜器103件,有铭者74件,包括了著名的(?)器和史墙盘。","categories":["06_族氏方国"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5XIBgEALFGkuAvhACQzvkqwm_DvvwrvD2mLtcxsk3p1h8ZltgR6Fvti5RlBWlVPwnFnV0H6Iz-qvMcCGbJZDKYirjJa_Yu5biK76hBZed5-9oTLtVkGjdXTvk6D-_jHamVkgzD6q1M9wk2SneXJhYRqC1GjKuSd8DSyNW1x7-xg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-57, 80","volume":""},{"id":5905,"author":"杨文山","title":"西周青铜器“邢侯簋”通释(下)","abstract":"“邢侯簋”为西周青铜器邢器之一,铭文内容涉及到周王对邢侯的“迁封”,是研究西周邢国封建的重要材料。对“邢侯簋”进行通释,并结合有关金文资料和文献记载,就邢国“迁封”有争议的若干历史问题进行了考述。","categories":["06_族氏方国"],"year":2005,"publication":"邢台学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOtUhxChzgrG3IgijYBx2QF2Rige9PCCTg9d7FkJE0wkw8atOyZSB3-sLGBZI2f3wDAcbz2ZfCAwqcz4GLXx8DbJoPI2_9WMTjaZk46rV6iCKf0MUtr-36bKV2HmiVgi1v5KaYJH_yZpGL5caXLK45yzprhdPMVVLDwxb75d9rgA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46151","volume":""},{"id":5922,"author":"李锦山","title":"郳国公室墓葬及其相关问题","abstract":"又称作小邾,为周代附庸小国,由于先秦文献记载过于简略,长期以来,有关国都邑确切地望以及历史概况一直扑朔迷离。综合最新考古资料以及文献记载,对国都邑,君墓葬,出土的铜器铭文所涉及的问题进行了考证和研究。","categories":["06_族氏方国"],"year":2005,"publication":"枣庄学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPNCKI7V2vQunW_3p46B57Chn_CxVaK6UxtIPZ4v-46qeUbkWuA_kBrnfJXgkT4XMzlsdlHokBRzw4W62Dkg3T27Q0ePiTeRNjDodgGl5QrmuMrK9otb3Qi0WfpTczufaWakY73xVRLzdbqzPIiUF2SaOS3NwpEX7HECuVVYSzSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-34","volume":""},{"id":6513,"author":"何景成; 吴振武","title":"商周青铜器族氏铭文研究","abstract":"族氏铭文是指商周青铜器上所铸的用以标识作器者家族名号的铭文,这类铭文往往比较象形,在整条铭文中相对独立,与其它铭文基本没有内容上的联系。本文即是对族氏铭文的系统整理和研究。本文首先界定了族氏铭文的概念和本文的研究范围,对这一问题的研究历史和现状做了一番总结。接着分析了族氏铭文的性质和特点,认为族氏铭文是代表家族名号的文字,有时常常联缀以职事性铭文,以表示该家族的出身和社会地位。然后我们将族氏铭文分为单一氏名和复合氏名两大类进行探讨。对于单一氏名,主要从出土情况的角度分析该家族的分布情况,分析了一些具体的族氏铭文,由此总结族氏铭文的出土地与该家族分布地的关系。对于复合氏名,我们主要讨论了复合氏名的各种类型,并分析各类复合氏名的含义与产生的原因。最后,我们从聚落形态的角度,探讨了安阳殷墟各家族的聚居状态。并依据族氏铭文资料,探讨殷亡后殷遗的状况。","categories":["06_族氏方国"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIc1WfXH2F2gzOQR69N3v1qW0_CsdTLBevuxhWY7jUsWcQCpkkXOfbhC3yPvnPzoNXe0AtGbLOQtg0t977Rlcc9ngELRLb793oV855hRq5NhLVEz4a5OVavgfjg9RO9OUVovu6NgBaTm_qhFDyKAxv0HWTfDcQZVwEocDjUsKmGo56472gXar-x&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6881,"author":"甘大明; 吴振武; 吴良宝","title":"曾国之谜再研究","abstract":"“曾国之谜”及其相关问题是学术界争议较大的重要问题。1978 年湖北随县擂鼓墩一号墓(即曾侯乙墓)的发掘,引发了学者们的激烈讨论,出现了关于曾、随关系的多种说法。这些说法,有的只侧重于考古材料,有的仅以文献资料为据,而在将两者结合起来进行讨论这一方面则做得不尽如人意,以致于各家得出彼此不同甚至截然对立的结论。从目前所能见到的资料来看,曾、随为一国两名的可能性不是很大。为了论证这一点,本文尽可能地收集有关随、鄫、缯及其相关的申国的文献资料和考古出土材料,将两种材料结合起来对已有的学术成果进行详细讨论,希望对今后的相关研究能起到参考作用。","categories":["06_族氏方国"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLnPP8Xf50RloFrQjtHTlLAmFCvZjA3IAQaR5LLxYt0vVJDXLR5SHZ_ZW2boag4GX5wWvXzwzVD_TeiKqdLPWwQfKaTE894BBnJUdOV6lR6AiVgeXWfkQJZiHEjS0o3ubHUwhuT_Ttwpoh8UQvYd2EB2VOohFDoeqJ4QT7dmovaPKWi-gBFXr-r&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6888,"author":"海宁; 张懋镕","title":"试论青铜盆、盂、敦的关系","abstract":"青铜盆、盂、敦是青铜器史上继簋之后相继出现的三类比较重要的粢盛器,它们在主流粢盛器由簋转变为敦的历史过程中具有十分重要的作用,因此学术界长久以来都十分关注这三类器的研究,但是由于这三类器器形相近、功能相通而且自名存在相互混淆的现象,所以有关这三类器的诸多论著都存在一定的分歧和问题。本文正是从分析和列举这些分歧和问题入手,进而分章节对这三类器的自名、型式划分、时代、地域分布、功用、在墓葬青铜容器组合中的特点以及使用者的身份等问题进行了专门的研究并在此基础上总结和阐明了它们三者之间在名称、器形、功用以及在主流粢盛器转变过程中所体现出来的关系。","categories":["06_族氏方国"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIkk7t96Ap4hLfYLB9ULnK5tay16G6WYPxLE18wWbNJ8HUtEpfGgb1waUVOh6Rdsl7k1_Rj9IEZsn8_xzYAqgfmbPe9qzP2pjAaou-SfvBXDV3GruWih_ocNscCxsHQiprTUd8qUHiRxrQOi-5IGI8PpLOvdBLEuHhZBv90lSirXO_wlgDMb0hq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":5937,"author":"杨亚长","title":"金文所见之益公、穆公与武公考","abstract":"","categories":["06_族氏方国"],"year":2004,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHmTqjJFpQSLwVD55RhWvfT6UdA6mMxHmmegZpOBl0JqP2Z0MbbGZuBsfznxAiNPXjyu4777KVqY82IpX2Z5ApyNr_XJLhlIIQR-HpOyC_Qk2c1G2kyyBFdflFXsihUggDfUkf82QQIYbjI1PP31pQJADoIVn17B1C3Dp2GKHA6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-75","volume":""},{"id":5952,"author":"李学勤","title":"祼玉与商末亲族制度","abstract":"安阳殷墟刘家庄M10 4 6出土的玉璋墨书文字具有特殊的重要性。通过对其文字的识读 ,可知这类玉璋即是见于金文和《周礼》的玉。尤为重要的是 ,通过对墨书文字所祭对象的研究 ,进一步证明习见于甲金文的“长子” ,实指首子或元子 ,而且说明已有嫡庶之别。结合其他称谓 ,也说明至迟在商末 ,其亲族制度已相当规范和复杂 ,后世的宗法制度于此时已具雏形","categories":["06_族氏方国"],"year":2004,"publication":"史学月刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx-QtUFHCm2Yz1cXMRnDPiCJ_75qrivDsWhCdVL_53vtvHauKy_UgcZJMHukL4LT0LqNuExn38zCXkzUAkyyRcPzLodGwdQ8NDVQf2CVvMa3zFPq2RDilZ8LokhIqqLV_hgSOlyzaudF1lxiB3IqLzkTJlKTo28hovgBe7zG2hzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-22","volume":""},{"id":5958,"author":"任相宏; 张庆法","title":"吴王诸樊之子通剑及相关问题探讨","abstract":"吴王诸樊之子通剑,2003年春季出土于山东省新泰市周家庄东周墓地,属首次发现。铜剑铸有铭文14字,据此可知剑为吴王诸樊之子通所铸,器主、年代明晰。这一铜剑出土地远离吴国故土,应当与伍子胥之子王孙氏及齐国鲍氏有着密切联系。","categories":["06_族氏方国"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJidZanf2FnIk_rAShKrSNdPCYSstcewefCC0OhKs8c5apKr8N2xm4fxQhW3e0gSlFXF-E0KnXm5VscaOnPBOKNA1E2gXm7GOo3fIsMS3zxSVfAAjR_hEHUpLGYTWD3ng-yfTGLGUjjCh_LmZ7v8Y2pcbyOnni5G17fc6OFoVcDKQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-23, 93-95, 97, 2","volume":""},{"id":5968,"author":"王辉; 萧春源","title":"珍秦斋藏王二十三年秦戈考","abstract":"澳门萧春源珍秦斋藏青铜戈一件,戈援细长上翘,中长胡三穿,内上有刻铭2行14字。铭“王二十三年”指秦昭襄王二十三年(前284年);“家丞”为魏冉封邑陶之丞,也是器物的监造者。本文据此戈及十四年、二十年相邦冉戈、二十六年丞相戈等相关秦兵器讨论魏冉五任相邦的情况,昭襄王时期秦戈形制及战国晚期秦的工官制度。","categories":["06_族氏方国"],"year":2004,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2004.04.004","pages":"68-75, 158","volume":""},{"id":5972,"author":"石岩","title":"周代金文女子称谓研究","abstract":"本文根据两周金文中所见女子称谓,并结合《春秋》、《左传》中所见女名,对两周的女子称谓作了比较全面的分析研究。从女子称谓在金文及文献中的各种构成方式的比较,及金文中女子称谓或以主体、或以客体出现的方式,对当时的姓氏制度、婚姻制度进行了探讨分析。","categories":["06_族氏方国"],"year":2004,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2004.03.003","pages":"46251","volume":""},{"id":5991,"author":"张彦修","title":"河南三门峡市虢国墓地M2001墓主考","abstract":" 《三门峡虢国墓》(第一卷)认为M2001墓主为虢季,身份为虢国的一代国君,该墓的年代应为西周晚期的晚段,即宣、幽时期。这个结论有理有据,当属无误。但是,M2001墓主当为历史文献或金文中哪一位虢国国君,却未深入考证。根据有关文","categories":["06_族氏方国"],"year":2004,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaDOt2B1UWt3TMgYuBvuoRQ8BrKqMEuTEYz0rymyc4LSWLzxywTUjLrJo_X2dZ39ihfGPED0_gSTvT-qzAB6vMzba1sqKjLPATpKGn7kvYkHcALVqt50vHrO5eDvQBtl8gnd-FkMhSfG9U1DT0jbZMdwvfoqnhfa0ymJzT8eXTdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-78","volume":""},{"id":6000,"author":"曹兆兰","title":"从金文看两周婚姻关系","abstract":"从两周金文可以看出当时婚姻关系:明言婚娶,载明夫方信息,铭文本身表明夫妇关系、子母关系,器铭之间互证可明确的婚姻关系。金文结合传世文献可看出:女性称谓首字所标示的父方信息、夫方信息,判断夫妇婚姻关系,从两周金文并结合遗存看婚姻关系。","categories":["06_族氏方国"],"year":2004,"publication":"武汉大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZU9MK2_vjUoOv_o5xQ2TpPfJjCsBrYx61ZhlIgDCxjoPTgiNnE8BGG2BvW7tVjMfF5qGG2UxiBkMPvV8bJQmgR7t4CpRdwIpK2pM3lCtfY909Jsdv5VU0r5Q0zEL6ed_XNksHnZu7xXzWuEFE7plJXtHtDjHRQoV-GpmSzlOYiQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-114","volume":""},{"id":6522,"author":"郑小炉; 林沄","title":"吴越和百越地区周代青铜器研究","abstract":"本论文研究内容为吴越和百越地区出土的周代青铜器，全文共分七个部分。《绪论》。界定了吴越和百越地区的地理范围和本文的主要研究对象，回顾了吴越地区和百越地区青铜器研究的简要历史，归纳了学术界对吴越和百越地区周代青铜器研究方法的发展变化、传统研究的范围和已取得的成果，并指出其不足之处。第一章 《各地出土的青铜器及其年代》。本章对江苏南部、安徽南部、浙江、福建、江西、湖南、广东、广西等八个地区出土的周代青铜器以及这些地区之外的区域出土的周代有铭吴越青铜器，按发现年代的早晚顺序逐一介绍了各遗址出土的铜器以及陶器等其它伴出器物的情况，并简要地判断了各遗址的年代和其中出土铜器的年代。第二章 《南方青铜器断代问题的探讨》。 本章首先对南方青铜器的断代理论进行了探讨，将之分为对单件青铜器断代和对青铜器群的断代两个层次，对单件青铜器的断代方法主要是参考中原标准和周边铜器断代成果、建立自身发展序列和根据伴出器物","categories":["06_族氏方国"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJd3xO6kwWvrG6RQx2aJOG4H_ZOIfbDsApBkkya0N1x70xA7PYJJ9Sj4feSbsSKrjikOw690RWlOM9w_RJBWdrJ4irmwLEWdTLll7Nu6mkTdFjavWtf46k8aIdz9ma4IzUQNDAG3wvCaRxirQMQHfn2FrRE-ZNzSkpjVnQmnZCyj1BxP_sWTv_-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6897,"author":"张良群","title":"徐福家世初考","abstract":"家世,指家庭的世系或门第。而家谱又名族谱、宗谱,家乘。是记载一姓世系和重要人物事迹的重要书籍。它不仅记录着该家族的来源、迁徙的轨迹,还包括了家族生息、繁衍、婚姻、文化等历史文化的过程.因此,探讨徐福家世也应是徐福研究的重要内容。本文主要通过徐氏家谱,追寻徐福家世之脉络。","categories":["06_族氏方国"],"year":2004,"publication":"中国（岱山）徐福东渡节暨徐福文化国际研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWUXjXodq_UwzL0WrHy8MAxCCScp6WNP5d3P0AdsZJQhg6DvRHSg0z_JxXClzYY2U-DYuL-d-luyFcAnD_DxDgp0h1I_7p9opa30IQuPaJOY-lwiJhPE4RcFT47EDwbbK2idfY3MzLryfN7WQnSbFeVd9RGXYxjECtmuLfKD_EOfKr1-lINn72&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-30","volume":""},{"id":7119,"author":"王恩田","title":"《金文编·附录》中所见的复合族徽","abstract":"商周金文中有一些图形和文字,或单独存在,或缀于铭文末尾,少数则书于铭文开头或中间,多诡异难识。自郭沫若首倡族徽说以来,经过一些学者的补充与诠释,特别是同一种族徽的铜器往往出土于同一墓地或同一墓区的事实,为族徽说提供了坚实的考古学证据。族徽说已为越来越多的学者所接受,但仍然有不少问题有待于深化。例如,在同一件铜器上,常常可以看到两种或更多的族徽共存。以往把两种族徽中的一个解为族徽,另一个则解为官名或人名。这种方法显然无法合理解释两种以上族徽","categories":["06_族氏方国"],"year":2004,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLM-Ts_nDSw63uxv_Yabhfw2NHs4hovPSVyih-biVB2BqbmhSQ1wIkcqjSOzBxCCyNNhAkpqQARt_PDp13neaLB627d9LsYCg1EVBk2fRRS0hA4gtXCvzsQd_Hk1GDkXQwhx6oEFkOxhE5RTy0dSOwSPzNmPuVrzf__CrUuFd1Mkg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"257-302","volume":"3"},{"id":7122,"author":"王长丰","title":"试论商周时期的楚——兼释《太保玉戈》所载之邾国初封","abstract":"楚国的强盛与繁荣是在春秋战国时期,楚文化的研究不仅应重视春秋战国时期的楚国历史、文化现象,此前楚的相关历史亦不容忽视。楚在春秋战国时期如此兴盛,而楚文化的兴起发展在古籍文献中仅见支言片语,其中深层次的背景不能不让人萦思。商代时,武丁的统治已达荆楚,《诗·商颂·殷武》载,&quot;挞彼殷武,奋伐荆楚&quot;。《史记·楚世家》对楚先民的记载:商汤灭夏,楚之先祖陆终生六子,一支彭祖氏为殷之侯伯,一支则为楚之先民——季连。&quot;季连生附沮,附沮生穴熊&quot;①。其后则语不能详。穴熊之世离《殷武》所载&quot;奋伐荆楚&quot;要古远,&quot;挞彼殷武,奋伐荆楚&quot;之荆楚定为穴熊之后世子孙。","categories":["06_族氏方国"],"year":2004,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJJ838i1loAvWgK6zkgKX46IqHIFIdUB0551o8az58yjeUsq8cmtPiZx7wkU-cfX53A5PGRQKu1JWGB1eHIMxJVHb8v18dWmU_EnltCQUfshG-PAQ-vnusUe5fKACd4r5CgWKjxK4kvhVcL1VMLGTpUO0mVEfhmZ5hzVjpPxo2lfQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"152-157","volume":""},{"id":4874,"author":"张天恩","title":"从逨盘铭文谈西周单氏家族的谱系及相关铜器","abstract":" 陕西眉县马家镇杨家村附近,屡有重要的西周青铜器出土。1955年在杨家村东约1公里的李村,发现了盠驹尊等器,1972年在杨家村西北台地上出土了大旗鼎,1985年又在该台地发现逨钟等18件铜器。2003年元月,新出土逨盘、速鼎等铜器27件。特别是新出的这一批铜器,每件都有铭文,为研究西周历史、考古提供了非常珍贵的资料。","categories":["06_族氏方国"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6UoNvbB2zBJd-xPoyGtxi8Z-LCTL33E49Jow0bvkQFQraRUcNJNhZmhU8mesHSHnuWRNG3O0LLv7H_8OJnuZn0OSfPkTgXDmfRyQdJw-EiFZCb8wncMcjwTIvIe7TsBahMWlzCT155buGSxP-JrtLob0XPBbsZoayUm3a-v_RinO_5S85ryQp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-65","volume":""},{"id":4881,"author":"任相宏","title":"邿中簠及邿国姓氏略考","abstract":" 1986年4月,山东省长清县万德镇石都庄发现2件邿中簠,现藏长清县博物馆。同时发现的还有铜鼎2件,为同一墓葬(编号M1)所出。现试将邿中簠铭文略作考释,并就其相关的邿国姓氏等问题也作一扼要探讨。","categories":["06_族氏方国"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUV8v38PkIvLfxfNS576PpEq8IpQL7pFEA1FPlqKr8tbbdAKMzuNVeACbObpHQi_yIxuLS8SQf_iy9VrOvE1g8vwPUKCY7FeB1esssFOUdIoAtpUYT3NnWE9hlScZR5tRun1tB0uvMTL7Agd2mFDJIzyON71EuWDTLnMgbsDKpBhQKJBdAJfIx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-43","volume":""},{"id":6010,"author":"岳连建; 王龙正","title":"金文“城虢”为东虢考","abstract":" 虢国是周初分封的姬姓诸侯国,据文献记载最初就有两个,其国君分别是周文王的两个弟弟——虢仲与虢叔,他们同时兼任周王朝的卿士,领有采邑和封地。虢仲的封地在今河南荥阳,后世称为东虢;虢叔的封地实为采邑,在今陕西宝鸡,位于西周王朝畿内,其相对于东虢而言,它位于西部,故而称为西虢。此外,在文献资料中还有南虢、北虢以及","categories":["06_族氏方国"],"year":2003,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4dSsH1vB7CTEFre8XoaYwKBerUNKK6_Gi-SZNhB5Fv9JxMCet5nwjtZH1fbS2jAUWUdTEbf4y-U1iNQuTFgYipAhI3-pfhRcCYpmoVW3Y7YYU-X5tUEloTqWXPp9oM8Azc_T-jrsGussgS1iOT5RdXDM2TYLl9owJ8iUbOmVWWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-36","volume":""},{"id":6037,"author":"牛济普","title":"格国、倗国考","abstract":"西周有格伯,格国故地在河南荥阳市北的张楼村一带。金文“倗” 和“冯”二字相通,“冯” 地与格国相邻。","categories":["06_族氏方国"],"year":2003,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeiRBPJ3YenyeA1Z6KV6wdKyC7kRva8wuJW0q2hISgF7Yh1HqSp9AP-nD2lLSgF82tC-3yzXS3sBU8f05UH8Xetj6ptMiOg58XRQwjPRgINDvOudvffblsnmNeM1kbqhMEUAG390eo7AQw4g80Nefa43Jwg9q9DuAVjl3N3sCadA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":6039,"author":"董珊","title":"略论西周单氏家族窖藏青铜器铭文","abstract":"本文是对2003年初陕西眉县杨家村发现窖藏青铜器铭文的初步研究。内容包括:1.根据近年新研究成果,对逑盘铭文的用语做必要的解释;2.讨论该窖藏器主的名、字、族氏,从逑盘铭所提供世系信息,系联出一批相关铜器;3.器主逑两次册命的职官及其间的关系;4.四十二年逑鼎铭关于杨侯的记载与地理问题。","categories":["06_族氏方国"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHpa4XR4nX9ykS5We00ysrQrlbYxg_rBMMvxqQOBFBn9lFJr3tKUvEqA7J6utj30N4JXzFxzU3kSzNMq-jFXb2FfeQZbVNZxCgatlj9mXi92vuMmmWO5dhXDo_eNiqAUoWBMOz7A2BbFEBq4x0xC19iVhwiL-i7Sgi2heFvZS9IA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-50","volume":""},{"id":6041,"author":"王晖","title":"殷商十干氏族研究","abstract":"先商时期的帝喾、河、岳、王亥等先公的祭日一般为辛日,正好印证古文献中所说的从帝喾开始的先商为“高辛氏”时代,商代的历代商王均是高辛氏之后。以十干来命名其庙号,是因为商王自认为是十干部族的共主,于是便擅占所有十干之日,选择来作为商王的庙号,其实其族仍属“辛”部族。伊尹(黄尹)祭日往往选丁日,殷墟卜辞中也常称伊尹族为“伊丁”、“伊丁人”,说明伊尹为丁族。据殷墟卜辞,兕应为庚族,(夏戊)可能为甲族;商铜器铭文中有丙族、己族,还有癸族、乙族及丁族组成的师旅,并由乙族受旗担任师旅指挥的任务。这些均证明商代及先商时期存在着以十干命名的部族。","categories":["06_族氏方国"],"year":2003,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLOjBSb-Y57mPzvoSR7U6z7Lvzi3rwW41MiLdvmTa0ItNi-bPj2QtdSrmkwlpm4pgQDCvYueXAFtEBOpiLiM7ukrgeRchDwKC28qJm4Ygn2_qbWusbPEC4CeMhT3BN1Re8WHRbaIzRR2Yd4hHhrMXCXACgy1AyyIbXbyupoEYpMNA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-42","volume":""},{"id":6045,"author":"李零","title":"读杨家村出土的虞逑诸器","abstract":"陕西眉县出土的二十七件青铜器,是2003年最重要的考古发现之一。本文对这批铜器的铭文,从遣词用语到历史内容进行系统考释,认为作器者以“逑”为氏,行辈为“叔”,字“五父”,是单氏家族的一个分支,即“灵伯”和“懿仲”的后代。这个家族曾历事西周各王(从文王到厉王),共七世。此人继承其先辈的职务,继续担任宣王的虞官,负责管理山林川泽。宣王四十二年,因协助杨侯长父伐猃狁有功,受到周王册赏;四十三年,又被册命加官,兼管“历人”。铜器出土地点周围还有三次重要发现。除一件年代较早的大鼎还不能完全肯定,其它两次都是属于这个家族的铜器,一次是其先辈(彖皿)的铜器,一次是他本人使用的乐器。作者认为,逑的七世祖考,其中的(彖皿)是重要人物,其祖父是成王前后的王室大臣益公,父亲是这批铭文中的“新室仲”。可见益氏家族也是从单氏分出。另外,从(彖皿)器讲养马的铭文以及文献所见虞的职司考虑,马政也是由虞官负责。这或可解释","categories":["06_族氏方国"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLG6CI-kiHpPFsJliEo5CWCKtAq38y4F0bRmWyloCns82buWXuxpRBj4FQ9Ivr256HljXA5HZ5Tx8ZXKqxtAeNXiO3o_0lAmtQN61rCf5ZIdSNhI6TXjWmv8Rh258o0EAwfFwsQJCC0sq4pOsRturcvFSIF4dl43-kSygOKEAStEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-27, 90-93","volume":""},{"id":6052,"author":"王辉; 刘军社; 刘怀君","title":"宝鸡眉县杨家村窖藏单氏家族青铜器群座谈纪要","abstract":" 2003年1月19日傍晚,陕西省杨家村一西周晚期窖藏出土青铜器27件,皆有铭文,最长者有372字,是建国以来发现的西周青铜器铭文中","categories":["06_族氏方国"],"year":2003,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIy2iF7AiMpLjM-Ze4RjRwLWiNLqPB8VjA3PDECGUmQm4mnfShqRwa1pbnP48kg7ptMVCfPcq-63xPZny12TXnkSeloax6acTAmuEhqjv8qHO7Heju7R8AARSqAxdfpfcXgcet9qXYvk51jlNr5bqItAdawc1EDyY50ugeRhP2UXg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-16","volume":""},{"id":6079,"author":"任伟","title":"西周早期金文中的召公家族与燕君世系","abstract":"司马迁《史记》对于周初燕君世系的记载非常简略,本文通过对西周燕国铜器铭文及相关文献资料的分析,初步拟出了西周早期的召公家族组织形态及燕君世系。周初第一代燕侯当为“克”,后“父子相传”,克之子燕侯旨成为第二代燕候。召伯父辛应是召公次子,留守宗周王朝继承父职,爵称当是“召伯”,其长子为伯(?)亦世为王官。留守宗周的可能还有召公另一子,其长子为伯觫。","categories":["06_族氏方国"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkzTWXSJLFL3InDyfqs0stCBxeIWb8I6YeEo0D_4G2Q1MlH423sF5sgZw4lOf9SYPlxdaBcdnE9nSc1yYFFn26C4NnDMNwhjHMdeBQL5FqkIM38FhuiAwhYak8CNAjO9ZNVnVjzHRHMF9S28yOLoBpSiK8l_vgW4Oubu6UA9VFow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-83","volume":""},{"id":6081,"author":"张彦修; 尹保科","title":"三门峡虢国的青铜文化","abstract":"三门峡虢国青铜文化是物质文化与精神文化高度交融的产物 ,青铜器的类型、形制、纹饰和铭文蕴含丰富的文化内容 ,当其与政治、经济、军事等活动结合起来之后 ,进一步酿造出崇礼乐、尊鬼神、尚武勇的青铜文化。","categories":["06_族氏方国"],"year":2003,"publication":"洛阳师范学院学报","link":"https://link.cnki.net/doi/10.16594/j.cnki.41-1302/g4.2003.01.029","pages":"90-93","volume":""},{"id":6082,"author":"杨文山","title":"青铜器“巳簋”与邢齐通婚——两周邢国历史综合研究之三","abstract":" 青铜器巳簋,又称邢姜太宰巳簋,铭文内容涉及到邢国与齐国的通婚,是研究邢齐关系的重要材料。李殿福先生《巳簋初释》[1]、张柏忠先生《霍林河矿区附近发现的西周铜器》[2]、李学勤先生《麦尊与邢国的初封》[3]、孙敬明先生《西周金文与邢史举隅》[4]、李先登先生《邢国青铜器的初步分析》[5]等,均对此器作过考释或论述。本文广集诸家之说,参","categories":["06_族氏方国"],"year":2003,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2003.01.003","pages":"17-27","volume":""},{"id":6107,"author":"叶林生","title":"“绝地天通”新考","abstract":"中国先秦典籍中的“绝地天通”故事 ,历来众说纷纭。本文以全新的视角 ,通过文献考证 ,结合考古资料 ,论证了“绝地天通”既不是神话故事 ,也不是宗教问题 ,而是发生在东夷族有虞氏与古三苗部族之间的、一个具有相当真实性的历史事件 ,其本质就是将苗民分隔南北 ,永不相通","categories":["06_族氏方国"],"year":2002,"publication":"中南民族学院学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITMs3ucXITHJGbStSwW2RSDRJ1t32r_YPNKgXRZ8n1UeevdanzyQ-8dEb8jELuKv_2gxUZ010XmZ6ocAgZ_QmTQ9_3ufbu45a-KfY7lrp07ALM5ikAgJrdhFZ82l6hTTMvC3IR0afYfH-5aD0j5vew0J41nF9Ed99NOq1Otx4vlg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-58, 63","volume":""},{"id":6109,"author":"任伟","title":"西周金文与召公身世之考证","abstract":"召公奭是商末周初著名历史人物之一,然而关于他的身世,却是自汉以降二千多年来学界颇有争议的问题。一种观点认为召公奭是周文王的儿子,而另一种观点却认为召公奭仅是“周之支族”,与周王室的血缘关系较远。本文通过对相关古典文献资料的梳理、分析,特别是通过对西周燕召铜器铭文中“日名之制”的分析,认为召公奭并非如某些文献所言为周文王子,困为“日名之制’是殷人使用的制度,周王室是不采用的,召公氏族虽与姬周同姓却是“周之支族”,此族本与姬周本支同居西土,后从本支分离出来迁居于东方“召”地,“召”随后演变为此姬周别支之氏族名、国名。","categories":["06_族氏方国"],"year":2002,"publication":"郑州大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJcFQEBC8JnAJh4ilxtIxiUpeGYLYfpoYxL5EY3Fn0dJMnfeeaEjXb8GWi92PkozUv3NmamD2L5ymxuPTJfGTjv_ZrmoradL-quVxKIhFIeHGsuc_qKegOrdieFYVKNIGBjXEK-50KyS2fabNauWLGokz90G8SWmJaiFuuCna3xUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-62","volume":""},{"id":6117,"author":"魏宜辉","title":"再谈■巢编镈及其相关问题","abstract":"巢编镈是南京博物院考古研究所1995年在发掘江苏省邳州市九女墩遗址2号墩时出土的,一组6枚,铭文表明器主巢乃吴王的玄孙,是吴国的贵族①。巢编镈的出土,无疑为吴越青铜器研究又增添了一份有价值的资料,但由于铜器铭文的刻写存在着漏字、讹误现象,以至于在讨论器主的身份及所属国族时出现了多种意见,对于这些","categories":["06_族氏方国"],"year":2002,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgbeCE7YJGWw8_4KxE1nZ0zTgUr7rMVI1xQhSO65ngRfqBuEfcY5e7IDO3oqbBpEiiUOjR-GgmY8eSeMJx5-P-6w3HHj52AccoIrmazuKrs1B2C47ZBZIu9v7tHXbOPt5rjoKHMeSXxJFML1JSSEtx5006NVRUEIuh9bNrFx8J6w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-44","volume":""},{"id":6121,"author":"杨肇清","title":"长国考","abstract":"长国曾是殷商王朝西部的重要盟邦 ,后分迁于东部和南部 ,商亡后归顺周朝。甲骨文、金文都有长国的相关资料 ,其历史延续至战国。“长”字与“微”字的古字形相近而有别 ,不可混淆。","categories":["06_族氏方国"],"year":2002,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4RSUEOdnuccPJdEu-pUS_HVvHh8F5h10gRG47nga0AwYWFqjSYiSWiLMq5wywzdbJC5HMIsSAD2k-lzoGnMnvoBwxCpFfeFbuR5uA2M8ZE6tXYjjDTsQolKbmosIAZlMVHZnf34EO9waKBXPdqV6ochWXpw_5w8pxbbYtvpXnBA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-50","volume":""},{"id":6162,"author":"杨文山","title":"西周青铜器“邢侯簋”通释","abstract":"“邢侯簋”为西周青铜器邢器之一 ,铭文内容涉及到周王对邢侯的“迁封” ,是研究西周邢国封建的重要材料。本文除对“邢侯簋”进行通释外 ,结合有关金文资料和文献记载 ,就邢国“迁封”有争议的若干历史问题进行了考述。","categories":["06_族氏方国"],"year":2002,"publication":"邢台师范高专学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_RRgg-NLB41OSbfd03t62zWNoDW8mOmAugFQoWpABacTsFltdsrJ4m1110yGfzAql6IAWMZNvdG31TAFGpYC0j5Rgp4k7yutT8Q0LDdk8FG4FXkvit3ALcZDCpXH8g1E01rMolj84JoEbg_Z9QYqpU_KlphQs2MKlerAp-pCpZw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-28","volume":""},{"id":6169,"author":"杨文山","title":"青铜器“邢侯簋”与邢国迁封──两周邢国历史综合研究之二","abstract":"","categories":["06_族氏方国"],"year":2002,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2002.01.001","pages":"1-10, 36","volume":""},{"id":6532,"author":"孔令远; 彭裕商","title":"徐国的考古发现与研究","abstract":"本文主要利用近年来江苏邳州九女墩徐国王族墓群的出土材料，以及梁王城、鹅鸭城遗址的考古发掘和调查材料，并结合有关文献记载和当地民间传说，论证了邳州九女墩大墓群为徐国王族墓群，梁王城、鹅鸭城遗址为春秋中、晚期徐国的都城遗址，证明史书和地方志中关于春秋时期徐人曾在汉彭城武原县一带活动的记载是真实的。本文还参照有相对纪年的具铭徐器，对徐国金文和徐国青铜器作了较为系统的收集和整理，并作了初步的分期、断代工作，对部分典型徐器作了初步的考证，并通过与邳州九女墩大墓群所出器物的对照，对绍兴306墓、丹徒北山顶春秋墓等国别有争议的墓葬进行了讨论，认为它们应为徐人墓葬，还对《余冉鉦鋮》、《(虘又)巢钟》、《王子婴次炉》等国别有争议的青铜器进行了考证，通过与典型徐国铜器在器物形制、纹饰和铭文风格等方面进行全面比较，得出它们应为徐国铜器的结论。本文还对徐国青铜器中所包含的多种文化因素进行了分析，同时又联系徐淮一带","categories":["06_族氏方国"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKKwzPFU-C-utyDBH-feF_iS9NzhXcJnEvtKtQ5CR_bTiDxBLRNWODnrO5_w0zF7uIVWTAX0CoG0CZSmkeIOeGoI57IOtuM79EHyS-YwVWywLFwriUsr6QsreQKwzmQMmbK2Z2c0dBgtQ6KI_GcMFhFCRGnAvo3OMi4gq2fDgFZWWszD8On9CU6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7164,"author":"辛恰华","title":"再论西周金文中的“秦夷”及相关问题","abstract":"&quot;秦夷&quot;一词见于西周时期的询簋和师酉簋,学者们曾对两器中的铭文内容作了探讨①,但仍有讨论的必要。一、询簋、师询簋、师酉簋的年代询簋1959年出土于陕西省蓝田县,它的出世引起了学者们对有关的师询簋、师酉簋的注意。但三器的相对年代却是学者们","categories":["06_族氏方国"],"year":2002,"publication":"秦文化论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIz5fSQlec8dpWa5sfEuM6qQEcRsqtCj0HyLig3KcH51eW2JgkLp68qcllT90fzxqZFngh3bMf2yLYXJpVXCrLJg3iUiWXie8RtV-Cr49FMjCHosIQoEzfNOkz1CxzJA5TAvYa-DwOYGVyNJu-TD4CqfGXUoWaHJb-OuDlDxEGUVA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"348-357","volume":""},{"id":6179,"author":"曹兆兰","title":"从金文看周代媵妾婚制","abstract":"金文中,作器者分别以7种名义为出嫁女铸媵器。有些铭文虽无“媵”字,但从内容上大致可以推定其为媵器。两女同时被媵送时,其中一女是作为异姓他国来媵的媵妾。两个出嫁女的称谓可能铸于同一媵器之中,也可能分别铸于不同的媵器之中。周代这种异姓嫡媵婚制,使周代女性地位一落千丈。","categories":["06_族氏方国"],"year":2001,"publication":"深圳大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLq8ELQfCfaHmoxZNTMD9HyIWWFKJirxqq97M30oSoduv4CTEtfeIgrxgy1rBua2zqKekXHdlEUejaZisvE5J8PdBEJv0PBMQRilIZRbyQ62whfRRw__Rq98YmrVFPJdjLwtNWcvd1uonapHMHU6TODjimn6hlOzW7hlDJt97Bn2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-107","volume":""},{"id":6201,"author":"辛怡华","title":"扶风庄白■墓族属考","abstract":"","categories":["06_族氏方国"],"year":2001,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iILgez8xsCOkPvLvtO9EHLdBbGU1KpAS_RGSC4HXU2FRWWiiWYG6nHs9JsZPVKnQC8PPvftUGXIxRwVLURW7Eb5Ec0gvV6nn9UHOS56XtmhXOglTACiAoirtuvVFxPOpqS1xAEN8vtso4pJAuhsybOcF09wulxRQPuu_tAnG86Drg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-57","volume":""},{"id":6202,"author":"杨东晨","title":"论西周时期河南地区的民族与文化","abstract":"西周时期 ,周王在河南一带封立的国家 ,从来源上说大致可分为六类 :一是周王室分封的姬姓国 ,二是姜姓炎帝的后裔国 ,三是姬姓黄帝的后裔国 ,四是殷人后裔国 ,五是族源为东夷而早已华夏化的诸国 ,六是南蛮裔族国","categories":["06_族氏方国"],"year":2001,"publication":"河南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15991/j.cnki.411028.2001.04.005","pages":"22-27","volume":""},{"id":6206,"author":"杨文山","title":"青铜器“麦尊”与邢国始封──两周邢国历史综合研究之一","abstract":"","categories":["06_族氏方国"],"year":2001,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2001.03.001","pages":"46031","volume":""},{"id":6550,"author":"张怀通","title":"《春秋·庄公三十二年》伐邢之“狄”考","abstract":"《春秋》所载伐邢之“狄”应为商人。在邢国墓葬考古中，发现有“毁墓”现象，由年代和情势判断，只能是对邢有“亡国”之恨的商人所为。狄也叫戎。戎在金文中写作“■”，最初是商王小乙之子“子■’的氏族徽志。这个氏族一部分居于王畿北境，今河北新乐一带，负守土之责。周公东征后逃匿太行山中。狄也作翟。翟，《说文》云“山雉尾长者”，《赵世家》云“子姓”。图腾和族姓皆与商人相同。","categories":["06_族氏方国"],"year":2001,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7jaS-b9CLN9eGztwUkag2NM3GAWsz-Ubaz4HTcQvA8ebmcTPBERCIzsrQQmftGcc3WW0XeRcwfAtHrek_Qxx_c6BsDVwRj6Q-_yrxqwn8kRnEH40p_wiI4IQ2Fjbh8iYhtABngS9oeIVqNo7rAsFNvLF18rRYjA5D5tOAYcmHLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-27","volume":""}]};